-- ============================================================
-- sp_CxC_Documentos_List
-- ============================================================
CREATE OR REPLACE FUNCTION public."sp_CxC_Documentos_List"(p_codcliente character varying DEFAULT NULL::character varying, p_tipodoc character varying DEFAULT NULL::character varying, p_estado character varying DEFAULT NULL::character varying, p_fechadesde date DEFAULT NULL::date, p_fechahasta date DEFAULT NULL::date, p_page integer DEFAULT 1, p_limit integer DEFAULT 50)
 RETURNS TABLE("codCliente" character varying, "tipoDoc" character varying, "numDoc" character varying, fecha date, total numeric, pendiente numeric, estado character varying, observacion character varying, "codUsuario" character varying)
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_Page  INT := GREATEST(COALESCE(p_Page, 1), 1);
  v_Limit INT := LEAST(GREATEST(COALESCE(p_Limit, 50), 1), 500);
  v_Offset INT := (v_Page - 1) * v_Limit;
BEGIN
  RETURN QUERY
  SELECT
    c."CustomerCode"::VARCHAR      AS "codCliente",
    d."DocumentType"::VARCHAR      AS "tipoDoc",
    d."DocumentNumber"::VARCHAR    AS "numDoc",
    d."IssueDate"                  AS "fecha",
    d."TotalAmount"                AS "total",
    d."PendingAmount"              AS "pendiente",
    d."Status"::VARCHAR            AS "estado",
    d."Notes"::VARCHAR             AS "observacion",
    u."UserCode"::VARCHAR          AS "codUsuario"
  FROM ar."ReceivableDocument" d
  INNER JOIN master."Customer" c ON c."CustomerId" = d."CustomerId"
  LEFT JOIN sec."User" u ON u."UserId" = d."CreatedByUserId"
  WHERE (p_CodCliente IS NULL OR c."CustomerCode" = p_CodCliente)
    AND (p_TipoDoc IS NULL OR d."DocumentType" = p_TipoDoc)
    AND (p_FechaDesde IS NULL OR d."IssueDate" >= p_FechaDesde)
    AND (p_FechaHasta IS NULL OR d."IssueDate" <= p_FechaHasta)
    AND (p_Estado IS NULL OR p_Estado = '' OR d."Status" = p_Estado)
  ORDER BY d."IssueDate" DESC, d."DocumentNumber" DESC, d."ReceivableDocumentId" DESC
  LIMIT v_Limit OFFSET v_Offset;
END;
$function$
;

-- ============================================================
-- sp_CxP_Documentos_List
-- ============================================================
CREATE OR REPLACE FUNCTION public."sp_CxP_Documentos_List"(p_codproveedor character varying DEFAULT NULL::character varying, p_tipodoc character varying DEFAULT NULL::character varying, p_estado character varying DEFAULT NULL::character varying, p_fechadesde date DEFAULT NULL::date, p_fechahasta date DEFAULT NULL::date, p_page integer DEFAULT 1, p_limit integer DEFAULT 50)
 RETURNS TABLE("codProveedor" character varying, "tipoDoc" character varying, "numDoc" character varying, fecha date, total numeric, pendiente numeric, estado character varying, observacion character varying, "codUsuario" character varying)
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_Page  INT := GREATEST(COALESCE(p_Page, 1), 1);
  v_Limit INT := LEAST(GREATEST(COALESCE(p_Limit, 50), 1), 500);
  v_Offset INT := (v_Page - 1) * v_Limit;
BEGIN
  RETURN QUERY
  SELECT
    s."SupplierCode"::VARCHAR      AS "codProveedor",
    d."DocumentType"::VARCHAR      AS "tipoDoc",
    d."DocumentNumber"::VARCHAR    AS "numDoc",
    d."IssueDate"                  AS "fecha",
    d."TotalAmount"                AS "total",
    d."PendingAmount"              AS "pendiente",
    d."Status"::VARCHAR            AS "estado",
    d."Notes"::VARCHAR             AS "observacion",
    u."UserCode"::VARCHAR          AS "codUsuario"
  FROM ap."PayableDocument" d
  INNER JOIN master."Supplier" s ON s."SupplierId" = d."SupplierId"
  LEFT JOIN sec."User" u ON u."UserId" = d."CreatedByUserId"
  WHERE (p_CodProveedor IS NULL OR s."SupplierCode" = p_CodProveedor)
    AND (p_TipoDoc IS NULL OR d."DocumentType" = p_TipoDoc)
    AND (p_FechaDesde IS NULL OR d."IssueDate" >= p_FechaDesde)
    AND (p_FechaHasta IS NULL OR d."IssueDate" <= p_FechaHasta)
    AND (p_Estado IS NULL OR p_Estado = '' OR d."Status" = p_Estado)
  ORDER BY d."IssueDate" DESC, d."DocumentNumber" DESC, d."PayableDocumentId" DESC
  LIMIT v_Limit OFFSET v_Offset;
END;
$function$
;

-- ============================================================
-- sp_anular_compra_tx
-- ============================================================
CREATE OR REPLACE FUNCTION public.sp_anular_compra_tx(p_num_fact character varying, p_cod_usuario character varying DEFAULT 'API'::character varying, p_motivo character varying DEFAULT ''::character varying)
 RETURNS TABLE(ok boolean, "numFact" character varying, "codProveedor" character varying, mensaje character varying)
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_fecha_anulacion  TIMESTAMP;
    v_cod_proveedor    VARCHAR(60);
    v_fecha_compra     TIMESTAMP;
    v_ya_anulada       BOOLEAN;
    v_saldo_total      DOUBLE PRECISION;
BEGIN
    v_fecha_anulacion := NOW() AT TIME ZONE 'UTC';

    -- ============================================
    -- 1. Validar que la compra existe
    -- TODO: tabla Compras es legacy
    -- ============================================
    SELECT
        "COD_PROVEEDOR",
        "FECHA",
        CASE WHEN "ANULADA"::TEXT IN ('1', 'true') THEN TRUE ELSE FALSE END
    INTO v_cod_proveedor, v_fecha_compra, v_ya_anulada
    FROM "Compras"
    WHERE "NUM_FACT" = p_num_fact;

    IF v_cod_proveedor IS NULL THEN
        RAISE EXCEPTION 'compra_not_found';
    END IF;

    IF v_ya_anulada = TRUE THEN
        RAISE EXCEPTION 'compra_already_anulled';
    END IF;

    -- ============================================
    -- 2. Marcar compra como anulada
    -- TODO: tabla Compras es legacy
    -- ============================================
    UPDATE "Compras"
    SET "ANULADA" = 1,
        "CONCEPTO" = COALESCE("CONCEPTO", '') || ' [ANULADA: ' || TO_CHAR(v_fecha_anulacion, 'YYYY-MM-DD HH24:MI:SS') || ']'
    WHERE "NUM_FACT" = p_num_fact;

    -- ============================================
    -- 3. Anular detalle
    -- TODO: tabla Detalle_Compras es legacy
    -- ============================================
    UPDATE "Detalle_Compras"
    SET "ANULADA" = 1
    WHERE "NUM_FACT" = p_num_fact;

    -- ============================================
    -- 4. Revertir master."Product" Ã¢â‚¬â€ restar lo que se habia sumado
    -- ============================================
    CREATE TEMP TABLE _detalles_compra_anul (
        "CODIGO"   VARCHAR(60),
        "CANTIDAD" DOUBLE PRECISION
    ) ON COMMIT DROP;

    -- TODO: tabla Detalle_Compras es legacy
    INSERT INTO _detalles_compra_anul ("CODIGO", "CANTIDAD")
    SELECT
        "CODIGO",
        COALESCE("CANTIDAD", 0)
    FROM "Detalle_Compras"
    WHERE "NUM_FACT" = p_num_fact
      AND COALESCE("ANULADA"::INT, 0) = 0;

    -- Insertar movimiento de anulacion en MovInvent
    INSERT INTO "MovInvent" (
        "DOCUMENTO", "CODIGO", "PRODUCT", "FECHA", "MOTIVO", "TIPO",
        "CANTIDAD_ACTUAL", "CANTIDAD", "CANTIDAD_NUEVA", "CO_USUARIO",
        "PRECIO_COMPRA", "ALICUOTA", "PRECIO_VENTA", "ANULADA"
    )
    SELECT
        p_num_fact || '_ANUL',
        d."CODIGO",
        d."CODIGO",
        v_fecha_anulacion,
        'Anulacion Compra:' || p_num_fact || ' - ' || p_motivo,
        'Anulacion Ingreso',
        COALESCE(i."StockQty", 0),
        d."CANTIDAD",
        COALESCE(i."StockQty", 0) - d."CANTIDAD",
        p_cod_usuario,
        COALESCE(i."COSTO_REFERENCIA", 0),
        0,
        COALESCE(i."SalesPrice", 0),
        0
    FROM _detalles_compra_anul d
    INNER JOIN master."Product" i ON i."ProductCode" = d."CODIGO"
    WHERE d."CODIGO" IS NOT NULL AND d."CANTIDAD" > 0;

    -- Restar del inventario en master.Product.StockQty (revertir el ingreso)
    WITH "Totales" AS (
        SELECT "CODIGO", SUM("CANTIDAD") AS "TOTAL"
        FROM _detalles_compra_anul
        WHERE "CODIGO" IS NOT NULL
        GROUP BY "CODIGO"
    )
    UPDATE master."Product" i
    SET "StockQty" = COALESCE(i."StockQty", 0) - t."TOTAL"
    FROM "Totales" t
    WHERE t."CODIGO" = i."ProductCode";

    -- ============================================
    -- 5. Anular CxP (marcar como anulada en P_Pagar)
    -- TODO: tabla P_Pagar es legacy
    -- ============================================
    UPDATE "P_Pagar"
    SET "PAID" = 1,
        "PEND" = 0,
        "SALDO" = 0
    WHERE "DOCUMENTO" = p_num_fact
      AND "TIPO" = 'FACT'
      AND "CODIGO" = v_cod_proveedor;

    -- ============================================
    -- 6. Recalcular saldos del proveedor en master."Supplier"
    -- Antes actualizaba dbo.Proveedores.SALDO_TOT; ahora actualiza master.Supplier.TotalBalance
    -- ============================================
    -- TODO: tabla P_Pagar es legacy
    SELECT COALESCE(SUM(COALESCE("PEND", 0)), 0)
    INTO v_saldo_total
    FROM "P_Pagar"
    WHERE "CODIGO" = v_cod_proveedor
      AND "PAID" = 0;

    UPDATE master."Supplier"
    SET "TotalBalance" = v_saldo_total
    WHERE "SupplierCode" = v_cod_proveedor
      AND COALESCE("IsDeleted", FALSE) = FALSE;

    -- Retornar resultado
    RETURN QUERY
    SELECT
        TRUE                                AS "ok",
        p_num_fact                          AS "numFact",
        v_cod_proveedor                     AS "codProveedor",
        'Compra anulada exitosamente'::TEXT AS "mensaje";

EXCEPTION WHEN OTHERS THEN
    RAISE;
END;
$function$
;

-- ============================================================
-- sp_anular_documento_compra_tx
-- ============================================================
CREATE OR REPLACE FUNCTION public.sp_anular_documento_compra_tx(p_num_fact character varying, p_tipo_operacion character varying DEFAULT NULL::character varying, p_cod_usuario character varying DEFAULT 'API'::character varying, p_motivo character varying DEFAULT ''::character varying)
 RETURNS TABLE(ok boolean, "numFact" character varying, mensaje character varying)
 LANGUAGE plpgsql
AS $function$
BEGIN
    IF NOT EXISTS (SELECT 1 FROM "DocumentosCompra" WHERE "NUM_FACT" = p_num_fact) THEN
        RAISE EXCEPTION 'documento_no_encontrado';
    END IF;

    IF EXISTS (SELECT 1 FROM "DocumentosCompra" WHERE "NUM_FACT" = p_num_fact AND "ANULADA" = 1) THEN
        RAISE EXCEPTION 'documento_ya_anulado';
    END IF;

    UPDATE "DocumentosCompra" SET "ANULADA" = 1 WHERE "NUM_FACT" = p_num_fact;

    -- Anular en CxP si existe
    IF p_tipo_operacion = 'COMPRA' THEN
        UPDATE "P_Pagar" SET
            "SALDO" = 0,
            "PAID" = 1,
            "OBS" = COALESCE("OBS", '') || ' [ANULADO]'
        WHERE "DOCUMENTO" = p_num_fact;
    END IF;

    RETURN QUERY SELECT TRUE, p_num_fact, 'Documento anulado'::TEXT;
END;
$function$
;

-- ============================================================
-- sp_anular_documento_compra_tx
-- ============================================================
CREATE OR REPLACE FUNCTION public.sp_anular_documento_compra_tx(p_num_doc character varying, p_tipo_operacion character varying, p_cod_usuario character varying DEFAULT 'API'::character varying, p_motivo character varying DEFAULT ''::character varying, p_revertir_inventario boolean DEFAULT true)
 RETURNS TABLE(ok boolean, "numDoc" character varying, "tipoOperacion" character varying, mensaje character varying, "inventarioRevertido" boolean)
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_fecha_anulacion TIMESTAMP := NOW() AT TIME ZONE 'UTC';
    v_ya_anulado      BOOLEAN;
BEGIN
    -- Verificar existencia
    -- TODO: tabla DocumentosCompra es legacy
    SELECT "ANULADA"::BOOLEAN
    INTO v_ya_anulado
    FROM "DocumentosCompra"
    WHERE "NUM_DOC" = p_num_doc AND "TIPO_OPERACION" = p_tipo_operacion;

    IF v_ya_anulado IS NULL THEN
        RAISE EXCEPTION 'documento_no_encontrado';
    END IF;

    IF v_ya_anulado = TRUE THEN
        RAISE EXCEPTION 'documento_ya_anulado';
    END IF;

    -- Validaciones especificas
    IF p_tipo_operacion = 'ORDEN' AND EXISTS (
        SELECT 1 FROM "DocumentosCompra"
        WHERE "DOC_ORIGEN" = p_num_doc AND "TIPO_OPERACION" = 'COMPRA' AND "ANULADA" = FALSE
    ) THEN
        RAISE EXCEPTION 'orden_tiene_compra_asociada';
    END IF;

    -- Cargar detalle para reversion de inventario
    CREATE TEMP TABLE IF NOT EXISTS _detalles_compra (
        "COD_SERV" VARCHAR(60),
        "CANTIDAD" DOUBLE PRECISION,
        "PRECIO"   DOUBLE PRECISION
    ) ON COMMIT DROP;

    DELETE FROM _detalles_compra;

    IF p_revertir_inventario = TRUE AND p_tipo_operacion = 'COMPRA' THEN
        INSERT INTO _detalles_compra
        SELECT "COD_SERV", COALESCE("CANTIDAD", 0), COALESCE("PRECIO", COALESCE("COSTO", 0))
        FROM "DocumentosCompraDetalle"
        WHERE "NUM_DOC" = p_num_doc AND "TIPO_OPERACION" = p_tipo_operacion AND COALESCE("ANULADA"::INT, 0) = 0;
    END IF;

    -- Marcar como anulado
    UPDATE "DocumentosCompra" SET
        "ANULADA" = TRUE,
        "OBSERV" = COALESCE("OBSERV", '') || ' [ANULADO: ' || TO_CHAR(v_fecha_anulacion, 'YYYY-MM-DD HH24:MI:SS') || COALESCE(' - ' || p_motivo, '') || ']'
    WHERE "NUM_DOC" = p_num_doc AND "TIPO_OPERACION" = p_tipo_operacion;

    -- Anular detalle
    UPDATE "DocumentosCompraDetalle" SET "ANULADA" = TRUE
    WHERE "NUM_DOC" = p_num_doc AND "TIPO_OPERACION" = p_tipo_operacion;

    -- Reversar inventario en master.Product si era compra
    IF p_revertir_inventario = TRUE AND p_tipo_operacion = 'COMPRA' THEN
        -- Restar inventario
        WITH "Totales" AS (
            SELECT "COD_SERV", SUM("CANTIDAD") AS "TOTAL"
            FROM _detalles_compra
            WHERE "COD_SERV" IS NOT NULL
            GROUP BY "COD_SERV"
        )
        UPDATE master."Product" i
        SET "StockQty" = COALESCE(i."StockQty", 0) - t."TOTAL"
        FROM "Totales" t
        WHERE t."COD_SERV" = i."ProductCode";

        -- Registrar movimiento de reversion
        INSERT INTO "MovInvent" ("CODIGO", "PRODUCT", "DOCUMENTO", "FECHA", "MOTIVO", "TIPO",
            "CANTIDAD_ACTUAL", "CANTIDAD", "CANTIDAD_NUEVA", "CO_USUARIO",
            "PRECIO_COMPRA", "ALICUOTA", "PRECIO_VENTA")
        SELECT d."COD_SERV", d."COD_SERV", p_num_doc || '_ANUL', v_fecha_anulacion,
            'Anulacion COMPRA:' || p_num_doc, 'Egreso',
            COALESCE(i."StockQty", 0) + d."CANTIDAD",
            d."CANTIDAD",
            COALESCE(i."StockQty", 0),
            p_cod_usuario,
            COALESCE(d."PRECIO", 0),
            0,
            COALESCE(i."SalesPrice", 0)
        FROM _detalles_compra d
        INNER JOIN master."Product" i ON i."ProductCode" = d."COD_SERV"
        WHERE d."COD_SERV" IS NOT NULL AND d."CANTIDAD" > 0;
    END IF;

    -- Reversar CxP si era compra
    IF p_tipo_operacion = 'COMPRA' THEN
        UPDATE "P_Pagar" SET
            "ANULADA" = TRUE,
            "SALDO" = 0,
            "OBSERVACION" = COALESCE("OBSERVACION", '') || ' [ANULADO]'
        WHERE "FACTURA" = p_num_doc AND "ANULADA" = FALSE;
    END IF;

    RETURN QUERY
    SELECT TRUE, p_num_doc, p_tipo_operacion, 'Documento anulado'::VARCHAR, p_revertir_inventario;

EXCEPTION WHEN OTHERS THEN
    RAISE EXCEPTION '%', SQLERRM;
END;
$function$
;

-- ============================================================
-- sp_anular_documento_venta_tx
-- ============================================================
CREATE OR REPLACE FUNCTION public.sp_anular_documento_venta_tx(p_num_fact character varying, p_tipo_operacion character varying DEFAULT NULL::character varying, p_cod_usuario character varying DEFAULT 'API'::character varying, p_motivo character varying DEFAULT ''::character varying)
 RETURNS TABLE(ok boolean, "numFact" character varying, mensaje character varying)
 LANGUAGE plpgsql
AS $function$
BEGIN
    IF NOT EXISTS (SELECT 1 FROM "DocumentosVenta" WHERE "NUM_FACT" = p_num_fact) THEN
        RAISE EXCEPTION 'documento_no_encontrado';
    END IF;

    IF EXISTS (SELECT 1 FROM "DocumentosVenta" WHERE "NUM_FACT" = p_num_fact AND "FECHA_ANULA" IS NOT NULL) THEN
        RAISE EXCEPTION 'documento_ya_anulado';
    END IF;

    UPDATE "DocumentosVenta" SET
        "FECHA_ANULA" = NOW() AT TIME ZONE 'UTC',
        "MOTIVO_ANULA" = p_motivo
    WHERE "NUM_FACT" = p_num_fact;

    -- Anular en CxC si existe
    IF p_tipo_operacion = 'FACT' THEN
        UPDATE "P_Cobrar" SET
            "SALDO" = 0,
            "PAID" = 1,
            "OBS" = COALESCE("OBS", '') || ' [ANULADO]'
        WHERE "DOCUMENTO" = p_num_fact;
    END IF;

    RETURN QUERY SELECT TRUE, p_num_fact, 'Documento anulado'::TEXT;
END;
$function$
;

-- ============================================================
-- sp_anular_documento_venta_tx
-- ============================================================
CREATE OR REPLACE FUNCTION public.sp_anular_documento_venta_tx(p_num_doc character varying, p_tipo_operacion character varying, p_cod_usuario character varying DEFAULT 'API'::character varying, p_motivo character varying DEFAULT ''::character varying, p_revertir_inventario boolean DEFAULT true)
 RETURNS TABLE(ok boolean, "numDoc" character varying, "tipoOperacion" character varying, mensaje character varying, "inventarioRevertido" boolean)
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_fecha_anulacion TIMESTAMP := NOW() AT TIME ZONE 'UTC';
    v_ya_anulado      BOOLEAN;
    v_fecha_doc       TIMESTAMP;
BEGIN
    -- Verificar existencia
    -- TODO: tabla DocumentosVenta es legacy
    SELECT "ANULADA"::BOOLEAN, "FECHA"
    INTO v_ya_anulado, v_fecha_doc
    FROM "DocumentosVenta"
    WHERE "NUM_DOC" = p_num_doc AND "TIPO_OPERACION" = p_tipo_operacion;

    IF v_ya_anulado IS NULL THEN
        RAISE EXCEPTION 'documento_no_encontrado';
    END IF;

    IF v_ya_anulado = TRUE THEN
        RAISE EXCEPTION 'documento_ya_anulado';
    END IF;

    -- Validaciones especificas por tipo
    IF p_tipo_operacion = 'PEDIDO' AND EXISTS (SELECT 1 FROM "DocumentosVenta" WHERE "DOC_ORIGEN" = p_num_doc AND "ANULADA" = FALSE) THEN
        RAISE EXCEPTION 'pedido_tiene_factura_asociada';
    END IF;

    -- Cargar detalle para reversion de inventario
    CREATE TEMP TABLE IF NOT EXISTS _detalles_venta (
        "COD_SERV" VARCHAR(60),
        "CANTIDAD" DOUBLE PRECISION,
        "PRECIO"   DOUBLE PRECISION,
        "ALICUOTA" DOUBLE PRECISION
    ) ON COMMIT DROP;

    DELETE FROM _detalles_venta;

    IF p_revertir_inventario = TRUE AND p_tipo_operacion IN ('PEDIDO', 'NOTA_ENTREGA') THEN
        INSERT INTO _detalles_venta
        SELECT "COD_SERV", COALESCE("CANTIDAD", 0), COALESCE("PRECIO", 0), COALESCE("ALICUOTA", 0)
        FROM "DocumentosVentaDetalle"
        WHERE "NUM_DOC" = p_num_doc AND "TIPO_OPERACION" = p_tipo_operacion AND COALESCE("ANULADA"::INT, 0) = 0;
    END IF;

    -- Marcar como anulado
    UPDATE "DocumentosVenta" SET
        "ANULADA" = TRUE,
        "OBSERV" = COALESCE("OBSERV", '') || ' [ANULADO: ' || TO_CHAR(v_fecha_anulacion, 'YYYY-MM-DD HH24:MI:SS') || COALESCE(' - ' || p_motivo, '') || ']'
    WHERE "NUM_DOC" = p_num_doc AND "TIPO_OPERACION" = p_tipo_operacion;

    -- Anular detalle
    UPDATE "DocumentosVentaDetalle" SET "ANULADA" = TRUE
    WHERE "NUM_DOC" = p_num_doc AND "TIPO_OPERACION" = p_tipo_operacion;

    -- Reversar inventario en master.Product si aplica
    IF p_revertir_inventario = TRUE AND p_tipo_operacion IN ('PEDIDO', 'NOTA_ENTREGA') THEN
        -- Devolver inventario
        WITH "Totales" AS (
            SELECT "COD_SERV", SUM("CANTIDAD") AS "TOTAL"
            FROM _detalles_venta
            WHERE "COD_SERV" IS NOT NULL
            GROUP BY "COD_SERV"
        )
        UPDATE master."Product" i
        SET "StockQty" = COALESCE(i."StockQty", 0) + t."TOTAL"
        FROM "Totales" t
        WHERE t."COD_SERV" = i."ProductCode";

        -- Registrar movimiento de reversion
        INSERT INTO "MovInvent" ("CODIGO", "PRODUCT", "DOCUMENTO", "FECHA", "MOTIVO", "TIPO",
            "CANTIDAD_ACTUAL", "CANTIDAD", "CANTIDAD_NUEVA", "CO_USUARIO",
            "PRECIO_COMPRA", "ALICUOTA", "PRECIO_VENTA")
        SELECT d."COD_SERV", d."COD_SERV", p_num_doc || '_ANUL', v_fecha_anulacion,
            'Anulacion ' || p_tipo_operacion || ':' || p_num_doc, 'Ingreso',
            COALESCE(i."StockQty", 0) - d."CANTIDAD",
            d."CANTIDAD",
            COALESCE(i."StockQty", 0),
            p_cod_usuario,
            COALESCE(i."COSTO_REFERENCIA", 0),
            COALESCE(d."ALICUOTA", 0),
            COALESCE(d."PRECIO", 0)
        FROM _detalles_venta d
        INNER JOIN master."Product" i ON i."ProductCode" = d."COD_SERV"
        WHERE d."COD_SERV" IS NOT NULL AND d."CANTIDAD" > 0;
    END IF;

    -- Reversar CxC si era factura
    IF p_tipo_operacion = 'FACT' THEN
        UPDATE "P_Cobrar" SET
            "ANULADA" = TRUE,
            "SALDO" = 0,
            "OBSERVACION" = COALESCE("OBSERVACION", '') || ' [ANULADO]'
        WHERE "FACTURA" = p_num_doc AND "ANULADA" = FALSE;
    END IF;

    RETURN QUERY
    SELECT TRUE, p_num_doc, p_tipo_operacion, 'Documento anulado'::VARCHAR, p_revertir_inventario;

EXCEPTION WHEN OTHERS THEN
    RAISE EXCEPTION '%', SQLERRM;
END;
$function$
;

-- ============================================================
-- sp_anular_factura_tx
-- ============================================================
CREATE OR REPLACE FUNCTION public.sp_anular_factura_tx(p_num_fact character varying, p_cod_usuario character varying DEFAULT 'API'::character varying, p_motivo character varying DEFAULT ''::character varying)
 RETURNS TABLE(ok boolean, "numFact" character varying, "codCliente" character varying, mensaje character varying)
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_fecha_anulacion    TIMESTAMP := NOW() AT TIME ZONE 'UTC';
    v_cod_cliente        VARCHAR(60);
    v_customer_id        BIGINT;
    v_ya_anulada         BOOLEAN;
    v_default_company_id INT := 1;
    v_default_branch_id  INT := 1;
BEGIN
    SELECT "CompanyId" INTO v_default_company_id
    FROM cfg."Company" WHERE "CompanyCode" = 'DEFAULT' LIMIT 1;

    SELECT "BranchId" INTO v_default_branch_id
    FROM cfg."Branch" WHERE "CompanyId" = v_default_company_id AND "BranchCode" = 'MAIN' LIMIT 1;

    -- 1. Validar factura en ar.SalesDocument
    SELECT
        "CustomerCode",
        CASE WHEN "IsVoided" = TRUE THEN TRUE ELSE FALSE END
    INTO v_cod_cliente, v_ya_anulada
    FROM ar."SalesDocument"
    WHERE "DocumentNumber" = p_num_fact AND "OperationType" = 'FACT' AND "IsDeleted" = FALSE;

    IF v_cod_cliente IS NULL THEN
        RAISE EXCEPTION 'factura_not_found';
    END IF;

    IF v_ya_anulada = TRUE THEN
        RAISE EXCEPTION 'factura_already_anulled';
    END IF;

    -- Resolver CustomerId
    SELECT "CustomerId" INTO v_customer_id
    FROM master."Customer"
    WHERE "CustomerCode" = v_cod_cliente AND COALESCE("IsDeleted", FALSE) = FALSE
    LIMIT 1;

    -- 2. Marcar anulada -> ar.SalesDocument
    UPDATE ar."SalesDocument"
    SET "IsVoided" = TRUE,
        "Notes" = COALESCE("Notes", '') || ' [ANULADA: ' || TO_CHAR(v_fecha_anulacion, 'YYYY-MM-DD HH24:MI:SS') || ']',
        "UpdatedAt" = NOW() AT TIME ZONE 'UTC'
    WHERE "DocumentNumber" = p_num_fact AND "OperationType" = 'FACT';

    -- 3. Anular detalle -> ar.SalesDocumentLine
    UPDATE ar."SalesDocumentLine"
    SET "IsVoided" = TRUE, "UpdatedAt" = NOW() AT TIME ZONE 'UTC'
    WHERE "DocumentNumber" = p_num_fact AND "OperationType" = 'FACT';

    -- 4. Revertir inventario
    CREATE TEMP TABLE IF NOT EXISTS _detalles_factura (
        "COD_SERV"     VARCHAR(60),
        "CANTIDAD"     NUMERIC(18,4),
        "RELACIONADA"  INT,
        "COD_ALTERNO"  VARCHAR(60)
    ) ON COMMIT DROP;

    DELETE FROM _detalles_factura;

    INSERT INTO _detalles_factura ("COD_SERV", "CANTIDAD", "RELACIONADA", "COD_ALTERNO")
    SELECT "ProductCode", COALESCE("Quantity", 0),
        CASE WHEN "RelatedRef" = '1' THEN 1 ELSE 0 END, "AlternateCode"
    FROM ar."SalesDocumentLine"
    WHERE "DocumentNumber" = p_num_fact AND "OperationType" = 'FACT' AND COALESCE("IsVoided", FALSE) = FALSE;

    -- Movimiento de anulacion -> master.InventoryMovement
    INSERT INTO master."InventoryMovement" ("CompanyId", "ProductCode", "DocumentRef", "MovementType", "MovementDate", "Quantity", "UnitCost", "TotalCost", "Notes")
    SELECT v_default_company_id, d."COD_SERV", p_num_fact || '_ANUL', 'ENTRADA',
        v_fecha_anulacion::DATE, d."CANTIDAD",
        COALESCE(i."COSTO_REFERENCIA", 0), d."CANTIDAD" * COALESCE(i."COSTO_REFERENCIA", 0),
        'Anulacion Factura:' || p_num_fact || ' - ' || p_motivo
    FROM _detalles_factura d
    INNER JOIN master."Product" i ON i."ProductCode" = d."COD_SERV"
    WHERE d."COD_SERV" IS NOT NULL AND d."CANTIDAD" > 0;

    -- Sumar de vuelta stock -> master.Product
    WITH "Totales" AS (
        SELECT "COD_SERV", SUM("CANTIDAD") AS "TOTAL"
        FROM _detalles_factura WHERE "COD_SERV" IS NOT NULL GROUP BY "COD_SERV"
    )
    UPDATE master."Product" i
    SET "StockQty" = COALESCE(i."StockQty", 0) + t."TOTAL"
    FROM "Totales" t WHERE t."COD_SERV" = i."ProductCode";

    -- Sumar de vuelta stock auxiliar -> master.AlternateStock
    WITH "AuxTotales" AS (
        SELECT "COD_ALTERNO", SUM("CANTIDAD") AS "TOTAL"
        FROM _detalles_factura WHERE "RELACIONADA" = 1 AND "COD_ALTERNO" IS NOT NULL GROUP BY "COD_ALTERNO"
    )
    UPDATE master."AlternateStock" a
    SET "StockQty" = COALESCE(a."StockQty", 0) + at2."TOTAL"
    FROM "AuxTotales" at2 WHERE at2."COD_ALTERNO" = a."ProductCode";

    -- 5. Anular CxC -> ar.ReceivableDocument
    UPDATE ar."ReceivableDocument"
    SET "PaidFlag" = TRUE, "PendingAmount" = 0, "Status" = 'VOIDED', "UpdatedAt" = NOW() AT TIME ZONE 'UTC'
    WHERE "DocumentNumber" = p_num_fact AND "DocumentType" = 'FACT'
      AND "CompanyId" = v_default_company_id AND "BranchId" = v_default_branch_id;

    -- 6. Recalcular saldos -> master.Customer.TotalBalance
    IF v_customer_id IS NOT NULL THEN
        UPDATE master."Customer"
        SET "TotalBalance" = COALESCE((
            SELECT SUM("PendingAmount")
            FROM ar."ReceivableDocument"
            WHERE "CustomerId" = v_customer_id AND "Status" <> 'VOIDED' AND "PaidFlag" = FALSE
        ), 0)
        WHERE "CustomerId" = v_customer_id AND COALESCE("IsDeleted", FALSE) = FALSE;
    END IF;

    RETURN QUERY
    SELECT TRUE, p_num_fact, v_cod_cliente, 'Factura anulada exitosamente'::VARCHAR;

EXCEPTION WHEN OTHERS THEN
    RAISE EXCEPTION '%', SQLERRM;
END;
$function$
;

-- ============================================================
-- sp_anular_pedido_tx
-- ============================================================
CREATE OR REPLACE FUNCTION public.sp_anular_pedido_tx(p_num_pedido character varying, p_cod_usuario character varying DEFAULT 'API'::character varying, p_motivo character varying DEFAULT ''::character varying)
 RETURNS TABLE(ok boolean, "numPedido" character varying, mensaje character varying)
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_fecha_anulacion TIMESTAMP := NOW() AT TIME ZONE 'UTC';
    v_ya_anulado      BOOLEAN;
BEGIN
    SELECT CASE WHEN "ANULADA"::TEXT IN ('1', 'true') THEN TRUE ELSE FALSE END
    INTO v_ya_anulado
    FROM "Pedidos" WHERE "NUM_FACT" = p_num_pedido;

    IF v_ya_anulado IS NULL THEN
        RAISE EXCEPTION 'pedido_not_found';
    END IF;

    IF v_ya_anulado = TRUE THEN
        RAISE EXCEPTION 'pedido_already_anulled';
    END IF;

    UPDATE "Pedidos" SET
        "ANULADA" = TRUE,
        "OBSERV" = COALESCE("OBSERV", '') || ' [ANULADO: ' || TO_CHAR(v_fecha_anulacion, 'YYYY-MM-DD HH24:MI:SS') || ']'
    WHERE "NUM_FACT" = p_num_pedido;

    UPDATE "Detalle_Pedidos" SET "ANULADA" = TRUE WHERE "NUM_FACT" = p_num_pedido;

    -- Reversar inventario
    CREATE TEMP TABLE IF NOT EXISTS _detalles_pedido (
        "COD_SERV" VARCHAR(60),
        "CANTIDAD" DOUBLE PRECISION
    ) ON COMMIT DROP;

    DELETE FROM _detalles_pedido;

    INSERT INTO _detalles_pedido
    SELECT "COD_SERV", COALESCE("CANTIDAD", 0)
    FROM "Detalle_Pedidos"
    WHERE "NUM_FACT" = p_num_pedido AND COALESCE("ANULADA"::INT, 0) = 0;

    INSERT INTO "MovInvent" ("DOCUMENTO", "CODIGO", "PRODUCT", "FECHA", "MOTIVO", "TIPO",
        "CANTIDAD_ACTUAL", "CANTIDAD", "CANTIDAD_NUEVA", "CO_USUARIO")
    SELECT p_num_pedido || '_ANUL', d."COD_SERV", d."COD_SERV", v_fecha_anulacion,
        'Anulacion Pedido:' || p_num_pedido, 'Anulacion Pedido',
        COALESCE(i."EXISTENCIA", 0), d."CANTIDAD", COALESCE(i."EXISTENCIA", 0) + d."CANTIDAD", p_cod_usuario
    FROM _detalles_pedido d
    INNER JOIN "Inventario" i ON i."CODIGO" = d."COD_SERV"
    WHERE d."COD_SERV" IS NOT NULL AND d."CANTIDAD" > 0;

    WITH "Totales" AS (
        SELECT "COD_SERV", SUM("CANTIDAD") AS "TOTAL"
        FROM _detalles_pedido WHERE "COD_SERV" IS NOT NULL GROUP BY "COD_SERV"
    )
    UPDATE "Inventario" i
    SET "EXISTENCIA" = COALESCE(i."EXISTENCIA", 0) + t."TOTAL"
    FROM "Totales" t WHERE t."COD_SERV" = i."CODIGO";

    RETURN QUERY
    SELECT TRUE, p_num_pedido, 'Pedido anulado'::VARCHAR;

EXCEPTION WHEN OTHERS THEN
    RAISE EXCEPTION '%', SQLERRM;
END;
$function$
;

-- ============================================================
-- sp_anular_presupuesto_tx
-- ============================================================
CREATE OR REPLACE FUNCTION public.sp_anular_presupuesto_tx(p_num_fact character varying, p_cod_usuario character varying DEFAULT 'API'::character varying, p_motivo character varying DEFAULT ''::character varying)
 RETURNS TABLE(ok boolean, "numFact" character varying, "codCliente" character varying, mensaje character varying)
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_fecha_anulacion TIMESTAMP := NOW() AT TIME ZONE 'UTC';
    v_cod_cliente     VARCHAR(60);
    v_ya_anulada      BOOLEAN;
    v_saldo_total     DOUBLE PRECISION;
    v_rows_affected   INT;
BEGIN
    -- TODO: tabla Presupuestos es legacy
    SELECT "CODIGO", CASE WHEN "ANULADA"::TEXT = '1' THEN TRUE ELSE FALSE END
    INTO v_cod_cliente, v_ya_anulada
    FROM "Presupuestos" WHERE "NUM_FACT" = p_num_fact;

    IF v_cod_cliente IS NULL THEN
        RAISE EXCEPTION 'presupuesto_not_found';
    END IF;

    IF v_ya_anulada = TRUE THEN
        RAISE EXCEPTION 'presupuesto_already_anulled';
    END IF;

    -- 1. Marcar presupuesto como anulado
    UPDATE "Presupuestos"
    SET "ANULADA" = TRUE,
        "OBSERV" = COALESCE("OBSERV", '') || ' [ANULADA: ' || TO_CHAR(v_fecha_anulacion, 'YYYY-MM-DD HH24:MI:SS') || ']'
    WHERE "NUM_FACT" = p_num_fact;

    -- 2. Anular detalle
    UPDATE "Detalle_Presupuestos" SET "ANULADA" = TRUE WHERE "NUM_FACT" = p_num_fact;

    -- 3. Revertir master.Product
    CREATE TEMP TABLE IF NOT EXISTS _detalles_presup (
        "COD_SERV"     VARCHAR(60),
        "CANTIDAD"     DOUBLE PRECISION,
        "RELACIONADA"  INT,
        "COD_ALTERNO"  VARCHAR(60)
    ) ON COMMIT DROP;

    DELETE FROM _detalles_presup;

    INSERT INTO _detalles_presup ("COD_SERV", "CANTIDAD", "RELACIONADA", "COD_ALTERNO")
    SELECT "COD_SERV", COALESCE("CANTIDAD", 0),
        CASE WHEN "Relacionada"::TEXT = '1' THEN 1 ELSE 0 END, "Cod_Alterno"
    FROM "Detalle_Presupuestos" WHERE "NUM_FACT" = p_num_fact AND COALESCE("ANULADA"::INT, 0) = 0;

    -- Insertar movimiento de anulacion
    INSERT INTO "MovInvent" (
        "DOCUMENTO", "CODIGO", "PRODUCT", "FECHA", "MOTIVO", "TIPO",
        "CANTIDAD_ACTUAL", "CANTIDAD", "CANTIDAD_NUEVA", "CO_USUARIO",
        "PRECIO_COMPRA", "ALICUOTA", "PRECIO_VENTA", "ANULADA"
    )
    SELECT
        p_num_fact || '_ANUL',
        d."COD_SERV",
        d."COD_SERV",
        v_fecha_anulacion,
        'Anulacion Presupuesto:' || p_num_fact || ' - ' || p_motivo,
        'Anulacion Egreso',
        COALESCE(i."StockQty", 0),
        d."CANTIDAD",
        COALESCE(i."StockQty", 0) + d."CANTIDAD",
        p_cod_usuario,
        COALESCE(i."COSTO_REFERENCIA", 0),
        0,
        COALESCE(i."SalesPrice", 0),
        FALSE
    FROM _detalles_presup d
    INNER JOIN master."Product" i ON i."ProductCode" = d."COD_SERV"
    WHERE d."COD_SERV" IS NOT NULL AND d."CANTIDAD" > 0;

    -- Sumar de vuelta al inventario
    WITH "Totales" AS (
        SELECT "COD_SERV", SUM("CANTIDAD") AS "TOTAL"
        FROM _detalles_presup WHERE "COD_SERV" IS NOT NULL GROUP BY "COD_SERV"
    )
    UPDATE master."Product" i
    SET "StockQty" = COALESCE(i."StockQty", 0) + t."TOTAL"
    FROM "Totales" t WHERE t."COD_SERV" = i."ProductCode";

    -- Sumar de vuelta a Inventario_Aux si es relacionada
    WITH "AuxTotales" AS (
        SELECT "COD_ALTERNO", SUM("CANTIDAD") AS "TOTAL"
        FROM _detalles_presup WHERE "RELACIONADA" = 1 AND "COD_ALTERNO" IS NOT NULL GROUP BY "COD_ALTERNO"
    )
    UPDATE "Inventario_Aux" ia
    SET "CANTIDAD" = COALESCE(ia."CANTIDAD", 0) + a."TOTAL"
    FROM "AuxTotales" a WHERE a."COD_ALTERNO" = ia."CODIGO";

    -- 4. Anular CxC (P_Cobrar / P_CobrarC)
    UPDATE "P_Cobrar" SET "PAID" = TRUE, "PEND" = 0, "SALDO" = 0
    WHERE "DOCUMENTO" = p_num_fact AND "TIPO" = 'PRESUP' AND "CODIGO" = v_cod_cliente;

    GET DIAGNOSTICS v_rows_affected = ROW_COUNT;

    IF v_rows_affected = 0 THEN
        UPDATE "P_CobrarC" SET "PAID" = TRUE, "PEND" = 0, "SALDO" = 0
        WHERE "DOCUMENTO" = p_num_fact AND "TIPO" = 'PRESUP' AND "CODIGO" = v_cod_cliente;
    END IF;

    -- 5. Recalcular saldos del cliente en master.Customer
    SELECT COALESCE(SUM(COALESCE("PEND", 0)), 0)
    INTO v_saldo_total
    FROM "P_Cobrar" WHERE "CODIGO" = v_cod_cliente AND "PAID" = FALSE;

    IF v_saldo_total IS NULL OR v_saldo_total = 0 THEN
        SELECT COALESCE(SUM(COALESCE("PEND", 0)), 0)
        INTO v_saldo_total
        FROM "P_CobrarC" WHERE "CODIGO" = v_cod_cliente AND "PAID" = FALSE;
    END IF;

    UPDATE master."Customer"
    SET "TotalBalance" = COALESCE(v_saldo_total, 0)
    WHERE "CustomerCode" = v_cod_cliente
      AND COALESCE("IsDeleted", FALSE) = FALSE;

    RETURN QUERY
    SELECT TRUE, p_num_fact, v_cod_cliente, 'Presupuesto anulada'::VARCHAR;

EXCEPTION WHEN OTHERS THEN
    RAISE EXCEPTION '%', SQLERRM;
END;
$function$
;

-- ============================================================
-- sp_cerrar_conciliacion
-- ============================================================
CREATE OR REPLACE FUNCTION public.sp_cerrar_conciliacion(p_conciliacion_id integer, p_saldo_final_banco numeric, p_observaciones character varying DEFAULT NULL::character varying, p_co_usuario character varying DEFAULT 'API'::character varying)
 RETURNS TABLE(ok boolean, diferencia numeric, estado character varying)
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_saldo_final_sistema NUMERIC(18,2);
    v_diferencia          NUMERIC(18,2);
    v_estado              VARCHAR(20);
BEGIN
    SELECT "Saldo_Final_Sistema" INTO v_saldo_final_sistema
    FROM "ConciliacionBancaria"
    WHERE "ID" = p_conciliacion_id;

    v_diferencia := v_saldo_final_sistema - p_saldo_final_banco;
    v_estado := CASE WHEN ABS(v_diferencia) < 0.01 THEN 'CONCILIADO' ELSE 'DIFERENCIA' END;

    UPDATE "ConciliacionBancaria" SET
        "Saldo_Final_Banco" = p_saldo_final_banco,
        "Diferencia" = v_diferencia,
        "Observaciones" = p_observaciones,
        "Estado" = v_estado,
        "Fecha_Cierre" = NOW() AT TIME ZONE 'UTC',
        "Co_Usuario" = p_co_usuario
    WHERE "ID" = p_conciliacion_id;

    RETURN QUERY SELECT TRUE, v_diferencia, v_estado;
END;
$function$
;

-- ============================================================
-- sp_cerrarmesinventario
-- ============================================================
CREATE OR REPLACE FUNCTION public.sp_cerrarmesinventario(p_periodo character varying)
 RETURNS TABLE("ProductosCerrados" integer, "Periodo" character varying, "FechaCierre" date)
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_mes        INT;
    v_anio       INT;
    v_fin        DATE;
    v_fin_dt     TIMESTAMP;
    v_filas      INT;
BEGIN
    v_mes  := CAST(LEFT(p_periodo, 2) AS INT);
    v_anio := CAST(RIGHT(p_periodo, 4) AS INT);
    v_fin  := (make_date(v_anio, v_mes, 1) + INTERVAL '1 month - 1 day')::DATE;
    v_fin_dt := (v_fin + INTERVAL '1 day')::TIMESTAMP;

    -- Verificar que exista la tabla CierreMensualInventario
    IF NOT EXISTS (
        SELECT 1 FROM information_schema.tables
        WHERE table_schema = 'public' AND table_name = 'cierremensualinventario'
    ) THEN
        RAISE EXCEPTION 'Crear antes la tabla CierreMensualInventario (create_cierre_mensual_inventario.sql).';
    END IF;

    -- Eliminar datos previos del periodo
    DELETE FROM public."CierreMensualInventario" WHERE "Periodo" = p_periodo;

    -- Ultimo movimiento por producto hasta v_fin
    WITH "UltimoMov" AS (
        SELECT
            COALESCE(m."Codigo", m."Product") AS "Codigo",
            m."cantidad_nueva"                AS "CantidadFinal",
            COALESCE(m."Precio_Compra", 0)    AS "CostoUnitario",
            ROW_NUMBER() OVER (
                PARTITION BY COALESCE(m."Codigo", m."Product")
                ORDER BY m."Fecha" DESC, m."id" DESC
            ) AS rn
        FROM public."MovInvent" m
        WHERE m."Fecha" < v_fin_dt
          AND COALESCE(m."Anulada", 0) = 0
          AND (
              (m."Codigo" IS NOT NULL AND TRIM(m."Codigo") <> '')
              OR (m."Product" IS NOT NULL AND TRIM(m."Product") <> '')
          )
    )
    INSERT INTO public."CierreMensualInventario"
        ("Periodo", "Codigo", "Descripcion", "CantidadFinal", "MontoFinal", "CostoUnitario", "FechaCierre")
    SELECT
        p_periodo,
        u."Codigo",
        i."DESCRIPCION",
        u."CantidadFinal",
        u."CantidadFinal" * u."CostoUnitario",
        u."CostoUnitario",
        NOW() AT TIME ZONE 'UTC'
    FROM "UltimoMov" u
    LEFT JOIN public."Inventario" i ON i."CODIGO" = u."Codigo"
    WHERE u.rn = 1 AND u."CantidadFinal" <> 0;

    -- Productos con existencia en Inventario sin movimiento hasta v_fin
    INSERT INTO public."CierreMensualInventario"
        ("Periodo", "Codigo", "Descripcion", "CantidadFinal", "MontoFinal", "CostoUnitario", "FechaCierre")
    SELECT
        p_periodo,
        i."CODIGO",
        i."DESCRIPCION",
        COALESCE(i."EXISTENCIA", 0),
        COALESCE(i."EXISTENCIA", 0) * COALESCE(i."COSTO_REFERENCIA", i."COSTO_PROMEDIO"),
        COALESCE(i."COSTO_REFERENCIA", i."COSTO_PROMEDIO"),
        NOW() AT TIME ZONE 'UTC'
    FROM public."Inventario" i
    WHERE COALESCE(i."EXISTENCIA", 0) > 0
      AND i."CODIGO" IS NOT NULL AND TRIM(i."CODIGO") <> ''
      AND NOT EXISTS (
          SELECT 1 FROM public."CierreMensualInventario" c
          WHERE c."Periodo" = p_periodo AND c."Codigo" = i."CODIGO"
      );

    GET DIAGNOSTICS v_filas = ROW_COUNT;

    RETURN QUERY SELECT v_filas, p_periodo, v_fin;
END;
$function$
;

-- ============================================================
-- sp_conciliacion_get_detalle_sistema
-- ============================================================
CREATE OR REPLACE FUNCTION public.sp_conciliacion_get_detalle_sistema(p_conciliacion_id integer)
 RETURNS TABLE("ID" integer, "Conciliacion_ID" integer, "Tipo_Origen" character varying, "MovCuentas_ID" integer, "Extracto_ID" integer, "Fecha" timestamp without time zone, "Descripcion" character varying, "Referencia" character varying, "Debito" numeric, "Credito" numeric, "Conciliado" boolean, "Nro_Ref" character varying, "MovFecha" timestamp without time zone)
 LANGUAGE plpgsql
AS $function$
BEGIN
    RETURN QUERY
    SELECT
        d."ID", d."Conciliacion_ID", d."Tipo_Origen", d."MovCuentas_ID",
        d."Extracto_ID", d."Fecha", d."Descripcion", d."Referencia",
        d."Debito", d."Credito", d."Conciliado",
        m."Nro_Ref", m."Fecha" AS "MovFecha"
    FROM "ConciliacionDetalle" d
    LEFT JOIN "MovCuentas" m ON m."id" = d."MovCuentas_ID"
    WHERE d."Conciliacion_ID" = p_conciliacion_id AND d."Tipo_Origen" = 'SISTEMA'
    ORDER BY d."Fecha";
END;
$function$
;

-- ============================================================
-- sp_conciliacion_get_extracto_pendiente
-- ============================================================
CREATE OR REPLACE FUNCTION public.sp_conciliacion_get_extracto_pendiente(p_conciliacion_id integer)
 RETURNS TABLE("ID" integer, "Nro_Cta" character varying, "Fecha" timestamp without time zone, "Descripcion" character varying, "Referencia" character varying, "Tipo" character varying, "Monto" numeric, "Saldo" numeric, "Conciliado" boolean)
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_nro_cta     VARCHAR(20);
    v_fecha_desde TIMESTAMP;
    v_fecha_hasta TIMESTAMP;
BEGIN
    SELECT cb."Nro_Cta", cb."Fecha_Desde", cb."Fecha_Hasta"
    INTO v_nro_cta, v_fecha_desde, v_fecha_hasta
    FROM "ConciliacionBancaria" cb
    WHERE cb."ID" = p_conciliacion_id;

    RETURN QUERY
    SELECT
        e."ID", e."Nro_Cta", e."Fecha", e."Descripcion", e."Referencia",
        e."Tipo", e."Monto", e."Saldo", e."Conciliado"
    FROM "ExtractoBancario" e
    WHERE e."Nro_Cta" = v_nro_cta
      AND e."Conciliado" = FALSE
      AND e."Fecha" BETWEEN v_fecha_desde AND v_fecha_hasta
    ORDER BY e."Fecha";
END;
$function$
;

-- ============================================================
-- sp_conciliacion_get_header
-- ============================================================
CREATE OR REPLACE FUNCTION public.sp_conciliacion_get_header(p_conciliacion_id integer)
 RETURNS TABLE("ID" integer, "Nro_Cta" character varying, "Fecha_Desde" timestamp without time zone, "Fecha_Hasta" timestamp without time zone, "Saldo_Inicial_Sistema" numeric, "Saldo_Final_Sistema" numeric, "Saldo_Inicial_Banco" numeric, "Saldo_Final_Banco" numeric, "Diferencia" numeric, "Estado" character varying, "Observaciones" character varying, "Banco" character varying, "Descripcion" character varying)
 LANGUAGE plpgsql
AS $function$
BEGIN
    RETURN QUERY
    SELECT
        c."ID", c."Nro_Cta", c."Fecha_Desde", c."Fecha_Hasta",
        c."Saldo_Inicial_Sistema", c."Saldo_Final_Sistema",
        c."Saldo_Inicial_Banco", c."Saldo_Final_Banco",
        c."Diferencia", c."Estado", c."Observaciones",
        b."Banco", b."Descripcion"
    FROM "ConciliacionBancaria" c
    LEFT JOIN "CuentasBank" b ON b."Nro_Cta" = c."Nro_Cta"
    WHERE c."ID" = p_conciliacion_id;
END;
$function$
;

-- ============================================================
-- sp_conciliacion_list
-- ============================================================
CREATE OR REPLACE FUNCTION public.sp_conciliacion_list(p_nro_cta character varying DEFAULT NULL::character varying, p_estado character varying DEFAULT NULL::character varying, p_page integer DEFAULT 1, p_limit integer DEFAULT 50)
 RETURNS TABLE("TotalCount" bigint, "ID" integer, "Nro_Cta" character varying, "Fecha_Desde" timestamp without time zone, "Fecha_Hasta" timestamp without time zone, "Saldo_Inicial_Sistema" numeric, "Saldo_Final_Sistema" numeric, "Saldo_Inicial_Banco" numeric, "Saldo_Final_Banco" numeric, "Diferencia" numeric, "Estado" character varying, "Observaciones" character varying, "Co_Usuario" character varying, "Fecha_Creacion" timestamp without time zone, "Fecha_Cierre" timestamp without time zone, "Banco" character varying, "Pendientes" bigint, "Conciliados" bigint)
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_offset INT := (p_page - 1) * p_limit;
    v_total  BIGINT;
BEGIN
    SELECT COUNT(1) INTO v_total
    FROM "ConciliacionBancaria"
    WHERE (p_nro_cta IS NULL OR "Nro_Cta" = p_nro_cta)
      AND (p_estado IS NULL OR "Estado" = p_estado);

    RETURN QUERY
    SELECT
        v_total,
        c."ID", c."Nro_Cta", c."Fecha_Desde", c."Fecha_Hasta",
        c."Saldo_Inicial_Sistema", c."Saldo_Final_Sistema",
        c."Saldo_Inicial_Banco", c."Saldo_Final_Banco",
        c."Diferencia", c."Estado", c."Observaciones",
        c."Co_Usuario", c."Fecha_Creacion", c."Fecha_Cierre",
        b."Banco",
        (SELECT COUNT(1) FROM "ConciliacionDetalle" d WHERE d."Conciliacion_ID" = c."ID" AND d."Conciliado" = FALSE),
        (SELECT COUNT(1) FROM "ConciliacionDetalle" d WHERE d."Conciliacion_ID" = c."ID" AND d."Conciliado" = TRUE)
    FROM "ConciliacionBancaria" c
    LEFT JOIN "CuentasBank" b ON b."Nro_Cta" = c."Nro_Cta"
    WHERE (p_nro_cta IS NULL OR c."Nro_Cta" = p_nro_cta)
      AND (p_estado IS NULL OR c."Estado" = p_estado)
    ORDER BY c."Fecha_Creacion" DESC
    LIMIT p_limit OFFSET v_offset;
END;
$function$
;

-- ============================================================
-- sp_conciliar_movimientos
-- ============================================================
CREATE OR REPLACE FUNCTION public.sp_conciliar_movimientos(p_conciliacion_id integer, p_movimiento_sistema_id integer, p_extracto_id integer DEFAULT NULL::integer, p_co_usuario character varying DEFAULT 'API'::character varying)
 RETURNS TABLE(ok boolean, mensaje character varying)
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_mov_cuentas_id   INT;
    v_sistema_debito   NUMERIC(18,2);
    v_sistema_credito  NUMERIC(18,2);
    v_banco_debito     NUMERIC(18,2);
    v_banco_credito    NUMERIC(18,2);
BEGIN
    -- Marcar como conciliado en detalle
    UPDATE "ConciliacionDetalle" SET
        "Conciliado" = TRUE,
        "Extracto_ID" = p_extracto_id
    WHERE "ID" = p_movimiento_sistema_id AND "Conciliacion_ID" = p_conciliacion_id;

    -- Obtener MovCuentas_ID
    SELECT "MovCuentas_ID" INTO v_mov_cuentas_id
    FROM "ConciliacionDetalle"
    WHERE "ID" = p_movimiento_sistema_id;

    -- Marcar MovCuentas como confirmado
    UPDATE "MovCuentas" SET "Confirmada" = TRUE
    WHERE "id" = v_mov_cuentas_id;

    -- Si hay extracto, marcarlo como conciliado
    IF p_extracto_id IS NOT NULL THEN
        UPDATE "ExtractoBancario" SET
            "Conciliado" = TRUE,
            "Fecha_Conciliacion" = NOW() AT TIME ZONE 'UTC',
            "MovCuentas_ID" = v_mov_cuentas_id
        WHERE "ID" = p_extracto_id;
    END IF;

    -- Recalcular diferencia
    SELECT SUM("Debito"), SUM("Credito")
    INTO v_sistema_debito, v_sistema_credito
    FROM "ConciliacionDetalle"
    WHERE "Conciliacion_ID" = p_conciliacion_id
      AND "Tipo_Origen" = 'SISTEMA'
      AND "Conciliado" = TRUE;

    SELECT
        SUM(CASE WHEN e."Tipo" = 'DEBITO' THEN e."Monto" ELSE 0 END),
        SUM(CASE WHEN e."Tipo" = 'CREDITO' THEN e."Monto" ELSE 0 END)
    INTO v_banco_debito, v_banco_credito
    FROM "ExtractoBancario" e
    INNER JOIN "ConciliacionDetalle" d ON e."ID" = d."Extracto_ID"
    WHERE d."Conciliacion_ID" = p_conciliacion_id AND d."Conciliado" = TRUE;

    -- Actualizar conciliacion
    UPDATE "ConciliacionBancaria" SET
        "Diferencia" = (COALESCE(v_sistema_credito, 0) - COALESCE(v_sistema_debito, 0)) -
                       (COALESCE(v_banco_credito, 0) - COALESCE(v_banco_debito, 0))
    WHERE "ID" = p_conciliacion_id;

    RETURN QUERY SELECT TRUE, 'Movimiento conciliado'::VARCHAR;
END;
$function$
;

-- ============================================================
-- sp_crear_conciliacion
-- ============================================================
CREATE OR REPLACE FUNCTION public.sp_crear_conciliacion(p_nro_cta character varying, p_fecha_desde timestamp without time zone, p_fecha_hasta timestamp without time zone, p_co_usuario character varying DEFAULT 'API'::character varying)
 RETURNS TABLE("conciliacionId" integer, "saldoInicial" numeric, "saldoFinal" numeric)
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_saldo_inicial   NUMERIC(18,2) := 0;
    v_saldo_final     NUMERIC(18,2) := 0;
    v_conciliacion_id INT;
BEGIN
    -- Obtener saldo inicial (al inicio del periodo)
    SELECT COALESCE("Saldo", 0) INTO v_saldo_inicial
    FROM "MovCuentas"
    WHERE "Nro_Cta" = p_nro_cta AND "Fecha" < p_fecha_desde
    ORDER BY "Fecha" DESC, "id" DESC
    LIMIT 1;

    -- Si no hay movimientos previos, tomar saldo apertura de CuentasBank
    IF v_saldo_inicial IS NULL THEN
        SELECT COALESCE("Saldo_Apertura", 0) INTO v_saldo_inicial
        FROM "CuentasBank"
        WHERE "Nro_Cta" = p_nro_cta;
    END IF;

    -- Obtener saldo final (movimientos hasta fecha hasta)
    SELECT COALESCE("Saldo", 0) INTO v_saldo_final
    FROM "MovCuentas"
    WHERE "Nro_Cta" = p_nro_cta AND "Fecha" <= p_fecha_hasta
    ORDER BY "Fecha" DESC, "id" DESC
    LIMIT 1;

    IF v_saldo_final IS NULL THEN
        v_saldo_final := v_saldo_inicial;
    END IF;

    -- Crear conciliacion
    INSERT INTO "ConciliacionBancaria" (
        "Nro_Cta", "Fecha_Desde", "Fecha_Hasta",
        "Saldo_Inicial_Sistema", "Saldo_Final_Sistema",
        "Estado", "Co_Usuario", "Fecha_Creacion"
    )
    VALUES (
        p_nro_cta, p_fecha_desde, p_fecha_hasta,
        v_saldo_inicial, v_saldo_final, 'PENDIENTE', p_co_usuario, NOW() AT TIME ZONE 'UTC'
    )
    RETURNING "ID" INTO v_conciliacion_id;

    -- Insertar movimientos del sistema no conciliados
    INSERT INTO "ConciliacionDetalle" (
        "Conciliacion_ID", "Tipo_Origen", "MovCuentas_ID",
        "Fecha", "Descripcion", "Referencia", "Debito", "Credito", "Conciliado"
    )
    SELECT
        v_conciliacion_id, 'SISTEMA', "id", "Fecha", "Concepto", "Nro_Ref",
        COALESCE("Gastos", 0), COALESCE("Ingresos", 0), "Confirmada"
    FROM "MovCuentas"
    WHERE "Nro_Cta" = p_nro_cta
      AND "Fecha" BETWEEN p_fecha_desde AND p_fecha_hasta
      AND "Confirmada" = FALSE;  -- Solo no conciliados

    RETURN QUERY SELECT v_conciliacion_id, v_saldo_inicial, v_saldo_final;
END;
$function$
;

-- ============================================================
-- sp_documentoscompra_get
-- ============================================================
CREATE OR REPLACE FUNCTION public.sp_documentoscompra_get(p_num_doc character varying, p_tipo_operacion character varying)
 RETURNS TABLE(result_set integer, data jsonb)
 LANGUAGE plpgsql
AS $function$
BEGIN
    -- Cabecera (result_set = 1)
    RETURN QUERY
    SELECT 1,
           ROW_TO_JSON(d)::JSONB
    FROM "DocumentosCompra" d
    WHERE d."NUM_DOC" = p_num_doc AND d."TIPO_OPERACION" = p_tipo_operacion;

    -- Detalle (result_set = 2)
    RETURN QUERY
    SELECT 2,
           ROW_TO_JSON(dd)::JSONB
    FROM "DocumentosCompraDetalle" dd
    WHERE dd."NUM_DOC" = p_num_doc AND dd."TIPO_OPERACION" = p_tipo_operacion
    ORDER BY dd."RENGLON";

    -- Pagos (result_set = 3)
    RETURN QUERY
    SELECT 3,
           ROW_TO_JSON(dp)::JSONB
    FROM "DocumentosCompraPago" dp
    WHERE dp."NUM_DOC" = p_num_doc AND dp."TIPO_OPERACION" = p_tipo_operacion;
END;
$function$
;

-- ============================================================
-- sp_documentoscompra_list
-- ============================================================
CREATE OR REPLACE FUNCTION public.sp_documentoscompra_list(p_tipo_operacion character varying DEFAULT NULL::character varying, p_search character varying DEFAULT NULL::character varying, p_cod_proveedor character varying DEFAULT NULL::character varying, p_desde date DEFAULT NULL::date, p_hasta date DEFAULT NULL::date, p_anulada boolean DEFAULT NULL::boolean, p_page integer DEFAULT 1, p_limit integer DEFAULT 50)
 RETURNS TABLE("TotalCount" bigint, "ID" integer, "NUM_DOC" character varying, "SERIALTIPO" character varying, "TIPO_OPERACION" character varying, "COD_PROVEEDOR" character varying, "NOMBRE" character varying, "RIF" character varying, "FECHA" timestamp without time zone, "FECHA_VENCE" timestamp without time zone, "FECHA_RECIBO" timestamp without time zone, "HORA" character varying, "SUBTOTAL" double precision, "MONTO_GRA" double precision, "MONTO_EXE" double precision, "EXENTO" double precision, "IVA" double precision, "ALICUOTA" double precision, "TOTAL" double precision, "ANULADA" integer, "CANCELADA" character varying, "RECIBIDA" character varying, "DOC_ORIGEN" character varying, "NUM_CONTROL" character varying, "LEGAL" integer, "CONCEPTO" character varying, "OBSERV" character varying, "ALMACEN" character varying, "IVA_RETENIDO" double precision, "ISLR" character varying, "MONTO_ISLR" double precision, "COD_USUARIO" character varying, "FECHA_REPORTE" timestamp without time zone, "ESTADO" character varying)
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_offset INT;
    v_total  BIGINT;
BEGIN
    v_offset := (p_page - 1) * p_limit;

    -- Contar total
    SELECT COUNT(1) INTO v_total
    FROM "DocumentosCompra"
    WHERE (p_tipo_operacion IS NULL OR "TIPO_OPERACION" = p_tipo_operacion)
      AND (p_search IS NULL OR "NUM_DOC" LIKE '%' || p_search || '%'
           OR "NOMBRE" LIKE '%' || p_search || '%'
           OR "RIF" LIKE '%' || p_search || '%'
           OR "COD_PROVEEDOR" LIKE '%' || p_search || '%')
      AND (p_cod_proveedor IS NULL OR "COD_PROVEEDOR" = p_cod_proveedor)
      AND (p_desde IS NULL OR "FECHA"::DATE >= p_desde)
      AND (p_hasta IS NULL OR "FECHA"::DATE <= p_hasta)
      AND (p_anulada IS NULL OR ("ANULADA" = 1) = p_anulada);

    -- Devolver resultados paginados
    RETURN QUERY
    SELECT
        v_total,
        d."ID", d."NUM_DOC", d."SERIALTIPO", d."TIPO_OPERACION",
        d."COD_PROVEEDOR", d."NOMBRE", d."RIF",
        d."FECHA", d."FECHA_VENCE", d."FECHA_RECIBO", d."HORA",
        d."SUBTOTAL", d."MONTO_GRA", d."MONTO_EXE", d."EXENTO",
        d."IVA", d."ALICUOTA", d."TOTAL",
        d."ANULADA", d."CANCELADA", d."RECIBIDA",
        d."DOC_ORIGEN", d."NUM_CONTROL", d."LEGAL",
        d."CONCEPTO", d."OBSERV", d."ALMACEN",
        d."IVA_RETENIDO", d."ISLR", d."MONTO_ISLR",
        d."COD_USUARIO", d."FECHA_REPORTE",
        CASE
            WHEN d."ANULADA" = 1 THEN 'ANULADO'
            WHEN d."CANCELADA" = 'S' THEN 'PAGADO'
            WHEN d."RECIBIDA" = 'S' THEN 'RECIBIDO'
            ELSE 'PENDIENTE'
        END::TEXT
    FROM "DocumentosCompra" d
    WHERE (p_tipo_operacion IS NULL OR d."TIPO_OPERACION" = p_tipo_operacion)
      AND (p_search IS NULL OR d."NUM_DOC" LIKE '%' || p_search || '%'
           OR d."NOMBRE" LIKE '%' || p_search || '%'
           OR d."RIF" LIKE '%' || p_search || '%'
           OR d."COD_PROVEEDOR" LIKE '%' || p_search || '%')
      AND (p_cod_proveedor IS NULL OR d."COD_PROVEEDOR" = p_cod_proveedor)
      AND (p_desde IS NULL OR d."FECHA"::DATE >= p_desde)
      AND (p_hasta IS NULL OR d."FECHA"::DATE <= p_hasta)
      AND (p_anulada IS NULL OR (d."ANULADA" = 1) = p_anulada)
    ORDER BY d."FECHA" DESC, d."ID" DESC
    LIMIT p_limit OFFSET v_offset;
END;
$function$
;

-- ============================================================
-- sp_documentoscompra_list_legacy
-- ============================================================
CREATE OR REPLACE FUNCTION public.sp_documentoscompra_list_legacy(p_tipo_operacion character varying DEFAULT NULL::character varying, p_search character varying DEFAULT NULL::character varying, p_cod_proveedor character varying DEFAULT NULL::character varying, p_desde date DEFAULT NULL::date, p_hasta date DEFAULT NULL::date, p_anulada boolean DEFAULT NULL::boolean, p_page integer DEFAULT 1, p_limit integer DEFAULT 50)
 RETURNS TABLE("TotalCount" bigint, "NUM_FACT" character varying, "COD_PROVEEDOR" character varying, "TIPO_OPERACION" character varying, "FECHA" timestamp without time zone, "NOMBRE" character varying, "RIF" character varying, "TOTAL" numeric, "COD_USUARIO" character varying, "ANULADA" integer, "ESTADO" character varying)
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_offset INT;
    v_total  BIGINT;
BEGIN
    v_offset := (p_page - 1) * p_limit;

    SELECT COUNT(1) INTO v_total
    FROM "DocumentosCompra"
    WHERE (p_tipo_operacion IS NULL OR "TIPO_OPERACION" = p_tipo_operacion)
      AND (p_search IS NULL OR "NUM_FACT" LIKE '%' || p_search || '%' OR "NOMBRE" LIKE '%' || p_search || '%')
      AND (p_cod_proveedor IS NULL OR "COD_PROVEEDOR" = p_cod_proveedor)
      AND (p_desde IS NULL OR "FECHA"::DATE >= p_desde)
      AND (p_hasta IS NULL OR "FECHA"::DATE <= p_hasta)
      AND (p_anulada IS NULL OR "ANULADA"::BOOLEAN = p_anulada);

    RETURN QUERY
    SELECT
        v_total,
        d."NUM_FACT", d."COD_PROVEEDOR", d."TIPO_OPERACION",
        d."FECHA", d."NOMBRE", d."RIF", d."TOTAL", d."COD_USUARIO", d."ANULADA",
        CASE WHEN d."ANULADA" = 1 THEN 'ANULADO' ELSE 'PENDIENTE' END::TEXT
    FROM "DocumentosCompra" d
    WHERE (p_tipo_operacion IS NULL OR d."TIPO_OPERACION" = p_tipo_operacion)
      AND (p_search IS NULL OR d."NUM_FACT" LIKE '%' || p_search || '%' OR d."NOMBRE" LIKE '%' || p_search || '%')
      AND (p_cod_proveedor IS NULL OR d."COD_PROVEEDOR" = p_cod_proveedor)
      AND (p_desde IS NULL OR d."FECHA"::DATE >= p_desde)
      AND (p_hasta IS NULL OR d."FECHA"::DATE <= p_hasta)
      AND (p_anulada IS NULL OR d."ANULADA"::BOOLEAN = p_anulada)
    ORDER BY d."FECHA" DESC
    LIMIT p_limit OFFSET v_offset;
END;
$function$
;

