;

-- ============================================================
-- sp_documentosventa_list_legacy
-- ============================================================
CREATE OR REPLACE FUNCTION public.sp_documentosventa_list_legacy(p_tipo_operacion character varying DEFAULT NULL::character varying, p_search character varying DEFAULT NULL::character varying, p_codigo character varying DEFAULT NULL::character varying, p_desde date DEFAULT NULL::date, p_hasta date DEFAULT NULL::date, p_anulada boolean DEFAULT NULL::boolean, p_page integer DEFAULT 1, p_limit integer DEFAULT 50)
 RETURNS TABLE("TotalCount" bigint, "NUM_FACT" character varying, "SERIALTIPO" character varying, "Tipo_Orden" character varying, "TIPO_OPERACION" character varying, "CODIGO" character varying, "FECHA" timestamp without time zone, "TOTAL" numeric, "COD_USUARIO" character varying, "OBSERV" character varying, "CANCELADA" character varying, "FECHA_ANULA" timestamp without time zone, "ESTADO" character varying)
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_offset INT;
    v_total  BIGINT;
BEGIN
    v_offset := (p_page - 1) * p_limit;

    SELECT COUNT(1) INTO v_total
    FROM "DocumentosVenta"
    WHERE (p_tipo_operacion IS NULL OR "TIPO_OPERACION" = p_tipo_operacion)
      AND (p_search IS NULL OR "NUM_FACT" LIKE '%' || p_search || '%' OR "OBSERV" LIKE '%' || p_search || '%')
      AND (p_codigo IS NULL OR "CODIGO" = p_codigo)
      AND (p_desde IS NULL OR "FECHA"::DATE >= p_desde)
      AND (p_hasta IS NULL OR "FECHA"::DATE <= p_hasta)
      AND (p_anulada IS NULL OR
           CASE WHEN "FECHA_ANULA" IS NULL THEN FALSE ELSE TRUE END = p_anulada);

    RETURN QUERY
    SELECT
        v_total,
        d."NUM_FACT", d."SERIALTIPO", d."Tipo_Orden", d."TIPO_OPERACION",
        d."CODIGO", d."FECHA", d."TOTAL", d."COD_USUARIO", d."OBSERV",
        d."CANCELADA", d."FECHA_ANULA",
        CASE
            WHEN d."FECHA_ANULA" IS NOT NULL THEN 'ANULADO'
            WHEN d."CANCELADA" = 'S' THEN 'CANCELADO'
            ELSE 'PENDIENTE'
        END::TEXT
    FROM "DocumentosVenta" d
    WHERE (p_tipo_operacion IS NULL OR d."TIPO_OPERACION" = p_tipo_operacion)
      AND (p_search IS NULL OR d."NUM_FACT" LIKE '%' || p_search || '%' OR d."OBSERV" LIKE '%' || p_search || '%')
      AND (p_codigo IS NULL OR d."CODIGO" = p_codigo)
      AND (p_desde IS NULL OR d."FECHA"::DATE >= p_desde)
      AND (p_hasta IS NULL OR d."FECHA"::DATE <= p_hasta)
      AND (p_anulada IS NULL OR
           CASE WHEN d."FECHA_ANULA" IS NULL THEN FALSE ELSE TRUE END = p_anulada)
    ORDER BY d."FECHA" DESC
    LIMIT p_limit OFFSET v_offset;
END;
$function$
;

-- ============================================================
-- sp_documentosventa_tipos
-- ============================================================
CREATE OR REPLACE FUNCTION public.sp_documentosventa_tipos()
 RETURNS TABLE(codigo character varying, nombre character varying, cantidad bigint)
 LANGUAGE plpgsql
AS $function$
BEGIN
    RETURN QUERY
    SELECT
        d."TIPO_OPERACION" AS "codigo",
        CASE d."TIPO_OPERACION"
            WHEN 'FACT' THEN 'Factura'
            WHEN 'PRESUP' THEN 'Presupuesto'
            WHEN 'PEDIDO' THEN 'Pedido'
            WHEN 'COTIZ' THEN 'Cotizacion'
            WHEN 'NOTACRED' THEN 'Nota de Credito'
            WHEN 'NOTADEB' THEN 'Nota de Debito'
            WHEN 'NOTA_ENTREGA' THEN 'Nota de Entrega'
            ELSE d."TIPO_OPERACION"
        END::TEXT AS "nombre",
        COUNT(*)
    FROM "DocumentosVenta" d
    WHERE d."ANULADA" = 0
    GROUP BY d."TIPO_OPERACION"
    ORDER BY d."TIPO_OPERACION";
END;
$function$
;

-- ============================================================
-- sp_emitir_compra_tx
-- ============================================================
CREATE OR REPLACE FUNCTION public.sp_emitir_compra_tx(p_compra_json jsonb, p_detalle_json jsonb, p_actualizar_inventario boolean DEFAULT true, p_generar_cxp boolean DEFAULT true, p_actualizar_saldos_proveedor boolean DEFAULT true)
 RETURNS TABLE(ok boolean, "numFact" character varying, "detalleRows" integer, "inventoryUpdated" boolean, "cxpGenerated" boolean)
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_num_fact        VARCHAR(60);
    v_cod_proveedor   VARCHAR(60);
    v_fecha           TIMESTAMP;
    v_total           NUMERIC(18,4);
    v_cod_usuario     VARCHAR(60);
    v_tipo            VARCHAR(30);
    v_nombre          VARCHAR(200);
    v_rif             VARCHAR(50);
    v_concepto        VARCHAR(500);
    v_detalle_rows    INT;
    v_saldo_previo    DOUBLE PRECISION;
    v_saldo_total     DOUBLE PRECISION;
BEGIN
    -- Extraer datos de la compra
    v_num_fact      := NULLIF(TRIM(p_compra_json->>'NUM_FACT'), '');
    v_cod_proveedor := NULLIF(TRIM(p_compra_json->>'COD_PROVEEDOR'), '');
    v_cod_usuario   := COALESCE(NULLIF(TRIM(p_compra_json->>'COD_USUARIO'), ''), 'API')::character varying;
    v_tipo          := UPPER(COALESCE(NULLIF(TRIM(p_compra_json->>'TIPO'), ''), 'CONTADO')::character varying)::character varying;
    v_nombre        := COALESCE(NULLIF(TRIM(p_compra_json->>'NOMBRE'), ''), '')::character varying;
    v_rif           := COALESCE(NULLIF(TRIM(p_compra_json->>'RIF'), ''), '')::character varying;
    v_concepto      := NULLIF(TRIM(p_compra_json->>'CONCEPTO'), '');

    BEGIN
        v_fecha := (p_compra_json->>'FECHA')::TIMESTAMP;
    EXCEPTION WHEN OTHERS THEN
        v_fecha := NOW() AT TIME ZONE 'UTC';
    END;

    v_total := COALESCE((p_compra_json->>'TOTAL')::NUMERIC(18,4), 0);

    IF v_num_fact IS NULL OR TRIM(v_num_fact) = '' THEN
        RAISE EXCEPTION 'missing_num_fact';
    END IF;

    -- Verificar que la compra no existe (tabla legacy "Compras")
    IF EXISTS (SELECT 1 FROM "Compras" WHERE "NUM_FACT" = v_num_fact) THEN
        RAISE EXCEPTION 'compra_already_exists';
    END IF;

    -- 1. Insertar cabecera en Compras (legacy)
    INSERT INTO "Compras" (
        "NUM_FACT", "COD_PROVEEDOR", "FECHA", "NOMBRE", "RIF", "TOTAL",
        "TIPO", "CONCEPTO", "COD_USUARIO", "ANULADA", "FECHARECIBO"
    )
    VALUES (
        v_num_fact, v_cod_proveedor, v_fecha, v_nombre, v_rif, v_total,
        v_tipo, v_concepto, v_cod_usuario, 0, v_fecha
    );

    -- 2. Insertar detalle en Detalle_Compras (legacy)
    INSERT INTO "Detalle_Compras" (
        "NUM_FACT", "CODIGO", "Referencia", "DESCRIPCION", "FECHA", "CANTIDAD",
        "PRECIO_COSTO", "Alicuota", "Co_Usuario"
    )
    SELECT
        v_num_fact,
        NULLIF(TRIM(d->>'CODIGO'), ''),
        NULLIF(TRIM(d->>'REFERENCIA'), ''),
        NULLIF(TRIM(d->>'DESCRIPCION'), ''),
        v_fecha,
        COALESCE((d->>'CANTIDAD')::NUMERIC(18,4), 0),
        COALESCE((d->>'PRECIO_COSTO')::NUMERIC(18,4), 0),
        COALESCE((d->>'ALICUOTA')::NUMERIC(18,4), 0),
        v_cod_usuario
    FROM jsonb_array_elements(p_detalle_json) AS d;

    SELECT COUNT(*) INTO v_detalle_rows FROM jsonb_array_elements(p_detalle_json);

    -- 3. Actualizar master."Product" Ã¢â‚¬â€ Ingreso
    IF p_actualizar_inventario THEN
        -- Insertar en MovInvent (historial)
        INSERT INTO "MovInvent" (
            "DOCUMENTO", "CODIGO", "PRODUCT", "FECHA", "MOTIVO", "TIPO",
            "CANTIDAD_ACTUAL", "CANTIDAD", "CANTIDAD_NUEVA", "CO_USUARIO",
            "PRECIO_COMPRA", "ALICUOTA", "PRECIO_VENTA"
        )
        SELECT
            v_num_fact,
            NULLIF(TRIM(d->>'CODIGO'), ''),
            NULLIF(TRIM(d->>'CODIGO'), ''),
            v_fecha,
            'Compra:' || v_num_fact,
            'Ingreso',
            COALESCE(inv."StockQty", 0),
            COALESCE((d->>'CANTIDAD')::NUMERIC(18,4), 0),
            COALESCE(inv."StockQty", 0) + COALESCE((d->>'CANTIDAD')::NUMERIC(18,4), 0),
            v_cod_usuario,
            COALESCE((d->>'PRECIO_COSTO')::NUMERIC(18,4), 0),
            COALESCE((d->>'ALICUOTA')::NUMERIC(18,4), 0),
            COALESCE(inv."SalesPrice", 0)
        FROM jsonb_array_elements(p_detalle_json) AS d
        INNER JOIN master."Product" inv ON inv."ProductCode" = NULLIF(TRIM(d->>'CODIGO'), '')
        WHERE NULLIF(TRIM(d->>'CODIGO'), '') IS NOT NULL
          AND COALESCE((d->>'CANTIDAD')::NUMERIC(18,4), 0) > 0;

        -- Actualizar existencias
        UPDATE master."Product" AS p
           SET "StockQty" = COALESCE(p."StockQty", 0) + agg."Total"
          FROM (
              SELECT NULLIF(TRIM(d->>'CODIGO'), '') AS cod_serv,
                     SUM(COALESCE((d->>'CANTIDAD')::NUMERIC(18,4), 0)) AS "Total"
                FROM jsonb_array_elements(p_detalle_json) AS d
               WHERE NULLIF(TRIM(d->>'CODIGO'), '') IS NOT NULL
               GROUP BY NULLIF(TRIM(d->>'CODIGO'), '')
          ) agg
         WHERE p."ProductCode" = agg.cod_serv;
    END IF;

    -- 4. Generar CxP (si es credito) Ã¢â‚¬â€ tabla legacy "P_Pagar"
    IF p_generar_cxp AND v_tipo = 'CREDITO' AND v_total > 0 THEN
        -- Obtener saldo previo del proveedor
        SELECT COALESCE("SALDO", 0) INTO v_saldo_previo
          FROM "P_Pagar"
         WHERE "CODIGO" = v_cod_proveedor
         ORDER BY "FECHA" DESC
         LIMIT 1;
        v_saldo_previo := COALESCE(v_saldo_previo, 0);

        -- Eliminar CxP previa del documento
        DELETE FROM "P_Pagar"
         WHERE "CODIGO" = v_cod_proveedor
           AND "DOCUMENTO" = v_num_fact
           AND "TIPO" = 'FACT';

        -- Insertar nueva CxP
        INSERT INTO "P_Pagar" (
            "CODIGO", "FECHA", "DOCUMENTO", "TIPO", "DEBE", "HABER", "PEND", "SALDO", "ISRL", "OBS"
        )
        VALUES (
            v_cod_proveedor, v_fecha, v_num_fact, 'FACT', 0, v_total::DOUBLE PRECISION,
            v_total::DOUBLE PRECISION, v_saldo_previo + v_total::DOUBLE PRECISION, '', ''
        );
    END IF;

    -- 5. Actualizar saldos del proveedor en master."Supplier"
    IF p_actualizar_saldos_proveedor AND v_cod_proveedor IS NOT NULL AND TRIM(v_cod_proveedor) <> '' THEN
        SELECT COALESCE(SUM(CASE WHEN "TIPO" = 'FACT' THEN COALESCE("PEND", 0) ELSE 0 END), 0)
          INTO v_saldo_total
          FROM "P_Pagar"
         WHERE "CODIGO" = v_cod_proveedor;

        UPDATE master."Supplier"
           SET "TotalBalance" = v_saldo_total
         WHERE "SupplierCode" = v_cod_proveedor
           AND COALESCE("IsDeleted", FALSE) = FALSE;
    END IF;

    RETURN QUERY SELECT
        TRUE AS "ok",
        v_num_fact AS "numFact",
        v_detalle_rows AS "detalleRows",
        p_actualizar_inventario AS "inventoryUpdated",
        (p_generar_cxp AND v_tipo = 'CREDITO') AS "cxpGenerated";

EXCEPTION WHEN OTHERS THEN
    RAISE EXCEPTION '%', SQLERRM;
END;
$function$
;

-- ============================================================
-- sp_emitir_cotizacion_tx
-- ============================================================
CREATE OR REPLACE FUNCTION public.sp_emitir_cotizacion_tx(p_cotizacion_json jsonb, p_detalle_json jsonb, p_cod_usuario character varying DEFAULT 'API'::character varying)
 RETURNS TABLE(ok boolean, "numFact" character varying, "detalleRows" integer)
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_num_fact      VARCHAR(60);
    v_codigo        VARCHAR(60);
    v_fecha         TIMESTAMP;
    v_total         NUMERIC(18,4);
    v_nombre        VARCHAR(200);
    v_serial_tipo   VARCHAR(60);
    v_detalle_rows  INT;
BEGIN
    v_num_fact    := NULLIF(TRIM(p_cotizacion_json->>'NUM_FACT'), '');
    v_codigo      := NULLIF(TRIM(p_cotizacion_json->>'CODIGO'), '');
    v_nombre      := COALESCE(NULLIF(TRIM(p_cotizacion_json->>'NOMBRE'), ''), '')::character varying;
    v_serial_tipo := COALESCE(NULLIF(TRIM(p_cotizacion_json->>'SERIALTIPO'), ''), '')::character varying;

    BEGIN
        v_fecha := (p_cotizacion_json->>'FECHA')::TIMESTAMP;
    EXCEPTION WHEN OTHERS THEN
        v_fecha := NOW() AT TIME ZONE 'UTC';
    END;

    v_total := COALESCE((p_cotizacion_json->>'TOTAL')::NUMERIC(18,4), 0);

    IF v_num_fact IS NULL OR TRIM(v_num_fact) = '' THEN
        RAISE EXCEPTION 'missing_num_fact';
    END IF;

    -- Verificar que no existe (tabla legacy "Cotizacion")
    IF EXISTS (SELECT 1 FROM "Cotizacion" WHERE "NUM_FACT" = v_num_fact) THEN
        RAISE EXCEPTION 'cotizacion_already_exists';
    END IF;

    -- 1. Insertar cabecera
    INSERT INTO "Cotizacion" (
        "NUM_FACT", "SERIALTIPO", "CODIGO", "FECHA", "NOMBRE", "TOTAL",
        "COD_USUARIO", "ANULADA", "FECHA_REPORTE", "CANCELADA"
    )
    VALUES (
        v_num_fact, v_serial_tipo, v_codigo, v_fecha, v_nombre, v_total,
        p_cod_usuario, 0, v_fecha, 'N'
    );

    -- 2. Insertar detalle
    INSERT INTO "Detalle_Cotizacion" (
        "NUM_FACT", "SERIALTIPO", "COD_SERV", "DESCRIPCION", "FECHA", "CANTIDAD",
        "PRECIO", "TOTAL", "ANULADA", "Co_Usuario", "Alicuota", "PRECIO_DESCUENTO",
        "Relacionada", "RENGLON", "Vendedor", "Cod_alterno"
    )
    SELECT
        v_num_fact,
        COALESCE(NULLIF(TRIM(d->>'SERIALTIPO'), ''), v_serial_tipo)::character varying,
        NULLIF(TRIM(d->>'COD_SERV'), ''),
        NULLIF(TRIM(d->>'DESCRIPCION'), ''),
        v_fecha,
        COALESCE((d->>'CANTIDAD')::DOUBLE PRECISION, 0),
        COALESCE((d->>'PRECIO')::DOUBLE PRECISION, 0),
        COALESCE(
            (d->>'TOTAL')::DOUBLE PRECISION,
            COALESCE((d->>'PRECIO')::DOUBLE PRECISION, 0) * COALESCE((d->>'CANTIDAD')::DOUBLE PRECISION, 0)
        ),
        0,
        p_cod_usuario,
        COALESCE((d->>'Alicuota')::DOUBLE PRECISION, 0),
        COALESCE(
            (d->>'PRECIO_DESCUENTO')::DOUBLE PRECISION,
            COALESCE((d->>'PRECIO')::DOUBLE PRECISION, 0)
        ),
        COALESCE(NULLIF(TRIM(d->>'Relacionada'), ''), '0')::character varying,
        COALESCE((d->>'RENGLON')::DOUBLE PRECISION, 0),
        NULLIF(TRIM(d->>'Vendedor'), ''),
        NULLIF(TRIM(d->>'Cod_alterno'), '')
    FROM jsonb_array_elements(p_detalle_json) AS d;

    SELECT COUNT(*) INTO v_detalle_rows FROM jsonb_array_elements(p_detalle_json);

    RETURN QUERY SELECT
        TRUE AS "ok",
        v_num_fact AS "numFact",
        v_detalle_rows AS "detalleRows";

EXCEPTION WHEN OTHERS THEN
    RAISE EXCEPTION '%', SQLERRM;
END;
$function$
;

-- ============================================================
-- sp_emitir_documento_compra_tx
-- ============================================================
CREATE OR REPLACE FUNCTION public.sp_emitir_documento_compra_tx(p_tipo_operacion character varying, p_doc_json jsonb, p_detalle_json jsonb, p_pagos_json jsonb DEFAULT NULL::jsonb, p_cod_usuario character varying DEFAULT 'API'::character varying, p_actualizar_inventario boolean DEFAULT true, p_generar_cxp boolean DEFAULT true)
 RETURNS TABLE(ok boolean, "numDoc" character varying, "tipoOperacion" character varying, total double precision, lineas bigint)
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_num_doc        VARCHAR(60);
    v_serial_tipo    VARCHAR(60);
    v_cod_proveedor  VARCHAR(60);
    v_nombre         VARCHAR(255);
    v_rif            VARCHAR(15);
    v_fecha_str      VARCHAR(50);
    v_fecha          TIMESTAMP;
    v_fecha_vence_str VARCHAR(50);
    v_fecha_vence    TIMESTAMP;
    v_fecha_recibo_str VARCHAR(50);
    v_fecha_recibo   TIMESTAMP;
    v_observ         VARCHAR(500);
    v_concepto       VARCHAR(255);
    v_num_control    VARCHAR(60);
    v_doc_origen     VARCHAR(60);
    v_almacen        VARCHAR(50);
    v_precio_dollar  DOUBLE PRECISION;
    v_moneda         VARCHAR(20);
    v_tasa_cambio    DOUBLE PRECISION;

    -- Retenciones
    v_iva_retenido   DOUBLE PRECISION;
    v_monto_islr     DOUBLE PRECISION;
    v_islr           VARCHAR(50);

    -- Calculos
    v_sub_total      DOUBLE PRECISION := 0;
    v_monto_iva      DOUBLE PRECISION := 0;
    v_total          DOUBLE PRECISION := 0;
    v_monto_gra      DOUBLE PRECISION := 0;
    v_monto_exe      DOUBLE PRECISION := 0;
    v_exento         DOUBLE PRECISION := 0;
    v_alicuota       DOUBLE PRECISION := 0;

    v_row            JSONB;
    v_linea_count    BIGINT := 0;
BEGIN
    -- Validar tipo de operacion
    IF p_tipo_operacion NOT IN ('ORDEN', 'COMPRA') THEN
        RAISE EXCEPTION 'tipo_operacion_invalido';
    END IF;

    -- Extraer campos principales
    v_num_doc         := NULLIF(p_doc_json->>'NUM_DOC', ''::character varying);
    v_serial_tipo     := COALESCE(NULLIF(p_doc_json->>'SERIALTIPO', ''::character varying), '')::character varying;
    v_cod_proveedor   := NULLIF(p_doc_json->>'COD_PROVEEDOR', ''::character varying);
    v_nombre          := NULLIF(p_doc_json->>'NOMBRE', ''::character varying);
    v_rif             := NULLIF(p_doc_json->>'RIF', ''::character varying);
    v_fecha_str       := NULLIF(p_doc_json->>'FECHA', ''::character varying);
    v_fecha           := CASE WHEN v_fecha_str IS NOT NULL THEN v_fecha_str::TIMESTAMP ELSE NOW() AT TIME ZONE 'UTC' END;
    v_fecha_vence_str := NULLIF(p_doc_json->>'FECHA_VENCE', ''::character varying);
    v_fecha_vence     := CASE WHEN v_fecha_vence_str IS NOT NULL THEN v_fecha_vence_str::TIMESTAMP ELSE NULL END;
    v_fecha_recibo_str := NULLIF(p_doc_json->>'FECHA_RECIBO', ''::character varying);
    v_fecha_recibo    := CASE WHEN v_fecha_recibo_str IS NOT NULL THEN v_fecha_recibo_str::TIMESTAMP ELSE NULL END;
    v_observ          := NULLIF(p_doc_json->>'OBSERV', ''::character varying);
    v_concepto        := NULLIF(p_doc_json->>'CONCEPTO', ''::character varying);
    v_num_control     := NULLIF(p_doc_json->>'NUM_CONTROL', ''::character varying);
    v_doc_origen      := NULLIF(p_doc_json->>'DOC_ORIGEN', ''::character varying);
    v_almacen         := NULLIF(p_doc_json->>'ALMACEN', ''::character varying);
    v_precio_dollar   := COALESCE(NULLIF(p_doc_json->>'PRECIO_DOLLAR', ''::character varying)::DOUBLE PRECISION, 0)::character varying;
    v_moneda          := COALESCE(NULLIF(p_doc_json->>'MONEDA', ''::character varying), 'BS')::character varying;
    v_tasa_cambio     := COALESCE(NULLIF(p_doc_json->>'TASA_CAMBIO', ''::character varying)::DOUBLE PRECISION, 1)::character varying;

    -- Retenciones
    v_iva_retenido    := COALESCE(NULLIF(p_doc_json->>'IVA_RETENIDO', ''::character varying)::DOUBLE PRECISION, 0)::character varying;
    v_monto_islr      := COALESCE(NULLIF(p_doc_json->>'MONTO_ISLR', ''::character varying)::DOUBLE PRECISION, 0)::character varying;
    v_islr            := NULLIF(p_doc_json->>'ISLR', ''::character varying);

    IF v_num_doc IS NULL THEN
        RAISE EXCEPTION 'num_doc_requerido';
    END IF;

    -- Verificar duplicado
    IF EXISTS (SELECT 1 FROM "DocumentosCompra" WHERE "NUM_DOC" = v_num_doc AND "TIPO_OPERACION" = p_tipo_operacion) THEN
        RAISE EXCEPTION 'documento_ya_existe';
    END IF;

    -- 1. Calcular detalle en tabla temporal
    CREATE TEMP TABLE _detalle_compra_temp (
        "RENGLON"     INT,
        "COD_SERV"    VARCHAR(60),
        "DESCRIPCION" VARCHAR(255),
        "CANTIDAD"    DOUBLE PRECISION,
        "PRECIO"      DOUBLE PRECISION,
        "COSTO"       DOUBLE PRECISION,
        "ALICUOTA"    DOUBLE PRECISION,
        "SUBTOTAL"    DOUBLE PRECISION,
        "MONTO_IVA"   DOUBLE PRECISION,
        "TOTAL"       DOUBLE PRECISION
    ) ON COMMIT DROP;

    INSERT INTO _detalle_compra_temp ("RENGLON", "COD_SERV", "DESCRIPCION", "CANTIDAD", "PRECIO", "COSTO", "ALICUOTA", "SUBTOTAL", "MONTO_IVA", "TOTAL")
    SELECT
        ROW_NUMBER() OVER (ORDER BY (SELECT NULL))::INT,
        NULLIF(elem->>'COD_SERV', ''::character varying),
        NULLIF(elem->>'DESCRIPCION', ''::character varying),
        COALESCE(NULLIF(elem->>'CANTIDAD', ''::character varying)::DOUBLE PRECISION, 0)::character varying,
        COALESCE(NULLIF(elem->>'PRECIO', ''::character varying)::DOUBLE PRECISION, 0)::character varying,
        COALESCE(NULLIF(elem->>'COSTO', ''::character varying)::DOUBLE PRECISION, 0)::character varying,
        COALESCE(NULLIF(elem->>'ALICUOTA', ''::character varying)::DOUBLE PRECISION, 0)::character varying,
        0, 0, 0
    FROM jsonb_array_elements(p_detalle_json) AS elem;

    -- Calcular totales por linea
    UPDATE _detalle_compra_temp SET
        "SUBTOTAL"  = "CANTIDAD" * "PRECIO",
        "MONTO_IVA" = CASE WHEN "ALICUOTA" > 0 THEN "CANTIDAD" * "PRECIO" * ("ALICUOTA" / 100) ELSE 0 END,
        "TOTAL"     = "CANTIDAD" * "PRECIO" * (1 + CASE WHEN "ALICUOTA" > 0 THEN "ALICUOTA" / 100 ELSE 0 END);

    -- Calcular totales del documento
    SELECT SUM("SUBTOTAL"), SUM("MONTO_IVA"), SUM("TOTAL"),
           SUM(CASE WHEN "ALICUOTA" > 0 THEN "SUBTOTAL" ELSE 0 END),
           SUM(CASE WHEN "ALICUOTA" = 0 THEN "SUBTOTAL" ELSE 0 END),
           SUM(CASE WHEN "ALICUOTA" = 0 THEN "SUBTOTAL" ELSE 0 END),
           MAX("ALICUOTA"),
           COUNT(1)
    INTO v_sub_total, v_monto_iva, v_total, v_monto_gra, v_monto_exe, v_exento, v_alicuota, v_linea_count
    FROM _detalle_compra_temp;

    -- 2. Insertar cabecera
    INSERT INTO "DocumentosCompra" (
        "NUM_DOC", "SERIALTIPO", "TIPO_OPERACION", "COD_PROVEEDOR", "NOMBRE", "RIF",
        "FECHA", "FECHA_VENCE", "FECHA_RECIBO", "HORA",
        "SUBTOTAL", "MONTO_GRA", "MONTO_EXE", "EXENTO", "IVA", "ALICUOTA", "TOTAL",
        "ANULADA", "CANCELADA", "RECIBIDA",
        "DOC_ORIGEN", "NUM_CONTROL", "LEGAL",
        "CONCEPTO", "OBSERV", "ALMACEN",
        "IVA_RETENIDO", "ISLR", "MONTO_ISLR",
        "MONEDA", "TASA_CAMBIO", "PRECIO_DOLLAR",
        "COD_USUARIO", "FECHA_REPORTE"
    ) VALUES (
        v_num_doc, v_serial_tipo, p_tipo_operacion, v_cod_proveedor, v_nombre, v_rif,
        v_fecha, v_fecha_vence, v_fecha_recibo, TO_CHAR(NOW() AT TIME ZONE 'UTC', 'HH24:MI:SS'),
        v_sub_total, v_monto_gra, v_monto_exe, v_exento, v_monto_iva, v_alicuota, v_total,
        0, 'N',
        CASE WHEN p_tipo_operacion = 'ORDEN' THEN 'N' ELSE NULL END,
        v_doc_origen, v_num_control,
        CASE WHEN p_tipo_operacion = 'COMPRA' THEN 1 ELSE 0 END,
        v_concepto, v_observ, v_almacen,
        v_iva_retenido, v_islr, v_monto_islr,
        v_moneda, v_tasa_cambio, v_precio_dollar,
        p_cod_usuario, NOW() AT TIME ZONE 'UTC'
    );

    -- 3. Insertar detalle
    INSERT INTO "DocumentosCompraDetalle" (
        "NUM_DOC", "TIPO_OPERACION", "RENGLON", "COD_SERV", "DESCRIPCION",
        "CANTIDAD", "PRECIO", "COSTO", "ALICUOTA",
        "SUBTOTAL", "MONTO_IVA", "TOTAL",
        "CO_USUARIO", "FECHA"
    )
    SELECT v_num_doc, p_tipo_operacion, d."RENGLON", d."COD_SERV", d."DESCRIPCION",
           d."CANTIDAD", d."PRECIO", d."COSTO", d."ALICUOTA",
           d."SUBTOTAL", d."MONTO_IVA", d."TOTAL",
           p_cod_usuario, v_fecha
    FROM _detalle_compra_temp d;

    -- 4. Insertar formas de pago (si aplica)
    IF p_pagos_json IS NOT NULL THEN
        FOR v_row IN SELECT * FROM jsonb_array_elements(p_pagos_json)
        LOOP
            INSERT INTO "DocumentosCompraPago" (
                "NUM_DOC", "TIPO_OPERACION", "TIPO_PAGO", "BANCO", "NUMERO", "MONTO", "FECHA", "CO_USUARIO"
            ) VALUES (
                v_num_doc, p_tipo_operacion,
                NULLIF(v_row->>'TIPO_PAGO', ''::character varying),
                NULLIF(v_row->>'BANCO', ''::character varying),
                NULLIF(v_row->>'NUMERO', ''::character varying),
                COALESCE(NULLIF(v_row->>'MONTO', ''::character varying)::DOUBLE PRECISION, 0)::character varying,
                v_fecha, p_cod_usuario
            );
        END LOOP;
    END IF;

    -- 5. Actualizar inventario (para COMPRA)
    IF p_actualizar_inventario AND p_tipo_operacion = 'COMPRA' THEN
        -- Actualizar costos y existencias
        UPDATE "Inventario" i SET
            "EXISTENCIA" = COALESCE(i."EXISTENCIA", 0) + c."TOTAL_CANT",
            "COSTO_REFERENCIA" = c."AVG_PRECIO",
            "ULTIMO_COSTO" = c."AVG_PRECIO"
        FROM (
            SELECT "COD_SERV",
                   SUM("CANTIDAD") AS "TOTAL_CANT",
                   AVG("PRECIO") AS "AVG_PRECIO"
            FROM _detalle_compra_temp
            WHERE "COD_SERV" IS NOT NULL
            GROUP BY "COD_SERV"
        ) c
        WHERE i."CODIGO" = c."COD_SERV";

        -- Registrar movimiento
        INSERT INTO "MovInvent" (
            "CODIGO", "PRODUCT", "DOCUMENTO", "FECHA", "MOTIVO", "TIPO",
            "CANTIDAD_ACTUAL", "CANTIDAD", "CANTIDAD_NUEVA", "CO_USUARIO",
            "PRECIO_COMPRA", "ALICUOTA", "PRECIO_VENTA"
        )
        SELECT
            d."COD_SERV", d."COD_SERV", v_num_doc, v_fecha,
            'COMPRA:' || v_num_doc, 'Ingreso',
            COALESCE(i."EXISTENCIA", 0) - d."CANTIDAD",
            d."CANTIDAD",
            COALESCE(i."EXISTENCIA", 0),
            p_cod_usuario,
            COALESCE(d."PRECIO", d."COSTO"),
            COALESCE(d."ALICUOTA", 0),
            COALESCE(i."PRECIO_VENTA", 0)
        FROM _detalle_compra_temp d
        INNER JOIN "Inventario" i ON i."CODIGO" = d."COD_SERV"
        WHERE d."COD_SERV" IS NOT NULL;
    END IF;

    -- 6. Generar CxP (solo para COMPRA)
    IF p_generar_cxp AND p_tipo_operacion = 'COMPRA' THEN
        INSERT INTO "P_Pagar" (
            "CODIGO", "FACTURA", "FECHA", "FECHA_VENCE", "TOTAL", "ABONO", "SALDO",
            "TIPO", "DOCUMENTO", "REFERENCIA", "OBSERVACION",
            "FECHA_E", "COD_USUARIO", "ANULADA", "CANCELADA"
        )
        SELECT v_cod_proveedor, v_num_doc, v_fecha, v_fecha_vence, v_total, 0, v_total,
               'COMPRA', v_num_doc, v_num_control, v_observ,
               v_fecha, p_cod_usuario, 0, 'N'
        WHERE NOT EXISTS (SELECT 1 FROM "P_Pagar" WHERE "FACTURA" = v_num_doc);
    END IF;

    -- 7. Actualizar orden si se esta recibiendo como compra
    IF v_doc_origen IS NOT NULL AND p_tipo_operacion = 'COMPRA' THEN
        UPDATE "DocumentosCompra" SET
            "RECIBIDA" = 'S'
        WHERE "NUM_DOC" = v_doc_origen AND "TIPO_OPERACION" = 'ORDEN';
    END IF;

    RETURN QUERY SELECT TRUE, v_num_doc, p_tipo_operacion, v_total, v_linea_count;
END;
$function$
;

-- ============================================================
-- sp_emitir_documento_venta_tx
-- ============================================================
CREATE OR REPLACE FUNCTION public.sp_emitir_documento_venta_tx(p_tipo_operacion character varying, p_doc_json jsonb, p_detalle_json jsonb, p_pagos_json jsonb DEFAULT NULL::jsonb, p_cod_usuario character varying DEFAULT 'API'::character varying, p_actualizar_inventario boolean DEFAULT true, p_generar_cxc boolean DEFAULT true)
 RETURNS TABLE(ok boolean, "numDoc" character varying, "tipoOperacion" character varying, total double precision, lineas bigint)
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_num_doc        VARCHAR(60);
    v_serial_tipo    VARCHAR(60);
    v_codigo         VARCHAR(60);
    v_nombre         VARCHAR(255);
    v_rif            VARCHAR(20);
    v_fecha_str      VARCHAR(50);
    v_fecha          TIMESTAMP;
    v_fecha_vence_str VARCHAR(50);
    v_fecha_vence    TIMESTAMP;
    v_observ         VARCHAR(500);
    v_vendedor       VARCHAR(60);
    v_doc_origen     VARCHAR(60);
    v_tipo_doc_origen VARCHAR(20);
    v_num_control    VARCHAR(60);
    v_terminos       VARCHAR(255);
    v_moneda         VARCHAR(20);
    v_tasa_cambio    DOUBLE PRECISION;
    v_descuento      DOUBLE PRECISION;
    v_placas         VARCHAR(20);
    v_kilometros     INT;

    v_sub_total      DOUBLE PRECISION := 0;
    v_monto_iva      DOUBLE PRECISION := 0;
    v_total          DOUBLE PRECISION := 0;
    v_monto_gra      DOUBLE PRECISION := 0;
    v_monto_exe      DOUBLE PRECISION := 0;
    v_alicuota       DOUBLE PRECISION := 0;

    v_row            JSONB;
    v_linea_count    BIGINT := 0;
BEGIN
    -- Validar tipo de operacion
    IF p_tipo_operacion NOT IN ('FACT', 'PRESUP', 'PEDIDO', 'COTIZ', 'NOTACRED', 'NOTADEB', 'NOTA_ENTREGA') THEN
        RAISE EXCEPTION 'tipo_operacion_invalido';
    END IF;

    -- Extraer campos principales
    v_num_doc         := NULLIF(p_doc_json->>'NUM_DOC', ''::character varying);
    v_serial_tipo     := COALESCE(NULLIF(p_doc_json->>'SERIALTIPO', ''::character varying), '')::character varying;
    v_codigo          := NULLIF(p_doc_json->>'CODIGO', ''::character varying);
    v_nombre          := NULLIF(p_doc_json->>'NOMBRE', ''::character varying);
    v_rif             := NULLIF(p_doc_json->>'RIF', ''::character varying);
    v_fecha_str       := NULLIF(p_doc_json->>'FECHA', ''::character varying);
    v_fecha           := CASE WHEN v_fecha_str IS NOT NULL THEN v_fecha_str::TIMESTAMP ELSE NOW() AT TIME ZONE 'UTC' END;
    v_fecha_vence_str := NULLIF(p_doc_json->>'FECHA_VENCE', ''::character varying);
    v_fecha_vence     := CASE WHEN v_fecha_vence_str IS NOT NULL THEN v_fecha_vence_str::TIMESTAMP ELSE NULL END;
    v_observ          := NULLIF(p_doc_json->>'OBSERV', ''::character varying);
    v_vendedor        := NULLIF(p_doc_json->>'VENDEDOR', ''::character varying);
    v_doc_origen      := NULLIF(p_doc_json->>'DOC_ORIGEN', ''::character varying);
    v_tipo_doc_origen := NULLIF(p_doc_json->>'TIPO_DOC_ORIGEN', ''::character varying);
    v_num_control     := NULLIF(p_doc_json->>'NUM_CONTROL', ''::character varying);
    v_terminos        := NULLIF(p_doc_json->>'TERMINOS', ''::character varying);
    v_moneda          := COALESCE(NULLIF(p_doc_json->>'MONEDA', ''::character varying), 'BS')::character varying;
    v_tasa_cambio     := COALESCE(NULLIF(p_doc_json->>'TASA_CAMBIO', ''::character varying)::DOUBLE PRECISION, 1)::character varying;
    v_descuento       := COALESCE(NULLIF(p_doc_json->>'DESCUENTO', ''::character varying)::DOUBLE PRECISION, 0)::character varying;
    v_placas          := NULLIF(p_doc_json->>'PLACAS', ''::character varying);
    v_kilometros      := NULLIF(p_doc_json->>'KILOMETROS', ''::character varying)::INT;

    IF v_num_doc IS NULL THEN
        RAISE EXCEPTION 'num_doc_requerido';
    END IF;

    -- Verificar duplicado
    IF EXISTS (SELECT 1 FROM "DocumentosVenta" WHERE "NUM_DOC" = v_num_doc AND "TIPO_OPERACION" = p_tipo_operacion) THEN
        RAISE EXCEPTION 'documento_ya_existe';
    END IF;

    -- 1. Calcular detalle en tabla temporal
    CREATE TEMP TABLE _detalle_temp (
        "RENGLON"     INT,
        "COD_SERV"    VARCHAR(60),
        "DESCRIPCION" VARCHAR(255),
        "CANTIDAD"    DOUBLE PRECISION,
        "PRECIO"      DOUBLE PRECISION,
        "PRECIO_DESC" DOUBLE PRECISION,
        "ALICUOTA"    DOUBLE PRECISION,
        "SUBTOTAL"    DOUBLE PRECISION,
        "MONTO_IVA"   DOUBLE PRECISION,
        "TOTAL"       DOUBLE PRECISION
    ) ON COMMIT DROP;

    INSERT INTO _detalle_temp ("RENGLON", "COD_SERV", "DESCRIPCION", "CANTIDAD", "PRECIO", "PRECIO_DESC", "ALICUOTA", "SUBTOTAL", "MONTO_IVA", "TOTAL")
    SELECT
        ROW_NUMBER() OVER (ORDER BY (SELECT NULL))::INT,
        NULLIF(elem->>'COD_SERV', ''::character varying),
        NULLIF(elem->>'DESCRIPCION', ''::character varying),
        COALESCE(NULLIF(elem->>'CANTIDAD', ''::character varying)::DOUBLE PRECISION, 0)::character varying,
        COALESCE(NULLIF(elem->>'PRECIO', ''::character varying)::DOUBLE PRECISION, 0)::character varying,
        COALESCE(NULLIF(elem->>'PRECIO_DESCUENTO', ''::character varying)::DOUBLE PRECISION, 0)::character varying,
        COALESCE(NULLIF(elem->>'ALICUOTA', ''::character varying)::DOUBLE PRECISION, 0)::character varying,
        0, 0, 0
    FROM jsonb_array_elements(p_detalle_json) AS elem;

    -- Calcular totales por linea
    UPDATE _detalle_temp SET
        "SUBTOTAL"  = "CANTIDAD" * CASE WHEN "PRECIO_DESC" > 0 THEN "PRECIO_DESC" ELSE "PRECIO" END,
        "MONTO_IVA" = CASE WHEN "ALICUOTA" > 0
                      THEN "CANTIDAD" * CASE WHEN "PRECIO_DESC" > 0 THEN "PRECIO_DESC" ELSE "PRECIO" END * ("ALICUOTA" / 100)
                      ELSE 0 END,
        "TOTAL"     = "CANTIDAD" * CASE WHEN "PRECIO_DESC" > 0 THEN "PRECIO_DESC" ELSE "PRECIO" END
                      * (1 + CASE WHEN "ALICUOTA" > 0 THEN "ALICUOTA" / 100 ELSE 0 END);

    -- Calcular totales del documento
    SELECT SUM("SUBTOTAL"), SUM("MONTO_IVA"), SUM("TOTAL"),
           SUM(CASE WHEN "ALICUOTA" > 0 THEN "SUBTOTAL" ELSE 0 END),
           SUM(CASE WHEN "ALICUOTA" = 0 THEN "SUBTOTAL" ELSE 0 END),
           MAX("ALICUOTA"),
           COUNT(1)
    INTO v_sub_total, v_monto_iva, v_total, v_monto_gra, v_monto_exe, v_alicuota, v_linea_count
    FROM _detalle_temp;

    -- Aplicar descuento global
    IF v_descuento > 0 THEN
        v_sub_total := v_sub_total * (1 - v_descuento / 100);
        v_monto_iva := v_monto_iva * (1 - v_descuento / 100);
        v_total     := v_sub_total + v_monto_iva;
    END IF;

    -- 2. Insertar cabecera
    INSERT INTO "DocumentosVenta" (
        "NUM_DOC", "SERIALTIPO", "TIPO_OPERACION", "CODIGO", "NOMBRE", "RIF",
        "FECHA", "FECHA_VENCE", "HORA",
        "SUBTOTAL", "MONTO_GRA", "MONTO_EXE", "IVA", "ALICUOTA", "TOTAL", "DESCUENTO",
        "ANULADA", "CANCELADA", "FACTURADA", "ENTREGADA",
        "DOC_ORIGEN", "TIPO_DOC_ORIGEN", "NUM_CONTROL", "LEGAL",
        "OBSERV", "TERMINOS", "VENDEDOR",
        "MONEDA", "TASA_CAMBIO",
        "PLACAS", "KILOMETROS",
        "COD_USUARIO", "FECHA_REPORTE"
    ) VALUES (
        v_num_doc, v_serial_tipo, p_tipo_operacion, v_codigo, v_nombre, v_rif,
        v_fecha, v_fecha_vence, TO_CHAR(NOW() AT TIME ZONE 'UTC', 'HH24:MI:SS'),
        v_sub_total, v_monto_gra, v_monto_exe, v_monto_iva, v_alicuota, v_total, v_descuento,
        0, 'N',
        CASE WHEN p_tipo_operacion = 'PEDIDO' THEN 'N' ELSE NULL END,
        CASE WHEN p_tipo_operacion = 'NOTA_ENTREGA' THEN 'N' ELSE NULL END,
        v_doc_origen, v_tipo_doc_origen, v_num_control,
        CASE WHEN p_tipo_operacion = 'FACT' THEN 1 ELSE 0 END,
        v_observ, v_terminos, v_vendedor,
        v_moneda, v_tasa_cambio,
        v_placas, v_kilometros,
        p_cod_usuario, NOW() AT TIME ZONE 'UTC'
    );

    -- 3. Insertar detalle
    INSERT INTO "DocumentosVentaDetalle" (
        "NUM_DOC", "TIPO_OPERACION", "RENGLON", "COD_SERV", "DESCRIPCION",
        "CANTIDAD", "PRECIO", "PRECIO_DESCUENTO", "ALICUOTA",
        "SUBTOTAL", "MONTO_IVA", "TOTAL",
        "CO_USUARIO", "FECHA"
    )
    SELECT v_num_doc, p_tipo_operacion, d."RENGLON", d."COD_SERV", d."DESCRIPCION",
           d."CANTIDAD", d."PRECIO", d."PRECIO_DESC", d."ALICUOTA",
           d."SUBTOTAL", d."MONTO_IVA", d."TOTAL",
           p_cod_usuario, v_fecha
    FROM _detalle_temp d;

    -- 4. Insertar formas de pago (si aplica)
    IF p_pagos_json IS NOT NULL THEN
        FOR v_row IN SELECT * FROM jsonb_array_elements(p_pagos_json)
        LOOP
            INSERT INTO "DocumentosVentaPago" (
                "NUM_DOC", "TIPO_OPERACION", "TIPO_PAGO", "BANCO", "NUMERO",
                "MONTO", "TASA_CAMBIO", "FECHA", "CO_USUARIO"
            ) VALUES (
                v_num_doc, p_tipo_operacion,
                NULLIF(v_row->>'TIPO_PAGO', ''::character varying),
                NULLIF(v_row->>'BANCO', ''::character varying),
                NULLIF(v_row->>'NUMERO', ''::character varying),
                COALESCE(NULLIF(v_row->>'MONTO', ''::character varying)::DOUBLE PRECISION, 0)::character varying,
                COALESCE(NULLIF(v_row->>'TASA_CAMBIO', ''::character varying)::DOUBLE PRECISION, v_tasa_cambio)::character varying,
                v_fecha, p_cod_usuario
            );
        END LOOP;
    END IF;

    -- 5. Actualizar inventario (para PEDIDO, NOTA_ENTREGA)
    IF p_actualizar_inventario AND p_tipo_operacion IN ('PEDIDO', 'NOTA_ENTREGA') THEN
        -- Descontar inventario
        UPDATE "Inventario" i SET
            "EXISTENCIA" = COALESCE(i."EXISTENCIA", 0) - t."TOTAL_CANT"
        FROM (
            SELECT "COD_SERV", SUM("CANTIDAD") AS "TOTAL_CANT"
            FROM _detalle_temp
            WHERE "COD_SERV" IS NOT NULL
            GROUP BY "COD_SERV"
        ) t
        WHERE i."CODIGO" = t."COD_SERV";

        -- Registrar movimiento
        INSERT INTO "MovInvent" (
            "CODIGO", "PRODUCT", "DOCUMENTO", "FECHA", "MOTIVO", "TIPO",
            "CANTIDAD_ACTUAL", "CANTIDAD", "CANTIDAD_NUEVA", "CO_USUARIO",
            "PRECIO_COMPRA", "ALICUOTA", "PRECIO_VENTA"
        )
        SELECT
            d."COD_SERV", d."COD_SERV", v_num_doc, v_fecha,
            p_tipo_operacion || ':' || v_num_doc,
            CASE p_tipo_operacion WHEN 'NOTACRED' THEN 'Ingreso' ELSE 'Egreso' END,
            COALESCE(i."EXISTENCIA", 0) + d."CANTIDAD" * CASE WHEN p_tipo_operacion = 'NOTACRED' THEN -1 ELSE 1 END,
            d."CANTIDAD",
            COALESCE(i."EXISTENCIA", 0),
            p_cod_usuario,
            COALESCE(i."COSTO_REFERENCIA", i."ULTIMO_COSTO"),
            COALESCE(d."ALICUOTA", 0),
            d."PRECIO"
        FROM _detalle_temp d
        INNER JOIN "Inventario" i ON i."CODIGO" = d."COD_SERV"
        WHERE d."COD_SERV" IS NOT NULL;
    END IF;

    -- 6. Generar CxC (solo para FACT)
    IF p_generar_cxc AND p_tipo_operacion = 'FACT' THEN
        INSERT INTO "P_Cobrar" (
            "CODIGO", "FACTURA", "FECHA", "FECHA_VENCE", "TOTAL", "ABONO", "SALDO",
            "TIPO", "DOCUMENTO", "NUMERO", "REFERENCIA", "OBSERVACION",
            "FECHA_E", "COD_USUARIO", "SERIALTIPO", "ANULADA"
        )
        SELECT v_codigo, v_num_doc, v_fecha, v_fecha_vence, v_total, 0, v_total,
               p_tipo_operacion, v_serial_tipo, v_num_doc, v_num_control, v_observ,
               v_fecha, p_cod_usuario, v_serial_tipo, 0
        WHERE NOT EXISTS (SELECT 1 FROM "P_Cobrar" WHERE "FACTURA" = v_num_doc);
    END IF;

    -- 7. Actualizar documento origen si aplica
    IF v_doc_origen IS NOT NULL AND v_tipo_doc_origen IS NOT NULL THEN
        UPDATE "DocumentosVenta" SET
            "FACTURADA" = 'S',
            "DOC_ORIGEN" = v_doc_origen
        WHERE "NUM_DOC" = v_doc_origen AND "TIPO_OPERACION" = v_tipo_doc_origen;
    END IF;

    RETURN QUERY SELECT TRUE, v_num_doc, p_tipo_operacion, v_total, v_linea_count;
END;
$function$
;

-- ============================================================
-- sp_emitir_factura_tx
-- ============================================================
CREATE OR REPLACE FUNCTION public.sp_emitir_factura_tx(p_factura_json jsonb, p_detalle_json jsonb, p_formas_pago_json jsonb DEFAULT NULL::jsonb, p_actualizar_inventario boolean DEFAULT true, p_generar_cxc boolean DEFAULT true, p_actualizar_saldos_cliente boolean DEFAULT true)
 RETURNS TABLE(ok boolean, "numFact" character varying, "detalleRows" integer, "montoEfectivo" numeric, "montoCheque" numeric, "montoTarjeta" numeric, "saldoPendiente" numeric, abono numeric)
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_num_fact        VARCHAR(60);
    v_codigo          VARCHAR(60);
    v_pago            VARCHAR(30);
    v_cod_usuario     VARCHAR(60);
    v_serial_tipo     VARCHAR(60);
    v_tipo_orden      VARCHAR(80);
    v_observ          VARCHAR(4000);
    v_fecha           TIMESTAMP;
    v_fecha_reporte   TIMESTAMP;
    v_total           NUMERIC(18,4);
    v_default_company_id INT := 1;
    v_default_branch_id  INT := 1;
    v_customer_id     BIGINT;
    v_memoria         VARCHAR(80);
    v_monto_efectivo  NUMERIC(18,4) := 0;
    v_monto_cheque    NUMERIC(18,4) := 0;
    v_monto_tarjeta   NUMERIC(18,4) := 0;
    v_saldo_pendiente NUMERIC(18,4) := 0;
    v_num_tarjeta     VARCHAR(60) := '0';
    v_cta             VARCHAR(80) := ' ';
    v_banco_cheque    VARCHAR(120) := ' ';
    v_banco_tarjeta   VARCHAR(120) := ' ';
    v_abono           NUMERIC(18,4);
    v_cancelada       CHAR(1);
    v_detalle_rows    INT;
BEGIN
    -- Parsear cabecera
    v_num_fact     := NULLIF(TRIM(p_factura_json->>'NUM_FACT'), '');
    v_codigo       := NULLIF(TRIM(p_factura_json->>'CODIGO'), '');
    v_pago         := UPPER(COALESCE(NULLIF(TRIM(p_factura_json->>'PAGO'), ''), '')::character varying)::character varying;
    v_cod_usuario  := COALESCE(NULLIF(TRIM(p_factura_json->>'COD_USUARIO'), ''), 'API')::character varying;
    v_serial_tipo  := COALESCE(NULLIF(TRIM(p_factura_json->>'SERIALTIPO'), ''), '')::character varying;
    v_tipo_orden   := COALESCE(NULLIF(TRIM(p_factura_json->>'TIPO_ORDEN'), ''), '1')::character varying;
    v_observ       := NULLIF(TRIM(p_factura_json->>'OBSERV'), '');

    BEGIN
        v_fecha := (p_factura_json->>'FECHA')::TIMESTAMP;
    EXCEPTION WHEN OTHERS THEN
        v_fecha := NOW() AT TIME ZONE 'UTC';
    END;

    BEGIN
        v_fecha_reporte := (p_factura_json->>'FECHA_REPORTE')::TIMESTAMP;
    EXCEPTION WHEN OTHERS THEN
        v_fecha_reporte := v_fecha;
    END;

    v_total := COALESCE((p_factura_json->>'TOTAL')::NUMERIC(18,4), 0);

    IF v_num_fact IS NULL OR TRIM(v_num_fact) = '' THEN
        RAISE EXCEPTION 'missing_num_fact';
    END IF;

    -- Resolver IDs canonicos
    SELECT "CompanyId" INTO v_default_company_id
      FROM cfg."Company" WHERE "CompanyCode" = 'DEFAULT' LIMIT 1;
    v_default_company_id := COALESCE(v_default_company_id, 1);

    SELECT "BranchId" INTO v_default_branch_id
      FROM cfg."Branch" WHERE "CompanyId" = v_default_company_id AND "BranchCode" = 'MAIN' LIMIT 1;
    v_default_branch_id := COALESCE(v_default_branch_id, 1);

    IF v_codigo IS NOT NULL THEN
        SELECT "CustomerId" INTO v_customer_id
          FROM master."Customer"
         WHERE "CustomerCode" = v_codigo AND COALESCE("IsDeleted", FALSE) = FALSE
         LIMIT 1;
    END IF;

    -- 1. Cabecera -> ar."SalesDocument"
    INSERT INTO ar."SalesDocument" (
        "DocumentNumber", "SerialType", "FiscalMemoryNumber", "OperationType",
        "CustomerCode", "DocumentDate", "ReportDate", "PaymentTerms",
        "TotalAmount", "UserCode", "Notes"
    )
    VALUES (
        v_num_fact, v_serial_tipo, v_tipo_orden, 'FACT',
        v_codigo, v_fecha, v_fecha_reporte, v_pago,
        v_total, v_cod_usuario, v_observ
    );

    -- 2. Detalle -> ar."SalesDocumentLine"
    INSERT INTO ar."SalesDocumentLine" (
        "DocumentNumber", "SerialType", "FiscalMemoryNumber", "OperationType",
        "ProductCode", "Quantity", "UnitPrice", "TaxRate", "TotalAmount",
        "DiscountedPrice", "RelatedRef", "AlternateCode"
    )
    SELECT
        COALESCE(NULLIF(TRIM(row_data->>'NUM_FACT'), ''), v_num_fact)::character varying,
        COALESCE(NULLIF(TRIM(row_data->>'SERIALTIPO'), ''), v_serial_tipo)::character varying,
        v_tipo_orden, 'FACT',
        NULLIF(TRIM(row_data->>'COD_SERV'), ''),
        COALESCE((row_data->>'CANTIDAD')::NUMERIC(18,4), 0),
        COALESCE((row_data->>'PRECIO')::NUMERIC(18,4), 0),
        COALESCE((row_data->>'ALICUOTA')::NUMERIC(18,4), 0),
        COALESCE(
            (row_data->>'TOTAL')::NUMERIC(18,4),
            COALESCE((row_data->>'PRECIO')::NUMERIC(18,4), 0) * COALESCE((row_data->>'CANTIDAD')::NUMERIC(18,4), 0)
        ),
        COALESCE(
            (row_data->>'PRECIO_DESCUENTO')::NUMERIC(18,4),
            COALESCE((row_data->>'PRECIO')::NUMERIC(18,4), 0)
        ),
        COALESCE(NULLIF(TRIM(row_data->>'RELACIONADA'), ''), '0')::character varying,
        NULLIF(TRIM(row_data->>'COD_ALTERNO'), '')
    FROM jsonb_array_elements(p_detalle_json) AS row_data;

    -- Contar filas de detalle
    SELECT COUNT(*) INTO v_detalle_rows FROM jsonb_array_elements(p_detalle_json);

    -- 3. Formas de pago
    v_memoria := v_tipo_orden;

    IF p_formas_pago_json IS NOT NULL THEN
        -- Eliminar pagos previos
        DELETE FROM ar."SalesDocumentPayment"
         WHERE "DocumentNumber" = v_num_fact AND "OperationType" = 'FACT';

        -- Insertar pagos
        INSERT INTO ar."SalesDocumentPayment" (
            "ExchangeRate", "PaymentMethod", "DocumentNumber", "Amount",
            "BankCode", "ReferenceNumber", "PaymentDate", "PaymentNumber",
            "FiscalMemoryNumber", "SerialType", "OperationType"
        )
        SELECT
            COALESCE((fp->>'tasacambio')::NUMERIC(18,6), 1),
            NULLIF(TRIM(fp->>'tipo'), ''),
            v_num_fact,
            COALESCE((fp->>'monto')::NUMERIC(18,4), 0),
            COALESCE(NULLIF(TRIM(fp->>'banco'), ''), ' ')::character varying,
            COALESCE(NULLIF(TRIM(fp->>'cuenta'), ''), ' ')::character varying,
            v_fecha,
            COALESCE(NULLIF(TRIM(fp->>'numero'), ''), '0')::character varying,
            v_memoria, v_serial_tipo, 'FACT'
        FROM jsonb_array_elements(p_formas_pago_json) AS fp;

        -- Calcular resumen de pagos
        SELECT
            COALESCE(SUM(CASE WHEN UPPER(COALESCE(NULLIF(TRIM(fp->>'tipo'), ''), ''))::character varying = 'EFECTIVO' THEN COALESCE((fp->>'monto')::NUMERIC(18,4), 0) ELSE 0 END), 0)::character varying,
            COALESCE(SUM(CASE WHEN UPPER(COALESCE(NULLIF(TRIM(fp->>'tipo'), ''), ''))::character varying = 'CHEQUE' THEN COALESCE((fp->>'monto')::NUMERIC(18,4), 0) ELSE 0 END), 0)::character varying,
            COALESCE(SUM(CASE WHEN UPPER(COALESCE(NULLIF(TRIM(fp->>'tipo'), ''), ''))::character varying LIKE 'TARJETA%' OR UPPER(COALESCE(NULLIF(TRIM(fp->>'tipo'), ''), ''))::character varying LIKE 'TICKET%' THEN COALESCE((fp->>'monto')::NUMERIC(18,4), 0) ELSE 0 END), 0)::character varying,
            COALESCE(SUM(CASE WHEN UPPER(COALESCE(NULLIF(TRIM(fp->>'tipo'), ''), ''))::character varying = 'SALDO PENDIENTE' THEN COALESCE((fp->>'monto')::NUMERIC(18,4), 0) ELSE 0 END), 0)::character varying
        INTO v_monto_efectivo, v_monto_cheque, v_monto_tarjeta, v_saldo_pendiente
        FROM jsonb_array_elements(p_formas_pago_json) AS fp;

        -- Depositos cheque -> acct."BankDeposit"
        INSERT INTO acct."BankDeposit" ("Amount", "CheckNumber", "BankAccount", "CustomerCode", "IsRelated", "BankName", "DocumentRef", "OperationType")
        SELECT
            COALESCE((fp->>'monto')::NUMERIC(18,4), 0),
            COALESCE(NULLIF(TRIM(fp->>'numero'), ''), '0')::character varying,
            COALESCE(NULLIF(TRIM(fp->>'cuenta'), ''), ' ')::character varying,
            v_codigo, FALSE,
            COALESCE(NULLIF(TRIM(fp->>'banco'), ''), ' ')::character varying,
            v_num_fact, 'FACT'
        FROM jsonb_array_elements(p_formas_pago_json) AS fp
        WHERE UPPER(COALESCE(NULLIF(TRIM(fp->>'tipo'), ''), '')::character varying)::character varying = 'CHEQUE';
    END IF;

    v_abono := v_total - v_saldo_pendiente;
    v_cancelada := CASE WHEN v_saldo_pendiente > 0 THEN 'N' ELSE 'S' END;

    -- Actualizar estado en ar."SalesDocument"
    UPDATE ar."SalesDocument"
       SET "IsPaid" = v_cancelada,
           "ReportDate" = v_fecha_reporte,
           "UpdatedAt" = NOW() AT TIME ZONE 'UTC'
     WHERE "DocumentNumber" = v_num_fact AND "OperationType" = 'FACT';

    -- 4. CxC -> ar."ReceivableDocument"
    IF p_generar_cxc AND v_customer_id IS NOT NULL AND (v_pago = 'CREDITO' OR v_saldo_pendiente > 0) THEN
        DELETE FROM ar."ReceivableDocument"
         WHERE "CompanyId" = v_default_company_id AND "BranchId" = v_default_branch_id
           AND "DocumentType" = 'FACT' AND "DocumentNumber" = v_num_fact;

        INSERT INTO ar."ReceivableDocument" (
            "CompanyId", "BranchId", "CustomerId", "DocumentType", "DocumentNumber",
            "IssueDate", "CurrencyCode", "TotalAmount", "PendingAmount",
            "PaidFlag", "Status"
        )
        VALUES (
            v_default_company_id, v_default_branch_id, v_customer_id, 'FACT', v_num_fact,
            v_fecha::DATE, 'VES', v_saldo_pendiente, v_saldo_pendiente,
            0, 'PENDING'
        );
    END IF;

    -- 5. Inventario -> master."Product" + master."InventoryMovement"
    IF p_actualizar_inventario THEN
        -- Movimientos -> master."InventoryMovement"
        INSERT INTO master."InventoryMovement" ("CompanyId", "ProductCode", "DocumentRef", "MovementType", "MovementDate", "Quantity", "UnitCost", "TotalCost", "Notes")
        SELECT
            v_default_company_id,
            NULLIF(TRIM(d->>'COD_SERV'), ''),
            v_num_fact, 'SALIDA', v_fecha::DATE,
            COALESCE((d->>'CANTIDAD')::NUMERIC(18,4), 0),
            COALESCE(i."COSTO_REFERENCIA", 0),
            COALESCE((d->>'CANTIDAD')::NUMERIC(18,4), 0) * COALESCE(i."COSTO_REFERENCIA", 0),
            'Doc:' || v_num_fact
        FROM jsonb_array_elements(p_detalle_json) AS d
        INNER JOIN master."Product" i ON i."ProductCode" = NULLIF(TRIM(d->>'COD_SERV'), '')
        WHERE NULLIF(TRIM(d->>'COD_SERV'), '') IS NOT NULL
          AND COALESCE((d->>'CANTIDAD')::NUMERIC(18,4), 0) > 0;

        -- Descontar stock -> master."Product"."StockQty"
        UPDATE master."Product" AS p
           SET "StockQty" = COALESCE(p."StockQty", 0) - agg."Total"
          FROM (
              SELECT NULLIF(TRIM(d->>'COD_SERV'), '') AS cod_serv, SUM(COALESCE((d->>'CANTIDAD')::NUMERIC(18,4), 0)) AS "Total"
                FROM jsonb_array_elements(p_detalle_json) AS d
               GROUP BY NULLIF(TRIM(d->>'COD_SERV'), '')
          ) agg
         WHERE p."ProductCode" = agg.cod_serv;

        -- Stock auxiliar -> master."AlternateStock"
        UPDATE master."AlternateStock" AS a
           SET "StockQty" = COALESCE(a."StockQty", 0) - agg."Total"
          FROM (
              SELECT NULLIF(TRIM(d->>'COD_ALTERNO'), '') AS cod_alterno, SUM(COALESCE((d->>'CANTIDAD')::NUMERIC(18,4), 0)) AS "Total"
                FROM jsonb_array_elements(p_detalle_json) AS d
               WHERE COALESCE((d->>'RELACIONADA')::INT, 0) = 1
               GROUP BY NULLIF(TRIM(d->>'COD_ALTERNO'), '')
          ) agg
         WHERE a."ProductCode" = agg.cod_alterno;
    END IF;

    -- 6. Saldos del cliente -> master."Customer"."TotalBalance"
    IF p_actualizar_saldos_cliente AND v_customer_id IS NOT NULL THEN
        UPDATE master."Customer"
           SET "TotalBalance" = COALESCE((
               SELECT SUM("PendingAmount")
                 FROM ar."ReceivableDocument"
                WHERE "CustomerId" = v_customer_id AND "Status" <> 'VOIDED' AND "PaidFlag" = 0
           ), 0)
         WHERE "CustomerId" = v_customer_id AND COALESCE("IsDeleted", FALSE) = FALSE;
    END IF;

    RETURN QUERY SELECT
        TRUE AS "ok",
        v_num_fact AS "numFact",
        v_detalle_rows AS "detalleRows",
        v_monto_efectivo AS "montoEfectivo",
        v_monto_cheque AS "montoCheque",
        v_monto_tarjeta AS "montoTarjeta",
        v_saldo_pendiente AS "saldoPendiente",
        v_abono AS "abono";

EXCEPTION WHEN OTHERS THEN
    RAISE EXCEPTION '%', SQLERRM;
END;
$function$
;

-- ============================================================
-- sp_emitir_pedido_tx
-- ============================================================
CREATE OR REPLACE FUNCTION public.sp_emitir_pedido_tx(p_pedido_json jsonb, p_detalle_json jsonb, p_actualizar_inventario boolean DEFAULT true, p_cod_usuario character varying DEFAULT 'API'::character varying)
 RETURNS TABLE(ok boolean, "numPedido" character varying, "detalleRows" integer, "inventoryUpdated" boolean)
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_num_fact      VARCHAR(60);
    v_codigo        VARCHAR(60);
    v_fecha         TIMESTAMP;
    v_total         NUMERIC(18,4);
    v_nombre        VARCHAR(200);
    v_serial_tipo   VARCHAR(60);
    v_vendedor      VARCHAR(60);
    v_detalle_rows  INT;
BEGIN
    v_num_fact    := NULLIF(TRIM(p_pedido_json->>'NUM_FACT'), '');
    v_codigo      := NULLIF(TRIM(p_pedido_json->>'CODIGO'), '');
    v_nombre      := COALESCE(NULLIF(TRIM(p_pedido_json->>'NOMBRE'), ''), '')::character varying;
    v_serial_tipo := COALESCE(NULLIF(TRIM(p_pedido_json->>'SERIALTIPO'), ''), '')::character varying;
    v_vendedor    := COALESCE(NULLIF(TRIM(p_pedido_json->>'Vendedor'), ''), '')::character varying;

    BEGIN
        v_fecha := (p_pedido_json->>'FECHA')::TIMESTAMP;
    EXCEPTION WHEN OTHERS THEN
        v_fecha := NOW() AT TIME ZONE 'UTC';
    END;

    v_total := COALESCE((p_pedido_json->>'TOTAL')::NUMERIC(18,4), 0);

    IF v_num_fact IS NULL OR TRIM(v_num_fact) = '' THEN
        RAISE EXCEPTION 'missing_num_pedido';
    END IF;

    -- Verificar que el pedido no existe (tabla legacy "Pedidos")
    IF EXISTS (SELECT 1 FROM "Pedidos" WHERE "NUM_FACT" = v_num_fact) THEN
        RAISE EXCEPTION 'pedido_already_exists';
    END IF;

    -- 1. Insertar cabecera en Pedidos (legacy)
    INSERT INTO "Pedidos" (
        "NUM_FACT", "SERIALTIPO", "CODIGO", "FECHA", "NOMBRE", "TOTAL",
        "COD_USUARIO", "ANULADA", "FECHA_REPORTE", "CANCELADA", "Vendedor"
    )
    VALUES (
        v_num_fact, v_serial_tipo, v_codigo, v_fecha, v_nombre, v_total,
        p_cod_usuario, 0, v_fecha, 'N', v_vendedor
    );

    -- 2. Insertar detalle en Detalle_Pedidos (legacy)
    INSERT INTO "Detalle_Pedidos" (
        "NUM_FACT", "SERIALTIPO", "COD_SERV", "DESCRIPCION", "FECHA", "CANTIDAD",
        "PRECIO", "TOTAL", "ANULADA", "Co_Usuario", "Alicuota", "PRECIO_DESCUENTO",
        "Relacionada", "RENGLON", "Vendedor", "Cod_alterno"
    )
    SELECT
        v_num_fact,
        COALESCE(NULLIF(TRIM(d->>'SERIALTIPO'), ''), v_serial_tipo)::character varying,
        NULLIF(TRIM(d->>'COD_SERV'), ''),
        NULLIF(TRIM(d->>'DESCRIPCION'), ''),
        v_fecha,
        COALESCE((d->>'CANTIDAD')::DOUBLE PRECISION, 0),
        COALESCE((d->>'PRECIO')::DOUBLE PRECISION, 0),
        COALESCE(
            (d->>'TOTAL')::DOUBLE PRECISION,
            COALESCE((d->>'PRECIO')::DOUBLE PRECISION, 0) * COALESCE((d->>'CANTIDAD')::DOUBLE PRECISION, 0)
        ),
        0,
        p_cod_usuario,
        COALESCE((d->>'Alicuota')::DOUBLE PRECISION, 0),
        COALESCE(
            (d->>'PRECIO_DESCUENTO')::DOUBLE PRECISION,
            COALESCE((d->>'PRECIO')::DOUBLE PRECISION, 0)
        ),
        COALESCE(NULLIF(TRIM(d->>'Relacionada'), ''), '0')::character varying,
        COALESCE((d->>'RENGLON')::DOUBLE PRECISION, 0),
        COALESCE(NULLIF(TRIM(d->>'Vendedor'), ''), v_vendedor)::character varying,
        NULLIF(TRIM(d->>'Cod_alterno'), '')
    FROM jsonb_array_elements(p_detalle_json) AS d;

    -- Contar filas de detalle
    SELECT COUNT(*) INTO v_detalle_rows FROM jsonb_array_elements(p_detalle_json);

    -- 3. Comprometer inventario en master."Product"
    IF p_actualizar_inventario THEN
        -- MovInvent (historial)
        INSERT INTO "MovInvent" (
            "DOCUMENTO", "CODIGO", "PRODUCT", "FECHA", "MOTIVO", "TIPO",
            "CANTIDAD_ACTUAL", "CANTIDAD", "CANTIDAD_NUEVA", "CO_USUARIO",
            "PRECIO_COMPRA", "ALICUOTA", "PRECIO_VENTA"
        )
        SELECT
            v_num_fact,
            NULLIF(TRIM(d->>'COD_SERV'), ''),
            NULLIF(TRIM(d->>'COD_SERV'), ''),
            v_fecha,
            'Pedido:' || v_num_fact,
            'Pedido',
            COALESCE(inv."StockQty", 0),
            COALESCE((d->>'CANTIDAD')::NUMERIC(18,4), 0),
            COALESCE(inv."StockQty", 0) - COALESCE((d->>'CANTIDAD')::NUMERIC(18,4), 0),
            p_cod_usuario,
            COALESCE(inv."COSTO_REFERENCIA", 0),
            COALESCE((d->>'ALICUOTA')::NUMERIC(18,4), 0),
            COALESCE((d->>'PRECIO')::NUMERIC(18,4), 0)
        FROM jsonb_array_elements(p_detalle_json) AS d
        INNER JOIN master."Product" inv ON inv."ProductCode" = NULLIF(TRIM(d->>'COD_SERV'), '')
        WHERE NULLIF(TRIM(d->>'COD_SERV'), '') IS NOT NULL
          AND COALESCE((d->>'CANTIDAD')::NUMERIC(18,4), 0) > 0;

        -- Descontar existencias en master."Product"."StockQty"
        UPDATE master."Product" AS p
           SET "StockQty" = COALESCE(p."StockQty", 0) - agg."Total"
          FROM (
              SELECT NULLIF(TRIM(d->>'COD_SERV'), '') AS cod_serv,
                     SUM(COALESCE((d->>'CANTIDAD')::NUMERIC(18,4), 0)) AS "Total"
                FROM jsonb_array_elements(p_detalle_json) AS d
               WHERE NULLIF(TRIM(d->>'COD_SERV'), '') IS NOT NULL
               GROUP BY NULLIF(TRIM(d->>'COD_SERV'), '')
          ) agg
         WHERE p."ProductCode" = agg.cod_serv;
    END IF;

    RETURN QUERY SELECT
        TRUE AS "ok",
        v_num_fact AS "numPedido",
        v_detalle_rows AS "detalleRows",
        p_actualizar_inventario AS "inventoryUpdated";

EXCEPTION WHEN OTHERS THEN
    RAISE EXCEPTION '%', SQLERRM;
END;
$function$
;

-- ============================================================
-- sp_emitir_presupuesto_tx
-- ============================================================
CREATE OR REPLACE FUNCTION public.sp_emitir_presupuesto_tx(p_presupuesto_json jsonb, p_detalle_json jsonb, p_formas_pago_json jsonb DEFAULT NULL::jsonb, p_actualizar_inventario boolean DEFAULT true, p_generar_cxc boolean DEFAULT true, p_actualizar_saldos_cliente boolean DEFAULT true)
 RETURNS TABLE(ok boolean, "numFact" character varying, "detalleRows" integer, "montoEfectivo" numeric, "montoCheque" numeric, "montoTarjeta" numeric, "saldoPendiente" numeric, abono numeric)
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_num_fact        VARCHAR(60);
    v_codigo          VARCHAR(60);
    v_pago            VARCHAR(30);
    v_cod_usuario     VARCHAR(60);
    v_serial_tipo     VARCHAR(60);
    v_tipo_orden      VARCHAR(80);
    v_observ          VARCHAR(4000);
    v_fecha           TIMESTAMP;
    v_fecha_reporte   TIMESTAMP;
    v_total           NUMERIC(18,4);
    v_default_company_id INT := 1;
    v_default_branch_id  INT := 1;
    v_customer_id     BIGINT;
    v_memoria         VARCHAR(80);
    v_monto_efectivo  NUMERIC(18,4) := 0;
    v_monto_cheque    NUMERIC(18,4) := 0;
    v_monto_tarjeta   NUMERIC(18,4) := 0;
    v_saldo_pendiente NUMERIC(18,4) := 0;
    v_num_tarjeta     VARCHAR(60) := '0';
    v_cta             VARCHAR(80) := ' ';
    v_banco_cheque    VARCHAR(120) := ' ';
    v_banco_tarjeta   VARCHAR(120) := ' ';
    v_abono           NUMERIC(18,4);
    v_cancelada       CHAR(1);
    v_detalle_rows    INT;
BEGIN
    -- Parsear cabecera (soporta nodos presupuesto y factura por compat)
    v_num_fact := COALESCE(NULLIF(TRIM(p_presupuesto_json->>'NUM_FACT'), ''), NULL)::character varying;
    v_codigo := NULLIF(TRIM(p_presupuesto_json->>'CODIGO'), '');
    v_pago := UPPER(COALESCE(NULLIF(TRIM(p_presupuesto_json->>'PAGO'), ''), '')::character varying)::character varying;
    v_cod_usuario := COALESCE(NULLIF(TRIM(p_presupuesto_json->>'COD_USUARIO'), ''), 'API')::character varying;
    v_serial_tipo := COALESCE(NULLIF(TRIM(p_presupuesto_json->>'SERIALTIPO'), ''), '')::character varying;
    v_tipo_orden := COALESCE(NULLIF(TRIM(p_presupuesto_json->>'TIPO_ORDEN'), ''),
                    COALESCE(NULLIF(TRIM(p_presupuesto_json->>'Tipo_orden'), ''), '1'))::character varying;
    v_observ := NULLIF(TRIM(p_presupuesto_json->>'OBSERV'), '');

    BEGIN
        v_fecha := (p_presupuesto_json->>'FECHA')::TIMESTAMP;
    EXCEPTION WHEN OTHERS THEN
        v_fecha := NOW() AT TIME ZONE 'UTC';
    END;

    BEGIN
        v_fecha_reporte := (p_presupuesto_json->>'FECHA_REPORTE')::TIMESTAMP;
    EXCEPTION WHEN OTHERS THEN
        v_fecha_reporte := v_fecha;
    END;

    v_total := COALESCE((p_presupuesto_json->>'TOTAL')::NUMERIC(18,4), 0);

    IF v_num_fact IS NULL OR TRIM(v_num_fact) = '' THEN
        RAISE EXCEPTION 'missing_num_fact';
    END IF;

    -- Resolver IDs canonicos
    SELECT "CompanyId" INTO v_default_company_id
      FROM cfg."Company" WHERE "CompanyCode" = 'DEFAULT' LIMIT 1;
    v_default_company_id := COALESCE(v_default_company_id, 1);

    SELECT "BranchId" INTO v_default_branch_id
      FROM cfg."Branch" WHERE "CompanyId" = v_default_company_id AND "BranchCode" = 'MAIN' LIMIT 1;
    v_default_branch_id := COALESCE(v_default_branch_id, 1);

    IF v_codigo IS NOT NULL THEN
        SELECT "CustomerId" INTO v_customer_id
          FROM master."Customer"
         WHERE "CustomerCode" = v_codigo AND COALESCE("IsDeleted", FALSE) = FALSE
         LIMIT 1;
    END IF;

    -- 1. Cabecera -> ar."SalesDocument" (OperationType='PRESUP')
    INSERT INTO ar."SalesDocument" (
        "DocumentNumber", "SerialType", "FiscalMemoryNumber", "OperationType",
        "CustomerCode", "DocumentDate", "ReportDate", "PaymentTerms",
        "TotalAmount", "UserCode", "Notes"
    )
    VALUES (
        v_num_fact, v_serial_tipo, v_tipo_orden, 'PRESUP',
        v_codigo, v_fecha, v_fecha_reporte, v_pago,
        v_total, v_cod_usuario, v_observ
    );

    -- 2. Detalle -> ar."SalesDocumentLine"
    INSERT INTO ar."SalesDocumentLine" (
        "DocumentNumber", "SerialType", "FiscalMemoryNumber", "OperationType",
        "ProductCode", "Quantity", "UnitPrice", "TaxRate", "TotalAmount",
        "DiscountedPrice", "RelatedRef", "AlternateCode"
    )
    SELECT
        COALESCE(NULLIF(TRIM(d->>'NUM_FACT'), ''), v_num_fact)::character varying,
        COALESCE(NULLIF(TRIM(d->>'SERIALTIPO'), ''), v_serial_tipo)::character varying,
        v_tipo_orden, 'PRESUP',
        NULLIF(TRIM(d->>'COD_SERV'), ''),
        COALESCE((d->>'CANTIDAD')::NUMERIC(18,4), 0),
        COALESCE((d->>'PRECIO')::NUMERIC(18,4), 0),
        COALESCE((d->>'ALICUOTA')::NUMERIC(18,4), 0),
        COALESCE(
            (d->>'TOTAL')::NUMERIC(18,4),
            COALESCE((d->>'PRECIO')::NUMERIC(18,4), 0) * COALESCE((d->>'CANTIDAD')::NUMERIC(18,4), 0)
        ),
        COALESCE(
            (d->>'PRECIO_DESCUENTO')::NUMERIC(18,4),
            COALESCE((d->>'PRECIO')::NUMERIC(18,4), 0)
        ),
        COALESCE(NULLIF(TRIM(d->>'RELACIONADA'), ''), '0')::character varying,
        NULLIF(TRIM(d->>'COD_ALTERNO'), '')
    FROM jsonb_array_elements(p_detalle_json) AS d;

    SELECT COUNT(*) INTO v_detalle_rows FROM jsonb_array_elements(p_detalle_json);

    -- 3. Formas de pago
    v_memoria := v_tipo_orden;

    IF p_formas_pago_json IS NOT NULL THEN
        DELETE FROM ar."SalesDocumentPayment"
         WHERE "DocumentNumber" = v_num_fact
           AND "FiscalMemoryNumber" = v_memoria
           AND "SerialType" = v_serial_tipo
           AND "OperationType" = 'PRESUP';

        INSERT INTO ar."SalesDocumentPayment" (
            "ExchangeRate", "PaymentMethod", "DocumentNumber", "Amount",
            "BankCode", "ReferenceNumber", "PaymentDate", "PaymentNumber",
            "FiscalMemoryNumber", "SerialType", "OperationType"
        )
        SELECT
            COALESCE((fp->>'tasacambio')::NUMERIC(18,6), 1),
            NULLIF(TRIM(fp->>'tipo'), ''),
            v_num_fact,
            COALESCE((fp->>'monto')::NUMERIC(18,4), 0),
            COALESCE(NULLIF(TRIM(fp->>'banco'), ''), ' ')::character varying,
            COALESCE(NULLIF(TRIM(fp->>'cuenta'), ''), ' ')::character varying,
            v_fecha,
            COALESCE(NULLIF(TRIM(fp->>'numero'), ''), '0')::character varying,
            v_memoria, v_serial_tipo, 'PRESUP'
        FROM jsonb_array_elements(p_formas_pago_json) AS fp;

        SELECT
            COALESCE(SUM(CASE WHEN UPPER(COALESCE(fp->>'tipo',''))::character varying = 'EFECTIVO' THEN COALESCE((fp->>'monto')::NUMERIC(18,4), 0) ELSE 0 END), 0),
            COALESCE(SUM(CASE WHEN UPPER(COALESCE(fp->>'tipo',''))::character varying = 'CHEQUE' THEN COALESCE((fp->>'monto')::NUMERIC(18,4), 0) ELSE 0 END), 0),
            COALESCE(SUM(CASE WHEN UPPER(COALESCE(fp->>'tipo',''))::character varying LIKE 'TARJETA%' OR UPPER(COALESCE(fp->>'tipo',''))::character varying LIKE 'TICKET%' THEN COALESCE((fp->>'monto')::NUMERIC(18,4), 0) ELSE 0 END), 0),
            COALESCE(SUM(CASE WHEN UPPER(COALESCE(fp->>'tipo',''))::character varying = 'SALDO PENDIENTE' THEN COALESCE((fp->>'monto')::NUMERIC(18,4), 0) ELSE 0 END), 0)
        INTO v_monto_efectivo, v_monto_cheque, v_monto_tarjeta, v_saldo_pendiente
        FROM jsonb_array_elements(p_formas_pago_json) AS fp;

        -- Depositos cheque
        INSERT INTO acct."BankDeposit" ("Amount", "CheckNumber", "BankAccount", "CustomerCode", "IsRelated", "BankName", "DocumentRef", "OperationType")
        SELECT
            COALESCE((fp->>'monto')::NUMERIC(18,4), 0),
            COALESCE(NULLIF(TRIM(fp->>'numero'), ''), '0')::character varying,
            COALESCE(NULLIF(TRIM(fp->>'cuenta'), ''), ' ')::character varying,
            v_codigo, FALSE,
            COALESCE(NULLIF(TRIM(fp->>'banco'), ''), ' ')::character varying,
            v_num_fact, 'PRESUP'
        FROM jsonb_array_elements(p_formas_pago_json) AS fp
        WHERE UPPER(COALESCE(fp->>'tipo', ''))::character varying = 'CHEQUE';
    END IF;

    v_abono := v_total - v_saldo_pendiente;
    v_cancelada := CASE WHEN v_saldo_pendiente > 0 THEN 'N' ELSE 'S' END;

    UPDATE ar."SalesDocument"
       SET "IsPaid" = v_cancelada,
           "ReportDate" = v_fecha_reporte,
           "UpdatedAt" = NOW() AT TIME ZONE 'UTC'
     WHERE "DocumentNumber" = v_num_fact AND "OperationType" = 'PRESUP';

    -- 4. CxC
    IF p_generar_cxc AND v_customer_id IS NOT NULL AND (v_pago = 'CREDITO' OR v_saldo_pendiente > 0) THEN
        DELETE FROM ar."ReceivableDocument"
         WHERE "CompanyId" = v_default_company_id AND "BranchId" = v_default_branch_id
           AND "DocumentType" = 'PRESUP' AND "DocumentNumber" = v_num_fact;

        INSERT INTO ar."ReceivableDocument" (
            "CompanyId", "BranchId", "CustomerId", "DocumentType", "DocumentNumber",
            "IssueDate", "CurrencyCode", "TotalAmount", "PendingAmount", "PaidFlag", "Status"
        )
        VALUES (
            v_default_company_id, v_default_branch_id, v_customer_id, 'PRESUP', v_num_fact,
            v_fecha::DATE, 'VES', v_saldo_pendiente, v_saldo_pendiente, 0, 'PENDING'
        );
    END IF;

    -- 5. Inventario
    IF p_actualizar_inventario THEN
        INSERT INTO master."InventoryMovement" ("CompanyId", "ProductCode", "DocumentRef", "MovementType", "MovementDate", "Quantity", "UnitCost", "TotalCost", "Notes")
        SELECT v_default_company_id, NULLIF(TRIM(d->>'COD_SERV'), ''), v_num_fact, 'SALIDA', v_fecha::DATE,
            COALESCE((d->>'CANTIDAD')::NUMERIC(18,4), 0),
            COALESCE(i."COSTO_REFERENCIA", 0),
            COALESCE((d->>'CANTIDAD')::NUMERIC(18,4), 0) * COALESCE(i."COSTO_REFERENCIA", 0),
            'Presup:' || v_num_fact
        FROM jsonb_array_elements(p_detalle_json) AS d
        INNER JOIN master."Product" i ON i."ProductCode" = NULLIF(TRIM(d->>'COD_SERV'), '')
        WHERE NULLIF(TRIM(d->>'COD_SERV'), '') IS NOT NULL AND COALESCE((d->>'CANTIDAD')::NUMERIC(18,4), 0) > 0;

        UPDATE master."Product" AS p
           SET "StockQty" = COALESCE(p."StockQty", 0) - agg."Total"
          FROM (
              SELECT NULLIF(TRIM(d->>'COD_SERV'), '') AS cod_serv, SUM(COALESCE((d->>'CANTIDAD')::NUMERIC(18,4), 0)) AS "Total"
                FROM jsonb_array_elements(p_detalle_json) AS d
               GROUP BY NULLIF(TRIM(d->>'COD_SERV'), '')
          ) agg
         WHERE p."ProductCode" = agg.cod_serv;

        UPDATE master."AlternateStock" AS a
           SET "StockQty" = COALESCE(a."StockQty", 0) - agg."Total"
          FROM (
              SELECT NULLIF(TRIM(d->>'COD_ALTERNO'), '') AS cod_alterno, SUM(COALESCE((d->>'CANTIDAD')::NUMERIC(18,4), 0)) AS "Total"
                FROM jsonb_array_elements(p_detalle_json) AS d
               WHERE COALESCE((d->>'RELACIONADA')::INT, 0) = 1
               GROUP BY NULLIF(TRIM(d->>'COD_ALTERNO'), '')
          ) agg
         WHERE a."ProductCode" = agg.cod_alterno;
    END IF;

    -- 6. Saldos
    IF p_actualizar_saldos_cliente AND v_customer_id IS NOT NULL THEN
        UPDATE master."Customer"
           SET "TotalBalance" = COALESCE((
               SELECT SUM("PendingAmount") FROM ar."ReceivableDocument"
                WHERE "CustomerId" = v_customer_id AND "Status" <> 'VOIDED' AND "PaidFlag" = 0
           ), 0)
         WHERE "CustomerId" = v_customer_id AND COALESCE("IsDeleted", FALSE) = FALSE;
    END IF;

    RETURN QUERY SELECT
        TRUE AS "ok",
        v_num_fact AS "numFact",
        v_detalle_rows AS "detalleRows",
        v_monto_efectivo AS "montoEfectivo",
        v_monto_cheque AS "montoCheque",
        v_monto_tarjeta AS "montoTarjeta",
        v_saldo_pendiente AS "saldoPendiente",
        v_abono AS "abono";

EXCEPTION WHEN OTHERS THEN
    RAISE EXCEPTION '%', SQLERRM;
END;
$function$
;

-- ============================================================
-- sp_generar_ajuste_bancario
-- ============================================================
CREATE OR REPLACE FUNCTION public.sp_generar_ajuste_bancario(p_conciliacion_id integer, p_tipo_ajuste character varying, p_monto numeric, p_descripcion character varying, p_co_usuario character varying DEFAULT 'API'::character varying)
 RETURNS TABLE(ok boolean, mensaje character varying)
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_nro_cta   VARCHAR(20);
    v_tipo_mov  VARCHAR(10);
    v_debito    NUMERIC(18,2) := 0;
    v_credito   NUMERIC(18,2) := 0;
BEGIN
    SELECT "Nro_Cta" INTO v_nro_cta
    FROM "ConciliacionBancaria"
    WHERE "ID" = p_conciliacion_id;

    IF v_nro_cta IS NULL THEN
        RAISE EXCEPTION 'conciliacion_no_existe';
    END IF;

    -- Determinar tipo
    IF p_tipo_ajuste = 'NOTA_CREDITO' THEN
        v_tipo_mov := 'NCR';
        v_credito  := p_monto;
    ELSIF p_tipo_ajuste = 'NOTA_DEBITO' THEN
        v_tipo_mov := 'NDB';
        v_debito   := p_monto;
    ELSE
        RAISE EXCEPTION 'tipo_ajuste_invalido';
    END IF;

    -- Generar movimiento bancario
    PERFORM sp_generar_movimiento_bancario(
        p_nro_cta               := v_nro_cta,
        p_tipo                  := v_tipo_mov,
        p_nro_ref               := 'AJUSTE-' || p_conciliacion_id::TEXT,
        p_beneficiario          := 'AJUSTE CONCILIACION',
        p_monto                 := p_monto,
        p_concepto              := p_descripcion,
        p_co_usuario            := p_co_usuario
    );

    -- Insertar en detalle de conciliacion como ajuste
    INSERT INTO "ConciliacionDetalle" (
        "Conciliacion_ID", "Tipo_Origen", "Fecha", "Descripcion",
        "Referencia", "Debito", "Credito", "Conciliado", "Tipo_Ajuste", "Co_Usuario"
    )
    VALUES (
        p_conciliacion_id, 'AJUSTE', NOW() AT TIME ZONE 'UTC', p_descripcion,
        'AJUSTE-' || p_conciliacion_id::TEXT, v_debito, v_credito, TRUE, p_tipo_ajuste, p_co_usuario
    );

    RETURN QUERY SELECT TRUE, 'Ajuste generado'::VARCHAR;
END;
$function$
;

-- ============================================================
-- sp_generar_movimiento_bancario
-- ============================================================
CREATE OR REPLACE FUNCTION public.sp_generar_movimiento_bancario(p_nro_cta character varying, p_tipo character varying, p_nro_ref character varying, p_beneficiario character varying, p_monto numeric, p_concepto character varying, p_categoria character varying DEFAULT NULL::character varying, p_co_usuario character varying DEFAULT 'API'::character varying, p_documento_relacionado character varying DEFAULT NULL::character varying, p_tipo_doc_rel character varying DEFAULT NULL::character varying)
 RETURNS TABLE(ok boolean, "movimientoId" integer, "saldoNuevo" numeric)
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_gastos       NUMERIC(18,2) := 0;
    v_ingresos     NUMERIC(18,2) := 0;
    v_saldo_actual NUMERIC(18,2);
    v_mov_id       INT;
    v_debe         NUMERIC(18,2);
    v_haber        NUMERIC(18,2);
    v_banco        VARCHAR(100);
BEGIN
    -- Validar cuenta existe
    IF NOT EXISTS (SELECT 1 FROM "CuentasBank" WHERE "Nro_Cta" = p_nro_cta) THEN
        RAISE EXCEPTION 'cuenta_bancaria_no_existe';
    END IF;

    -- Determinar si es gasto o ingreso segun tipo
    -- PCH (cheque), NDB (nota debito) = Gasto
    -- DEP (deposito), NCR (nota credito) = Ingreso
    IF p_tipo IN ('PCH', 'NDB', 'IDB') THEN
        v_gastos := p_monto;
    ELSIF p_tipo IN ('DEP', 'NCR') THEN
        v_ingresos := p_monto;
    END IF;

    -- Obtener saldo actual
    SELECT COALESCE("Saldo", 0) INTO v_saldo_actual
    FROM "CuentasBank"
    WHERE "Nro_Cta" = p_nro_cta;

    -- Calcular nuevo saldo
    v_saldo_actual := v_saldo_actual + v_ingresos - v_gastos;

    -- Insertar en MovCuentas
    INSERT INTO "MovCuentas" (
        "Nro_Cta", "Fecha", "Tipo", "Nro_Ref", "Beneficiario", "Categoria",
        "Gastos", "Ingresos", "Saldo_Dia", "Saldo", "Confirmada",
        "Co_Usuario", "Concepto", "Fecha_Banco"
    )
    VALUES (
        p_nro_cta, NOW() AT TIME ZONE 'UTC', p_tipo, p_nro_ref, p_beneficiario, p_categoria,
        v_gastos, v_ingresos, v_saldo_actual, v_saldo_actual, FALSE,
        p_co_usuario, p_concepto, NULL
    )
    RETURNING "id" INTO v_mov_id;

    -- Actualizar saldo en CuentasBank
    UPDATE "CuentasBank" SET
        "Saldo" = v_saldo_actual,
        "Saldo_Disponible" = v_saldo_actual
    WHERE "Nro_Cta" = p_nro_cta;

    -- Si hay documento relacionado, insertar en Movimiento_Cuenta para control contable
    IF p_documento_relacionado IS NOT NULL THEN
        v_debe  := CASE WHEN v_gastos > 0 THEN v_gastos ELSE 0 END;
        v_haber := CASE WHEN v_ingresos > 0 THEN v_ingresos ELSE 0 END;

        SELECT "Banco" INTO v_banco FROM "CuentasBank" WHERE "Nro_Cta" = p_nro_cta;

        INSERT INTO "Movimiento_Cuenta" (
            "COD_CUENTA", "COD_OPER", "FECHA", "DEBE", "HABER",
            "COD_USUARIO", "DESCRIPCION", "CONCEPTO", "Banco", "Cheque"
        )
        VALUES (
            p_nro_cta, p_tipo_doc_rel, NOW() AT TIME ZONE 'UTC', v_debe, v_haber,
            p_co_usuario, p_concepto, p_documento_relacionado, v_banco, p_nro_ref
        );
    END IF;

    RETURN QUERY SELECT TRUE, v_mov_id, v_saldo_actual;
END;
$function$
;

-- ============================================================
-- sp_get_movimiento_bancario_by_id
-- ============================================================
CREATE OR REPLACE FUNCTION public.sp_get_movimiento_bancario_by_id(p_movimiento_id integer)
 RETURNS TABLE(id integer, "BankAccountId" integer, "Fecha" timestamp without time zone, "Tipo" character varying, "MovementSign" character varying, "Monto" numeric, "NetAmount" numeric, "Nro_Ref" character varying, "Beneficiario" character varying, "Concepto" character varying, "Categoria" character varying, "Documento_Relacionado" character varying, "Tipo_Doc_Rel" character varying, "Saldo" numeric, "IsReconciled" boolean, "CreatedAt" timestamp without time zone, "Nro_Cta" character varying, "CuentaDescripcion" character varying, "SaldoActual" numeric, "BancoNombre" character varying)
 LANGUAGE plpgsql
AS $function$
BEGIN
    RETURN QUERY
    SELECT
        m."BankMovementId",
        m."BankAccountId",
        m."MovementDate",
        m."MovementType",
        m."MovementSign",
        m."Amount",
        m."NetAmount",
        m."ReferenceNo",
        m."Beneficiary",
        m."Concept",
        m."CategoryCode",
        m."RelatedDocumentNo",
        m."RelatedDocumentType",
        m."BalanceAfter",
        m."IsReconciled",
        m."CreatedAt",
        a."AccountNumber",
        a."AccountName",
        a."Balance",
        b."BankName"
    FROM fin."BankMovement" m
    INNER JOIN fin."BankAccount" a ON a."BankAccountId" = m."BankAccountId"
    LEFT JOIN fin."Bank" b ON b."BankId" = a."BankId"
    WHERE m."BankMovementId" = p_movimiento_id;
END;
$function$
;

-- ============================================================
-- sp_importar_extracto
-- ============================================================
CREATE OR REPLACE FUNCTION public.sp_importar_extracto(p_extracto_json jsonb, p_nro_cta character varying, p_co_usuario character varying DEFAULT 'API'::character varying)
 RETURNS TABLE(ok boolean, "registrosImportados" integer)
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_count INT := 0;
BEGIN
    INSERT INTO "ExtractoBancario" (
        "Nro_Cta", "Fecha", "Descripcion", "Referencia", "Tipo", "Monto", "Saldo", "Conciliado", "Co_Usuario"
    )
    SELECT
        p_nro_cta,
        CASE WHEN (elem->>'Fecha') IS NOT NULL
             THEN (elem->>'Fecha')::TIMESTAMP
             ELSE NOW() AT TIME ZONE 'UTC' END,
        NULLIF(elem->>'Descripcion', ''::character varying),
        NULLIF(elem->>'Referencia', ''::character varying),
        NULLIF(elem->>'Tipo', ''::character varying),                -- DEBITO/CREDITO
        CASE WHEN (elem->>'Monto') IS NOT NULL
             THEN (elem->>'Monto')::NUMERIC(18,2)
             ELSE 0 END,
        CASE WHEN (elem->>'Saldo') IS NOT NULL
             THEN (elem->>'Saldo')::NUMERIC(18,2)
             ELSE NULL END,
        FALSE,  -- No conciliado
        p_co_usuario
    FROM jsonb_array_elements(p_extracto_json) AS elem;

    GET DIAGNOSTICS v_count = ROW_COUNT;

    RETURN QUERY SELECT TRUE, v_count;
END;
$function$
;

-- ============================================================
-- sp_movunidades
-- ============================================================
CREATE OR REPLACE FUNCTION public.sp_movunidades(p_periodo character varying DEFAULT NULL::character varying, p_fecha_desde date DEFAULT NULL::date, p_fecha_hasta date DEFAULT NULL::date, p_solo_estructura boolean DEFAULT false)
 RETURNS TABLE("FilasInsertadas" integer, "Periodo" character varying)
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_ini            DATE;
    v_fin            DATE;
    v_ini_dt         TIMESTAMP;
    v_fin_dt         TIMESTAMP;
    v_periodo        VARCHAR(10);
    v_mes            INT;
    v_anio           INT;
    v_inv_inicial    DOUBLE PRECISION;
    v_filas          INT;
BEGIN
    v_periodo := p_periodo;

    IF p_periodo IS NOT NULL THEN
        v_mes    := CAST(LEFT(p_periodo, 2) AS INT);
        v_anio   := CAST(RIGHT(p_periodo, 4) AS INT);
        v_ini    := make_date(v_anio, v_mes, 1);
        v_fin    := (v_ini + INTERVAL '1 month - 1 day')::DATE;
        v_ini_dt := v_ini::TIMESTAMP;
        v_fin_dt := (v_fin + INTERVAL '1 day')::TIMESTAMP;
    ELSIF p_fecha_desde IS NOT NULL AND p_fecha_hasta IS NOT NULL THEN
        v_ini     := p_fecha_desde;
        v_fin     := p_fecha_hasta;
        v_periodo := TO_CHAR(v_ini, 'MM/YYYY');
        v_ini_dt  := v_ini::TIMESTAMP;
        v_fin_dt  := (v_fin + INTERVAL '1 day')::TIMESTAMP;
    ELSE
        RAISE EXCEPTION 'Especificar p_periodo (MM/YYYY) o p_fecha_desde y p_fecha_hasta.';
    END IF;

    -- Eliminar datos del periodo en MovInventMes para refrescar
    DELETE FROM public."MovInventMes" WHERE "Periodo" = v_periodo;

    IF p_solo_estructura THEN
        RETURN QUERY SELECT 0, v_periodo;
        RETURN;
    END IF;

    -- Clasificacion: 1=Entradas, 2=Salidas, 3=AutoConsumo, 4=Retiros
    WITH "MovClasificado" AS (
        SELECT
            m."Fecha"::DATE                      AS "FechaDia",
            COALESCE(m."Codigo", m."Product")    AS "Codigo",
            m."Cantidad",
            COALESCE(m."Precio_Compra", 0)       AS "CostoUnit",
            m."Cantidad" * COALESCE(m."Precio_Compra", 0) AS "Monto",
            CASE
                WHEN UPPER(TRIM(COALESCE(m."Tipo", '')))::character varying = 'INGRESO' THEN 1
                WHEN UPPER(TRIM(COALESCE(m."Tipo", '')))::character varying = 'EGRESO' THEN
                    CASE
                        WHEN m."Motivo" ILIKE '%Autoconsumo%' THEN 3
                        WHEN m."Motivo" ILIKE '%FACT%'
                             OR m."Motivo" ILIKE '%Doc:%'
                             OR m."Motivo" ILIKE '%PEDIDO%'
                             OR m."Motivo" ILIKE '%NOTA_ENTREGA%'
                             OR m."Motivo" ILIKE '%Presup%'
                             OR m."Motivo" ILIKE '%Factura%'
                             OR m."Motivo" ILIKE '%Pedido%' THEN 2
                        ELSE 4
                    END
                WHEN UPPER(TRIM(COALESCE(m."Tipo", '')))::character varying LIKE '%ANULACION%INGRESO%' THEN 1
                WHEN UPPER(TRIM(COALESCE(m."Tipo", '')))::character varying LIKE '%ANULACION%EGRESO%' THEN 1
                ELSE 4
            END AS "Clase"
        FROM public."MovInvent" m
        WHERE m."Fecha" >= v_ini_dt AND m."Fecha" < v_fin_dt
          AND COALESCE(m."Anulada", 0) = 0
          AND (
              (m."Codigo" IS NOT NULL AND TRIM(m."Codigo") <> '')
              OR (m."Product" IS NOT NULL AND TRIM(m."Product") <> '')
          )
    ),
    "AgregadoDia" AS (
        SELECT
            "FechaDia",
            "Codigo",
            SUM(CASE WHEN "Clase" = 1 THEN "Cantidad" ELSE 0 END) AS "EntradasCant",
            SUM(CASE WHEN "Clase" = 1 THEN "Monto"    ELSE 0 END) AS "EntradasMonto",
            SUM(CASE WHEN "Clase" = 2 THEN "Cantidad" ELSE 0 END) AS "SalidasCant",
            SUM(CASE WHEN "Clase" = 2 THEN "Monto"    ELSE 0 END) AS "SalidasMonto",
            SUM(CASE WHEN "Clase" = 3 THEN "Cantidad" ELSE 0 END) AS "AutoConsumoCant",
            SUM(CASE WHEN "Clase" = 3 THEN "Monto"    ELSE 0 END) AS "AutoConsumoMonto",
            SUM(CASE WHEN "Clase" = 4 THEN "Cantidad" ELSE 0 END) AS "RetirosCant",
            SUM(CASE WHEN "Clase" = 4 THEN "Monto"    ELSE 0 END) AS "RetirosMonto"
        FROM "MovClasificado"
        GROUP BY "FechaDia", "Codigo"
    ),
    -- Inventario inicial: (1) CierreMensualInventario mes anterior (2) MovInvent ultimo antes del periodo (3) Inventario
    "PeriodoAnterior" AS (
        SELECT TO_CHAR(v_ini - INTERVAL '1 month', 'MM/YYYY') AS "Periodo"
    ),
    "InicialDesdeCierre" AS (
        SELECT c."Codigo", c."CantidadFinal" AS "InicialCant", c."CostoUnitario" AS "CostoUnit"
        FROM public."CierreMensualInventario" c
        INNER JOIN "PeriodoAnterior" p ON p."Periodo" = c."Periodo"
        WHERE c."CantidadFinal" <> 0
    ),
    "InicialMes" AS (
        SELECT
            COALESCE(m."Codigo", m."Product") AS "Codigo",
            m."cantidad_nueva"                AS "InicialCant",
            COALESCE(m."Precio_Compra", 0)    AS "CostoUnit",
            ROW_NUMBER() OVER (
                PARTITION BY COALESCE(m."Codigo", m."Product")
                ORDER BY m."Fecha" DESC, m."id" DESC
            ) AS rn
        FROM public."MovInvent" m
        WHERE m."Fecha" < v_ini_dt
          AND COALESCE(m."Anulada", 0) = 0
          AND (
              (m."Codigo" IS NOT NULL AND TRIM(m."Codigo") <> '')
              OR (m."Product" IS NOT NULL AND TRIM(m."Product") <> '')
          )
    ),
    "InicialDesdeMov" AS (
        SELECT "Codigo", "InicialCant", "CostoUnit"
        FROM "InicialMes"
        WHERE rn = 1 AND "InicialCant" <> 0
          AND NOT EXISTS (SELECT 1 FROM "InicialDesdeCierre" c WHERE c."Codigo" = "InicialMes"."Codigo")
    ),
    "InicialDesdeInventario" AS (
        SELECT
            i."ProductCode"                                       AS "Codigo",
            COALESCE(i."StockQty", 0)                             AS "InicialCant",
            COALESCE(i."COSTO_REFERENCIA", i."COSTO_PROMEDIO")    AS "CostoUnit"
        FROM master."Product" i
        WHERE COALESCE(i."IsDeleted", FALSE) = FALSE
          AND COALESCE(i."StockQty", 0) > 0
          AND i."ProductCode" IS NOT NULL AND TRIM(i."ProductCode") <> ''
          AND NOT EXISTS (SELECT 1 FROM "InicialDesdeCierre" c WHERE c."Codigo" = i."ProductCode")
          AND NOT EXISTS (SELECT 1 FROM "InicialDesdeMov" m2 WHERE m2."Codigo" = i."ProductCode")
    ),
    "InicialPorProducto" AS (
        SELECT "Codigo", "InicialCant", "CostoUnit" FROM "InicialDesdeCierre"
        UNION ALL
        SELECT "Codigo", "InicialCant", "CostoUnit" FROM "InicialDesdeMov"
        UNION ALL
        SELECT "Codigo", "InicialCant", "CostoUnit" FROM "InicialDesdeInventario"
    ),
    "DiasProducto" AS (
        SELECT "FechaDia", "Codigo" FROM "AgregadoDia"
        UNION
        SELECT v_ini, "Codigo" FROM "InicialPorProducto"
    ),
    "ConInicial" AS (
        SELECT
            d."FechaDia",
            d."Codigo",
            COALESCE(i."InicialCant", 0) AS "InicialCantMes",
            COALESCE(i."CostoUnit", 0)   AS "CostoInicial",
            a."EntradasCant", a."EntradasMonto", a."SalidasCant", a."SalidasMonto",
            a."AutoConsumoCant", a."AutoConsumoMonto", a."RetirosCant", a."RetirosMonto"
        FROM "DiasProducto" d
        LEFT JOIN "InicialPorProducto" i ON i."Codigo" = d."Codigo"
        LEFT JOIN "AgregadoDia" a ON a."FechaDia" = d."FechaDia" AND a."Codigo" = d."Codigo"
    ),
    "ConAcum" AS (
        SELECT
            "FechaDia", "Codigo", "InicialCantMes", "CostoInicial",
            "EntradasCant", "EntradasMonto", "SalidasCant", "SalidasMonto",
            "AutoConsumoCant", "AutoConsumoMonto", "RetirosCant", "RetirosMonto",
            SUM(
                COALESCE("EntradasCant", 0) - COALESCE("SalidasCant", 0)
                - COALESCE("AutoConsumoCant", 0) - COALESCE("RetirosCant", 0)
            ) OVER (PARTITION BY "Codigo" ORDER BY "FechaDia" ROWS UNBOUNDED PRECEDING) AS "Acumulado"
        FROM "ConInicial"
    ),
    "ConSaldo" AS (
        SELECT
            "FechaDia", "Codigo", "InicialCantMes", "CostoInicial",
            "EntradasCant", "EntradasMonto", "SalidasCant", "SalidasMonto",
            "AutoConsumoCant", "AutoConsumoMonto", "RetirosCant", "RetirosMonto",
            "InicialCantMes" + "Acumulado" - (
                COALESCE("EntradasCant", 0) - COALESCE("SalidasCant", 0)
                - COALESCE("AutoConsumoCant", 0) - COALESCE("RetirosCant", 0)
            ) AS "InicialDelDia",
            "InicialCantMes" + "Acumulado" AS "FinalDelDia"
        FROM "ConAcum"
    )
    INSERT INTO public."MovInventMes"
        ("Periodo", "Codigo", "Descripcion", "Costo", "Inicial", "Entradas", "Salidas",
         "AutoConsumo", "Retiros", "Inventario", "Final", "fecha")
    SELECT
        v_periodo,
        s."Codigo",
        COALESCE(inv."ProductName", s."Codigo"),
        COALESCE(s."CostoInicial", 0),
        s."InicialDelDia",
        COALESCE(s."EntradasCant", 0),
        COALESCE(s."SalidasCant", 0),
        COALESCE(s."AutoConsumoCant", 0),
        COALESCE(s."RetirosCant", 0),
        s."FinalDelDia" * COALESCE(s."CostoInicial", 0),
        s."FinalDelDia",
        s."FechaDia"
    FROM "ConSaldo" s
    LEFT JOIN master."Product" inv ON inv."ProductCode" = s."Codigo"
    WHERE COALESCE(inv."IsDeleted", FALSE) = FALSE OR inv."ProductCode" IS NULL;

    -- Fila resumen INVENTARIO INICIAL MES ANTERIOR
    SELECT SUM("Inicial" * "Costo") INTO v_inv_inicial
    FROM public."MovInventMes"
    WHERE "Periodo" = v_periodo AND "fecha" = v_ini AND "Codigo" <> '0000000001';

    INSERT INTO public."MovInventMes"
        ("Periodo", "Codigo", "Descripcion", "Costo", "Inicial", "Entradas", "Salidas",
         "AutoConsumo", "Retiros", "Inventario", "Final", "AjusteIncial", "AjusteFinal", "fecha")
    VALUES (
        v_periodo,
        '0000000001',
        'INVENTARIO INICIAL MES ANTERIOR',
        COALESCE(v_inv_inicial, 0),
        1,
        0, 0, 0, 0,
        COALESCE(v_inv_inicial, 0),
        1,
        NULL, NULL,
        v_ini
    );

    GET DIAGNOSTICS v_filas = ROW_COUNT;

    RETURN QUERY SELECT v_filas, v_periodo;
END;
$function$
;

-- ============================================================
-- sp_movunidadesmes
-- ============================================================
CREATE OR REPLACE FUNCTION public.sp_movunidadesmes(p_periodo character varying, p_cerrar_mes_anterior boolean DEFAULT true, p_refrescar_siguiente boolean DEFAULT false)
 RETURNS TABLE("FilasInsertadas" integer, "Periodo" character varying)
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_mes           INT;
    v_anio          INT;
    v_prev_date     DATE;
    v_prev_periodo  VARCHAR(10);
    v_next_periodo  VARCHAR(10);
    v_result        RECORD;
BEGIN
    IF p_periodo IS NULL OR TRIM(p_periodo) = '' THEN
        RAISE EXCEPTION 'p_periodo es requerido (formato MM/YYYY).';
    END IF;

    v_mes  := CAST(LEFT(p_periodo, 2) AS INT);
    v_anio := CAST(RIGHT(p_periodo, 4) AS INT);

    -- Cerrar mes anterior si se solicita
    IF p_cerrar_mes_anterior THEN
        v_prev_date   := make_date(v_anio, v_mes, 1) - INTERVAL '1 month';
        v_prev_periodo := TO_CHAR(v_prev_date, 'MM/YYYY');

        PERFORM public.sp_CerrarMesInventario(v_prev_periodo);
    END IF;

    -- Ejecutar sp_MovUnidades para el periodo solicitado
    RETURN QUERY SELECT * FROM public.sp_MovUnidades(p_periodo);

    -- Refrescar el mes siguiente si se solicita
    IF p_refrescar_siguiente THEN
        v_next_periodo := TO_CHAR(make_date(v_anio, v_mes, 1) + INTERVAL '1 month', 'MM/YYYY');

        PERFORM public.sp_MovUnidades(v_next_periodo);
    END IF;
END;
$function$
;

-- ============================================================
-- sp_nomina_calcular_antiguedad
-- ============================================================
CREATE OR REPLACE FUNCTION public.sp_nomina_calcular_antiguedad(p_session_id character varying, p_cedula character varying, p_fecha_calculo date DEFAULT NULL::date)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_company_id INT;
  v_branch_id INT;
  v_fecha_ingreso DATE;
  v_dias INT := 0;
  v_anios INT := 0;
  v_meses INT := 0;
  v_total_meses INT := 0;
  v_fecha_calc DATE;
BEGIN
  v_fecha_calc := COALESCE(p_fecha_calculo, (NOW() AT TIME ZONE 'UTC')::DATE);

  SELECT * INTO v_company_id, v_branch_id FROM sp_nomina_get_scope();

  SELECT e."HireDate" INTO v_fecha_ingreso
  FROM master."Employee" e
  WHERE e."CompanyId" = v_company_id
    AND e."EmployeeCode" = p_cedula
    AND e."IsDeleted" = FALSE
  LIMIT 1;

  IF v_fecha_ingreso IS NOT NULL THEN
    v_dias := v_fecha_calc - v_fecha_ingreso;
    v_anios := v_dias / 365;
    v_meses := (v_dias % 365) / 30;
    v_total_meses := EXTRACT(YEAR FROM AGE(v_fecha_calc, v_fecha_ingreso)) * 12
                   + EXTRACT(MONTH FROM AGE(v_fecha_calc, v_fecha_ingreso));
  END IF;

  PERFORM sp_nomina_set_variable(p_session_id, 'ANTI_ANIOS', v_anios, 'Anios de antiguedad');
  PERFORM sp_nomina_set_variable(p_session_id, 'ANTI_MESES', v_meses, 'Meses de antiguedad');
  PERFORM sp_nomina_set_variable(p_session_id, 'ANTI_DIAS', v_dias, 'Dias de antiguedad');
  PERFORM sp_nomina_set_variable(p_session_id, 'ANTI_TOTAL_MESES', v_total_meses, 'Total meses de antiguedad');
END;
$function$
;

-- ============================================================
-- sp_nomina_calcular_antiguedad_compat
-- ============================================================
CREATE OR REPLACE FUNCTION public.sp_nomina_calcular_antiguedad_compat(p_session_id character varying, p_cedula character varying, p_fecha_calculo date DEFAULT NULL::date)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_fecha_calc DATE;
BEGIN
  v_fecha_calc := COALESCE(p_fecha_calculo, (NOW() AT TIME ZONE 'UTC')::DATE);
  PERFORM sp_nomina_set_variable_compat(p_session_id, 'ANTI_ANIOS', 0, 'Anios');
  PERFORM sp_nomina_set_variable_compat(p_session_id, 'ANTI_MESES', 0, 'Meses');
  PERFORM sp_nomina_set_variable_compat(p_session_id, 'ANTI_TOTAL_MESES', 0, 'Total meses');
END;
$function$
;

-- ============================================================
-- sp_nomina_calcular_concepto
-- ============================================================
CREATE OR REPLACE FUNCTION public.sp_nomina_calcular_concepto(p_session_id character varying, p_cedula character varying, p_co_concepto character varying, p_co_nomina character varying, p_cantidad numeric DEFAULT NULL::numeric, OUT p_monto numeric, OUT p_total numeric, OUT p_descripcion character varying)
 RETURNS record
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_company_id INT;
  v_branch_id INT;
  v_formula TEXT;
  v_default_value NUMERIC(18,6);
  v_cantidad NUMERIC(18,6);
  v_formula_resuelta TEXT;
BEGIN
  SELECT * INTO v_company_id, v_branch_id FROM sp_nomina_get_scope();

  SELECT pc."Formula", pc."DefaultValue", pc."ConceptName"
  INTO v_formula, v_default_value, p_descripcion
  FROM hr."PayrollConcept" pc
  WHERE pc."CompanyId" = v_company_id
    AND pc."PayrollCode" = p_co_nomina
    AND pc."ConceptCode" = p_co_concepto
    AND pc."IsActive" = TRUE
  LIMIT 1;

  v_cantidad := p_cantidad;
  IF v_cantidad IS NULL OR v_cantidad <= 0 THEN v_cantidad := 1; END IF;

  IF v_formula IS NOT NULL AND TRIM(v_formula) <> '' THEN
    SELECT r.p_resultado, r.p_formula_resuelta
    INTO p_monto, v_formula_resuelta
    FROM sp_nomina_evaluar_formula(p_session_id, v_formula) r;
  ELSE
    p_monto := COALESCE(v_default_value, 0);
  END IF;

  p_monto := COALESCE(p_monto, 0);
  p_total := p_monto * v_cantidad;
END;
$function$
;

-- ============================================================
-- sp_nomina_calcular_dias_vacaciones
-- ============================================================
CREATE OR REPLACE FUNCTION public.sp_nomina_calcular_dias_vacaciones(p_session_id character varying, p_cedula character varying, p_fecha_retiro date DEFAULT NULL::date, OUT p_dias_vacaciones numeric, OUT p_dias_bono_vacacional numeric)
 RETURNS record
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_fecha_retiro DATE;
  v_company_id INT;
  v_branch_id INT;
  v_hire_date DATE;
  v_years INT := 0;
  v_base_vac NUMERIC(18,6);
  v_base_bono NUMERIC(18,6);
BEGIN
  v_fecha_retiro := COALESCE(p_fecha_retiro, (NOW() AT TIME ZONE 'UTC')::DATE);

  v_base_vac := fn_nomina_get_variable(p_session_id, 'DIAS_VACACIONES_BASE');
  v_base_bono := fn_nomina_get_variable(p_session_id, 'DIAS_BONO_VAC_BASE');

  SELECT * INTO v_company_id, v_branch_id FROM sp_nomina_get_scope();

  SELECT e."HireDate" INTO v_hire_date
  FROM master."Employee" e
  WHERE e."CompanyId" = v_company_id
    AND e."EmployeeCode" = p_cedula
    AND e."IsDeleted" = FALSE
  LIMIT 1;

  IF v_base_vac <= 0 THEN v_base_vac := 15; END IF;
  IF v_base_bono <= 0 THEN v_base_bono := 15; END IF;

  IF v_hire_date IS NOT NULL THEN
    v_years := EXTRACT(YEAR FROM AGE(v_fecha_retiro, v_hire_date))::INT;
  END IF;

  IF v_years < 0 THEN v_years := 0; END IF;

  p_dias_vacaciones := v_base_vac + CASE WHEN v_years > 0 THEN (v_years - 1) ELSE 0 END;
  p_dias_bono_vacacional := v_base_bono + CASE WHEN v_years > 0 THEN (v_years - 1) ELSE 0 END;

  PERFORM sp_nomina_set_variable(p_session_id, 'DIAS_VACACIONES', p_dias_vacaciones, 'Dias vacaciones calculados');
  PERFORM sp_nomina_set_variable(p_session_id, 'DIAS_BONO_VAC', p_dias_bono_vacacional, 'Dias bono vacacional calculados');
END;
$function$
;

-- ============================================================
-- sp_nomina_calcular_liquidacion
-- ============================================================
CREATE OR REPLACE FUNCTION public.sp_nomina_calcular_liquidacion(p_liquidacion_id character varying, p_cedula character varying, p_fecha_retiro date, p_causa_retiro character varying DEFAULT 'RENUNCIA'::character varying, p_co_usuario character varying DEFAULT 'API'::character varying, OUT p_resultado integer, OUT p_mensaje character varying)
 RETURNS record
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_company_id INT;
  v_branch_id INT;
  v_user_id INT := NULL;
  v_employee_id BIGINT;
  v_employee_name VARCHAR(120);
  v_hire_date DATE;
  v_session_id VARCHAR(80) := 'LIQ_' || p_liquidacion_id;
  v_service_years INT := 0;
  v_salario_diario NUMERIC(18,6);
  v_prestaciones NUMERIC(18,6);
  v_vac_pendientes NUMERIC(18,6);
  v_bono_salida NUMERIC(18,6);
  v_total NUMERIC(18,6);
  v_settlement_process_id BIGINT;
  v_fecha_desde_base DATE;
BEGIN
  p_resultado := 0;
  p_mensaje := '';

  BEGIN
    SELECT * INTO v_company_id, v_branch_id FROM sp_nomina_get_scope();

    SELECT u."UserId" INTO v_user_id
    FROM sec."User" u
    WHERE u."UserCode" = p_co_usuario AND u."IsDeleted" = FALSE
    LIMIT 1;

    SELECT e."EmployeeId", e."EmployeeName", e."HireDate"
    INTO v_employee_id, v_employee_name, v_hire_date
    FROM master."Employee" e
    WHERE e."CompanyId" = v_company_id
      AND e."EmployeeCode" = p_cedula
      AND e."IsDeleted" = FALSE
    LIMIT 1;

    IF v_employee_id IS NULL THEN
      p_mensaje := 'Empleado no encontrado';
      RETURN;
    END IF;

    v_fecha_desde_base := p_fecha_retiro - INTERVAL '1 month';
    PERFORM sp_nomina_preparar_variables_base(v_session_id, p_cedula, 'LIQUIDACION', v_fecha_desde_base::DATE, p_fecha_retiro);
    v_salario_diario := fn_nomina_get_variable(v_session_id, 'SALARIO_DIARIO');

    IF v_hire_date IS NOT NULL THEN
      v_service_years := EXTRACT(YEAR FROM AGE(p_fecha_retiro, v_hire_date))::INT;
    END IF;

    IF v_service_years < 0 THEN v_service_years := 0; END IF;
    IF v_salario_diario < 0 THEN v_salario_diario := 0; END IF;

    v_prestaciones := v_service_years * v_salario_diario * 30;
    v_vac_pendientes := v_salario_diario * 15;
    v_bono_salida := CASE WHEN UPPER(p_causa_retiro)::character varying = 'DESPIDO' THEN (v_salario_diario * 15) ELSE (v_salario_diario * 10) END;
    v_total := v_prestaciones + v_vac_pendientes + v_bono_salida;

    SELECT sp."SettlementProcessId" INTO v_settlement_process_id
    FROM hr."SettlementProcess" sp
    WHERE sp."CompanyId" = v_company_id
      AND sp."BranchId" = v_branch_id
      AND sp."SettlementCode" = p_liquidacion_id
    ORDER BY sp."SettlementProcessId" DESC
    LIMIT 1;

    IF v_settlement_process_id IS NULL THEN
      INSERT INTO hr."SettlementProcess" (
        "CompanyId", "BranchId", "SettlementCode", "EmployeeId", "EmployeeCode", "EmployeeName",
        "RetirementDate", "RetirementCause", "TotalAmount",
        "CreatedAt", "UpdatedAt", "CreatedByUserId", "UpdatedByUserId"
      )
      VALUES (
        v_company_id, v_branch_id, p_liquidacion_id, v_employee_id, p_cedula, v_employee_name,
        p_fecha_retiro, p_causa_retiro, v_total,
        NOW() AT TIME ZONE 'UTC', NOW() AT TIME ZONE 'UTC', v_user_id, v_user_id
      )
      RETURNING "SettlementProcessId" INTO v_settlement_process_id;
    ELSE
      UPDATE hr."SettlementProcess"
      SET "EmployeeId" = v_employee_id,
          "EmployeeCode" = p_cedula,
          "EmployeeName" = v_employee_name,
          "RetirementDate" = p_fecha_retiro,
          "RetirementCause" = p_causa_retiro,
          "TotalAmount" = v_total,
          "UpdatedAt" = NOW() AT TIME ZONE 'UTC',
          "UpdatedByUserId" = v_user_id
      WHERE "SettlementProcessId" = v_settlement_process_id;

      DELETE FROM hr."SettlementProcessLine" WHERE "SettlementProcessId" = v_settlement_process_id;
    END IF;

    INSERT INTO hr."SettlementProcessLine" ("SettlementProcessId", "ConceptCode", "ConceptName", "Amount", "CreatedAt")
    VALUES
      (v_settlement_process_id, 'LIQ_PREST', 'Prestaciones', v_prestaciones, NOW() AT TIME ZONE 'UTC'),
      (v_settlement_process_id, 'LIQ_VAC', 'Vacaciones pendientes', v_vac_pendientes, NOW() AT TIME ZONE 'UTC'),
      (v_settlement_process_id, 'LIQ_BONO', 'Bono de salida', v_bono_salida, NOW() AT TIME ZONE 'UTC');

    PERFORM sp_nomina_limpiar_variables(v_session_id);

    p_resultado := 1;
    p_mensaje := 'Liquidacion calculada. Total=' || CAST(v_total AS VARCHAR(40));

  EXCEPTION WHEN OTHERS THEN
    PERFORM sp_nomina_limpiar_variables(v_session_id);
    p_resultado := 0;
    p_mensaje := SQLERRM;
  END;
END;
$function$
;

-- ============================================================
-- sp_nomina_calcular_prestaciones_regimen
-- ============================================================
CREATE OR REPLACE FUNCTION public.sp_nomina_calcular_prestaciones_regimen(p_session_id character varying, p_regimen character varying, p_anios_servicio integer, p_meses_adicionales integer, p_salario_integral numeric, OUT p_prestaciones numeric, OUT p_intereses numeric)
 RETURNS record
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_dias_anio NUMERIC(18,6);
  v_interes_anual NUMERIC(18,6);
  v_dias_totales NUMERIC(18,6);
BEGIN
  v_dias_anio := fn_nomina_get_variable(p_session_id, 'PREST_DIAS_ANIO');
  v_interes_anual := fn_nomina_get_variable(p_session_id, 'PREST_INTERES_ANUAL');

  IF v_dias_anio <= 0 THEN v_dias_anio := 30; END IF;
  IF v_interes_anual <= 0 THEN v_interes_anual := 0.15; END IF;

  v_dias_totales := (p_anios_servicio * v_dias_anio) + (p_meses_adicionales * (v_dias_anio / 12.0));
  p_prestaciones := p_salario_integral * v_dias_totales;
  p_intereses := p_prestaciones * v_interes_anual;

  PERFORM sp_nomina_set_variable(p_session_id, 'DIAS_PRESTACIONES', v_dias_totales, 'Dias prestaciones');
  PERFORM sp_nomina_set_variable(p_session_id, 'MONTO_PRESTACIONES', p_prestaciones, 'Monto prestaciones');
  PERFORM sp_nomina_set_variable(p_session_id, 'INTERESES_PRESTACIONES', p_intereses, 'Intereses prestaciones');
END;
$function$
;

-- ============================================================
-- sp_nomina_calcular_salarios_promedio
-- ============================================================
CREATE OR REPLACE FUNCTION public.sp_nomina_calcular_salarios_promedio(p_session_id character varying, p_cedula character varying, p_fecha_desde date, p_fecha_hasta date)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_salario_diario NUMERIC(18,6);
  v_base_util NUMERIC(18,6);
  v_salario_normal NUMERIC(18,6);
  v_salario_integral NUMERIC(18,6);
  v_dias INT;
BEGIN
  v_salario_diario := fn_nomina_get_variable(p_session_id, 'SALARIO_DIARIO');
  v_base_util := fn_nomina_get_variable(p_session_id, 'DIAS_UTILIDADES_MIN');
  v_dias := (p_fecha_hasta - p_fecha_desde) + 1;

  IF v_salario_diario <= 0 THEN v_salario_diario := 0; END IF;
  IF v_base_util <= 0 THEN v_base_util := 30; END IF;

  v_salario_normal := v_salario_diario;
  v_salario_integral := v_salario_diario + (v_salario_diario * (v_base_util / 360.0));

  PERFORM sp_nomina_set_variable(p_session_id, 'SALARIO_NORMAL', v_salario_normal, 'Salario promedio diario');
  PERFORM sp_nomina_set_variable(p_session_id, 'SALARIO_INTEGRAL', v_salario_integral, 'Salario integral diario');
  PERFORM sp_nomina_set_variable(p_session_id, 'BASE_UTIL', v_base_util, 'Base de utilidad');
  PERFORM sp_nomina_set_variable(p_session_id, 'DIAS_CALCULO', v_dias, 'Dias del calculo');
END;
$function$
;

-- ============================================================
-- sp_nomina_calcular_utilidades_regimen
-- ============================================================
CREATE OR REPLACE FUNCTION public.sp_nomina_calcular_utilidades_regimen(p_session_id character varying, p_regimen character varying, p_dias_trabajados_ano integer, p_salario_normal numeric, OUT p_utilidades numeric)
 RETURNS numeric
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_dias_min NUMERIC(18,6);
  v_dias_max NUMERIC(18,6);
  v_dias_util NUMERIC(18,6);
BEGIN
  v_dias_min := fn_nomina_get_variable(p_session_id, 'DIAS_UTILIDADES_MIN');
  v_dias_max := fn_nomina_get_variable(p_session_id, 'DIAS_UTILIDADES_MAX');

  IF v_dias_min <= 0 THEN v_dias_min := 30; END IF;
  IF v_dias_max <= 0 THEN v_dias_max := 120; END IF;

  v_dias_util := CASE
    WHEN p_dias_trabajados_ano >= 365 THEN v_dias_max
    WHEN p_dias_trabajados_ano <= 0 THEN 0
    ELSE (v_dias_max * p_dias_trabajados_ano) / 365.0
  END;

  IF v_dias_util < v_dias_min AND p_dias_trabajados_ano > 0 THEN
    v_dias_util := v_dias_min;
  END IF;

  p_utilidades := p_salario_normal * v_dias_util;
  PERFORM sp_nomina_set_variable(p_session_id, 'DIAS_UTILIDADES', v_dias_util, 'Dias utilidades');
  PERFORM sp_nomina_set_variable(p_session_id, 'MONTO_UTILIDADES', p_utilidades, 'Monto utilidades');
END;
$function$
;

-- ============================================================
-- sp_nomina_calcular_vacaciones_regimen
-- ============================================================
CREATE OR REPLACE FUNCTION public.sp_nomina_calcular_vacaciones_regimen(p_session_id character varying, p_regimen character varying, p_anios_servicio integer, p_meses_periodo integer DEFAULT 12, OUT p_dias_vacaciones numeric, OUT p_dias_bono_vacacional numeric, OUT p_dias_bono_post_vacacional numeric)
 RETURNS record
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_vac_base NUMERIC(18,6);
  v_bono_base NUMERIC(18,6);
BEGIN
  v_vac_base := fn_nomina_get_variable(p_session_id, 'DIAS_VACACIONES_BASE');
  v_bono_base := fn_nomina_get_variable(p_session_id, 'DIAS_BONO_VAC_BASE');

  IF v_vac_base <= 0 THEN v_vac_base := 15; END IF;
  IF v_bono_base <= 0 THEN v_bono_base := 15; END IF;

  p_dias_vacaciones := v_vac_base + CASE WHEN p_anios_servicio > 0 THEN (p_anios_servicio - 1) ELSE 0 END;
  p_dias_bono_vacacional := v_bono_base + CASE WHEN p_anios_servicio > 0 THEN (p_anios_servicio - 1) ELSE 0 END;
  p_dias_bono_post_vacacional := 0;

  PERFORM sp_nomina_set_variable(p_session_id, 'DIAS_VACACIONES', p_dias_vacaciones, 'Dias vacaciones (regimen)');
  PERFORM sp_nomina_set_variable(p_session_id, 'DIAS_BONO_VAC', p_dias_bono_vacacional, 'Dias bono vacacional (regimen)');
  PERFORM sp_nomina_set_variable(p_session_id, 'DIAS_BONO_POST_VAC', p_dias_bono_post_vacacional, 'Bono post vacacional');
END;
$function$
;

-- ============================================================
-- sp_nomina_cargar_constantes
-- ============================================================
CREATE OR REPLACE FUNCTION public.sp_nomina_cargar_constantes(p_session_id character varying)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_company_id INT;
  v_branch_id INT;
BEGIN
  SELECT * INTO v_company_id, v_branch_id FROM sp_nomina_get_scope();

  INSERT INTO hr."PayrollCalcVariable" ("SessionID", "Variable", "Valor", "Descripcion")
  SELECT
    p_session_id,
    pc."ConstantCode",
    pc."ConstantValue",
    pc."ConstantName"
  FROM hr."PayrollConstant" pc
  WHERE pc."CompanyId" = v_company_id
    AND pc."IsActive" = TRUE
    AND NOT EXISTS (
      SELECT 1
      FROM hr."PayrollCalcVariable" v
      WHERE v."SessionID" = p_session_id
        AND v."Variable" = pc."ConstantCode"
    );
END;
$function$
;

-- ============================================================
-- sp_nomina_cargar_constantes_desde_concepto_legal
-- ============================================================
CREATE OR REPLACE FUNCTION public.sp_nomina_cargar_constantes_desde_concepto_legal(p_session_id character varying, p_convencion character varying DEFAULT 'LOT'::character varying, p_tipo_calculo character varying DEFAULT 'MENSUAL'::character varying)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_regimen VARCHAR(10) := UPPER(LEFT(COALESCE(p_convencion, 'LOT'), 10))::character varying;
  v_tipo_nomina VARCHAR(15) := UPPER(CASE WHEN p_tipo_calculo IN ('SEMANAL', 'QUINCENAL') THEN p_tipo_calculo ELSE 'MENSUAL' END)::character varying;
BEGIN
  PERFORM sp_nomina_cargar_constantes_regimen(p_session_id, v_regimen, v_tipo_nomina);
END;
$function$
;

-- ============================================================
-- sp_nomina_cargar_constantes_regimen
-- ============================================================
CREATE OR REPLACE FUNCTION public.sp_nomina_cargar_constantes_regimen(p_session_id character varying, p_regimen character varying DEFAULT 'LOT'::character varying, p_tipo_nomina character varying DEFAULT 'MENSUAL'::character varying)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_company_id INT;
  v_branch_id INT;
  v_prefix VARCHAR(20) := UPPER(COALESCE(p_regimen, 'LOT'))::character varying || '_';
BEGIN
  SELECT * INTO v_company_id, v_branch_id FROM sp_nomina_get_scope();

  PERFORM sp_nomina_cargar_constantes(p_session_id);

  INSERT INTO hr."PayrollCalcVariable" ("SessionID", "Variable", "Valor", "Descripcion")
  SELECT
    p_session_id,
    REPLACE(pc."ConstantCode", v_prefix, ''),
    pc."ConstantValue",
    (pc."ConstantName" || ' [' || p_regimen || ']')
  FROM hr."PayrollConstant" pc
  WHERE pc."CompanyId" = v_company_id
    AND pc."IsActive" = TRUE
    AND pc."ConstantCode" LIKE v_prefix || '%'
    AND NOT EXISTS (
      SELECT 1
      FROM hr."PayrollCalcVariable" v
      WHERE v."SessionID" = p_session_id
        AND v."Variable" = REPLACE(pc."ConstantCode", v_prefix, '')
    );

  PERFORM sp_nomina_set_variable(p_session_id, 'REGIMEN_ID', 0, p_regimen);

  IF UPPER(p_tipo_nomina)::character varying = 'SEMANAL' THEN
    PERFORM sp_nomina_set_variable(p_session_id, 'DIAS_PERIODO', 7, 'Dias periodo semanal');
  ELSIF UPPER(p_tipo_nomina)::character varying = 'QUINCENAL' THEN
    PERFORM sp_nomina_set_variable(p_session_id, 'DIAS_PERIODO', 15, 'Dias periodo quincenal');
  END IF;
END;
$function$
;

-- ============================================================
-- sp_nomina_cerrar
-- ============================================================
CREATE OR REPLACE FUNCTION public.sp_nomina_cerrar(p_nomina character varying, p_cedula character varying DEFAULT NULL::character varying, p_co_usuario character varying DEFAULT 'API'::character varying)
 RETURNS TABLE("Resultado" integer, "Mensaje" character varying)
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_company_id INT;
    v_branch_id  INT;
    v_user_id    INT := NULL;
    v_rows       INT;
BEGIN
    SELECT * INTO v_company_id, v_branch_id FROM public.sp_Nomina_GetScope();

    SELECT u."UserId" INTO v_user_id
    FROM sec."User" u
    WHERE u."UserCode" = p_co_usuario
      AND u."IsDeleted" = FALSE
    LIMIT 1;

    UPDATE hr."PayrollRun"
    SET "IsClosed"        = TRUE,
        "ClosedAt"        = NOW() AT TIME ZONE 'UTC',
        "ClosedByUserId"  = v_user_id,
        "UpdatedAt"       = NOW() AT TIME ZONE 'UTC',
        "UpdatedByUserId" = v_user_id
    WHERE "CompanyId" = v_company_id
      AND "BranchId" = v_branch_id
      AND "PayrollCode" = p_nomina
      AND (p_cedula IS NULL OR "EmployeeCode" = p_cedula)
      AND "IsClosed" = FALSE;

    GET DIAGNOSTICS v_rows = ROW_COUNT;

    RETURN QUERY SELECT 1, ('Registros cerrados: ' || v_rows::VARCHAR)::VARCHAR;
END;
$function$
;

-- ============================================================
-- sp_nomina_concepto_save
-- ============================================================
CREATE OR REPLACE FUNCTION public.sp_nomina_concepto_save(p_co_concept character varying, p_co_nomina character varying, p_nb_concepto character varying, p_formula text DEFAULT NULL::text, p_sobre character varying DEFAULT NULL::character varying, p_clase character varying DEFAULT NULL::character varying, p_tipo character varying DEFAULT NULL::character varying, p_uso character varying DEFAULT NULL::character varying, p_bonificable character varying DEFAULT NULL::character varying, p_antiguedad character varying DEFAULT NULL::character varying, p_contable character varying DEFAULT NULL::character varying, p_aplica character varying DEFAULT 'S'::character varying, p_defecto double precision DEFAULT NULL::double precision)
 RETURNS TABLE("Resultado" integer, "Mensaje" character varying)
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_company_id  INT;
    v_branch_id   INT;
    v_resultado   INT := 0;
    v_mensaje     VARCHAR(500) := '';
    v_bonif       BOOLEAN;
    v_antig       BOOLEAN;
    v_aplica_flag BOOLEAN;
    v_defecto_val NUMERIC(18,6);
BEGIN
    SELECT * INTO v_company_id, v_branch_id FROM public.sp_Nomina_GetScope();

    v_bonif       := UPPER(COALESCE(p_bonificable, 'S'))::character varying IN ('S', '1');
    v_antig       := UPPER(COALESCE(p_antiguedad, 'N'))::character varying IN ('S', '1');
    v_aplica_flag := UPPER(COALESCE(p_aplica, 'S'))::character varying IN ('S', '1');
    v_defecto_val := COALESCE(p_defecto::NUMERIC(18,6), 0);

    IF EXISTS (
        SELECT 1 FROM hr."PayrollConcept"
        WHERE "CompanyId" = v_company_id
          AND "PayrollCode" = p_co_nomina
          AND "ConceptCode" = p_co_concept
          AND COALESCE("ConventionCode", '') = ''
          AND COALESCE("CalculationType", '') = ''
    ) THEN
        UPDATE hr."PayrollConcept"
        SET "ConceptName"           = p_nb_concepto,
            "Formula"               = p_formula,
            "BaseExpression"        = p_sobre,
            "ConceptClass"          = p_clase,
            "ConceptType"           = COALESCE(p_tipo, 'ASIGNACION'),
            "UsageType"             = p_uso,
            "IsBonifiable"          = v_bonif,
            "IsSeniority"           = v_antig,
            "AccountingAccountCode" = p_contable,
            "AppliesFlag"           = v_aplica_flag,
            "DefaultValue"          = v_defecto_val,
            "UpdatedAt"             = NOW() AT TIME ZONE 'UTC',
            "IsActive"              = TRUE
        WHERE "CompanyId" = v_company_id
          AND "PayrollCode" = p_co_nomina
          AND "ConceptCode" = p_co_concept
          AND COALESCE("ConventionCode", '') = ''
          AND COALESCE("CalculationType", '') = '';

        v_resultado := 1;
        v_mensaje   := 'Concepto actualizado';
    ELSE
        INSERT INTO hr."PayrollConcept" (
            "CompanyId", "PayrollCode", "ConceptCode", "ConceptName",
            "Formula", "BaseExpression", "ConceptClass", "ConceptType",
            "UsageType", "IsBonifiable", "IsSeniority",
            "AccountingAccountCode", "AppliesFlag", "DefaultValue",
            "ConventionCode", "CalculationType", "LotttArticle", "CcpClause",
            "SortOrder", "IsActive", "CreatedAt", "UpdatedAt"
        )
        VALUES (
            v_company_id, p_co_nomina, p_co_concept, p_nb_concepto,
            p_formula, p_sobre, p_clase, COALESCE(p_tipo, 'ASIGNACION'),
            p_uso, v_bonif, v_antig,
            p_contable, v_aplica_flag, v_defecto_val,
            NULL, NULL, NULL, NULL,
            0, TRUE, NOW() AT TIME ZONE 'UTC', NOW() AT TIME ZONE 'UTC'
        );

        v_resultado := 1;
        v_mensaje   := 'Concepto creado';
    END IF;

    RETURN QUERY SELECT v_resultado, v_mensaje;
END;
$function$
;

-- ============================================================
-- sp_nomina_conceptos_legales_list
-- ============================================================
CREATE OR REPLACE FUNCTION public.sp_nomina_conceptos_legales_list(p_convencion character varying DEFAULT NULL::character varying, p_tipo_calculo character varying DEFAULT NULL::character varying, p_tipo character varying DEFAULT NULL::character varying, p_activo boolean DEFAULT true)
 RETURNS TABLE("Id" bigint, "Convencion" character varying, "TipoCalculo" character varying, "CO_CONCEPT" character varying, "NB_CONCEPTO" character varying, "Formula" character varying, "SOBRE" character varying, "TIPO" character varying, "BONIFICABLE" character varying, "LOTTT_Articulo" character varying, "CCP_Clausula" character varying, "Orden" integer, "Activo" boolean, "CO_NOMINA" character varying)
 LANGUAGE plpgsql
AS $function$
BEGIN
  RETURN QUERY
  SELECT
    pc."PayrollConceptId" AS "Id",
    pc."ConventionCode" AS "Convencion",
    pc."CalculationType" AS "TipoCalculo",
    pc."ConceptCode" AS "CO_CONCEPT",
    pc."ConceptName" AS "NB_CONCEPTO",
    pc."Formula"::TEXT AS "Formula",
    pc."BaseExpression"::TEXT AS "SOBRE",
    pc."ConceptType" AS "TIPO",
    CASE WHEN pc."IsBonifiable" = TRUE THEN 'S'::VARCHAR(1) ELSE 'N'::VARCHAR(1) END AS "BONIFICABLE",
    pc."LotttArticle" AS "LOTTT_Articulo",
    pc."CcpClause" AS "CCP_Clausula",
    pc."SortOrder" AS "Orden",
    pc."IsActive" AS "Activo",
    pc."PayrollCode" AS "CO_NOMINA"
  FROM hr."PayrollConcept" pc
  WHERE pc."ConventionCode" IS NOT NULL
    AND (p_convencion IS NULL OR pc."ConventionCode" = p_convencion)
    AND (p_tipo_calculo IS NULL OR pc."CalculationType" = p_tipo_calculo)
    AND (p_tipo IS NULL OR pc."ConceptType" = p_tipo)
    AND (p_activo IS NULL OR pc."IsActive" = p_activo)
  ORDER BY pc."ConventionCode", pc."CalculationType", pc."SortOrder", pc."ConceptCode";
END;
$function$
;

-- ============================================================
-- sp_nomina_conceptos_list
-- ============================================================
CREATE OR REPLACE FUNCTION public.sp_nomina_conceptos_list(p_co_nomina character varying DEFAULT NULL::character varying, p_tipo character varying DEFAULT NULL::character varying, p_search character varying DEFAULT NULL::character varying, p_page integer DEFAULT 1, p_limit integer DEFAULT 50)
 RETURNS TABLE("TotalCount" integer, "Codigo" character varying, "CodigoNomina" character varying, "Nombre" character varying, "Formula" character varying, "Sobre" character varying, "Clase" character varying, "Tipo" character varying, "Uso" character varying, "Bonificable" character varying, "Antiguedad" character varying, "Contable" character varying, "Aplica" character varying, "Defecto" double precision, "Convencion" character varying, "TipoCalculo" character varying, "Orden" integer, "Activo" boolean)
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_company_id INT;
    v_branch_id  INT;
    v_offset     INT;
    v_total      INT;
BEGIN
    v_offset := (p_page - 1) * p_limit;

    SELECT * INTO v_company_id, v_branch_id FROM public.sp_Nomina_GetScope();

    SELECT COUNT(1) INTO v_total
    FROM hr."PayrollConcept" pc
    WHERE pc."CompanyId" = v_company_id
      AND (p_co_nomina IS NULL OR pc."PayrollCode" = p_co_nomina)
      AND (p_tipo IS NULL OR pc."ConceptType" = p_tipo)
      AND (
          p_search IS NULL
          OR pc."ConceptName" ILIKE '%' || p_search || '%'
          OR pc."ConceptCode" ILIKE '%' || p_search || '%'
      );

    RETURN QUERY
    SELECT
        v_total,
        pc."ConceptCode",
        pc."PayrollCode",
        pc."ConceptName",
        pc."Formula",
        pc."BaseExpression",
        pc."ConceptClass",
        pc."ConceptType",
        pc."UsageType",
        CASE WHEN pc."IsBonifiable" THEN 'S' ELSE 'N' END,
        CASE WHEN pc."IsSeniority"  THEN 'S' ELSE 'N' END,
        pc."AccountingAccountCode",
        CASE WHEN pc."AppliesFlag"  THEN 'S' ELSE 'N' END,
        pc."DefaultValue"::DOUBLE PRECISION,
        pc."ConventionCode",
        pc."CalculationType",
        pc."SortOrder",
        pc."IsActive"
    FROM hr."PayrollConcept" pc
    WHERE pc."CompanyId" = v_company_id
      AND (p_co_nomina IS NULL OR pc."PayrollCode" = p_co_nomina)
      AND (p_tipo IS NULL OR pc."ConceptType" = p_tipo)
      AND (
          p_search IS NULL
          OR pc."ConceptName" ILIKE '%' || p_search || '%'
          OR pc."ConceptCode" ILIKE '%' || p_search || '%'
      )
    ORDER BY pc."PayrollCode", pc."SortOrder", pc."ConceptCode"
    LIMIT p_limit OFFSET v_offset;
END;
$function$
;

-- ============================================================
-- sp_nomina_constante_save
-- ============================================================
CREATE OR REPLACE FUNCTION public.sp_nomina_constante_save(p_codigo character varying, p_nombre character varying DEFAULT NULL::character varying, p_valor double precision DEFAULT NULL::double precision, p_origen character varying DEFAULT NULL::character varying)
 RETURNS TABLE("Resultado" integer, "Mensaje" character varying)
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_company_id INT;
    v_branch_id  INT;
    v_resultado  INT := 0;
    v_mensaje    VARCHAR(500) := '';
BEGIN
    SELECT * INTO v_company_id, v_branch_id FROM public.sp_Nomina_GetScope();

    IF EXISTS (
        SELECT 1 FROM hr."PayrollConstant"
        WHERE "CompanyId" = v_company_id
          AND "ConstantCode" = p_codigo
    ) THEN
        UPDATE hr."PayrollConstant"
        SET "ConstantName"  = COALESCE(p_nombre, "ConstantName"),
            "ConstantValue" = COALESCE(p_valor::NUMERIC(18,6), "ConstantValue"),
            "SourceName"    = COALESCE(p_origen, "SourceName"),
            "IsActive"      = TRUE,
            "UpdatedAt"     = NOW() AT TIME ZONE 'UTC'
        WHERE "CompanyId" = v_company_id
          AND "ConstantCode" = p_codigo;

        v_resultado := 1;
        v_mensaje   := 'Constante actualizada';
    ELSE
        INSERT INTO hr."PayrollConstant" (
            "CompanyId", "ConstantCode", "ConstantName", "ConstantValue", "SourceName",
            "IsActive", "CreatedAt", "UpdatedAt"
        )
        VALUES (
            v_company_id,
            p_codigo,
            COALESCE(p_nombre, p_codigo),
            COALESCE(p_valor::NUMERIC(18,6), 0),
            p_origen,
            TRUE,
            NOW() AT TIME ZONE 'UTC',
            NOW() AT TIME ZONE 'UTC'
        );

        v_resultado := 1;
        v_mensaje   := 'Constante creada';
    END IF;

    RETURN QUERY SELECT v_resultado, v_mensaje;
END;
$function$
;

