-- ============================================================
-- usp_cfg_appsetting_upsert
-- ============================================================
CREATE OR REPLACE FUNCTION public.usp_cfg_appsetting_upsert(p_company_id integer, p_module character varying, p_setting_key character varying, p_setting_value text, p_value_type character varying DEFAULT NULL::character varying, p_description character varying DEFAULT NULL::character varying, p_user_id integer DEFAULT NULL::integer)
 RETURNS TABLE("Resultado" integer, "Mensaje" character varying)
 LANGUAGE plpgsql
AS $function$
BEGIN
    INSERT INTO cfg."AppSetting"
        ("CompanyId", "Module", "SettingKey", "SettingValue", "ValueType",
         "Description", "UpdatedAt", "UpdatedByUserId")
    VALUES
        (p_company_id, p_module, p_setting_key, p_setting_value, p_value_type,
         p_description, NOW() AT TIME ZONE 'UTC', p_user_id)
    ON CONFLICT ("CompanyId", "Module", "SettingKey")
    DO UPDATE SET
        "SettingValue"     = EXCLUDED."SettingValue",
        "ValueType"        = COALESCE(EXCLUDED."ValueType", cfg."AppSetting"."ValueType"),
        "Description"      = COALESCE(EXCLUDED."Description", cfg."AppSetting"."Description"),
        "UpdatedAt"        = NOW() AT TIME ZONE 'UTC',
        "UpdatedByUserId"  = EXCLUDED."UpdatedByUserId";

    RETURN QUERY SELECT 0, 'Configuracion guardada correctamente.'::TEXT;

EXCEPTION WHEN OTHERS THEN
    RETURN QUERY SELECT -1, SQLERRM::TEXT;
END;
$function$
;

-- ============================================================
-- usp_cfg_country_get
-- ============================================================
CREATE OR REPLACE FUNCTION public.usp_cfg_country_get(p_country_code character)
 RETURNS TABLE("CountryCode" character, "CountryName" character varying, "CurrencyCode" character, "TaxAuthorityCode" character varying, "FiscalIdName" character varying, "IsActive" boolean, "CreatedAt" timestamp without time zone, "UpdatedAt" timestamp without time zone)
 LANGUAGE plpgsql
AS $function$
BEGIN
    RETURN QUERY
    SELECT
        c."CountryCode",
        c."CountryName",
        c."CurrencyCode",
        c."TaxAuthorityCode",
        c."FiscalIdName",
        c."IsActive",
        c."CreatedAt",
        c."UpdatedAt"
    FROM cfg."Country" c
    WHERE c."CountryCode" = p_country_code;
END;
$function$
;

-- ============================================================
-- usp_cfg_country_list
-- ============================================================
CREATE OR REPLACE FUNCTION public.usp_cfg_country_list(p_active_only boolean DEFAULT true)
 RETURNS TABLE("CountryCode" character, "CountryName" character varying, "CurrencyCode" character, "TaxAuthorityCode" character varying, "FiscalIdName" character varying, "IsActive" boolean, "CreatedAt" timestamp without time zone, "UpdatedAt" timestamp without time zone)
 LANGUAGE plpgsql
AS $function$
BEGIN
    RETURN QUERY
    SELECT
        c."CountryCode",
        c."CountryName",
        c."CurrencyCode",
        c."TaxAuthorityCode",
        c."FiscalIdName",
        c."IsActive",
        c."CreatedAt",
        c."UpdatedAt"
    FROM cfg."Country" c
    WHERE (NOT p_active_only OR c."IsActive" = TRUE)
