;

-- ============================================================
-- usp_cfg_country_save
-- ============================================================
CREATE OR REPLACE FUNCTION public.usp_cfg_country_save(p_country_code character, p_country_name character varying, p_currency_code character, p_tax_authority_code character varying, p_fiscal_id_name character varying, p_is_active boolean, OUT p_resultado integer, OUT p_mensaje character varying)
 RETURNS record
 LANGUAGE plpgsql
AS $function$
BEGIN
    p_resultado := 0;
    p_mensaje   := '';

    BEGIN
        IF EXISTS (SELECT 1 FROM cfg."Country" WHERE "CountryCode" = p_country_code) THEN
            UPDATE cfg."Country"
            SET "CountryName"       = p_country_name,
                "CurrencyCode"      = p_currency_code,
                "TaxAuthorityCode"  = p_tax_authority_code,
                "FiscalIdName"      = p_fiscal_id_name,
                "IsActive"          = p_is_active,
                "UpdatedAt"         = (NOW() AT TIME ZONE 'UTC')
            WHERE "CountryCode" = p_country_code;

            p_resultado := 0;
            p_mensaje   := 'PaÃƒÂ­s actualizado correctamente.';
        ELSE
            INSERT INTO cfg."Country" (
                "CountryCode", "CountryName", "CurrencyCode",
                "TaxAuthorityCode", "FiscalIdName",
                "IsActive", "CreatedAt", "UpdatedAt"
            )
            VALUES (
                p_country_code, p_country_name, p_currency_code,
                p_tax_authority_code, p_fiscal_id_name,
                p_is_active,
                (NOW() AT TIME ZONE 'UTC'), (NOW() AT TIME ZONE 'UTC')
            );

            p_resultado := 0;
            p_mensaje   := 'PaÃƒÂ­s creado correctamente.';
        END IF;

    EXCEPTION WHEN OTHERS THEN
        p_resultado := -1;
        p_mensaje   := SQLERRM;
    END;
END;
$function$
;

