-- ============================================================
-- usp_cfg_resolvecontext
-- ============================================================
CREATE OR REPLACE FUNCTION public.usp_cfg_resolvecontext(p_user_code character varying DEFAULT NULL::character varying)
 RETURNS TABLE("CompanyId" integer, "BranchId" integer, "UserId" integer)
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_company_id INT;
    v_branch_id  INT;
    v_user_id    INT := NULL;
BEGIN
    SELECT c."CompanyId" INTO v_company_id
    FROM   cfg."Company" c
    WHERE  c."IsDeleted" = FALSE
    ORDER BY CASE WHEN c."CompanyCode" = 'DEFAULT' THEN 0 ELSE 1 END, c."CompanyId"
    LIMIT 1;

    SELECT b."BranchId" INTO v_branch_id
    FROM   cfg."Branch" b
    WHERE  b."CompanyId" = v_company_id
      AND  b."IsDeleted" = FALSE
    ORDER BY CASE WHEN b."BranchCode" = 'MAIN' THEN 0 ELSE 1 END, b."BranchId"
    LIMIT 1;

    IF p_user_code IS NOT NULL THEN
        SELECT u."UserId" INTO v_user_id
        FROM   sec."User" u
        WHERE  u."UserCode"  = p_user_code
          AND  u."IsDeleted" = FALSE
        LIMIT 1;
    END IF;

    RETURN QUERY SELECT v_company_id, v_branch_id, v_user_id;
END;
$function$
;

-- ============================================================
-- usp_cfg_scope_getdefault
-- ============================================================
CREATE OR REPLACE FUNCTION public.usp_cfg_scope_getdefault()
 RETURNS TABLE("companyId" integer, "branchId" integer, "systemUserId" integer)
 LANGUAGE plpgsql
AS $function$
BEGIN
    RETURN QUERY
    SELECT c."CompanyId", b."BranchId", su."UserId"
    FROM cfg."Company" c
    INNER JOIN cfg."Branch" b ON b."CompanyId" = c."CompanyId" AND b."BranchCode" = 'MAIN'
    LEFT JOIN sec."User" su ON su."UserCode" = 'SYSTEM'
    WHERE c."CompanyCode" = 'DEFAULT'
    ORDER BY c."CompanyId", b."BranchId"
    LIMIT 1;
END;
$function$
;

-- ============================================================
-- usp_cfg_scope_getdefaultcompanyuser
-- ============================================================
CREATE OR REPLACE FUNCTION public.usp_cfg_scope_getdefaultcompanyuser()
 RETURNS TABLE("companyId" integer, "systemUserId" integer)
 LANGUAGE plpgsql
AS $function$
BEGIN
    RETURN QUERY
    SELECT c."CompanyId", su."UserId"
    FROM cfg."Company" c
    LEFT JOIN sec."User" su ON su."UserCode" = 'SYSTEM'
    WHERE c."CompanyCode" = 'DEFAULT'
    ORDER BY c."CompanyId"
    LIMIT 1;
END;
$function$
;

-- ============================================================
-- usp_clases_delete
-- ============================================================
CREATE OR REPLACE FUNCTION public.usp_clases_delete(p_codigo integer)
 RETURNS TABLE("Resultado" integer, "Mensaje" character varying)
 LANGUAGE plpgsql
AS $function$
BEGIN
    IF NOT EXISTS (SELECT 1 FROM public."Clases" WHERE "Codigo" = p_codigo) THEN
        RETURN QUERY SELECT 0, 'Clase no encontrada'::VARCHAR(500);
        RETURN;
    END IF;

    DELETE FROM public."Clases" WHERE "Codigo" = p_codigo;

    RETURN QUERY SELECT 1, 'Clase eliminada exitosamente'::VARCHAR(500);

EXCEPTION WHEN OTHERS THEN
    RETURN QUERY SELECT 0, SQLERRM::VARCHAR(500);
END;
$function$
;

-- ============================================================
-- usp_clases_getbycodigo
-- ============================================================
CREATE OR REPLACE FUNCTION public.usp_clases_getbycodigo(p_codigo integer)
 RETURNS TABLE("Codigo" integer, "Descripcion" character varying)
 LANGUAGE plpgsql
AS $function$
BEGIN
    RETURN QUERY
    SELECT
        cl."Codigo",
        cl."Descripcion"
    FROM public."Clases" cl
    WHERE cl."Codigo" = p_codigo;
END;
$function$
;

-- ============================================================
-- usp_clases_insert
-- ============================================================
CREATE OR REPLACE FUNCTION public.usp_clases_insert(p_row_json jsonb)
 RETURNS TABLE("Resultado" integer, "Mensaje" character varying, "NuevoCodigo" integer)
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_descripcion VARCHAR(25);
    v_new_id      INT;
BEGIN
    v_descripcion := NULLIF(p_row_json->>'Descripcion', ''::character varying);

    INSERT INTO public."Clases" ("Descripcion")
    VALUES (v_descripcion)
    RETURNING "Codigo" INTO v_new_id;

    RETURN QUERY SELECT 1, 'Clase creada exitosamente'::VARCHAR(500), v_new_id;

EXCEPTION WHEN OTHERS THEN
    RETURN QUERY SELECT 0, SQLERRM::VARCHAR(500), NULL::INT;
END;
$function$
;

-- ============================================================
-- usp_clases_list
-- ============================================================
CREATE OR REPLACE FUNCTION public.usp_clases_list(p_search character varying DEFAULT NULL::character varying, p_page integer DEFAULT 1, p_limit integer DEFAULT 50)
 RETURNS TABLE("Codigo" integer, "Descripcion" character varying, "TotalCount" integer)
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_offset INT;
    v_limit  INT;
    v_search VARCHAR(100);
    v_total  INT;
BEGIN
    v_limit  := COALESCE(NULLIF(p_limit, 0), 50)::character varying;
    IF v_limit < 1  THEN v_limit := 50;  END IF;
    IF v_limit > 500 THEN v_limit := 500; END IF;

    v_offset := (COALESCE(NULLIF(p_page, 0), 1)::character varying - 1) * v_limit;
    IF v_offset < 0 THEN v_offset := 0; END IF;

    v_search := NULL;
    IF p_search IS NOT NULL AND TRIM(p_search) <> '' THEN
        v_search := '%' || p_search || '%';
    END IF;

    -- Conteo total
    SELECT COUNT(1) INTO v_total
    FROM public."Clases" cl
    WHERE v_search IS NULL
       OR (cl."Codigo"::VARCHAR ILIKE v_search OR cl."Descripcion" ILIKE v_search);

    -- Resultados paginados
    RETURN QUERY
    SELECT
        cl."Codigo",
        cl."Descripcion",
        v_total AS "TotalCount"
    FROM public."Clases" cl
    WHERE v_search IS NULL
       OR (cl."Codigo"::VARCHAR ILIKE v_search OR cl."Descripcion" ILIKE v_search)
    ORDER BY cl."Codigo"
    LIMIT v_limit OFFSET v_offset;
END;
$function$
;

-- ============================================================
-- usp_clases_update
-- ============================================================
CREATE OR REPLACE FUNCTION public.usp_clases_update(p_codigo integer, p_row_json jsonb)
 RETURNS TABLE("Resultado" integer, "Mensaje" character varying)
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_descripcion VARCHAR(25);
BEGIN
    IF NOT EXISTS (SELECT 1 FROM public."Clases" WHERE "Codigo" = p_codigo) THEN
        RETURN QUERY SELECT 0, 'Clase no encontrada'::VARCHAR(500);
        RETURN;
    END IF;

    v_descripcion := NULLIF(p_row_json->>'Descripcion', ''::character varying);

    UPDATE public."Clases"
    SET "Descripcion" = v_descripcion
    WHERE "Codigo" = p_codigo;

    RETURN QUERY SELECT 1, 'Clase actualizada exitosamente'::VARCHAR(500);

EXCEPTION WHEN OTHERS THEN
    RETURN QUERY SELECT 0, SQLERRM::VARCHAR(500);
END;
$function$
;

-- ============================================================
-- usp_clientes_delete
-- ============================================================
CREATE OR REPLACE FUNCTION public.usp_clientes_delete(p_codigo character varying)
 RETURNS TABLE("Resultado" integer, "Mensaje" character varying)
 LANGUAGE plpgsql
AS $function$
BEGIN
    IF NOT EXISTS (
        SELECT 1 FROM master."Customer"
        WHERE "CustomerCode" = p_codigo AND COALESCE("IsDeleted", FALSE) = FALSE
    ) THEN
        RETURN QUERY SELECT -1, 'Cliente no encontrado'::VARCHAR(500);
        RETURN;
    END IF;

    UPDATE master."Customer"
    SET "IsDeleted" = TRUE, "IsActive" = FALSE
    WHERE "CustomerCode" = p_codigo;

    RETURN QUERY SELECT 1, 'OK'::VARCHAR(500);

EXCEPTION WHEN OTHERS THEN
    RETURN QUERY SELECT -99, SQLERRM::VARCHAR(500);
END;
$function$
;

