-- ============================================================
-- usp_clientes_insert
-- ============================================================
CREATE OR REPLACE FUNCTION public.usp_clientes_insert(p_row_json jsonb)
 RETURNS TABLE("Resultado" integer, "Mensaje" character varying)
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_company_id INT;
    v_codigo     VARCHAR(12);
BEGIN
    -- Obtener CompanyId por defecto
    SELECT co."CompanyId" INTO v_company_id
    FROM cfg."Company" co
    WHERE COALESCE(co."IsDeleted", FALSE) = FALSE
    ORDER BY co."CompanyId"
    LIMIT 1;

    IF v_company_id IS NULL THEN v_company_id := 1; END IF;

    v_codigo := NULLIF(p_row_json->>'CODIGO', ''::character varying);

    -- Verificar duplicado
    IF EXISTS (
        SELECT 1 FROM master."Customer"
        WHERE "CustomerCode" = v_codigo AND "CompanyId" = v_company_id
    ) THEN
        RETURN QUERY SELECT -1, 'Cliente ya existe'::VARCHAR(500);
        RETURN;
    END IF;

    INSERT INTO master."Customer" (
        "CustomerCode", "CustomerName", "FiscalId", "NIT",
        "Direccion", "Direccion1", "Sucursal", "Telefono",
        "Contacto", "SalespersonCode", "ESTADO", "Ciudad",
        "CodPostal", "Email", "PaginaWww", "CodUsuario",
        "CreditLimit", "Credito", "PriceListCode",
        "IsActive", "IsDeleted", "CompanyId"
    )
    VALUES (
        v_codigo,
        NULLIF(p_row_json->>'NOMBRE', ''::character varying),
        NULLIF(p_row_json->>'RIF', ''::character varying),
        NULLIF(p_row_json->>'NIT', ''::character varying),
        NULLIF(p_row_json->>'DIRECCION', ''::character varying),
        NULLIF(p_row_json->>'DIRECCION1', ''::character varying),
        NULLIF(p_row_json->>'SUCURSAL', ''::character varying),
        NULLIF(p_row_json->>'TELEFONO', ''::character varying),
        NULLIF(p_row_json->>'CONTACTO', ''::character varying),
        NULLIF(p_row_json->>'VENDEDOR', ''::character varying),
        NULLIF(p_row_json->>'ESTADO', ''::character varying),
        NULLIF(p_row_json->>'CIUDAD', ''::character varying),
        NULLIF(p_row_json->>'CPOSTAL', ''::character varying),
        NULLIF(p_row_json->>'EMAIL', ''::character varying),
        NULLIF(p_row_json->>'PAGINA_WWW', ''::character varying),
        NULLIF(p_row_json->>'COD_USUARIO', ''::character varying),
        CASE WHEN p_row_json->>'LIMITE' IS NULL OR p_row_json->>'LIMITE' = ''
             THEN NULL
             ELSE (p_row_json->>'LIMITE')::DOUBLE PRECISION END,
        CASE WHEN p_row_json->>'CREDITO' IS NULL OR p_row_json->>'CREDITO' = ''
             THEN NULL
             ELSE (p_row_json->>'CREDITO')::DOUBLE PRECISION END,
        CASE WHEN p_row_json->>'LISTA_PRECIO' IS NULL OR p_row_json->>'LISTA_PRECIO' = ''
             THEN NULL
             ELSE NULLIF(p_row_json->>'LISTA_PRECIO', ''::character varying) END,
        TRUE,   -- IsActive
        FALSE,  -- IsDeleted
        v_company_id
    );

    RETURN QUERY SELECT 1, 'OK'::VARCHAR(500);

EXCEPTION WHEN OTHERS THEN
    RETURN QUERY SELECT -99, SQLERRM::VARCHAR(500);
END;
$function$
;

-- ============================================================
-- usp_clientes_list
-- ============================================================
CREATE OR REPLACE FUNCTION public.usp_clientes_list(p_search character varying DEFAULT NULL::character varying, p_estado character varying DEFAULT NULL::character varying, p_vendedor character varying DEFAULT NULL::character varying, p_page integer DEFAULT 1, p_limit integer DEFAULT 50)
 RETURNS TABLE("CODIGO" character varying, "NOMBRE" character varying, "RIF" character varying, "SALDO_TOT" double precision, "LIMITE" double precision, "IsActive" boolean, "IsDeleted" boolean, "CompanyId" integer, "CustomerCode" character varying, "CustomerName" character varying, "FiscalId" character varying, "TotalBalance" double precision, "CreditLimit" double precision, "NIT" character varying, "Direccion" character varying, "Telefono" character varying, "Contacto" character varying, "SalespersonCode" character varying, "PriceListCode" character varying, "Ciudad" character varying, "CodPostal" character varying, "Email" character varying, "PaginaWww" character varying, "CodUsuario" character varying, "Credito" double precision, "TotalCount" integer)
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_offset INT;
    v_limit  INT;
    v_search VARCHAR(100);
    v_total  INT;
BEGIN
    v_limit  := COALESCE(NULLIF(p_limit, 0), 50)::character varying;
    IF v_limit < 1  THEN v_limit := 50;  END IF;
    IF v_limit > 500 THEN v_limit := 500; END IF;

    v_offset := (COALESCE(NULLIF(p_page, 0), 1)::character varying - 1) * v_limit;
    IF v_offset < 0 THEN v_offset := 0; END IF;

    v_search := NULL;
    IF p_search IS NOT NULL AND TRIM(p_search) <> '' THEN
        v_search := '%' || p_search || '%';
    END IF;

    -- Conteo total
    SELECT COUNT(1) INTO v_total
    FROM master."Customer" c
    WHERE COALESCE(c."IsDeleted", FALSE) = FALSE
      AND (v_search IS NULL OR (c."CustomerCode" ILIKE v_search OR c."CustomerName" ILIKE v_search OR c."FiscalId" ILIKE v_search))
      AND (p_estado IS NULL OR TRIM(p_estado) = '' OR c."ESTADO" = p_estado)
      AND (p_vendedor IS NULL OR TRIM(p_vendedor) = '' OR c."SalespersonCode" = p_vendedor);

    -- Resultados paginados
    RETURN QUERY
    SELECT
        c."CustomerCode"    AS "CODIGO",
        c."CustomerName"    AS "NOMBRE",
        c."FiscalId"        AS "RIF",
        c."TotalBalance"    AS "SALDO_TOT",
        c."CreditLimit"     AS "LIMITE",
        c."IsActive",
        c."IsDeleted",
        c."CompanyId",
        c."CustomerCode",
        c."CustomerName",
        c."FiscalId",
        c."TotalBalance",
        c."CreditLimit",
        c."NIT",
        c."Direccion",
        c."Telefono",
        c."Contacto",
        c."SalespersonCode",
        c."PriceListCode",
        c."Ciudad",
        c."CodPostal",
        c."Email",
        c."PaginaWww",
        c."CodUsuario",
        c."Credito",
        v_total             AS "TotalCount"
    FROM master."Customer" c
    WHERE COALESCE(c."IsDeleted", FALSE) = FALSE
      AND (v_search IS NULL OR (c."CustomerCode" ILIKE v_search OR c."CustomerName" ILIKE v_search OR c."FiscalId" ILIKE v_search))
      AND (p_estado IS NULL OR TRIM(p_estado) = '' OR c."ESTADO" = p_estado)
      AND (p_vendedor IS NULL OR TRIM(p_vendedor) = '' OR c."SalespersonCode" = p_vendedor)
    ORDER BY c."CustomerCode"
    LIMIT v_limit OFFSET v_offset;
END;
$function$
;

-- ============================================================
-- usp_clientes_update
-- ============================================================
CREATE OR REPLACE FUNCTION public.usp_clientes_update(p_codigo character varying, p_row_json jsonb)
 RETURNS TABLE("Resultado" integer, "Mensaje" character varying)
 LANGUAGE plpgsql
AS $function$
BEGIN
    -- Verificar existencia
    IF NOT EXISTS (
        SELECT 1 FROM master."Customer"
        WHERE "CustomerCode" = p_codigo AND COALESCE("IsDeleted", FALSE) = FALSE
    ) THEN
        RETURN QUERY SELECT -1, 'Cliente no encontrado'::VARCHAR(500);
        RETURN;
    END IF;

    UPDATE master."Customer" SET
        "CustomerName"    = COALESCE(NULLIF(p_row_json->>'NOMBRE', ''::character varying), "CustomerName")::character varying,
        "FiscalId"        = COALESCE(NULLIF(p_row_json->>'RIF', ''::character varying), "FiscalId")::character varying,
        "NIT"             = COALESCE(NULLIF(p_row_json->>'NIT', ''::character varying), "NIT")::character varying,
        "Direccion"       = COALESCE(NULLIF(p_row_json->>'DIRECCION', ''::character varying), "Direccion")::character varying,
        "Direccion1"      = COALESCE(NULLIF(p_row_json->>'DIRECCION1', ''::character varying), "Direccion1")::character varying,
        "Sucursal"        = COALESCE(NULLIF(p_row_json->>'SUCURSAL', ''::character varying), "Sucursal")::character varying,
        "Telefono"        = COALESCE(NULLIF(p_row_json->>'TELEFONO', ''::character varying), "Telefono")::character varying,
        "Contacto"        = COALESCE(NULLIF(p_row_json->>'CONTACTO', ''::character varying), "Contacto")::character varying,
        "SalespersonCode" = COALESCE(NULLIF(p_row_json->>'VENDEDOR', ''::character varying), "SalespersonCode")::character varying,
        "ESTADO"          = COALESCE(NULLIF(p_row_json->>'ESTADO', ''::character varying), "ESTADO")::character varying,
        "Ciudad"          = COALESCE(NULLIF(p_row_json->>'CIUDAD', ''::character varying), "Ciudad")::character varying,
        "CodPostal"       = COALESCE(NULLIF(p_row_json->>'CPOSTAL', ''::character varying), "CodPostal")::character varying,
        "Email"           = COALESCE(NULLIF(p_row_json->>'EMAIL', ''::character varying), "Email")::character varying,
        "PaginaWww"       = COALESCE(NULLIF(p_row_json->>'PAGINA_WWW', ''::character varying), "PaginaWww")::character varying,
        "CodUsuario"      = COALESCE(NULLIF(p_row_json->>'COD_USUARIO', ''::character varying), "CodUsuario")::character varying,
        "CreditLimit"     = CASE WHEN p_row_json->>'LIMITE' IS NULL OR p_row_json->>'LIMITE' = ''
                                 THEN "CreditLimit"
                                 ELSE (p_row_json->>'LIMITE')::DOUBLE PRECISION END,
        "Credito"         = CASE WHEN p_row_json->>'CREDITO' IS NULL OR p_row_json->>'CREDITO' = ''
                                 THEN "Credito"
                                 ELSE (p_row_json->>'CREDITO')::DOUBLE PRECISION END,
        "PriceListCode"   = CASE WHEN p_row_json->>'LISTA_PRECIO' IS NULL OR p_row_json->>'LISTA_PRECIO' = ''
                                 THEN "PriceListCode"
                                 ELSE NULLIF(p_row_json->>'LISTA_PRECIO', ''::character varying) END
    WHERE "CustomerCode" = p_codigo
      AND COALESCE("IsDeleted", FALSE) = FALSE;

    RETURN QUERY SELECT 1, 'OK'::VARCHAR(500);

EXCEPTION WHEN OTHERS THEN
    RETURN QUERY SELECT -99, SQLERRM::VARCHAR(500);
END;
$function$
;

-- ============================================================
-- usp_compras_getbynumfact
-- ============================================================
CREATE OR REPLACE FUNCTION public.usp_compras_getbynumfact(p_num_fact character varying)
 RETURNS TABLE("NUM_FACT" character varying, "FECHA" date, "COD_PROVEEDOR" character varying, "NOMBRE" character varying, "RIF" character varying, "TIPO" character varying, "MONTO" numeric, "IVA" numeric, "TOTAL" numeric)
 LANGUAGE plpgsql
AS $function$
BEGIN
    RETURN QUERY
    SELECT
        co."NUM_FACT",
        co."FECHA",
        co."COD_PROVEEDOR",
        co."NOMBRE",
        co."RIF",
        co."TIPO",
        co."MONTO",
        co."IVA",
        co."TOTAL"
    FROM public."Compras" co
    WHERE co."NUM_FACT" = p_num_fact;
END;
$function$
;

-- ============================================================
-- usp_compras_list
-- ============================================================
CREATE OR REPLACE FUNCTION public.usp_compras_list(p_search character varying DEFAULT NULL::character varying, p_proveedor character varying DEFAULT NULL::character varying, p_estado character varying DEFAULT NULL::character varying, p_fecha_desde date DEFAULT NULL::date, p_fecha_hasta date DEFAULT NULL::date, p_page integer DEFAULT 1, p_limit integer DEFAULT 50)
 RETURNS TABLE("NUM_FACT" character varying, "FECHA" date, "COD_PROVEEDOR" character varying, "NOMBRE" character varying, "RIF" character varying, "TIPO" character varying, "MONTO" numeric, "IVA" numeric, "TOTAL" numeric, "TotalCount" integer)
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_offset INT;
    v_limit  INT;
    v_search VARCHAR(100);
    v_total  INT;
BEGIN
    v_limit  := COALESCE(NULLIF(p_limit, 0), 50)::character varying;
    IF v_limit < 1  THEN v_limit := 50;  END IF;
    IF v_limit > 500 THEN v_limit := 500; END IF;

    v_offset := (COALESCE(NULLIF(p_page, 0), 1)::character varying - 1) * v_limit;
    IF v_offset < 0 THEN v_offset := 0; END IF;

    v_search := NULL;
    IF p_search IS NOT NULL AND TRIM(p_search) <> '' THEN
        v_search := '%' || p_search || '%';
    END IF;

    -- Conteo total
    SELECT COUNT(1) INTO v_total
    FROM public."Compras" co
    WHERE (v_search IS NULL OR (co."NUM_FACT" ILIKE v_search OR co."NOMBRE" ILIKE v_search OR co."RIF" ILIKE v_search))
      AND (p_proveedor IS NULL OR TRIM(p_proveedor) = '' OR co."COD_PROVEEDOR" = p_proveedor)
      AND (p_estado IS NULL OR TRIM(p_estado) = '' OR co."TIPO" = p_estado)
      AND (p_fecha_desde IS NULL OR co."FECHA" >= p_fecha_desde)
      AND (p_fecha_hasta IS NULL OR co."FECHA" <= p_fecha_hasta);

    -- Resultados paginados
    RETURN QUERY
    SELECT
        co."NUM_FACT",
        co."FECHA",
        co."COD_PROVEEDOR",
        co."NOMBRE",
        co."RIF",
        co."TIPO",
        co."MONTO",
        co."IVA",
        co."TOTAL",
        v_total AS "TotalCount"
    FROM public."Compras" co
    WHERE (v_search IS NULL OR (co."NUM_FACT" ILIKE v_search OR co."NOMBRE" ILIKE v_search OR co."RIF" ILIKE v_search))
      AND (p_proveedor IS NULL OR TRIM(p_proveedor) = '' OR co."COD_PROVEEDOR" = p_proveedor)
      AND (p_estado IS NULL OR TRIM(p_estado) = '' OR co."TIPO" = p_estado)
      AND (p_fecha_desde IS NULL OR co."FECHA" >= p_fecha_desde)
      AND (p_fecha_hasta IS NULL OR co."FECHA" <= p_fecha_hasta)
    ORDER BY co."FECHA" DESC
    LIMIT v_limit OFFSET v_offset;
END;
$function$
;

-- ============================================================
-- usp_contabilidad_ajuste_crear
-- ============================================================
CREATE OR REPLACE FUNCTION public.usp_contabilidad_ajuste_crear(p_fecha date, p_tipo_ajuste character varying, p_referencia character varying DEFAULT NULL::character varying, p_motivo character varying DEFAULT ''::character varying, p_cod_usuario character varying DEFAULT NULL::character varying, p_detalle_json jsonb DEFAULT '[]'::jsonb)
 RETURNS TABLE("AsientoId" bigint, "Resultado" integer, "Mensaje" character varying)
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_asiento_id     BIGINT;
    v_numero_asiento VARCHAR(40);
    v_resultado      INT;
    v_mensaje        TEXT;
    rec              RECORD;
BEGIN
    SELECT * INTO rec
    FROM usp_contabilidad_asiento_crear(
        p_fecha,
        'AJU',
        p_referencia,
        p_motivo,
        'VES',
        1,
        'CONTABILIDAD',
        p_referencia,
        p_cod_usuario,
        p_detalle_json
    );

    v_asiento_id := rec."AsientoId";
    v_resultado  := rec."Resultado";
    v_mensaje    := rec."Mensaje";

    IF v_resultado = 1 THEN
        INSERT INTO "AjusteContable" ("AsientoId", "TipoAjuste", "Motivo", "Fecha", "Estado", "CodUsuario")
        VALUES (v_asiento_id, p_tipo_ajuste, p_motivo, p_fecha, 'APROBADO', p_cod_usuario);
    END IF;

    RETURN QUERY SELECT v_asiento_id, v_resultado, v_mensaje;
END;
$function$
;

-- ============================================================
-- usp_contabilidad_asiento_anular
-- ============================================================
CREATE OR REPLACE FUNCTION public.usp_contabilidad_asiento_anular(p_asiento_id bigint, p_motivo character varying, p_cod_usuario character varying)
 RETURNS TABLE("Resultado" integer, "Mensaje" character varying)
 LANGUAGE plpgsql
AS $function$
BEGIN
    IF NOT EXISTS (SELECT 1 FROM "AsientoContable" WHERE "Id" = p_asiento_id) THEN
        RETURN QUERY SELECT -1, 'Asiento no encontrado'::TEXT;
        RETURN;
    END IF;

    UPDATE "AsientoContable"
    SET "Estado" = 'ANULADO',
        "FechaAnulacion" = NOW() AT TIME ZONE 'UTC',
        "UsuarioAnulacion" = p_cod_usuario,
        "MotivoAnulacion" = p_motivo
    WHERE "Id" = p_asiento_id;

    RETURN QUERY SELECT 1, 'OK'::TEXT;

EXCEPTION WHEN OTHERS THEN
    RETURN QUERY SELECT -99, SQLERRM::TEXT;
END;
$function$
;

-- ============================================================
-- usp_contabilidad_asiento_crear
-- ============================================================
CREATE OR REPLACE FUNCTION public.usp_contabilidad_asiento_crear(p_fecha date, p_tipo_asiento character varying, p_referencia character varying DEFAULT NULL::character varying, p_concepto character varying DEFAULT ''::character varying, p_moneda character varying DEFAULT 'VES'::character varying, p_tasa numeric DEFAULT 1, p_origen_modulo character varying DEFAULT NULL::character varying, p_origen_documento character varying DEFAULT NULL::character varying, p_cod_usuario character varying DEFAULT NULL::character varying, p_detalle_json jsonb DEFAULT '[]'::jsonb)
 RETURNS TABLE("AsientoId" bigint, "NumeroAsiento" character varying, "Resultado" integer, "Mensaje" character varying)
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_asiento_id      BIGINT;
    v_numero_asiento  VARCHAR(40);
    v_periodo         VARCHAR(7);
    v_debe            NUMERIC(18,2);
    v_haber           NUMERIC(18,2);
    v_next            INT;
BEGIN
    v_periodo := TO_CHAR(p_fecha, 'YYYY-MM');

    -- Crear tabla temporal con el detalle parseado del JSONB
    CREATE TEMP TABLE _det_asiento (
        "Renglon"        SERIAL,
        "CodCuenta"      VARCHAR(40),
        "Descripcion"    VARCHAR(400),
        "CentroCosto"    VARCHAR(20),
        "AuxiliarTipo"   VARCHAR(30),
        "AuxiliarCodigo" VARCHAR(120),
        "Documento"      VARCHAR(120),
        "Debe"           NUMERIC(18,2),
        "Haber"          NUMERIC(18,2)
    ) ON COMMIT DROP;

    INSERT INTO _det_asiento ("CodCuenta", "Descripcion", "CentroCosto",
                               "AuxiliarTipo", "AuxiliarCodigo", "Documento", "Debe", "Haber")
    SELECT
        NULLIF(item->>'codCuenta', ''::character varying),
        NULLIF(item->>'descripcion', ''::character varying),
        NULLIF(item->>'centroCosto', ''::character varying),
        NULLIF(item->>'auxiliarTipo', ''::character varying),
        NULLIF(item->>'auxiliarCodigo', ''::character varying),
        NULLIF(item->>'documento', ''::character varying),
        COALESCE(NULLIF(item->>'debe', ''::character varying)::NUMERIC(18,2), 0)::character varying,
        COALESCE(NULLIF(item->>'haber', ''::character varying)::NUMERIC(18,2), 0)::character varying
    FROM jsonb_array_elements(p_detalle_json) AS item;

    IF NOT EXISTS (SELECT 1 FROM _det_asiento) THEN
        RETURN QUERY SELECT NULL::BIGINT, NULL::VARCHAR, -1, 'Detalle requerido'::TEXT;
        RETURN;
    END IF;

    IF EXISTS (SELECT 1 FROM _det_asiento WHERE "CodCuenta" IS NULL) THEN
        RETURN QUERY SELECT NULL::BIGINT, NULL::VARCHAR, -2, 'Existe detalle sin cuenta contable'::TEXT;
        RETURN;
    END IF;

    IF EXISTS (
        SELECT 1
        FROM _det_asiento d
        LEFT JOIN "Cuentas" c ON c."COD_CUENTA" = d."CodCuenta"
        WHERE c."COD_CUENTA" IS NULL
    ) THEN
        RETURN QUERY SELECT NULL::BIGINT, NULL::VARCHAR, -3, 'Existe detalle con cuenta no registrada en Cuentas'::TEXT;
        RETURN;
    END IF;

    SELECT COALESCE(SUM("Debe"), 0), COALESCE(SUM("Haber"), 0)
    INTO v_debe, v_haber
    FROM _det_asiento;

    IF ABS(v_debe - v_haber) > 0.009 THEN
        RETURN QUERY SELECT NULL::BIGINT, NULL::VARCHAR, -4, 'Asiento descuadrado: Debe y Haber no coinciden'::TEXT;
        RETURN;
    END IF;

    -- Generar numero secuencial
    SELECT COALESCE(MAX(
        CASE WHEN RIGHT("NumeroAsiento", 8) ~ '^\d+$'
             THEN RIGHT("NumeroAsiento", 8)::INT
             ELSE 0 END
    ), 0) + 1
    INTO v_next
    FROM "AsientoContable";

    v_numero_asiento := 'AST-' || LPAD(v_next::TEXT, 8, '0');

    INSERT INTO "AsientoContable" (
        "NumeroAsiento", "Fecha", "Periodo", "TipoAsiento", "Referencia", "Concepto", "Moneda", "Tasa",
        "TotalDebe", "TotalHaber", "Estado", "OrigenModulo", "OrigenDocumento", "CodUsuario", "FechaCreacion"
    )
    VALUES (
        v_numero_asiento, p_fecha, v_periodo, p_tipo_asiento, p_referencia, p_concepto, p_moneda, p_tasa,
        v_debe, v_haber, 'APROBADO', p_origen_modulo, p_origen_documento, p_cod_usuario, NOW() AT TIME ZONE 'UTC'
    )
    RETURNING "Id" INTO v_asiento_id;

    INSERT INTO "AsientoContableDetalle" (
        "AsientoId", "Renglon", "CodCuenta", "Descripcion", "CentroCosto",
        "AuxiliarTipo", "AuxiliarCodigo", "Documento", "Debe", "Haber"
    )
    SELECT
        v_asiento_id, "Renglon", "CodCuenta", "Descripcion", "CentroCosto",
        "AuxiliarTipo", "AuxiliarCodigo", "Documento", "Debe", "Haber"
    FROM _det_asiento
    ORDER BY "Renglon";

    IF p_origen_modulo IS NOT NULL AND p_origen_documento IS NOT NULL THEN
        INSERT INTO "AsientoOrigenAuxiliar" (
            "OrigenModulo", "TipoDocumento", "NumeroDocumento", "TablaOrigen", "LlaveOrigen", "AsientoId", "Estado"
        )
        VALUES (
            p_origen_modulo,
            p_tipo_asiento,
            p_origen_documento,
            NULL,
            p_origen_documento,
            v_asiento_id,
            'APLICADO'
        );
    END IF;

    RETURN QUERY SELECT v_asiento_id, v_numero_asiento, 1, 'OK'::TEXT;

EXCEPTION WHEN OTHERS THEN
    RETURN QUERY SELECT NULL::BIGINT, NULL::VARCHAR, -99, SQLERRM::TEXT;
END;
$function$
;

-- ============================================================
-- usp_contabilidad_asiento_get_detalle
-- ============================================================
CREATE OR REPLACE FUNCTION public.usp_contabilidad_asiento_get_detalle(p_asiento_id bigint)
 RETURNS TABLE("Id" bigint, "AsientoId" bigint, "Renglon" integer, "CodCuenta" character varying, "Descripcion" character varying, "CentroCosto" character varying, "AuxiliarTipo" character varying, "AuxiliarCodigo" character varying, "Documento" character varying, "Debe" numeric, "Haber" numeric)
 LANGUAGE plpgsql
AS $function$
BEGIN
    RETURN QUERY
    SELECT d."Id", d."AsientoId", d."Renglon", d."CodCuenta", d."Descripcion",
           d."CentroCosto", d."AuxiliarTipo", d."AuxiliarCodigo", d."Documento",
           d."Debe", d."Haber"
    FROM "AsientoContableDetalle" d
    WHERE d."AsientoId" = p_asiento_id
    ORDER BY d."Renglon", d."Id";
END;
$function$
;

-- ============================================================
-- usp_contabilidad_asiento_get_header
-- ============================================================
CREATE OR REPLACE FUNCTION public.usp_contabilidad_asiento_get_header(p_asiento_id bigint)
 RETURNS TABLE("Id" bigint, "NumeroAsiento" character varying, "Fecha" date, "Periodo" character varying, "TipoAsiento" character varying, "Referencia" character varying, "Concepto" character varying, "Moneda" character varying, "Tasa" numeric, "TotalDebe" numeric, "TotalHaber" numeric, "Estado" character varying, "OrigenModulo" character varying, "OrigenDocumento" character varying, "CodUsuario" character varying, "FechaCreacion" timestamp without time zone, "FechaAnulacion" timestamp without time zone, "UsuarioAnulacion" character varying, "MotivoAnulacion" character varying)
 LANGUAGE plpgsql
AS $function$
BEGIN
    RETURN QUERY
    SELECT a."Id", a."NumeroAsiento", a."Fecha", a."Periodo", a."TipoAsiento",
           a."Referencia", a."Concepto", a."Moneda", a."Tasa",
           a."TotalDebe", a."TotalHaber", a."Estado",
           a."OrigenModulo", a."OrigenDocumento", a."CodUsuario",
           a."FechaCreacion", a."FechaAnulacion", a."UsuarioAnulacion", a."MotivoAnulacion"
    FROM "AsientoContable" a
    WHERE a."Id" = p_asiento_id;
END;
$function$
;

-- ============================================================
-- usp_contabilidad_asientos_list
-- ============================================================
CREATE OR REPLACE FUNCTION public.usp_contabilidad_asientos_list(p_fecha_desde date DEFAULT NULL::date, p_fecha_hasta date DEFAULT NULL::date, p_tipo_asiento character varying DEFAULT NULL::character varying, p_estado character varying DEFAULT NULL::character varying, p_origen_modulo character varying DEFAULT NULL::character varying, p_origen_documento character varying DEFAULT NULL::character varying, p_page integer DEFAULT 1, p_limit integer DEFAULT 50)
 RETURNS TABLE("TotalCount" bigint, "Id" bigint, "NumeroAsiento" character varying, "Fecha" date, "Periodo" character varying, "TipoAsiento" character varying, "Referencia" character varying, "Concepto" character varying, "Moneda" character varying, "Tasa" numeric, "TotalDebe" numeric, "TotalHaber" numeric, "Estado" character varying, "OrigenModulo" character varying, "OrigenDocumento" character varying, "CodUsuario" character varying, "FechaCreacion" timestamp without time zone, "FechaAnulacion" timestamp without time zone, "UsuarioAnulacion" character varying, "MotivoAnulacion" character varying)
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_offset INT;
    v_limit  INT;
    v_total  BIGINT;
BEGIN
    v_limit := CASE WHEN p_limit IS NULL OR p_limit < 1 THEN 50 ELSE p_limit END;
    IF v_limit > 500 THEN v_limit := 500; END IF;
    v_offset := (CASE WHEN p_page IS NULL OR p_page < 1 THEN 1 ELSE p_page END - 1) * v_limit;

    SELECT COUNT(1) INTO v_total
    FROM "AsientoContable" a
    WHERE (p_fecha_desde IS NULL OR a."Fecha" >= p_fecha_desde)
      AND (p_fecha_hasta IS NULL OR a."Fecha" <= p_fecha_hasta)
      AND (p_tipo_asiento IS NULL OR a."TipoAsiento" = p_tipo_asiento)
      AND (p_estado IS NULL OR a."Estado" = p_estado)
      AND (p_origen_modulo IS NULL OR a."OrigenModulo" = p_origen_modulo)
      AND (p_origen_documento IS NULL OR a."OrigenDocumento" = p_origen_documento);

    RETURN QUERY
    SELECT
        v_total,
        a."Id",
        a."NumeroAsiento",
        a."Fecha",
        a."Periodo",
        a."TipoAsiento",
        a."Referencia",
        a."Concepto",
        a."Moneda",
        a."Tasa",
        a."TotalDebe",
        a."TotalHaber",
        a."Estado",
        a."OrigenModulo",
        a."OrigenDocumento",
        a."CodUsuario",
        a."FechaCreacion",
        a."FechaAnulacion",
        a."UsuarioAnulacion",
        a."MotivoAnulacion"
    FROM "AsientoContable" a
    WHERE (p_fecha_desde IS NULL OR a."Fecha" >= p_fecha_desde)
      AND (p_fecha_hasta IS NULL OR a."Fecha" <= p_fecha_hasta)
      AND (p_tipo_asiento IS NULL OR a."TipoAsiento" = p_tipo_asiento)
      AND (p_estado IS NULL OR a."Estado" = p_estado)
      AND (p_origen_modulo IS NULL OR a."OrigenModulo" = p_origen_modulo)
      AND (p_origen_documento IS NULL OR a."OrigenDocumento" = p_origen_documento)
    ORDER BY a."Id" DESC
    LIMIT v_limit OFFSET v_offset;
END;
$function$
;

-- ============================================================
-- usp_contabilidad_balance_comprobacion
-- ============================================================
CREATE OR REPLACE FUNCTION public.usp_contabilidad_balance_comprobacion(p_fecha_desde date, p_fecha_hasta date)
 RETURNS TABLE("CodCuenta" character varying, "CuentaDescripcion" character varying, "TotalDebe" numeric, "TotalHaber" numeric, "SaldoDeudor" numeric, "SaldoAcreedor" numeric)
 LANGUAGE plpgsql
AS $function$
BEGIN
    RETURN QUERY
    SELECT
        d."CodCuenta",
        c."DESCRIPCION",
        SUM(d."Debe"),
        SUM(d."Haber"),
        CASE
            WHEN SUM(d."Debe" - d."Haber") > 0 THEN SUM(d."Debe" - d."Haber")
            ELSE 0::NUMERIC
        END,
        CASE
            WHEN SUM(d."Debe" - d."Haber") < 0 THEN ABS(SUM(d."Debe" - d."Haber"))
            ELSE 0::NUMERIC
        END
    FROM "AsientoContableDetalle" d
    INNER JOIN "AsientoContable" a ON a."Id" = d."AsientoId"
    LEFT JOIN "Cuentas" c ON c."COD_CUENTA" = d."CodCuenta"
    WHERE a."Estado" <> 'ANULADO'
      AND a."Fecha" BETWEEN p_fecha_desde AND p_fecha_hasta
    GROUP BY d."CodCuenta", c."DESCRIPCION"
    ORDER BY d."CodCuenta";
END;
$function$
;

-- ============================================================
-- usp_contabilidad_balance_general
-- ============================================================
CREATE OR REPLACE FUNCTION public.usp_contabilidad_balance_general(p_fecha_corte date)
 RETURNS TABLE("Grupo" character varying, "CodCuenta" character varying, "CuentaDescripcion" character varying, "Saldo" numeric)
 LANGUAGE plpgsql
AS $function$
BEGIN
    RETURN QUERY
    WITH base AS (
        SELECT
            d."CodCuenta",
            c."DESCRIPCION" AS "CuentaDescripcion",
            SUM(d."Debe" - d."Haber") AS "Saldo"
        FROM "AsientoContableDetalle" d
        INNER JOIN "AsientoContable" a ON a."Id" = d."AsientoId"
        LEFT JOIN "Cuentas" c ON c."COD_CUENTA" = d."CodCuenta"
        WHERE a."Estado" <> 'ANULADO'
          AND a."Fecha" <= p_fecha_corte
          AND (d."CodCuenta" LIKE '1%' OR d."CodCuenta" LIKE '2%' OR d."CodCuenta" LIKE '3%')
        GROUP BY d."CodCuenta", c."DESCRIPCION"
    )
    SELECT
        CASE
            WHEN b."CodCuenta" LIKE '1%' THEN 'ACTIVOS'::VARCHAR
            WHEN b."CodCuenta" LIKE '2%' THEN 'PASIVOS'::VARCHAR
            WHEN b."CodCuenta" LIKE '3%' THEN 'PATRIMONIO'::VARCHAR
            ELSE 'OTROS'::VARCHAR
        END,
        b."CodCuenta",
        b."CuentaDescripcion",
        b."Saldo"
    FROM base b
    ORDER BY b."CodCuenta";
END;
$function$
;

-- ============================================================
-- usp_contabilidad_balance_general_resumen
-- ============================================================
CREATE OR REPLACE FUNCTION public.usp_contabilidad_balance_general_resumen(p_fecha_corte date)
 RETURNS TABLE("TotalActivos" numeric, "TotalPasivos" numeric, "TotalPatrimonio" numeric)
 LANGUAGE plpgsql
AS $function$
BEGIN
    RETURN QUERY
    SELECT
        SUM(CASE WHEN d."CodCuenta" LIKE '1%' THEN (d."Debe" - d."Haber") ELSE 0 END),
        SUM(CASE WHEN d."CodCuenta" LIKE '2%' THEN (d."Haber" - d."Debe") ELSE 0 END),
        SUM(CASE WHEN d."CodCuenta" LIKE '3%' THEN (d."Haber" - d."Debe") ELSE 0 END)
    FROM "AsientoContableDetalle" d
    INNER JOIN "AsientoContable" a ON a."Id" = d."AsientoId"
    WHERE a."Estado" <> 'ANULADO'
      AND a."Fecha" <= p_fecha_corte;
END;
$function$
;

-- ============================================================
-- usp_contabilidad_depreciacion_generar
-- ============================================================
CREATE OR REPLACE FUNCTION public.usp_contabilidad_depreciacion_generar(p_periodo character varying, p_cod_usuario character varying, p_centro_costo character varying DEFAULT NULL::character varying)
 RETURNS TABLE("Resultado" integer, "Mensaje" character varying)
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_fecha        DATE;
    v_ultimo_dia   DATE;
    v_detalle_json JSONB;
    v_asiento_id   BIGINT;
    v_numero       VARCHAR(40);
    v_res          INT;
    v_msg          TEXT;
    v_concepto     VARCHAR(400);
    rec            RECORD;
BEGIN
    v_fecha      := (p_periodo || '-01')::DATE;
    v_ultimo_dia := (v_fecha + INTERVAL '1 month' - INTERVAL '1 day')::DATE;

    -- Crear tabla temporal de activos a depreciar
    CREATE TEMP TABLE _tmp_deprec (
        "ActivoId"       BIGINT,
        "CuentaGasto"    VARCHAR(40),
        "CuentaDepAcum"  VARCHAR(40),
        "CentroCosto"    VARCHAR(20),
        "Monto"          NUMERIC(18,2)
    ) ON COMMIT DROP;

    INSERT INTO _tmp_deprec ("ActivoId", "CuentaGasto", "CuentaDepAcum", "CentroCosto", "Monto")
    SELECT
        a."Id",
        a."CuentaGastoDepreciacion",
        a."CuentaDepreciacionAcum",
        COALESCE(p_centro_costo, a."CentroCosto"),
        ROUND((a."CostoAdquisicion" - a."ValorResidual") / NULLIF(a."VidaUtilMeses", 0), 2)
    FROM "ActivoFijoContable" a
    WHERE a."Activo" = TRUE
      AND a."VidaUtilMeses" > 0
      AND NOT EXISTS (
          SELECT 1 FROM "DepreciacionContable" d WHERE d."ActivoId" = a."Id" AND d."Periodo" = p_periodo
      );

    IF NOT EXISTS (SELECT 1 FROM _tmp_deprec) THEN
        RETURN QUERY SELECT 1, 'Sin activos pendientes para depreciar'::TEXT;
        RETURN;
    END IF;

    -- Construir JSON del detalle (equivalente a FOR XML PATH)
    SELECT jsonb_agg(row_to_json(x)::JSONB) INTO v_detalle_json
    FROM (
        SELECT
            t."CuentaGasto"                                AS "codCuenta",
            'Depreciacion del periodo ' || p_periodo       AS "descripcion",
            COALESCE(t."CentroCosto", 'ADM')               AS "centroCosto",
            t."Monto"                                       AS "debe",
            0::NUMERIC(18,2)                                AS "haber"
        FROM _tmp_deprec t
        UNION ALL
        SELECT
            t."CuentaDepAcum"                                       AS "codCuenta",
            'Depreciacion acumulada del periodo ' || p_periodo      AS "descripcion",
            COALESCE(t."CentroCosto", 'ADM')                        AS "centroCosto",
            0::NUMERIC(18,2)                                         AS "debe",
            t."Monto"                                                AS "haber"
        FROM _tmp_deprec t
    ) x;

    v_concepto := 'Depreciacion contable ' || p_periodo;

    SELECT * INTO rec
    FROM usp_contabilidad_asiento_crear(
        v_ultimo_dia,
        'DEP',
        p_periodo,
        v_concepto,
        'VES',
        1,
        'ACTIVOS_FIJOS',
        p_periodo,
        p_cod_usuario,
        v_detalle_json
    );

    v_asiento_id := rec."AsientoId";
    v_res        := rec."Resultado";
    v_msg        := rec."Mensaje";

    IF v_res <> 1 THEN
        RETURN QUERY SELECT v_res, v_msg;
        RETURN;
    END IF;

    INSERT INTO "DepreciacionContable" ("ActivoId", "Periodo", "Fecha", "Monto", "AsientoId", "Estado")
    SELECT "ActivoId", p_periodo, v_ultimo_dia, "Monto", v_asiento_id, 'GENERADO'
    FROM _tmp_deprec;

    RETURN QUERY SELECT 1, 'OK'::TEXT;

EXCEPTION WHEN OTHERS THEN
    RETURN QUERY SELECT -99, SQLERRM::TEXT;
END;
$function$
;

-- ============================================================
-- usp_contabilidad_estado_resultados
-- ============================================================
CREATE OR REPLACE FUNCTION public.usp_contabilidad_estado_resultados(p_fecha_desde date, p_fecha_hasta date)
 RETURNS TABLE("Grupo" character varying, "CodCuenta" character varying, "CuentaDescripcion" character varying, "Debe" numeric, "Haber" numeric, "Neto" numeric)
 LANGUAGE plpgsql
AS $function$
BEGIN
    RETURN QUERY
    WITH base AS (
        SELECT
            d."CodCuenta",
            c."DESCRIPCION" AS "CuentaDescripcion",
            SUM(d."Debe") AS "Debe",
            SUM(d."Haber") AS "Haber",
            SUM(d."Haber" - d."Debe") AS "Neto"
        FROM "AsientoContableDetalle" d
        INNER JOIN "AsientoContable" a ON a."Id" = d."AsientoId"
        LEFT JOIN "Cuentas" c ON c."COD_CUENTA" = d."CodCuenta"
        WHERE a."Estado" <> 'ANULADO'
          AND a."Fecha" BETWEEN p_fecha_desde AND p_fecha_hasta
          AND (d."CodCuenta" LIKE '4%' OR d."CodCuenta" LIKE '5%'
               OR d."CodCuenta" LIKE '6%' OR d."CodCuenta" LIKE '7%')
        GROUP BY d."CodCuenta", c."DESCRIPCION"
    )
    SELECT
        CASE
            WHEN b."CodCuenta" LIKE '4%' THEN 'INGRESOS'::VARCHAR
            WHEN b."CodCuenta" LIKE '5%' THEN 'COSTOS'::VARCHAR
            WHEN b."CodCuenta" LIKE '6%' THEN 'GASTOS'::VARCHAR
            WHEN b."CodCuenta" LIKE '7%' THEN 'CIERRE'::VARCHAR
            ELSE 'OTROS'::VARCHAR
        END,
        b."CodCuenta",
        b."CuentaDescripcion",
        b."Debe",
        b."Haber",
        b."Neto"
    FROM base b
    ORDER BY b."CodCuenta";
END;
$function$
;

-- ============================================================
-- usp_contabilidad_estado_resultados_resumen
-- ============================================================
CREATE OR REPLACE FUNCTION public.usp_contabilidad_estado_resultados_resumen(p_fecha_desde date, p_fecha_hasta date)
 RETURNS TABLE("TotalIngresos" numeric, "TotalCostos" numeric, "TotalGastos" numeric, "ResultadoNeto" numeric)
 LANGUAGE plpgsql
AS $function$
BEGIN
    RETURN QUERY
    SELECT
        SUM(CASE WHEN d."CodCuenta" LIKE '4%' THEN (d."Haber" - d."Debe") ELSE 0 END),
        SUM(CASE WHEN d."CodCuenta" LIKE '5%' THEN (d."Debe" - d."Haber") ELSE 0 END),
        SUM(CASE WHEN d."CodCuenta" LIKE '6%' THEN (d."Debe" - d."Haber") ELSE 0 END),
        SUM(CASE
            WHEN d."CodCuenta" LIKE '4%' THEN (d."Haber" - d."Debe")
            WHEN d."CodCuenta" LIKE '5%' OR d."CodCuenta" LIKE '6%' THEN -(d."Debe" - d."Haber")
            ELSE 0
        END)
    FROM "AsientoContableDetalle" d
    INNER JOIN "AsientoContable" a ON a."Id" = d."AsientoId"
    WHERE a."Estado" <> 'ANULADO'
      AND a."Fecha" BETWEEN p_fecha_desde AND p_fecha_hasta;
END;
$function$
;

-- ============================================================
-- usp_contabilidad_libro_mayor
-- ============================================================
CREATE OR REPLACE FUNCTION public.usp_contabilidad_libro_mayor(p_fecha_desde date, p_fecha_hasta date)
 RETURNS TABLE("CodCuenta" character varying, "CuentaDescripcion" character varying, "Debe" numeric, "Haber" numeric, "Saldo" numeric)
 LANGUAGE plpgsql
AS $function$
BEGIN
    RETURN QUERY
    SELECT
        d."CodCuenta",
        c."DESCRIPCION",
        SUM(d."Debe"),
        SUM(d."Haber"),
        SUM(d."Debe" - d."Haber")
    FROM "AsientoContableDetalle" d
    INNER JOIN "AsientoContable" a ON a."Id" = d."AsientoId"
    LEFT JOIN "Cuentas" c ON c."COD_CUENTA" = d."CodCuenta"
    WHERE a."Estado" <> 'ANULADO'
      AND a."Fecha" BETWEEN p_fecha_desde AND p_fecha_hasta
    GROUP BY d."CodCuenta", c."DESCRIPCION"
    ORDER BY d."CodCuenta";
END;
$function$
;

-- ============================================================
-- usp_contabilidad_mayor_analitico
-- ============================================================
CREATE OR REPLACE FUNCTION public.usp_contabilidad_mayor_analitico(p_cod_cuenta character varying, p_fecha_desde date, p_fecha_hasta date)
 RETURNS TABLE("Fecha" date, "NumeroAsiento" character varying, "Referencia" character varying, "Concepto" character varying, "Renglon" integer, "CodCuenta" character varying, "CuentaDescripcion" character varying, "CentroCosto" character varying, "AuxiliarTipo" character varying, "AuxiliarCodigo" character varying, "Documento" character varying, "Debe" numeric, "Haber" numeric)
 LANGUAGE plpgsql
AS $function$
BEGIN
    RETURN QUERY
    SELECT
        a."Fecha",
        a."NumeroAsiento",
        a."Referencia",
        a."Concepto",
        d."Renglon",
        d."CodCuenta",
        c."DESCRIPCION",
        d."CentroCosto",
        d."AuxiliarTipo",
        d."AuxiliarCodigo",
        d."Documento",
        d."Debe",
        d."Haber"
    FROM "AsientoContableDetalle" d
    INNER JOIN "AsientoContable" a ON a."Id" = d."AsientoId"
    LEFT JOIN "Cuentas" c ON c."COD_CUENTA" = d."CodCuenta"
    WHERE d."CodCuenta" = p_cod_cuenta
      AND a."Estado" <> 'ANULADO'
      AND a."Fecha" BETWEEN p_fecha_desde AND p_fecha_hasta
    ORDER BY a."Fecha", a."Id", d."Renglon";
END;
$function$
;

-- ============================================================
-- usp_cotizacion_getbynumfact
-- ============================================================
CREATE OR REPLACE FUNCTION public.usp_cotizacion_getbynumfact(p_num_fact character varying)
 RETURNS TABLE("NUM_FACT" character varying, "FECHA" date, "CODIGO" character varying, "NOMBRE" character varying, "RIF" character varying, "MONTO" numeric, "IVA" numeric, "TOTAL" numeric)
 LANGUAGE plpgsql
AS $function$
BEGIN
    RETURN QUERY
    SELECT
        ct."NUM_FACT",
        ct."FECHA",
        ct."CODIGO",
        ct."NOMBRE",
        ct."RIF",
        ct."MONTO",
        ct."IVA",
        ct."TOTAL"
    FROM public."Cotizacion" ct
    WHERE ct."NUM_FACT" = p_num_fact;
END;
$function$
;

-- ============================================================
-- usp_cotizacion_list
-- ============================================================
CREATE OR REPLACE FUNCTION public.usp_cotizacion_list(p_search character varying DEFAULT NULL::character varying, p_codigo character varying DEFAULT NULL::character varying, p_page integer DEFAULT 1, p_limit integer DEFAULT 50)
 RETURNS TABLE("NUM_FACT" character varying, "FECHA" date, "CODIGO" character varying, "NOMBRE" character varying, "RIF" character varying, "MONTO" numeric, "IVA" numeric, "TOTAL" numeric, "TotalCount" integer)
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_offset INT;
    v_limit  INT;
    v_search VARCHAR(100);
    v_total  INT;
BEGIN
    v_limit  := COALESCE(NULLIF(p_limit, 0), 50)::character varying;
    IF v_limit < 1  THEN v_limit := 50;  END IF;
    IF v_limit > 500 THEN v_limit := 500; END IF;

    v_offset := (COALESCE(NULLIF(p_page, 0), 1)::character varying - 1) * v_limit;
    IF v_offset < 0 THEN v_offset := 0; END IF;

    v_search := NULL;
    IF p_search IS NOT NULL AND TRIM(p_search) <> '' THEN
        v_search := '%' || p_search || '%';
    END IF;

    -- Conteo total
    SELECT COUNT(1) INTO v_total
    FROM public."Cotizacion" ct
    WHERE (v_search IS NULL OR (ct."NUM_FACT" ILIKE v_search OR ct."NOMBRE" ILIKE v_search OR ct."RIF" ILIKE v_search))
      AND (p_codigo IS NULL OR TRIM(p_codigo) = '' OR ct."CODIGO" = p_codigo);

    -- Resultados paginados
    RETURN QUERY
    SELECT
        ct."NUM_FACT",
        ct."FECHA",
        ct."CODIGO",
        ct."NOMBRE",
        ct."RIF",
        ct."MONTO",
        ct."IVA",
        ct."TOTAL",
        v_total AS "TotalCount"
    FROM public."Cotizacion" ct
    WHERE (v_search IS NULL OR (ct."NUM_FACT" ILIKE v_search OR ct."NOMBRE" ILIKE v_search OR ct."RIF" ILIKE v_search))
      AND (p_codigo IS NULL OR TRIM(p_codigo) = '' OR ct."CODIGO" = p_codigo)
    ORDER BY ct."FECHA" DESC
    LIMIT v_limit OFFSET v_offset;
END;
$function$
;

-- ============================================================
-- usp_cuentas_delete
-- ============================================================
CREATE OR REPLACE FUNCTION public.usp_cuentas_delete(p_cod_cuenta character varying)
 RETURNS TABLE("Resultado" integer, "Mensaje" character varying)
 LANGUAGE plpgsql
AS $function$
BEGIN
    IF NOT EXISTS (SELECT 1 FROM public."Cuentas" WHERE "COD_CUENTA" = p_cod_cuenta) THEN
        RETURN QUERY SELECT -1, 'Cuenta no encontrada'::VARCHAR(500);
        RETURN;
    END IF;

    DELETE FROM public."Cuentas" WHERE "COD_CUENTA" = p_cod_cuenta;

    RETURN QUERY SELECT 1, 'OK'::VARCHAR(500);

EXCEPTION WHEN OTHERS THEN
    RETURN QUERY SELECT -99, SQLERRM::VARCHAR(500);
END;
$function$
;

-- ============================================================
-- usp_cuentas_getbycodigo
-- ============================================================
CREATE OR REPLACE FUNCTION public.usp_cuentas_getbycodigo(p_cod_cuenta character varying)
 RETURNS TABLE("COD_CUENTA" character varying, "DESCRIPCION" character varying, "TIPO" character varying, "PRESUPUESTO" integer, "SALDO" integer, "COD_USUARIO" character varying, grupo character varying, "LINEA" character varying, "USO" character varying, "Nivel" integer, "Porcentaje" double precision)
 LANGUAGE plpgsql
AS $function$
BEGIN
    RETURN QUERY
    SELECT
        c."COD_CUENTA",
        c."DESCRIPCION",
        c."TIPO",
        c."PRESUPUESTO",
        c."SALDO",
        c."COD_USUARIO",
        c."grupo",
        c."LINEA",
        c."USO",
        c."Nivel",
        c."Porcentaje"
    FROM public."Cuentas" c
    WHERE c."COD_CUENTA" = p_cod_cuenta;
END;
$function$
;

-- ============================================================
-- usp_cuentas_insert
-- ============================================================
CREATE OR REPLACE FUNCTION public.usp_cuentas_insert(p_row_json jsonb)
 RETURNS TABLE("Resultado" integer, "Mensaje" character varying)
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_resultado INT := 0;
    v_mensaje   VARCHAR(500) := '';
BEGIN
    -- Verificar duplicado
    IF EXISTS (
        SELECT 1 FROM public."Cuentas"
        WHERE "COD_CUENTA" = (p_row_json->>'COD_CUENTA')
    ) THEN
        RETURN QUERY SELECT -1, 'Cuenta ya existe'::VARCHAR(500);
        RETURN;
    END IF;

    INSERT INTO public."Cuentas" (
        "COD_CUENTA", "DESCRIPCION", "TIPO", "PRESUPUESTO", "SALDO",
        "COD_USUARIO", "grupo", "LINEA", "USO", "Nivel", "Porcentaje"
    ) VALUES (
        NULLIF(p_row_json->>'COD_CUENTA', ''::character varying),
        NULLIF(p_row_json->>'DESCRIPCION', ''::character varying),
        NULLIF(p_row_json->>'TIPO', ''::character varying),
        CASE WHEN COALESCE(p_row_json->>'PRESUPUESTO', '') = '' THEN NULL
             ELSE (p_row_json->>'PRESUPUESTO')::INT END,
        CASE WHEN COALESCE(p_row_json->>'SALDO', '') = '' THEN NULL
             ELSE (p_row_json->>'SALDO')::INT END,
        NULLIF(p_row_json->>'COD_USUARIO', ''::character varying),
        NULLIF(p_row_json->>'grupo', ''::character varying),
        NULLIF(p_row_json->>'LINEA', ''::character varying),
        NULLIF(p_row_json->>'USO', ''::character varying),
        CASE WHEN COALESCE(p_row_json->>'Nivel', '') = '' THEN NULL
             ELSE (p_row_json->>'Nivel')::INT END,
        CASE WHEN COALESCE(p_row_json->>'Porcentaje', '') = '' THEN NULL
             ELSE (p_row_json->>'Porcentaje')::DOUBLE PRECISION END
    );

    RETURN QUERY SELECT 1, 'OK'::VARCHAR(500);

EXCEPTION WHEN OTHERS THEN
    RETURN QUERY SELECT -99, SQLERRM::VARCHAR(500);
END;
$function$
;

-- ============================================================
-- usp_cuentas_list
-- ============================================================
CREATE OR REPLACE FUNCTION public.usp_cuentas_list(p_search character varying DEFAULT NULL::character varying, p_tipo character varying DEFAULT NULL::character varying, p_grupo character varying DEFAULT NULL::character varying, p_page integer DEFAULT 1, p_limit integer DEFAULT 50)
 RETURNS TABLE("TotalCount" integer, "COD_CUENTA" character varying, "DESCRIPCION" character varying, "TIPO" character varying, "PRESUPUESTO" integer, "SALDO" integer, "COD_USUARIO" character varying, grupo character varying, "LINEA" character varying, "USO" character varying, "Nivel" integer, "Porcentaje" double precision)
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_offset   INT;
    v_limit    INT;
    v_search   VARCHAR(100);
    v_total    INT;
BEGIN
    v_limit  := COALESCE(NULLIF(p_limit, 0), 50)::character varying;
    IF v_limit < 1 THEN v_limit := 50; END IF;
    IF v_limit > 500 THEN v_limit := 500; END IF;
    v_offset := (COALESCE(NULLIF(p_page, 0), 1)::character varying - 1) * v_limit;
    IF v_offset < 0 THEN v_offset := 0; END IF;

    v_search := NULL;
    IF p_search IS NOT NULL AND TRIM(p_search) <> '' THEN
        v_search := '%' || p_search || '%';
    END IF;

    -- Contar total
    SELECT COUNT(1) INTO v_total
    FROM public."Cuentas" c
    WHERE (v_search IS NULL OR c."COD_CUENTA" LIKE v_search OR c."DESCRIPCION" LIKE v_search)
      AND (p_tipo IS NULL OR TRIM(p_tipo) = '' OR c."TIPO" = p_tipo)
      AND (p_grupo IS NULL OR TRIM(p_grupo) = '' OR c."grupo" = p_grupo);

    -- Devolver filas
    RETURN QUERY
    SELECT
        v_total,
        c."COD_CUENTA",
        c."DESCRIPCION",
        c."TIPO",
        c."PRESUPUESTO",
        c."SALDO",
        c."COD_USUARIO",
        c."grupo",
        c."LINEA",
        c."USO",
        c."Nivel",
        c."Porcentaje"
    FROM public."Cuentas" c
    WHERE (v_search IS NULL OR c."COD_CUENTA" LIKE v_search OR c."DESCRIPCION" LIKE v_search)
      AND (p_tipo IS NULL OR TRIM(p_tipo) = '' OR c."TIPO" = p_tipo)
      AND (p_grupo IS NULL OR TRIM(p_grupo) = '' OR c."grupo" = p_grupo)
    ORDER BY c."COD_CUENTA"
    LIMIT v_limit OFFSET v_offset;
END;
$function$
;

-- ============================================================
-- usp_cuentas_update
-- ============================================================
CREATE OR REPLACE FUNCTION public.usp_cuentas_update(p_cod_cuenta character varying, p_row_json jsonb)
 RETURNS TABLE("Resultado" integer, "Mensaje" character varying)
 LANGUAGE plpgsql
AS $function$
BEGIN
    IF NOT EXISTS (SELECT 1 FROM public."Cuentas" WHERE "COD_CUENTA" = p_cod_cuenta) THEN
        RETURN QUERY SELECT -1, 'Cuenta no encontrada'::VARCHAR(500);
        RETURN;
    END IF;

    UPDATE public."Cuentas" SET
        "DESCRIPCION" = COALESCE(NULLIF(p_row_json->>'DESCRIPCION', ''::character varying), "DESCRIPCION")::character varying,
        "TIPO"        = COALESCE(NULLIF(p_row_json->>'TIPO', ''::character varying), "TIPO")::character varying,
        "grupo"       = COALESCE(NULLIF(p_row_json->>'grupo', ''::character varying), "grupo")::character varying,
        "LINEA"       = COALESCE(NULLIF(p_row_json->>'LINEA', ''::character varying), "LINEA")::character varying,
        "USO"         = COALESCE(NULLIF(p_row_json->>'USO', ''::character varying), "USO")::character varying,
        "Nivel"       = CASE WHEN COALESCE(p_row_json->>'Nivel', '') = '' THEN "Nivel"
                             ELSE (p_row_json->>'Nivel')::INT END,
        "Porcentaje"  = CASE WHEN COALESCE(p_row_json->>'Porcentaje', '') = '' THEN "Porcentaje"
                             ELSE (p_row_json->>'Porcentaje')::DOUBLE PRECISION END
    WHERE "COD_CUENTA" = p_cod_cuenta;

    RETURN QUERY SELECT 1, 'OK'::VARCHAR(500);

EXCEPTION WHEN OTHERS THEN
    RETURN QUERY SELECT -99, SQLERRM::VARCHAR(500);
END;
$function$
;

-- ============================================================
-- usp_cxc_aplicar_cobro
-- ============================================================
CREATE OR REPLACE FUNCTION public.usp_cxc_aplicar_cobro(p_request_id character varying, p_cod_cliente character varying, p_fecha character varying, p_monto_total numeric, p_cod_usuario character varying, p_observaciones character varying DEFAULT ''::character varying, p_documentos_json jsonb DEFAULT NULL::jsonb, p_formas_pago_json jsonb DEFAULT NULL::jsonb)
 RETURNS TABLE("NumRecibo" character varying, "Resultado" integer, "Mensaje" character varying)
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_resultado     INT := 0;
    v_mensaje       VARCHAR(500) := '';
    v_num_recibo    VARCHAR(50) := '';
    v_fecha_date    DATE;
    v_customer_id   BIGINT;
    v_receivable_id BIGINT;
    v_pending       NUMERIC(18,2);
    v_total         NUMERIC(18,2);
    v_apply         NUMERIC(18,2);
    v_applied_total NUMERIC(18,2) := 0;
    v_doc           RECORD;
    v_dup_ref       VARCHAR(150);
BEGIN
    -- -------------------------------------------------------
    -- Validar fecha
    -- -------------------------------------------------------
    BEGIN
        v_fecha_date := p_fecha::DATE;
    EXCEPTION WHEN OTHERS THEN
        RETURN QUERY SELECT
            ''::VARCHAR(50),
            -91,
            ('Fecha invalida: ' || COALESCE(p_fecha, 'NULL'))::VARCHAR(500);
        RETURN;
    END;

    -- -------------------------------------------------------
    -- Buscar cliente
    -- -------------------------------------------------------
    SELECT c."CustomerId"
      INTO v_customer_id
      FROM master."Customer" c
     WHERE c."CustomerCode" = p_cod_cliente
       AND c."IsDeleted" = FALSE
     LIMIT 1;

    IF v_customer_id IS NULL THEN
        RETURN QUERY SELECT
            ''::VARCHAR(50),
            -1,
            ('Cliente no encontrado: ' || p_cod_cliente)::VARCHAR(500);
        RETURN;
    END IF;

    -- -------------------------------------------------------
    -- Validar JSON de documentos
    -- -------------------------------------------------------
    IF p_documentos_json IS NULL THEN
        RETURN QUERY SELECT
            ''::VARCHAR(50),
            -2,
            'DocumentosJson invalido'::VARCHAR(500);
        RETURN;
    END IF;

    -- Verificar que haya al menos un documento valido
    IF NOT EXISTS (
        SELECT 1
          FROM jsonb_array_elements(p_documentos_json) AS elem
         WHERE COALESCE(NULLIF(elem->>'numDoc', ''::character varying), '')::character varying <> ''
    ) THEN
        RETURN QUERY SELECT
            ''::VARCHAR(50),
            -3,
            'No se recibieron documentos validos para aplicar'::VARCHAR(500);
        RETURN;
    END IF;

    -- -------------------------------------------------------
    -- Generar numero de recibo
    -- -------------------------------------------------------
    v_num_recibo := 'RCB-' || TO_CHAR(NOW() AT TIME ZONE 'UTC', 'YYYYMMDDHH24MISS');

    -- -------------------------------------------------------
    -- Idempotencia: verificar si ya se proceso este RequestId
    -- -------------------------------------------------------
    SELECT SUBSTRING(ra."PaymentReference" FROM POSITION(':' IN ra."PaymentReference") + 1)
      INTO v_dup_ref
      FROM ar."ReceivableApplication" ra
     INNER JOIN ar."ReceivableDocument" rd
        ON rd."ReceivableDocumentId" = ra."ReceivableDocumentId"
     WHERE rd."CustomerId" = v_customer_id
       AND ra."PaymentReference" LIKE p_request_id || ':%'
     ORDER BY ra."ReceivableApplicationId" DESC
     LIMIT 1;

    IF v_dup_ref IS NOT NULL THEN
        RETURN QUERY SELECT
            v_dup_ref::VARCHAR(50),
            1,
            ('Duplicado idempotente. Recibo: ' || COALESCE(v_dup_ref, ''))::VARCHAR(500);
        RETURN;
    END IF;

    -- -------------------------------------------------------
    -- Iterar documentos y aplicar cobros
    -- -------------------------------------------------------
    FOR v_doc IN
        SELECT
            UPPER(COALESCE(NULLIF(elem->>'tipoDoc', ''::character varying), 'FACT')::character varying)::character varying AS tipo_doc,
            COALESCE(NULLIF(elem->>'numDoc', ''::character varying), '')::character varying             AS num_doc,
            COALESCE(NULLIF(elem->>'montoAplicar', ''::character varying), '0')::character varying::NUMERIC(18,2) AS monto_aplicar
          FROM jsonb_array_elements(p_documentos_json) AS elem
         WHERE COALESCE(NULLIF(elem->>'numDoc', ''::character varying), '')::character varying <> ''
    LOOP
        -- Buscar documento pendiente
        SELECT rd."ReceivableDocumentId",
               rd."PendingAmount",
               rd."TotalAmount"
          INTO v_receivable_id, v_pending, v_total
          FROM ar."ReceivableDocument" rd
         WHERE rd."CustomerId" = v_customer_id
           AND rd."DocumentType" = v_doc.tipo_doc
           AND rd."DocumentNumber" = v_doc.num_doc
           AND rd."Status" <> 'VOIDED'
         ORDER BY rd."ReceivableDocumentId" DESC
         LIMIT 1
           FOR UPDATE;

        IF v_receivable_id IS NOT NULL AND v_pending > 0 AND v_doc.monto_aplicar > 0 THEN
            v_apply := LEAST(v_doc.monto_aplicar, v_pending);

            INSERT INTO ar."ReceivableApplication" (
                "ReceivableDocumentId",
                "ApplyDate",
                "AppliedAmount",
                "PaymentReference"
            )
            VALUES (
                v_receivable_id,
                v_fecha_date,
                v_apply,
                p_request_id || ':' || v_num_recibo
            );

            UPDATE ar."ReceivableDocument"
               SET "PendingAmount" = CASE
                       WHEN "PendingAmount" - v_apply < 0 THEN 0
                       ELSE "PendingAmount" - v_apply
                   END,
                   "PaidFlag" = CASE
                       WHEN "PendingAmount" - v_apply <= 0 THEN TRUE
                       ELSE FALSE
                   END,
                   "Status" = CASE
                       WHEN "PendingAmount" - v_apply <= 0 THEN 'PAID'
                       WHEN "PendingAmount" - v_apply < "TotalAmount" THEN 'PARTIAL'
                       ELSE 'PENDING'
                   END,
                   "UpdatedAt" = NOW() AT TIME ZONE 'UTC'
             WHERE "ReceivableDocumentId" = v_receivable_id;

            v_applied_total := v_applied_total + v_apply;
        END IF;

        -- Limpiar variables para siguiente iteracion
        v_receivable_id := NULL;
        v_pending := NULL;
        v_total := NULL;
        v_apply := NULL;
    END LOOP;

    -- -------------------------------------------------------
    -- Verificar que se haya aplicado algo
    -- -------------------------------------------------------
    IF v_applied_total <= 0 THEN
        RAISE EXCEPTION 'No se aplico ningun monto'
            USING ERRCODE = 'P0001';
    END IF;

    -- -------------------------------------------------------
    -- Actualizar saldo total del cliente
    -- -------------------------------------------------------
    UPDATE master."Customer"
       SET "TotalBalance" = (
               SELECT COALESCE(SUM("PendingAmount"), 0)
                 FROM ar."ReceivableDocument"
                WHERE "CustomerId" = v_customer_id
                  AND "Status" <> 'VOIDED'
           ),
           "UpdatedAt" = NOW() AT TIME ZONE 'UTC'
     WHERE "CustomerId" = v_customer_id;

    -- -------------------------------------------------------
    -- Retornar resultado exitoso
    -- -------------------------------------------------------
    v_resultado := 1;
    v_mensaje := 'Cobro aplicado exitosamente. Recibo: ' || v_num_recibo;

    RETURN QUERY SELECT
        v_num_recibo::VARCHAR(50),
        v_resultado,
        v_mensaje::VARCHAR(500);

EXCEPTION WHEN OTHERS THEN
    v_resultado := -99;
    v_mensaje := SQLERRM;

    RETURN QUERY SELECT
        ''::VARCHAR(50),
        v_resultado,
        v_mensaje::VARCHAR(500);
END;
$function$
;

-- ============================================================
-- usp_cxp_aplicar_pago
-- ============================================================
CREATE OR REPLACE FUNCTION public.usp_cxp_aplicar_pago(p_request_id character varying, p_cod_proveedor character varying, p_fecha character varying, p_monto_total numeric, p_cod_usuario character varying, p_observaciones character varying DEFAULT ''::character varying, p_documentos_json jsonb DEFAULT NULL::jsonb, p_formas_pago_json jsonb DEFAULT NULL::jsonb)
 RETURNS TABLE("NumPago" character varying, "Resultado" integer, "Mensaje" character varying)
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_resultado     INT := 0;
    v_mensaje       VARCHAR(500) := '';
    v_num_pago      VARCHAR(50) := '';
    v_fecha_date    DATE;
    v_supplier_id   BIGINT;
    v_payable_id    BIGINT;
    v_pending       NUMERIC(18,2);
    v_total         NUMERIC(18,2);
    v_apply         NUMERIC(18,2);
    v_applied_total NUMERIC(18,2) := 0;
    v_doc           RECORD;
    v_dup_ref       VARCHAR(150);
BEGIN
    -- -------------------------------------------------------
    -- Validar fecha
    -- -------------------------------------------------------
    BEGIN
        v_fecha_date := p_fecha::DATE;
    EXCEPTION WHEN OTHERS THEN
        RETURN QUERY SELECT
            ''::VARCHAR(50),
            -91,
            ('Fecha invalida: ' || COALESCE(p_fecha, 'NULL'))::VARCHAR(500);
        RETURN;
    END;

    -- -------------------------------------------------------
    -- Buscar proveedor
    -- -------------------------------------------------------
    SELECT s."SupplierId"
      INTO v_supplier_id
      FROM master."Supplier" s
     WHERE s."SupplierCode" = p_cod_proveedor
       AND s."IsDeleted" = FALSE
     LIMIT 1;

    IF v_supplier_id IS NULL THEN
        RETURN QUERY SELECT
            ''::VARCHAR(50),
            -1,
            ('Proveedor no encontrado: ' || p_cod_proveedor)::VARCHAR(500);
        RETURN;
    END IF;

    -- -------------------------------------------------------
    -- Validar JSON de documentos
    -- -------------------------------------------------------
    IF p_documentos_json IS NULL THEN
        RETURN QUERY SELECT
            ''::VARCHAR(50),
            -2,
            'DocumentosJson invalido'::VARCHAR(500);
        RETURN;
    END IF;

    -- Verificar que haya al menos un documento valido
    IF NOT EXISTS (
        SELECT 1
          FROM jsonb_array_elements(p_documentos_json) AS elem
         WHERE COALESCE(NULLIF(elem->>'numDoc', ''::character varying), '')::character varying <> ''
    ) THEN
        RETURN QUERY SELECT
            ''::VARCHAR(50),
            -3,
            'No se recibieron documentos validos para aplicar'::VARCHAR(500);
        RETURN;
    END IF;

    -- -------------------------------------------------------
    -- Generar numero de pago
    -- -------------------------------------------------------
    v_num_pago := 'PAG-' || TO_CHAR(NOW() AT TIME ZONE 'UTC', 'YYYYMMDDHH24MISS');

    -- -------------------------------------------------------
    -- Idempotencia: verificar si ya se proceso este RequestId
    -- -------------------------------------------------------
    SELECT SUBSTRING(pa."PaymentReference" FROM POSITION(':' IN pa."PaymentReference") + 1)
      INTO v_dup_ref
      FROM ap."PayableApplication" pa
     INNER JOIN ap."PayableDocument" pd
        ON pd."PayableDocumentId" = pa."PayableDocumentId"
     WHERE pd."SupplierId" = v_supplier_id
       AND pa."PaymentReference" LIKE p_request_id || ':%'
     ORDER BY pa."PayableApplicationId" DESC
     LIMIT 1;

    IF v_dup_ref IS NOT NULL THEN
        RETURN QUERY SELECT
            v_dup_ref::VARCHAR(50),
            1,
            ('Duplicado idempotente. Pago: ' || COALESCE(v_dup_ref, ''))::VARCHAR(500);
        RETURN;
    END IF;

    -- -------------------------------------------------------
    -- Iterar documentos y aplicar pagos
    -- -------------------------------------------------------
    FOR v_doc IN
        SELECT
            UPPER(COALESCE(NULLIF(elem->>'tipoDoc', ''::character varying), 'COMPRA')::character varying)::character varying AS tipo_doc,
            COALESCE(NULLIF(elem->>'numDoc', ''::character varying), '')::character varying               AS num_doc,
            COALESCE(NULLIF(elem->>'montoAplicar', ''::character varying), '0')::character varying::NUMERIC(18,2) AS monto_aplicar
          FROM jsonb_array_elements(p_documentos_json) AS elem
         WHERE COALESCE(NULLIF(elem->>'numDoc', ''::character varying), '')::character varying <> ''
    LOOP
        -- Buscar documento pendiente
        SELECT pd."PayableDocumentId",
               pd."PendingAmount",
               pd."TotalAmount"
          INTO v_payable_id, v_pending, v_total
          FROM ap."PayableDocument" pd
         WHERE pd."SupplierId" = v_supplier_id
           AND pd."DocumentType" = v_doc.tipo_doc
           AND pd."DocumentNumber" = v_doc.num_doc
           AND pd."Status" <> 'VOIDED'
         ORDER BY pd."PayableDocumentId" DESC
         LIMIT 1
           FOR UPDATE;

        IF v_payable_id IS NOT NULL AND v_pending > 0 AND v_doc.monto_aplicar > 0 THEN
            v_apply := LEAST(v_doc.monto_aplicar, v_pending);

            INSERT INTO ap."PayableApplication" (
                "PayableDocumentId",
                "ApplyDate",
                "AppliedAmount",
                "PaymentReference"
            )
            VALUES (
                v_payable_id,
                v_fecha_date,
                v_apply,
                p_request_id || ':' || v_num_pago
            );

            UPDATE ap."PayableDocument"
               SET "PendingAmount" = CASE
                       WHEN "PendingAmount" - v_apply < 0 THEN 0
                       ELSE "PendingAmount" - v_apply
                   END,
                   "PaidFlag" = CASE
                       WHEN "PendingAmount" - v_apply <= 0 THEN TRUE
                       ELSE FALSE
                   END,
                   "Status" = CASE
                       WHEN "PendingAmount" - v_apply <= 0 THEN 'PAID'
                       WHEN "PendingAmount" - v_apply < "TotalAmount" THEN 'PARTIAL'
                       ELSE 'PENDING'
                   END,
                   "UpdatedAt" = NOW() AT TIME ZONE 'UTC'
             WHERE "PayableDocumentId" = v_payable_id;

            v_applied_total := v_applied_total + v_apply;
        END IF;

        -- Limpiar variables para siguiente iteracion
        v_payable_id := NULL;
        v_pending := NULL;
        v_total := NULL;
        v_apply := NULL;
    END LOOP;

    -- -------------------------------------------------------
    -- Verificar que se haya aplicado algo
    -- -------------------------------------------------------
    IF v_applied_total <= 0 THEN
        RAISE EXCEPTION 'No se aplico ningun monto'
            USING ERRCODE = 'P0001';
    END IF;

    -- -------------------------------------------------------
    -- Actualizar saldo total del proveedor
    -- -------------------------------------------------------
    UPDATE master."Supplier"
       SET "TotalBalance" = (
               SELECT COALESCE(SUM("PendingAmount"), 0)
                 FROM ap."PayableDocument"
                WHERE "SupplierId" = v_supplier_id
                  AND "Status" <> 'VOIDED'
           ),
           "UpdatedAt" = NOW() AT TIME ZONE 'UTC'
     WHERE "SupplierId" = v_supplier_id;

    -- -------------------------------------------------------
    -- Retornar resultado exitoso
    -- -------------------------------------------------------
    v_resultado := 1;
    v_mensaje := 'Pago aplicado exitosamente. Pago: ' || v_num_pago;

    RETURN QUERY SELECT
        v_num_pago::VARCHAR(50),
        v_resultado,
        v_mensaje::VARCHAR(500);

EXCEPTION WHEN OTHERS THEN
    v_resultado := -99;
    v_mensaje := SQLERRM;

    RETURN QUERY SELECT
        ''::VARCHAR(50),
        v_resultado,
        v_mensaje::VARCHAR(500);
END;
$function$
;

-- ============================================================
-- usp_doc_purchasedocument_convertorder
-- ============================================================
CREATE OR REPLACE FUNCTION public.usp_doc_purchasedocument_convertorder(p_num_doc_orden character varying, p_num_doc_compra character varying, p_compra_override_json jsonb DEFAULT NULL::jsonb, p_detalle_json jsonb DEFAULT NULL::jsonb, p_cod_usuario character varying DEFAULT 'API'::character varying)
 RETURNS TABLE(ok boolean, orden character varying, compra character varying, "detalleRows" integer, "formasPagoRows" integer, "pendingAmount" double precision, mensaje character varying)
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_ok              BOOLEAN := FALSE;
    v_detalle_rows    INT := 0;
    v_formas_pago_rows INT := 0;
    v_pending_amount  DOUBLE PRECISION := 0;
    v_total_amount    DOUBLE PRECISION;
    v_supplier_code   VARCHAR(60);
    v_is_paid         VARCHAR(1);
    v_doc_date        TIMESTAMP;
    v_notes           VARCHAR(500);
    v_company_id      INT;
    v_branch_id       INT;
    v_user_id         INT;
    v_supplier_id     BIGINT;
    v_safe_pending    DOUBLE PRECISION;
    v_status          VARCHAR(20);
    v_existing_id     BIGINT;
BEGIN
    -- Validate params
    IF p_num_doc_orden IS NULL OR TRIM(p_num_doc_orden) = '' THEN
        RETURN QUERY SELECT FALSE, p_num_doc_orden, p_num_doc_compra, 0, 0, 0::DOUBLE PRECISION,
                     'Numero de orden requerido (@NumDocOrden)'::VARCHAR;
        RETURN;
    END IF;

    IF p_num_doc_compra IS NULL OR TRIM(p_num_doc_compra) = '' THEN
        RETURN QUERY SELECT FALSE, p_num_doc_orden, p_num_doc_compra, 0, 0, 0::DOUBLE PRECISION,
                     'Numero de compra requerido (@NumDocCompra)'::VARCHAR;
        RETURN;
    END IF;

    IF NOT EXISTS (SELECT 1 FROM doc."PurchaseDocument" WHERE "DocumentNumber" = p_num_doc_orden AND "DocumentType" = 'ORDEN' AND "IsDeleted" = FALSE) THEN
        RETURN QUERY SELECT FALSE, p_num_doc_orden, p_num_doc_compra, 0, 0, 0::DOUBLE PRECISION,
                     ('Orden de compra no encontrada: ' || p_num_doc_orden)::VARCHAR;
        RETURN;
    END IF;

    IF EXISTS (SELECT 1 FROM doc."PurchaseDocument" WHERE "DocumentNumber" = p_num_doc_orden AND "DocumentType" = 'ORDEN' AND "IsDeleted" = FALSE AND "IsVoided" = TRUE) THEN
        RETURN QUERY SELECT FALSE, p_num_doc_orden, p_num_doc_compra, 0, 0, 0::DOUBLE PRECISION,
                     ('La orden esta anulada y no puede convertirse: ' || p_num_doc_orden)::VARCHAR;
        RETURN;
    END IF;

    -- 1. Delete existing purchase (idempotent)
    DELETE FROM doc."PurchaseDocumentPayment" WHERE "DocumentNumber" = p_num_doc_compra AND "DocumentType" = 'COMPRA';
    DELETE FROM doc."PurchaseDocumentLine" WHERE "DocumentNumber" = p_num_doc_compra AND "DocumentType" = 'COMPRA';
    DELETE FROM doc."PurchaseDocument" WHERE "DocumentNumber" = p_num_doc_compra AND "DocumentType" = 'COMPRA';

    -- 2. Copy header from order with overrides
    INSERT INTO doc."PurchaseDocument" (
        "DocumentNumber", "SerialType", "DocumentType",
        "SupplierCode", "SupplierName", "FiscalId",
        "IssueDate", "DueDate", "ReceiptDate", "PaymentDate", "DocumentTime",
        "SubTotal", "TaxableAmount", "ExemptAmount", "TaxAmount", "TaxRate",
        "TotalAmount", "DiscountAmount",
        "IsVoided", "IsPaid", "IsReceived", "IsLegal",
        "OriginDocumentNumber", "ControlNumber",
        "VoucherNumber", "VoucherDate", "RetainedTax",
        "IsrCode", "IsrAmount", "IsrSubjectCode", "IsrSubjectAmount", "RetentionRate",
        "ImportAmount", "ImportTax", "ImportBase", "FreightAmount",
        "Notes", "Concept", "OrderNumber", "ReceivedBy", "WarehouseCode",
        "CurrencyCode", "ExchangeRate", "UsdAmount",
        "UserCode", "ShortUserCode", "ReportDate", "HostName",
        "CreatedAt", "UpdatedAt"
    )
    SELECT
        p_num_doc_compra,
        o."SerialType",
        'COMPRA',
        COALESCE(CASE WHEN p_compra_override_json IS NOT NULL THEN p_compra_override_json->>'SupplierCode' END, o."SupplierCode"),
        COALESCE(CASE WHEN p_compra_override_json IS NOT NULL THEN p_compra_override_json->>'SupplierName' END, o."SupplierName"),
        COALESCE(CASE WHEN p_compra_override_json IS NOT NULL THEN p_compra_override_json->>'FiscalId' END, o."FiscalId"),
        COALESCE(CASE WHEN p_compra_override_json IS NOT NULL THEN (p_compra_override_json->>'IssueDate')::TIMESTAMP END, NOW() AT TIME ZONE 'UTC'),
        COALESCE(CASE WHEN p_compra_override_json IS NOT NULL THEN (p_compra_override_json->>'DueDate')::TIMESTAMP END, o."DueDate"),
        COALESCE(CASE WHEN p_compra_override_json IS NOT NULL THEN (p_compra_override_json->>'ReceiptDate')::TIMESTAMP END, o."ReceiptDate"),
        COALESCE(CASE WHEN p_compra_override_json IS NOT NULL THEN (p_compra_override_json->>'PaymentDate')::TIMESTAMP END, o."PaymentDate"),
        COALESCE(CASE WHEN p_compra_override_json IS NOT NULL THEN p_compra_override_json->>'DocumentTime' END, TO_CHAR(NOW() AT TIME ZONE 'UTC', 'HH24:MI:SS')),
        COALESCE(CASE WHEN p_compra_override_json IS NOT NULL THEN (p_compra_override_json->>'SubTotal')::DOUBLE PRECISION END, o."SubTotal"),
        COALESCE(CASE WHEN p_compra_override_json IS NOT NULL THEN (p_compra_override_json->>'TaxableAmount')::DOUBLE PRECISION END, o."TaxableAmount"),
        COALESCE(CASE WHEN p_compra_override_json IS NOT NULL THEN (p_compra_override_json->>'ExemptAmount')::DOUBLE PRECISION END, o."ExemptAmount"),
        COALESCE(CASE WHEN p_compra_override_json IS NOT NULL THEN (p_compra_override_json->>'TaxAmount')::DOUBLE PRECISION END, o."TaxAmount"),
        COALESCE(CASE WHEN p_compra_override_json IS NOT NULL THEN (p_compra_override_json->>'TaxRate')::DOUBLE PRECISION END, o."TaxRate"),
        COALESCE(CASE WHEN p_compra_override_json IS NOT NULL THEN (p_compra_override_json->>'TotalAmount')::DOUBLE PRECISION END, o."TotalAmount"),
        COALESCE(CASE WHEN p_compra_override_json IS NOT NULL THEN (p_compra_override_json->>'DiscountAmount')::DOUBLE PRECISION END, o."DiscountAmount"),
        FALSE,
        COALESCE(CASE WHEN p_compra_override_json IS NOT NULL THEN p_compra_override_json->>'IsPaid' END, 'N'),
        'N',
        COALESCE(CASE WHEN p_compra_override_json IS NOT NULL THEN (p_compra_override_json->>'IsLegal')::BOOLEAN END, o."IsLegal"),
        p_num_doc_orden,
        COALESCE(CASE WHEN p_compra_override_json IS NOT NULL THEN p_compra_override_json->>'ControlNumber' END, o."ControlNumber"),
        o."VoucherNumber", o."VoucherDate", o."RetainedTax",
        o."IsrCode", o."IsrAmount", o."IsrSubjectCode", o."IsrSubjectAmount", o."RetentionRate",
        o."ImportAmount", o."ImportTax", o."ImportBase", o."FreightAmount",
        COALESCE(CASE WHEN p_compra_override_json IS NOT NULL THEN p_compra_override_json->>'Notes' END, o."Notes"),
        o."Concept", o."OrderNumber", o."ReceivedBy",
        COALESCE(CASE WHEN p_compra_override_json IS NOT NULL THEN p_compra_override_json->>'WarehouseCode' END, o."WarehouseCode"),
        COALESCE(o."CurrencyCode", 'BS'),
        COALESCE(o."ExchangeRate", 1),
        o."UsdAmount",
        p_cod_usuario,
        o."ShortUserCode",
        NOW() AT TIME ZONE 'UTC',
        inet_client_addr()::TEXT,
        NOW() AT TIME ZONE 'UTC',
        NOW() AT TIME ZONE 'UTC'
    FROM doc."PurchaseDocument" o
    WHERE o."DocumentNumber" = p_num_doc_orden AND o."DocumentType" = 'ORDEN' AND o."IsDeleted" = FALSE;

    -- 3. Copy detail lines (from JSONB or from order)
    IF p_detalle_json IS NOT NULL AND jsonb_array_length(p_detalle_json) > 0 THEN
        INSERT INTO doc."PurchaseDocumentLine" (
            "DocumentNumber", "DocumentType", "LineNumber",
            "ProductCode", "Description",
            "Quantity", "UnitPrice", "UnitCost",
            "SubTotal", "DiscountAmount", "TotalAmount",
            "TaxRate", "TaxAmount",
            "IsVoided", "UserCode", "LineDate",
            "CreatedAt", "UpdatedAt"
        )
        SELECT
            p_num_doc_compra, 'COMPRA',
            (r->>'LineNumber')::INT,
            r->>'ProductCode',
            r->>'Description',
            COALESCE((r->>'Quantity')::DOUBLE PRECISION, 0),
            COALESCE((r->>'UnitPrice')::DOUBLE PRECISION, 0),
            COALESCE((r->>'UnitCost')::DOUBLE PRECISION, 0),
            COALESCE((r->>'SubTotal')::DOUBLE PRECISION, 0),
            COALESCE((r->>'DiscountAmount')::DOUBLE PRECISION, 0),
            COALESCE((r->>'TotalAmount')::DOUBLE PRECISION, 0),
            COALESCE((r->>'TaxRate')::DOUBLE PRECISION, 0),
            COALESCE((r->>'TaxAmount')::DOUBLE PRECISION, 0),
            COALESCE((r->>'IsVoided')::BOOLEAN, FALSE),
            p_cod_usuario,
            NOW() AT TIME ZONE 'UTC',
            NOW() AT TIME ZONE 'UTC',
            NOW() AT TIME ZONE 'UTC'
        FROM jsonb_array_elements(p_detalle_json) AS r;

        GET DIAGNOSTICS v_detalle_rows = ROW_COUNT;
    ELSE
        INSERT INTO doc."PurchaseDocumentLine" (
            "DocumentNumber", "DocumentType", "LineNumber",
            "ProductCode", "Description",
            "Quantity", "UnitPrice", "UnitCost",
            "SubTotal", "DiscountAmount", "TotalAmount",
            "TaxRate", "TaxAmount",
            "IsVoided", "UserCode", "LineDate",
            "CreatedAt", "UpdatedAt"
        )
        SELECT
            p_num_doc_compra, 'COMPRA',
            ol."LineNumber", ol."ProductCode", ol."Description",
            ol."Quantity", ol."UnitPrice", ol."UnitCost",
            ol."SubTotal", ol."DiscountAmount", ol."TotalAmount",
            ol."TaxRate", ol."TaxAmount",
            FALSE, p_cod_usuario, NOW() AT TIME ZONE 'UTC',
            NOW() AT TIME ZONE 'UTC', NOW() AT TIME ZONE 'UTC'
        FROM doc."PurchaseDocumentLine" ol
        WHERE ol."DocumentNumber" = p_num_doc_orden AND ol."DocumentType" = 'ORDEN' AND ol."IsDeleted" = FALSE;

        GET DIAGNOSTICS v_detalle_rows = ROW_COUNT;
    END IF;

    IF v_detalle_rows = 0 THEN
        RAISE EXCEPTION 'La orden no tiene lineas de detalle: %', p_num_doc_orden;
    END IF;

    -- 4. Mark order as received
    UPDATE doc."PurchaseDocument"
    SET "IsReceived" = 'S',
        "Notes" = COALESCE("Notes", '') || ' | Convertida a compra ' || p_num_doc_compra
                  || ' el ' || TO_CHAR(NOW() AT TIME ZONE 'UTC', 'YYYY-MM-DD HH24:MI') || ' por ' || p_cod_usuario,
        "UpdatedAt" = NOW() AT TIME ZONE 'UTC'
    WHERE "DocumentNumber" = p_num_doc_orden AND "DocumentType" = 'ORDEN' AND "IsDeleted" = FALSE;

    -- 5. Sync ap."PayableDocument"
    SELECT "TotalAmount", "SupplierCode", COALESCE("IsPaid", 'N'), "IssueDate", "Notes"
    INTO v_total_amount, v_supplier_code, v_is_paid, v_doc_date, v_notes
    FROM doc."PurchaseDocument"
    WHERE "DocumentNumber" = p_num_doc_compra AND "DocumentType" = 'COMPRA';

    v_pending_amount := CASE WHEN UPPER(v_is_paid)::character varying = 'S' THEN 0 ELSE v_total_amount END;

    IF v_supplier_code IS NOT NULL AND TRIM(v_supplier_code) <> '' THEN
        SELECT c."CompanyId" INTO v_company_id FROM cfg."Company" c
        WHERE c."IsDeleted" = FALSE AND c."IsActive" = TRUE
        ORDER BY CASE WHEN c."CompanyCode" = 'DEFAULT' THEN 0 ELSE 1 END, c."CompanyId" LIMIT 1;

        SELECT b."BranchId" INTO v_branch_id FROM cfg."Branch" b
        WHERE b."CompanyId" = v_company_id AND b."IsDeleted" = FALSE AND b."IsActive" = TRUE
        ORDER BY CASE WHEN b."BranchCode" = 'MAIN' THEN 0 ELSE 1 END, b."BranchId" LIMIT 1;

        SELECT u."UserId" INTO v_user_id FROM sec."User" u
        WHERE u."UserCode" = p_cod_usuario AND u."IsDeleted" = FALSE LIMIT 1;

        SELECT s."SupplierId" INTO v_supplier_id FROM master."Supplier" s
        WHERE s."SupplierCode" = v_supplier_code AND s."CompanyId" = v_company_id AND s."IsDeleted" = FALSE LIMIT 1;

        IF v_supplier_id IS NOT NULL AND v_company_id IS NOT NULL AND v_branch_id IS NOT NULL THEN
            v_safe_pending := CASE WHEN v_pending_amount < 0 THEN 0 ELSE v_pending_amount END;
            v_status := CASE
                WHEN v_safe_pending <= 0 THEN 'PAID'
                WHEN v_safe_pending < v_total_amount THEN 'PARTIAL'
                ELSE 'PENDING'
            END;

            SELECT pd."PayableDocumentId" INTO v_existing_id FROM ap."PayableDocument" pd
            WHERE pd."CompanyId" = v_company_id AND pd."BranchId" = v_branch_id
              AND pd."DocumentType" = 'COMPRA' AND pd."DocumentNumber" = p_num_doc_compra LIMIT 1;

            IF v_existing_id IS NOT NULL THEN
                UPDATE ap."PayableDocument"
                SET "SupplierId" = v_supplier_id, "IssueDate" = v_doc_date, "DueDate" = v_doc_date,
                    "TotalAmount" = v_total_amount, "PendingAmount" = v_safe_pending,
                    "PaidFlag" = CASE WHEN v_safe_pending <= 0 THEN TRUE ELSE FALSE END,
                    "Status" = v_status, "Notes" = v_notes,
                    "UpdatedAt" = NOW() AT TIME ZONE 'UTC', "UpdatedByUserId" = v_user_id
                WHERE "PayableDocumentId" = v_existing_id;
            ELSE
                INSERT INTO ap."PayableDocument" (
                    "CompanyId", "BranchId", "SupplierId", "DocumentType", "DocumentNumber",
                    "IssueDate", "DueDate", "CurrencyCode", "TotalAmount", "PendingAmount",
                    "PaidFlag", "Status", "Notes",
                    "CreatedAt", "UpdatedAt", "CreatedByUserId", "UpdatedByUserId"
                )
                VALUES (
                    v_company_id, v_branch_id, v_supplier_id, 'COMPRA', p_num_doc_compra,
                    v_doc_date, v_doc_date, 'USD', v_total_amount, v_safe_pending,
                    CASE WHEN v_safe_pending <= 0 THEN TRUE ELSE FALSE END,
                    v_status, v_notes,
                    NOW() AT TIME ZONE 'UTC', NOW() AT TIME ZONE 'UTC', v_user_id, v_user_id
                );
            END IF;

            PERFORM usp_master_supplier_updatebalance(v_supplier_id, v_user_id);
        END IF;
    END IF;

    v_ok := TRUE;

    RETURN QUERY SELECT v_ok, p_num_doc_orden, p_num_doc_compra,
                        v_detalle_rows, v_formas_pago_rows, v_pending_amount, ''::VARCHAR;
END;
$function$
;

-- ============================================================
-- usp_doc_purchasedocument_get
-- ============================================================
CREATE OR REPLACE FUNCTION public.usp_doc_purchasedocument_get(p_tipo_operacion character varying, p_num_doc character varying)
 RETURNS TABLE("PurchaseDocumentId" bigint, "DocumentNumber" character varying, "SerialType" character varying, "DocumentType" character varying, "SupplierCode" character varying, "SupplierName" character varying, "FiscalId" character varying, "IssueDate" timestamp without time zone, "DueDate" timestamp without time zone, "ReceiptDate" timestamp without time zone, "PaymentDate" timestamp without time zone, "DocumentTime" character varying, "SubTotal" double precision, "TaxableAmount" double precision, "ExemptAmount" double precision, "TaxAmount" double precision, "TaxRate" double precision, "TotalAmount" double precision, "DiscountAmount" double precision, "IsVoided" boolean, "IsPaid" character varying, "IsReceived" character varying, "IsLegal" boolean, "OriginDocumentNumber" character varying, "ControlNumber" character varying, "VoucherNumber" character varying, "VoucherDate" timestamp without time zone, "RetainedTax" double precision, "IsrCode" character varying, "IsrAmount" double precision, "IsrSubjectCode" character varying, "IsrSubjectAmount" double precision, "RetentionRate" double precision, "ImportAmount" double precision, "ImportTax" double precision, "ImportBase" double precision, "FreightAmount" double precision, "Notes" character varying, "Concept" character varying, "OrderNumber" character varying, "ReceivedBy" character varying, "WarehouseCode" character varying, "CurrencyCode" character varying, "ExchangeRate" double precision, "UsdAmount" double precision, "UserCode" character varying, "ShortUserCode" character varying, "ReportDate" timestamp without time zone, "HostName" character varying, "IsDeleted" boolean, "CreatedAt" timestamp without time zone, "UpdatedAt" timestamp without time zone)
 LANGUAGE plpgsql
AS $function$
BEGIN
    RETURN QUERY
    SELECT
        d."PurchaseDocumentId",
        d."DocumentNumber",
        d."SerialType",
        d."DocumentType",
        d."SupplierCode",
        d."SupplierName",
        d."FiscalId",
        d."IssueDate",
        d."DueDate",
        d."ReceiptDate",
        d."PaymentDate",
        d."DocumentTime",
        d."SubTotal",
        d."TaxableAmount",
        d."ExemptAmount",
        d."TaxAmount",
        d."TaxRate",
        d."TotalAmount",
        d."DiscountAmount",
        d."IsVoided",
        d."IsPaid",
        d."IsReceived",
        d."IsLegal",
        d."OriginDocumentNumber",
        d."ControlNumber",
        d."VoucherNumber",
        d."VoucherDate",
        d."RetainedTax",
        d."IsrCode",
        d."IsrAmount",
        d."IsrSubjectCode",
        d."IsrSubjectAmount",
        d."RetentionRate",
        d."ImportAmount",
        d."ImportTax",
        d."ImportBase",
        d."FreightAmount",
        d."Notes",
        d."Concept",
        d."OrderNumber",
        d."ReceivedBy",
        d."WarehouseCode",
        d."CurrencyCode",
        d."ExchangeRate",
        d."UsdAmount",
        d."UserCode",
        d."ShortUserCode",
        d."ReportDate",
        d."HostName",
        d."IsDeleted",
        d."CreatedAt",
        d."UpdatedAt"
    FROM doc."PurchaseDocument" d
    WHERE d."DocumentNumber" = p_num_doc
      AND d."DocumentType" = p_tipo_operacion
      AND d."IsDeleted" = FALSE
    LIMIT 1;
END;
$function$
;

-- ============================================================
-- usp_doc_purchasedocument_getdetail
-- ============================================================
CREATE OR REPLACE FUNCTION public.usp_doc_purchasedocument_getdetail(p_tipo_operacion character varying, p_num_doc character varying)
 RETURNS TABLE("LineId" bigint, "DocumentNumber" character varying, "DocumentType" character varying, "LineNumber" integer, "ProductCode" character varying, "Description" character varying, "Quantity" double precision, "UnitPrice" double precision, "UnitCost" double precision, "SubTotal" double precision, "DiscountAmount" double precision, "TotalAmount" double precision, "TaxRate" double precision, "TaxAmount" double precision, "IsVoided" boolean, "IsDeleted" boolean, "UserCode" character varying, "LineDate" timestamp without time zone, "CreatedAt" timestamp without time zone, "UpdatedAt" timestamp without time zone)
 LANGUAGE plpgsql
AS $function$
BEGIN
    RETURN QUERY
    SELECT
        l."LineId",
        l."DocumentNumber",
        l."DocumentType",
        l."LineNumber",
        l."ProductCode",
        l."Description",
        l."Quantity",
        l."UnitPrice",
        l."UnitCost",
        l."SubTotal",
        l."DiscountAmount",
        l."TotalAmount",
        l."TaxRate",
        l."TaxAmount",
        l."IsVoided",
        l."IsDeleted",
        l."UserCode",
        l."LineDate",
        l."CreatedAt",
        l."UpdatedAt"
    FROM doc."PurchaseDocumentLine" l
    WHERE l."DocumentNumber" = p_num_doc
      AND l."DocumentType" = p_tipo_operacion
      AND l."IsDeleted" = FALSE
    ORDER BY COALESCE(l."LineNumber", 0), l."LineId";
END;
$function$
;

