-- ============================================================
-- usp_doc_salesdocument_invoicefromorder
-- ============================================================
CREATE OR REPLACE FUNCTION public.usp_doc_salesdocument_invoicefromorder(p_num_doc_pedido character varying, p_num_doc_factura character varying, p_formas_pago_json jsonb DEFAULT NULL::jsonb, p_cod_usuario character varying DEFAULT 'API'::character varying)
 RETURNS TABLE(ok boolean, pedido character varying, factura character varying, mensaje character varying)
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_elem JSONB;
BEGIN
    -- Validar que el pedido existe
    IF NOT EXISTS (
        SELECT 1 FROM doc."SalesDocument"
        WHERE "DocumentNumber" = p_num_doc_pedido
          AND "OperationType" = 'PEDIDO'
          AND "IsDeleted" = FALSE
    ) THEN
        RETURN QUERY SELECT FALSE, p_num_doc_pedido, p_num_doc_factura,
            ('Pedido no encontrado: ' || p_num_doc_pedido)::TEXT;
        RETURN;
    END IF;

    -- Validar que no esta anulado
    IF EXISTS (
        SELECT 1 FROM doc."SalesDocument"
        WHERE "DocumentNumber" = p_num_doc_pedido
          AND "OperationType" = 'PEDIDO'
          AND "IsDeleted" = FALSE
          AND "IsVoided" = TRUE
    ) THEN
        RETURN QUERY SELECT FALSE, p_num_doc_pedido, p_num_doc_factura,
            ('El pedido esta anulado y no puede facturarse: ' || p_num_doc_pedido)::TEXT;
        RETURN;
    END IF;

    -- Validar que no fue ya facturado
    IF EXISTS (
        SELECT 1 FROM doc."SalesDocument"
        WHERE "DocumentNumber" = p_num_doc_pedido
          AND "OperationType" = 'PEDIDO'
          AND "IsDeleted" = FALSE
          AND "IsInvoiced" = 'S'
    ) THEN
        RETURN QUERY SELECT FALSE, p_num_doc_pedido, p_num_doc_factura,
            ('El pedido ya fue facturado previamente: ' || p_num_doc_pedido)::TEXT;
        RETURN;
    END IF;

    -- Copiar cabecera del pedido como nueva factura
    INSERT INTO doc."SalesDocument" (
        "DocumentNumber", "SerialType", "FiscalMemoryNumber", "OperationType",
        "CustomerCode", "CustomerName", "FiscalId",
        "DocumentDate", "DueDate", "DocumentTime",
        "SubTotal", "TaxableAmount", "ExemptAmount", "TaxAmount", "TaxRate", "TotalAmount", "DiscountAmount",
        "IsVoided", "IsPaid", "IsInvoiced", "IsDelivered",
        "OriginDocumentNumber", "OriginDocumentType",
        "ControlNumber", "IsLegal", "IsPrinted",
        "Notes", "Concept", "PaymentTerms", "ShipToAddress",
        "SellerCode", "DepartmentCode", "LocationCode",
        "CurrencyCode", "ExchangeRate",
        "UserCode", "ReportDate", "HostName",
        "VehiclePlate", "Mileage", "TollAmount",
        "CreatedAt", "UpdatedAt"
    )
    SELECT
        p_num_doc_factura,
        s."SerialType",
        s."FiscalMemoryNumber",
        'FACT',
        s."CustomerCode", s."CustomerName", s."FiscalId",
        NOW() AT TIME ZONE 'UTC',
        s."DueDate",
        to_char(NOW() AT TIME ZONE 'UTC', 'HH24:MI:SS'),
        s."SubTotal", s."TaxableAmount", s."ExemptAmount", s."TaxAmount", s."TaxRate", s."TotalAmount", s."DiscountAmount",
        FALSE,
        'N',
        'N',
        'N',
        p_num_doc_pedido,
        'PEDIDO',
        s."ControlNumber", s."IsLegal", FALSE,
        s."Notes", s."Concept", s."PaymentTerms", s."ShipToAddress",
        s."SellerCode", s."DepartmentCode", s."LocationCode",
        s."CurrencyCode", s."ExchangeRate",
        p_cod_usuario,
        NOW() AT TIME ZONE 'UTC',
        inet_client_addr()::TEXT,
        s."VehiclePlate", s."Mileage", s."TollAmount",
        NOW() AT TIME ZONE 'UTC', NOW() AT TIME ZONE 'UTC'
    FROM doc."SalesDocument" s
    WHERE s."DocumentNumber" = p_num_doc_pedido
      AND s."OperationType" = 'PEDIDO'
      AND s."IsDeleted" = FALSE;

    -- Copiar lineas del pedido a la factura
    INSERT INTO doc."SalesDocumentLine" (
        "DocumentNumber", "SerialType", "FiscalMemoryNumber", "OperationType",
        "LineNumber", "ProductCode", "Description", "AlternateCode",
        "Quantity", "UnitPrice", "DiscountedPrice", "UnitCost",
        "SubTotal", "DiscountAmount", "TotalAmount",
        "TaxRate", "TaxAmount",
        "IsVoided", "RelatedRef",
        "UserCode", "LineDate",
        "CreatedAt", "UpdatedAt"
    )
    SELECT
        p_num_doc_factura,
        sl."SerialType",
        sl."FiscalMemoryNumber",
        'FACT',
        sl."LineNumber", sl."ProductCode", sl."Description", sl."AlternateCode",
        sl."Quantity", sl."UnitPrice", sl."DiscountedPrice", sl."UnitCost",
        sl."SubTotal", sl."DiscountAmount", sl."TotalAmount",
        sl."TaxRate", sl."TaxAmount",
        FALSE,
        sl."RelatedRef",
        p_cod_usuario,
        NOW() AT TIME ZONE 'UTC',
        NOW() AT TIME ZONE 'UTC', NOW() AT TIME ZONE 'UTC'
    FROM doc."SalesDocumentLine" sl
    WHERE sl."DocumentNumber" = p_num_doc_pedido
      AND sl."OperationType" = 'PEDIDO'
      AND sl."IsDeleted" = FALSE;

    -- Insertar formas de pago desde JSONB si se proporcionaron
    IF p_formas_pago_json IS NOT NULL AND jsonb_array_length(p_formas_pago_json) > 0 THEN
        INSERT INTO doc."SalesDocumentPayment" (
            "DocumentNumber", "SerialType", "FiscalMemoryNumber", "OperationType",
            "PaymentMethod", "BankCode", "PaymentNumber",
            "Amount", "AmountBs", "ExchangeRate",
            "PaymentDate", "DueDate",
            "ReferenceNumber", "UserCode",
            "CreatedAt", "UpdatedAt"
        )
        SELECT
            p_num_doc_factura,
            COALESCE(elem->>'serialType', ''),
            COALESCE(elem->>'fiscalMemoryNumber', '1'),
            'FACT',
            elem->>'paymentMethod',
            elem->>'bankCode',
            elem->>'paymentNumber',
            COALESCE((elem->>'amount')::NUMERIC, 0),
            COALESCE((elem->>'amountBs')::NUMERIC, 0),
            COALESCE((elem->>'exchangeRate')::NUMERIC, 1),
            COALESCE((elem->>'paymentDate')::TIMESTAMP, NOW() AT TIME ZONE 'UTC'),
            (elem->>'dueDate')::TIMESTAMP,
            elem->>'referenceNumber',
            p_cod_usuario,
            NOW() AT TIME ZONE 'UTC', NOW() AT TIME ZONE 'UTC'
        FROM jsonb_array_elements(p_formas_pago_json) elem;
    END IF;

    -- Marcar el pedido como facturado
    UPDATE doc."SalesDocument"
    SET "IsInvoiced" = 'S',
        "Notes"      = CONCAT(COALESCE("Notes", ''), ' | Facturado como ', p_num_doc_factura,
                        ' el ', to_char(NOW() AT TIME ZONE 'UTC', 'YYYY-MM-DD HH24:MI'),
                        ' por ', p_cod_usuario),
        "UpdatedAt"  = NOW() AT TIME ZONE 'UTC'
    WHERE "DocumentNumber" = p_num_doc_pedido
      AND "OperationType" = 'PEDIDO'
      AND "IsDeleted" = FALSE;

    RETURN QUERY SELECT TRUE, p_num_doc_pedido, p_num_doc_factura,
        ('Factura ' || p_num_doc_factura || ' generada exitosamente desde pedido ' || p_num_doc_pedido)::TEXT;
END;
$function$
;

-- ============================================================
-- usp_doc_salesdocument_list
-- ============================================================
CREATE OR REPLACE FUNCTION public.usp_doc_salesdocument_list(p_tipo_operacion character varying, p_search character varying DEFAULT NULL::character varying, p_codigo character varying DEFAULT NULL::character varying, p_from_date date DEFAULT NULL::date, p_to_date date DEFAULT NULL::date, p_page integer DEFAULT 1, p_limit integer DEFAULT 50)
 RETURNS TABLE("SalesDocumentId" bigint, "DocumentNumber" character varying, "SerialType" character varying, "FiscalMemoryNumber" character varying, "OperationType" character varying, "CustomerCode" character varying, "CustomerName" character varying, "FiscalId" character varying, "DocumentDate" timestamp without time zone, "DueDate" timestamp without time zone, "DocumentTime" character varying, "SubTotal" numeric, "TaxableAmount" numeric, "ExemptAmount" numeric, "TaxAmount" numeric, "TaxRate" numeric, "TotalAmount" numeric, "DiscountAmount" numeric, "IsVoided" boolean, "IsPaid" character varying, "IsInvoiced" character varying, "IsDelivered" character varying, "OriginDocumentNumber" character varying, "OriginDocumentType" character varying, "ControlNumber" character varying, "IsLegal" character varying, "IsPrinted" boolean, "Notes" character varying, "Concept" character varying, "PaymentTerms" character varying, "ShipToAddress" character varying, "SellerCode" character varying, "DepartmentCode" character varying, "LocationCode" character varying, "CurrencyCode" character varying, "ExchangeRate" numeric, "UserCode" character varying, "ReportDate" timestamp without time zone, "HostName" character varying, "VehiclePlate" character varying, "Mileage" numeric, "TollAmount" numeric, "CreatedAt" timestamp without time zone, "UpdatedAt" timestamp without time zone, "IsDeleted" boolean, "TotalCount" bigint)
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_total  BIGINT;
    v_page   INT := GREATEST(p_page, 1);
    v_limit  INT := LEAST(GREATEST(p_limit, 1), 500);
BEGIN
    SELECT COUNT(*) INTO v_total
    FROM doc."SalesDocument"
    WHERE "OperationType" = p_tipo_operacion
      AND "IsDeleted" = FALSE
      AND (p_search IS NULL OR (
            "DocumentNumber" LIKE '%' || p_search || '%'
            OR "CustomerName" LIKE '%' || p_search || '%'
            OR "FiscalId" LIKE '%' || p_search || '%'
          ))
      AND (p_codigo IS NULL OR "CustomerCode" = p_codigo)
      AND (p_from_date IS NULL OR "DocumentDate" >= p_from_date)
      AND (p_to_date IS NULL OR "DocumentDate" < (p_to_date + INTERVAL '1 day'));

    RETURN QUERY
    SELECT
        sd."SalesDocumentId",
        sd."DocumentNumber"::VARCHAR,
        sd."SerialType"::VARCHAR,
        sd."FiscalMemoryNumber"::VARCHAR,
        sd."OperationType"::VARCHAR,
        sd."CustomerCode"::VARCHAR,
        sd."CustomerName"::VARCHAR,
        sd."FiscalId"::VARCHAR,
        sd."DocumentDate",
        sd."DueDate",
        sd."DocumentTime"::VARCHAR,
        sd."SubTotal",
        sd."TaxableAmount",
        sd."ExemptAmount",
        sd."TaxAmount",
        sd."TaxRate",
        sd."TotalAmount",
        sd."DiscountAmount",
        sd."IsVoided",
        sd."IsPaid"::VARCHAR,
        sd."IsInvoiced"::VARCHAR,
        sd."IsDelivered"::VARCHAR,
        sd."OriginDocumentNumber"::VARCHAR,
        sd."OriginDocumentType"::VARCHAR,
        sd."ControlNumber"::VARCHAR,
        sd."IsLegal"::VARCHAR,
        sd."IsPrinted",
        sd."Notes"::TEXT,
        sd."Concept"::VARCHAR,
        sd."PaymentTerms"::VARCHAR,
        sd."ShipToAddress"::VARCHAR,
        sd."SellerCode"::VARCHAR,
        sd."DepartmentCode"::VARCHAR,
        sd."LocationCode"::VARCHAR,
        sd."CurrencyCode"::VARCHAR,
        sd."ExchangeRate",
        sd."UserCode"::VARCHAR,
        sd."ReportDate",
        sd."HostName"::VARCHAR,
        sd."VehiclePlate"::VARCHAR,
        sd."Mileage",
        sd."TollAmount",
        sd."CreatedAt",
        sd."UpdatedAt",
        sd."IsDeleted",
        v_total
    FROM doc."SalesDocument" sd
    WHERE sd."OperationType" = p_tipo_operacion
      AND sd."IsDeleted" = FALSE
      AND (p_search IS NULL OR (
            sd."DocumentNumber" LIKE '%' || p_search || '%'
            OR sd."CustomerName" LIKE '%' || p_search || '%'
            OR sd."FiscalId" LIKE '%' || p_search || '%'
          ))
      AND (p_codigo IS NULL OR sd."CustomerCode" = p_codigo)
      AND (p_from_date IS NULL OR sd."DocumentDate" >= p_from_date)
      AND (p_to_date IS NULL OR sd."DocumentDate" < (p_to_date + INTERVAL '1 day'))
    ORDER BY sd."DocumentDate" DESC, sd."DocumentNumber" DESC
    LIMIT v_limit OFFSET (v_page - 1) * v_limit;
END;
$function$
;

-- ============================================================
-- usp_doc_salesdocument_upsert
-- ============================================================
CREATE OR REPLACE FUNCTION public.usp_doc_salesdocument_upsert(p_tipo_operacion character varying, p_header_json jsonb, p_detail_json jsonb, p_payments_json jsonb DEFAULT NULL::jsonb, p_doc_origen character varying DEFAULT NULL::character varying, p_tipo_doc_origen character varying DEFAULT NULL::character varying)
 RETURNS TABLE(ok boolean, "numDoc" character varying, "detalleRows" integer, "formasPagoRows" integer, "pendingAmount" numeric)
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_num_doc           VARCHAR(60);
    v_detalle_rows      INT := 0;
    v_formas_pago_rows  INT := 0;
    v_pending_amount    NUMERIC(18,4) := 0;
    -- Header fields
    v_serial_type       VARCHAR(60);
    v_fiscal_memory     VARCHAR(10);
    v_customer_code     VARCHAR(60);
    v_customer_name     VARCHAR(200);
    v_fiscal_id         VARCHAR(60);
    v_document_date     TIMESTAMP;
    v_due_date          TIMESTAMP;
    v_document_time     VARCHAR(20);
    v_sub_total         NUMERIC(18,4);
    v_taxable_amount    NUMERIC(18,4);
    v_exempt_amount     NUMERIC(18,4);
    v_tax_amount        NUMERIC(18,4);
    v_tax_rate          NUMERIC(8,4);
    v_total_amount      NUMERIC(18,4);
    v_discount_amount   NUMERIC(18,4);
    v_is_voided         BOOLEAN;
    v_is_paid           VARCHAR(10);
    v_is_invoiced       VARCHAR(10);
    v_is_delivered      VARCHAR(10);
    v_origin_doc_number VARCHAR(60);
    v_origin_doc_type   VARCHAR(20);
    v_control_number    VARCHAR(60);
    v_is_legal          VARCHAR(10);
    v_is_printed        BOOLEAN;
    v_notes             TEXT;
    v_concept           VARCHAR(200);
    v_payment_terms     VARCHAR(100);
    v_ship_to_address   VARCHAR(500);
    v_seller_code       VARCHAR(60);
    v_department_code   VARCHAR(60);
    v_location_code     VARCHAR(60);
    v_currency_code     VARCHAR(10);
    v_exchange_rate     NUMERIC(18,6);
    v_user_code         VARCHAR(60);
    v_report_date       TIMESTAMP;
    v_host_name         VARCHAR(100);
    v_vehicle_plate     VARCHAR(30);
    v_mileage           NUMERIC(18,2);
    v_toll_amount       NUMERIC(18,4);
    -- AR sync
    v_cod_cliente       VARCHAR(60);
    v_company_id        INT;
    v_branch_id         INT;
    v_customer_id       BIGINT;
    v_user_id           INT;
    v_total_pagado      NUMERIC(18,4) := 0;
    v_ar_status         VARCHAR(20);
    v_ar_paid_flag      BOOLEAN;
BEGIN
    -- Parsear cabecera
    v_num_doc           := TRIM(p_header_json->>'DocumentNumber');
    v_serial_type       := COALESCE(p_header_json->>'SerialType', '');
    v_fiscal_memory     := COALESCE(p_header_json->>'FiscalMemoryNumber', '1');
    v_customer_code     := p_header_json->>'CustomerCode';
    v_customer_name     := p_header_json->>'CustomerName';
    v_fiscal_id         := p_header_json->>'FiscalId';
    v_document_date     := COALESCE((p_header_json->>'DocumentDate')::TIMESTAMP, NOW() AT TIME ZONE 'UTC');
    v_due_date          := (p_header_json->>'DueDate')::TIMESTAMP;
    v_document_time     := p_header_json->>'DocumentTime';
    v_sub_total         := COALESCE((p_header_json->>'SubTotal')::NUMERIC, 0);
    v_taxable_amount    := (p_header_json->>'TaxableAmount')::NUMERIC;
    v_exempt_amount     := (p_header_json->>'ExemptAmount')::NUMERIC;
    v_tax_amount        := COALESCE((p_header_json->>'TaxAmount')::NUMERIC, 0);
    v_tax_rate          := COALESCE((p_header_json->>'TaxRate')::NUMERIC, 0);
    v_total_amount      := COALESCE((p_header_json->>'TotalAmount')::NUMERIC, 0);
    v_discount_amount   := (p_header_json->>'DiscountAmount')::NUMERIC;
    v_is_voided         := COALESCE((p_header_json->>'IsVoided')::BOOLEAN, FALSE);
    v_is_paid           := COALESCE(p_header_json->>'IsPaid', 'N');
    v_is_invoiced       := COALESCE(p_header_json->>'IsInvoiced', 'N');
    v_is_delivered      := COALESCE(p_header_json->>'IsDelivered', 'N');
    v_origin_doc_number := COALESCE(p_doc_origen, p_header_json->>'OriginDocumentNumber');
    v_origin_doc_type   := COALESCE(p_tipo_doc_origen, p_header_json->>'OriginDocumentType');
    v_control_number    := p_header_json->>'ControlNumber';
    v_is_legal          := p_header_json->>'IsLegal';
    v_is_printed        := (p_header_json->>'IsPrinted')::BOOLEAN;
    v_notes             := p_header_json->>'Notes';
    v_concept           := p_header_json->>'Concept';
    v_payment_terms     := p_header_json->>'PaymentTerms';
    v_ship_to_address   := p_header_json->>'ShipToAddress';
    v_seller_code       := p_header_json->>'SellerCode';
    v_department_code   := p_header_json->>'DepartmentCode';
    v_location_code     := p_header_json->>'LocationCode';
    v_currency_code     := p_header_json->>'CurrencyCode';
    v_exchange_rate     := (p_header_json->>'ExchangeRate')::NUMERIC;
    v_user_code         := p_header_json->>'UserCode';
    v_report_date       := COALESCE((p_header_json->>'ReportDate')::TIMESTAMP, NOW() AT TIME ZONE 'UTC');
    v_host_name         := p_header_json->>'HostName';
    v_vehicle_plate     := p_header_json->>'VehiclePlate';
    v_mileage           := (p_header_json->>'Mileage')::NUMERIC;
    v_toll_amount       := (p_header_json->>'TollAmount')::NUMERIC;

    -- Validar DocumentNumber
    IF v_num_doc IS NULL OR v_num_doc = '' THEN
        RETURN QUERY SELECT FALSE, NULL::VARCHAR, 0, 0, 0::NUMERIC;
        RETURN;
    END IF;

    -- DELETE existente (detalle, pagos, cabecera)
    DELETE FROM doc."SalesDocumentLine"
    WHERE "DocumentNumber" = v_num_doc AND "OperationType" = p_tipo_operacion;

    DELETE FROM doc."SalesDocumentPayment"
    WHERE "DocumentNumber" = v_num_doc AND "OperationType" = p_tipo_operacion;

    DELETE FROM doc."SalesDocument"
    WHERE "DocumentNumber" = v_num_doc AND "OperationType" = p_tipo_operacion;

    -- INSERT cabecera
    INSERT INTO doc."SalesDocument" (
        "DocumentNumber", "SerialType", "FiscalMemoryNumber", "OperationType",
        "CustomerCode", "CustomerName", "FiscalId",
        "DocumentDate", "DueDate", "DocumentTime",
        "SubTotal", "TaxableAmount", "ExemptAmount", "TaxAmount", "TaxRate",
        "TotalAmount", "DiscountAmount",
        "IsVoided", "IsPaid", "IsInvoiced", "IsDelivered",
        "OriginDocumentNumber", "OriginDocumentType",
        "ControlNumber", "IsLegal", "IsPrinted",
        "Notes", "Concept", "PaymentTerms", "ShipToAddress",
        "SellerCode", "DepartmentCode", "LocationCode",
        "CurrencyCode", "ExchangeRate",
        "UserCode", "ReportDate", "HostName",
        "VehiclePlate", "Mileage", "TollAmount",
        "CreatedAt", "UpdatedAt", "IsDeleted"
    )
    VALUES (
        v_num_doc, v_serial_type, v_fiscal_memory, p_tipo_operacion,
        v_customer_code, v_customer_name, v_fiscal_id,
        v_document_date, v_due_date, v_document_time,
        v_sub_total, v_taxable_amount, v_exempt_amount, v_tax_amount, v_tax_rate,
        v_total_amount, v_discount_amount,
        v_is_voided, v_is_paid, v_is_invoiced, v_is_delivered,
        v_origin_doc_number, v_origin_doc_type,
        v_control_number, v_is_legal, v_is_printed,
        v_notes, v_concept, v_payment_terms, v_ship_to_address,
        v_seller_code, v_department_code, v_location_code,
        v_currency_code, v_exchange_rate,
        v_user_code, v_report_date, v_host_name,
        v_vehicle_plate, v_mileage, v_toll_amount,
        NOW() AT TIME ZONE 'UTC', NOW() AT TIME ZONE 'UTC', FALSE
    );

    -- INSERT lineas de detalle desde JSONB
    IF p_detail_json IS NOT NULL AND jsonb_array_length(p_detail_json) > 0 THEN
        INSERT INTO doc."SalesDocumentLine" (
            "DocumentNumber", "SerialType", "FiscalMemoryNumber", "OperationType",
            "LineNumber", "ProductCode", "Description", "AlternateCode",
            "Quantity", "UnitPrice", "DiscountedPrice", "UnitCost",
            "SubTotal", "DiscountAmount", "TotalAmount",
            "TaxRate", "TaxAmount",
            "IsVoided", "RelatedRef",
            "UserCode", "LineDate",
            "CreatedAt", "UpdatedAt", "IsDeleted"
        )
        SELECT
            v_num_doc,
            COALESCE(elem->>'SerialType', v_serial_type),
            COALESCE(elem->>'FiscalMemoryNumber', v_fiscal_memory),
            p_tipo_operacion,
            (elem->>'LineNumber')::INT,
            elem->>'ProductCode',
            elem->>'Description',
            elem->>'AlternateCode',
            COALESCE((elem->>'Quantity')::NUMERIC, 0),
            COALESCE((elem->>'UnitPrice')::NUMERIC, 0),
            (elem->>'DiscountedPrice')::NUMERIC,
            (elem->>'UnitCost')::NUMERIC,
            COALESCE((elem->>'SubTotal')::NUMERIC, 0),
            COALESCE((elem->>'DiscountAmount')::NUMERIC, 0),
            COALESCE((elem->>'TotalAmount')::NUMERIC, 0),
            COALESCE((elem->>'TaxRate')::NUMERIC, 0),
            COALESCE((elem->>'TaxAmount')::NUMERIC, 0),
            COALESCE((elem->>'IsVoided')::BOOLEAN, FALSE),
            elem->>'RelatedRef',
            COALESCE(elem->>'UserCode', v_user_code),
            COALESCE((elem->>'LineDate')::TIMESTAMP, NOW() AT TIME ZONE 'UTC'),
            NOW() AT TIME ZONE 'UTC', NOW() AT TIME ZONE 'UTC', FALSE
        FROM jsonb_array_elements(p_detail_json) elem;

        GET DIAGNOSTICS v_detalle_rows = ROW_COUNT;
    END IF;

    -- INSERT formas de pago desde JSONB
    IF p_payments_json IS NOT NULL AND jsonb_array_length(p_payments_json) > 0 THEN
        INSERT INTO doc."SalesDocumentPayment" (
            "DocumentNumber", "SerialType", "FiscalMemoryNumber", "OperationType",
            "PaymentMethod", "BankCode", "PaymentNumber",
            "Amount", "AmountBs", "ExchangeRate",
            "PaymentDate", "DueDate",
            "ReferenceNumber", "UserCode",
            "CreatedAt", "UpdatedAt", "IsDeleted"
        )
        SELECT
            v_num_doc,
            COALESCE(elem->>'SerialType', v_serial_type),
            COALESCE(elem->>'FiscalMemoryNumber', v_fiscal_memory),
            p_tipo_operacion,
            elem->>'PaymentMethod',
            elem->>'BankCode',
            elem->>'PaymentNumber',
            COALESCE((elem->>'Amount')::NUMERIC, 0),
            COALESCE((elem->>'AmountBs')::NUMERIC, 0),
            COALESCE((elem->>'ExchangeRate')::NUMERIC, 1),
            COALESCE((elem->>'PaymentDate')::TIMESTAMP, NOW() AT TIME ZONE 'UTC'),
            (elem->>'DueDate')::TIMESTAMP,
            elem->>'ReferenceNumber',
            COALESCE(elem->>'UserCode', v_user_code),
            NOW() AT TIME ZONE 'UTC', NOW() AT TIME ZONE 'UTC', FALSE
        FROM jsonb_array_elements(p_payments_json) elem;

        GET DIAGNOSTICS v_formas_pago_rows = ROW_COUNT;
    END IF;

    -- Sincronizar cuenta por cobrar para FACT/NOTADEB/NOTACRED
    IF p_tipo_operacion IN ('FACT', 'NOTADEB', 'NOTACRED') THEN
        v_cod_cliente := TRIM(COALESCE(v_customer_code, ''));

        IF v_cod_cliente <> '' THEN
            -- Resolver contexto canonico
            SELECT c."CompanyId" INTO v_company_id
            FROM cfg."Company" c
            WHERE c."IsDeleted" = FALSE AND c."IsActive" = TRUE
            ORDER BY CASE WHEN c."CompanyCode" = 'DEFAULT' THEN 0 ELSE 1 END, c."CompanyId"
            LIMIT 1;

            SELECT b."BranchId" INTO v_branch_id
            FROM cfg."Branch" b
            WHERE b."CompanyId" = v_company_id AND b."IsDeleted" = FALSE AND b."IsActive" = TRUE
            ORDER BY CASE WHEN b."BranchCode" = 'MAIN' THEN 0 ELSE 1 END, b."BranchId"
            LIMIT 1;

            SELECT "CustomerId" INTO v_customer_id
            FROM master."Customer"
            WHERE "CustomerCode" = v_cod_cliente
              AND "CompanyId" = v_company_id
              AND "IsDeleted" = FALSE
            LIMIT 1;

            IF v_customer_id IS NOT NULL AND v_company_id IS NOT NULL AND v_branch_id IS NOT NULL THEN
                -- Calcular monto pendiente
                IF UPPER(v_is_paid)::character varying = 'S' THEN
                    v_pending_amount := 0;
                ELSE
                    IF p_payments_json IS NOT NULL AND jsonb_array_length(p_payments_json) > 0 THEN
                        SELECT COALESCE(SUM(COALESCE((elem->>'Amount')::NUMERIC, 0)), 0)
                        INTO v_total_pagado
                        FROM jsonb_array_elements(p_payments_json) elem
                        WHERE UPPER(COALESCE(elem->>'PaymentMethod', ''))::character varying NOT LIKE '%SALDO%';
                    END IF;

                    v_pending_amount := CASE
                        WHEN v_total_amount - v_total_pagado > 0 THEN v_total_amount - v_total_pagado
                        ELSE 0
                    END;
                END IF;

                -- Determinar status
                v_ar_status := CASE
                    WHEN v_pending_amount <= 0              THEN 'PAID'
                    WHEN v_pending_amount < v_total_amount  THEN 'PARTIAL'
                    ELSE                                         'PENDING'
                END;
                v_ar_paid_flag := (v_pending_amount <= 0);

                -- Resolver UserId
                IF v_user_code IS NOT NULL AND v_user_code <> '' THEN
                    SELECT "UserId" INTO v_user_id
                    FROM sec."User"
                    WHERE "UserCode" = v_user_code AND "IsDeleted" = FALSE
                    LIMIT 1;
                END IF;

                -- Upsert ar.ReceivableDocument
                IF EXISTS (
                    SELECT 1 FROM ar."ReceivableDocument"
                    WHERE "CompanyId" = v_company_id
                      AND "BranchId"  = v_branch_id
                      AND "DocumentType"   = p_tipo_operacion
                      AND "DocumentNumber" = v_num_doc
                ) THEN
                    UPDATE ar."ReceivableDocument"
                    SET "CustomerId"      = v_customer_id,
                        "IssueDate"       = v_document_date,
                        "DueDate"         = COALESCE(v_due_date, v_document_date),
                        "TotalAmount"     = v_total_amount,
                        "PendingAmount"   = v_pending_amount,
                        "PaidFlag"        = v_ar_paid_flag,
                        "Status"          = v_ar_status,
                        "Notes"           = v_notes,
                        "UpdatedAt"       = NOW() AT TIME ZONE 'UTC',
                        "UpdatedByUserId" = v_user_id
                    WHERE "CompanyId"      = v_company_id
                      AND "BranchId"       = v_branch_id
                      AND "DocumentType"   = p_tipo_operacion
                      AND "DocumentNumber" = v_num_doc;
                ELSE
                    INSERT INTO ar."ReceivableDocument" (
                        "CompanyId", "BranchId", "CustomerId", "DocumentType", "DocumentNumber",
                        "IssueDate", "DueDate", "CurrencyCode",
                        "TotalAmount", "PendingAmount", "PaidFlag", "Status", "Notes",
                        "CreatedAt", "UpdatedAt", "CreatedByUserId", "UpdatedByUserId"
                    )
                    VALUES (
                        v_company_id, v_branch_id, v_customer_id, p_tipo_operacion, v_num_doc,
                        v_document_date, COALESCE(v_due_date, v_document_date), COALESCE(v_currency_code, 'USD'),
                        v_total_amount, v_pending_amount, v_ar_paid_flag, v_ar_status, v_notes,
                        NOW() AT TIME ZONE 'UTC', NOW() AT TIME ZONE 'UTC', v_user_id, v_user_id
                    );
                END IF;

                -- Actualizar saldo del cliente
                PERFORM usp_master_customer_updatebalance(v_customer_id, v_user_id);
            END IF;
        END IF;
    END IF;

    RETURN QUERY SELECT TRUE, v_num_doc, v_detalle_rows, v_formas_pago_rows, v_pending_amount;
END;
$function$
;

-- ============================================================
-- usp_doc_salesdocument_void
-- ============================================================
CREATE OR REPLACE FUNCTION public.usp_doc_salesdocument_void(p_tipo_operacion character varying, p_num_doc character varying, p_cod_usuario character varying DEFAULT 'API'::character varying, p_motivo character varying DEFAULT ''::character varying)
 RETURNS TABLE(ok boolean, "numFact" character varying, "codCliente" character varying, mensaje character varying)
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_cod_cliente  VARCHAR(60);
    v_company_id   INT;
    v_branch_id    INT;
    v_customer_id  BIGINT;
BEGIN
    -- Validar que el documento existe
    IF NOT EXISTS (
        SELECT 1 FROM doc."SalesDocument"
        WHERE "DocumentNumber" = p_num_doc
          AND "OperationType" = p_tipo_operacion
          AND "IsDeleted" = FALSE
    ) THEN
        RETURN QUERY SELECT FALSE, p_num_doc, NULL::VARCHAR,
            ('Documento no encontrado: ' || p_num_doc || ' / ' || p_tipo_operacion)::TEXT;
        RETURN;
    END IF;

    -- Validar que no esta ya anulado
    IF EXISTS (
        SELECT 1 FROM doc."SalesDocument"
        WHERE "DocumentNumber" = p_num_doc
          AND "OperationType" = p_tipo_operacion
          AND "IsDeleted" = FALSE
          AND "IsVoided" = TRUE
    ) THEN
        RETURN QUERY SELECT FALSE, p_num_doc, NULL::VARCHAR,
            ('El documento ya se encuentra anulado: ' || p_num_doc)::TEXT;
        RETURN;
    END IF;

    -- Obtener codigo de cliente
    SELECT "CustomerCode" INTO v_cod_cliente
    FROM doc."SalesDocument"
    WHERE "DocumentNumber" = p_num_doc
      AND "OperationType" = p_tipo_operacion
      AND "IsDeleted" = FALSE;

    -- Anular cabecera
    UPDATE doc."SalesDocument"
    SET "IsVoided"  = TRUE,
        "Notes"     = CONCAT(COALESCE("Notes", ''), ' | ANULADO ',
                       to_char(NOW() AT TIME ZONE 'UTC', 'YYYY-MM-DD HH24:MI'),
                       ' por ', p_cod_usuario,
                       CASE WHEN p_motivo <> '' THEN ' - Motivo: ' || p_motivo ELSE '' END),
        "UpdatedAt" = NOW() AT TIME ZONE 'UTC'
    WHERE "DocumentNumber" = p_num_doc
      AND "OperationType" = p_tipo_operacion
      AND "IsDeleted" = FALSE;

    -- Anular lineas
    UPDATE doc."SalesDocumentLine"
    SET "IsVoided"  = TRUE,
        "UpdatedAt" = NOW() AT TIME ZONE 'UTC'
    WHERE "DocumentNumber" = p_num_doc
      AND "OperationType" = p_tipo_operacion
      AND "IsDeleted" = FALSE;

    -- Resolver contexto
    SELECT c."CompanyId" INTO v_company_id
    FROM cfg."Company" c
    WHERE c."IsDeleted" = FALSE AND c."IsActive" = TRUE
    ORDER BY c."CompanyId"
    LIMIT 1;

    SELECT b."BranchId" INTO v_branch_id
    FROM cfg."Branch" b
    WHERE b."CompanyId" = v_company_id AND b."IsDeleted" = FALSE AND b."IsActive" = TRUE
    ORDER BY b."BranchId"
    LIMIT 1;

    -- Resolver CustomerId
    SELECT "CustomerId" INTO v_customer_id
    FROM master."Customer"
    WHERE "CustomerCode" = v_cod_cliente
      AND "CompanyId" = v_company_id
      AND "IsDeleted" = FALSE
    LIMIT 1;

    -- Actualizar cuenta por cobrar si existe
    IF v_customer_id IS NOT NULL AND v_company_id IS NOT NULL AND v_branch_id IS NOT NULL THEN
        UPDATE ar."ReceivableDocument"
        SET "PendingAmount" = 0,
            "PaidFlag"      = TRUE,
            "Status"        = 'VOIDED',
            "UpdatedAt"     = NOW() AT TIME ZONE 'UTC'
        WHERE "CompanyId"      = v_company_id
          AND "BranchId"       = v_branch_id
          AND "DocumentNumber" = p_num_doc
          AND "DocumentType"   = p_tipo_operacion
          AND "CustomerId"     = v_customer_id;

        -- Recalcular saldo total del cliente
        UPDATE master."Customer"
        SET "TotalBalance" = COALESCE((
                SELECT SUM("PendingAmount")
                FROM ar."ReceivableDocument"
                WHERE "CustomerId" = v_customer_id
                  AND "Status" <> 'VOIDED'
            ), 0),
            "UpdatedAt" = NOW() AT TIME ZONE 'UTC'
        WHERE "CustomerId" = v_customer_id;
    END IF;

    RETURN QUERY SELECT TRUE, p_num_doc, v_cod_cliente,
        ('Documento anulado exitosamente: ' || p_num_doc)::TEXT;
END;
$function$
;

-- ============================================================
-- usp_empleados_delete
-- ============================================================
CREATE OR REPLACE FUNCTION public.usp_empleados_delete(p_cedula character varying)
 RETURNS TABLE("Resultado" integer, "Mensaje" character varying)
 LANGUAGE plpgsql
AS $function$
BEGIN
    IF NOT EXISTS (SELECT 1 FROM public."Empleados" WHERE "CEDULA" = p_cedula) THEN
        RETURN QUERY SELECT -1, 'Empleado no encontrado'::VARCHAR(500);
        RETURN;
    END IF;

    DELETE FROM public."Empleados" WHERE "CEDULA" = p_cedula;

    RETURN QUERY SELECT 1, 'OK'::VARCHAR(500);

EXCEPTION WHEN OTHERS THEN
    RETURN QUERY SELECT -99, SQLERRM::VARCHAR(500);
END;
$function$
;

-- ============================================================
-- usp_empleados_getbycedula
-- ============================================================
CREATE OR REPLACE FUNCTION public.usp_empleados_getbycedula(p_cedula character varying)
 RETURNS TABLE("CEDULA" character varying, "GRUPO" character varying, "NOMBRE" character varying, "DIRECCION" character varying, "TELEFONO" character varying, "NACIMIENTO" timestamp without time zone, "CARGO" character varying, "NOMINA" character varying, "SUELDO" double precision, "INGRESO" timestamp without time zone, "RETIRO" timestamp without time zone, "STATUS" character varying, "COMISION" double precision, "UTILIDAD" double precision, "CO_Usuario" character varying, "SEXO" character varying, "NACIONALIDAD" character varying, "Autoriza" boolean, "Apodo" character varying)
 LANGUAGE plpgsql
AS $function$
BEGIN
    RETURN QUERY
    SELECT
        e."CEDULA",
        e."GRUPO",
        e."NOMBRE",
        e."DIRECCION",
        e."TELEFONO",
        e."NACIMIENTO",
        e."CARGO",
        e."NOMINA",
        e."SUELDO",
        e."INGRESO",
        e."RETIRO",
        e."STATUS",
        e."COMISION",
        e."UTILIDAD",
        e."CO_Usuario",
        e."SEXO",
        e."NACIONALIDAD",
        e."Autoriza",
        e."Apodo"
    FROM public."Empleados" e
    WHERE e."CEDULA" = p_cedula;
END;
$function$
;

-- ============================================================
-- usp_empleados_insert
-- ============================================================
CREATE OR REPLACE FUNCTION public.usp_empleados_insert(p_row_json jsonb)
 RETURNS TABLE("Resultado" integer, "Mensaje" character varying)
 LANGUAGE plpgsql
AS $function$
BEGIN
    -- Verificar duplicado
    IF EXISTS (
        SELECT 1 FROM public."Empleados"
        WHERE "CEDULA" = (p_row_json->>'CEDULA')
    ) THEN
        RETURN QUERY SELECT -1, 'Empleado ya existe'::VARCHAR(500);
        RETURN;
    END IF;

    INSERT INTO public."Empleados" (
        "CEDULA", "GRUPO", "NOMBRE", "DIRECCION", "TELEFONO", "NACIMIENTO",
        "CARGO", "NOMINA", "SUELDO", "INGRESO", "RETIRO", "STATUS",
        "COMISION", "UTILIDAD", "CO_Usuario", "SEXO", "NACIONALIDAD",
        "Autoriza", "Apodo"
    ) VALUES (
        NULLIF(p_row_json->>'CEDULA', ''::character varying),
        NULLIF(p_row_json->>'GRUPO', ''::character varying),
        NULLIF(p_row_json->>'NOMBRE', ''::character varying),
        NULLIF(p_row_json->>'DIRECCION', ''::character varying),
        NULLIF(p_row_json->>'TELEFONO', ''::character varying),
        CASE WHEN COALESCE(p_row_json->>'NACIMIENTO', '') = '' THEN NULL
             ELSE (p_row_json->>'NACIMIENTO')::TIMESTAMP END,
        NULLIF(p_row_json->>'CARGO', ''::character varying),
        NULLIF(p_row_json->>'NOMINA', ''::character varying),
        CASE WHEN COALESCE(p_row_json->>'SUELDO', '') = '' THEN NULL
             ELSE (p_row_json->>'SUELDO')::DOUBLE PRECISION END,
        CASE WHEN COALESCE(p_row_json->>'INGRESO', '') = '' THEN NULL
             ELSE (p_row_json->>'INGRESO')::TIMESTAMP END,
        CASE WHEN COALESCE(p_row_json->>'RETIRO', '') = '' THEN NULL
             ELSE (p_row_json->>'RETIRO')::TIMESTAMP END,
        NULLIF(p_row_json->>'STATUS', ''::character varying),
        CASE WHEN COALESCE(p_row_json->>'COMISION', '') = '' THEN NULL
             ELSE (p_row_json->>'COMISION')::DOUBLE PRECISION END,
        CASE WHEN COALESCE(p_row_json->>'UTILIDAD', '') = '' THEN NULL
             ELSE (p_row_json->>'UTILIDAD')::DOUBLE PRECISION END,
        NULLIF(p_row_json->>'CO_Usuario', ''::character varying),
        NULLIF(p_row_json->>'SEXO', ''::character varying),
        NULLIF(p_row_json->>'NACIONALIDAD', ''::character varying),
        COALESCE((p_row_json->>'Autoriza')::BOOLEAN, FALSE),
        NULLIF(p_row_json->>'Apodo', ''::character varying)
    );

    RETURN QUERY SELECT 1, 'OK'::VARCHAR(500);

EXCEPTION WHEN OTHERS THEN
    RETURN QUERY SELECT -99, SQLERRM::VARCHAR(500);
END;
$function$
;

-- ============================================================
-- usp_empleados_list
-- ============================================================
CREATE OR REPLACE FUNCTION public.usp_empleados_list(p_search character varying DEFAULT NULL::character varying, p_grupo character varying DEFAULT NULL::character varying, p_status character varying DEFAULT NULL::character varying, p_page integer DEFAULT 1, p_limit integer DEFAULT 50)
 RETURNS TABLE("TotalCount" integer, "CEDULA" character varying, "GRUPO" character varying, "NOMBRE" character varying, "DIRECCION" character varying, "TELEFONO" character varying, "NACIMIENTO" timestamp without time zone, "CARGO" character varying, "NOMINA" character varying, "SUELDO" double precision, "INGRESO" timestamp without time zone, "RETIRO" timestamp without time zone, "STATUS" character varying, "COMISION" double precision, "UTILIDAD" double precision, "CO_Usuario" character varying, "SEXO" character varying, "NACIONALIDAD" character varying, "Autoriza" boolean, "Apodo" character varying)
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_offset  INT;
    v_limit   INT;
    v_search  VARCHAR(100);
    v_total   INT;
BEGIN
    v_limit  := COALESCE(NULLIF(p_limit, 0), 50)::character varying;
    IF v_limit < 1 THEN v_limit := 50; END IF;
    IF v_limit > 500 THEN v_limit := 500; END IF;
    v_offset := (COALESCE(NULLIF(p_page, 0), 1)::character varying - 1) * v_limit;
    IF v_offset < 0 THEN v_offset := 0; END IF;

    v_search := NULL;
    IF p_search IS NOT NULL AND TRIM(p_search) <> '' THEN
        v_search := '%' || p_search || '%';
    END IF;

    -- Contar total
    SELECT COUNT(1) INTO v_total
    FROM public."Empleados" e
    WHERE (v_search IS NULL OR e."CEDULA" LIKE v_search OR e."NOMBRE" LIKE v_search OR e."CARGO" LIKE v_search)
      AND (p_grupo IS NULL OR TRIM(p_grupo) = '' OR e."GRUPO" = p_grupo)
      AND (p_status IS NULL OR TRIM(p_status) = '' OR e."STATUS" = p_status);

    -- Devolver filas
    RETURN QUERY
    SELECT
        v_total,
        e."CEDULA",
        e."GRUPO",
        e."NOMBRE",
        e."DIRECCION",
        e."TELEFONO",
        e."NACIMIENTO",
        e."CARGO",
        e."NOMINA",
        e."SUELDO",
        e."INGRESO",
        e."RETIRO",
        e."STATUS",
        e."COMISION",
        e."UTILIDAD",
        e."CO_Usuario",
        e."SEXO",
        e."NACIONALIDAD",
        e."Autoriza",
        e."Apodo"
    FROM public."Empleados" e
    WHERE (v_search IS NULL OR e."CEDULA" LIKE v_search OR e."NOMBRE" LIKE v_search OR e."CARGO" LIKE v_search)
      AND (p_grupo IS NULL OR TRIM(p_grupo) = '' OR e."GRUPO" = p_grupo)
      AND (p_status IS NULL OR TRIM(p_status) = '' OR e."STATUS" = p_status)
    ORDER BY e."NOMBRE"
    LIMIT v_limit OFFSET v_offset;
END;
$function$
;

-- ============================================================
-- usp_empleados_update
-- ============================================================
CREATE OR REPLACE FUNCTION public.usp_empleados_update(p_cedula character varying, p_row_json jsonb)
 RETURNS TABLE("Resultado" integer, "Mensaje" character varying)
 LANGUAGE plpgsql
AS $function$
BEGIN
    IF NOT EXISTS (SELECT 1 FROM public."Empleados" WHERE "CEDULA" = p_cedula) THEN
        RETURN QUERY SELECT -1, 'Empleado no encontrado'::VARCHAR(500);
        RETURN;
    END IF;

    UPDATE public."Empleados" SET
        "GRUPO"        = COALESCE(NULLIF(p_row_json->>'GRUPO', ''::character varying), "GRUPO")::character varying,
        "NOMBRE"       = COALESCE(NULLIF(p_row_json->>'NOMBRE', ''::character varying), "NOMBRE")::character varying,
        "DIRECCION"    = COALESCE(NULLIF(p_row_json->>'DIRECCION', ''::character varying), "DIRECCION")::character varying,
        "TELEFONO"     = COALESCE(NULLIF(p_row_json->>'TELEFONO', ''::character varying), "TELEFONO")::character varying,
        "CARGO"        = COALESCE(NULLIF(p_row_json->>'CARGO', ''::character varying), "CARGO")::character varying,
        "NOMINA"       = COALESCE(NULLIF(p_row_json->>'NOMINA', ''::character varying), "NOMINA")::character varying,
        "SUELDO"       = CASE WHEN COALESCE(p_row_json->>'SUELDO', '') = '' THEN "SUELDO"
                              ELSE (p_row_json->>'SUELDO')::DOUBLE PRECISION END,
        "STATUS"       = COALESCE(NULLIF(p_row_json->>'STATUS', ''::character varying), "STATUS")::character varying,
        "COMISION"     = CASE WHEN COALESCE(p_row_json->>'COMISION', '') = '' THEN "COMISION"
                              ELSE (p_row_json->>'COMISION')::DOUBLE PRECISION END,
        "SEXO"         = COALESCE(NULLIF(p_row_json->>'SEXO', ''::character varying), "SEXO")::character varying,
        "NACIONALIDAD" = COALESCE(NULLIF(p_row_json->>'NACIONALIDAD', ''::character varying), "NACIONALIDAD")::character varying,
        "Autoriza"     = COALESCE((p_row_json->>'Autoriza')::BOOLEAN, "Autoriza")
    WHERE "CEDULA" = p_cedula;

    RETURN QUERY SELECT 1, 'OK'::VARCHAR(500);

EXCEPTION WHEN OTHERS THEN
    RETURN QUERY SELECT -99, SQLERRM::VARCHAR(500);
END;
$function$
;

-- ============================================================
-- usp_empresa_get
-- ============================================================
CREATE OR REPLACE FUNCTION public.usp_empresa_get()
 RETURNS TABLE("Empresa" character varying, "RIF" character varying, "Nit" character varying, "Telefono" character varying, "Direccion" character varying, "Rifs" character varying)
 LANGUAGE plpgsql
AS $function$
BEGIN
    RETURN QUERY
    SELECT
        e."Empresa",
        e."RIF",
        e."Nit",
        e."Telefono",
        e."Direccion",
        e."Rifs"
    FROM public."Empresa" e
    LIMIT 1;
END;
$function$
;

-- ============================================================
-- usp_empresa_update
-- ============================================================
CREATE OR REPLACE FUNCTION public.usp_empresa_update(p_row_json jsonb)
 RETURNS TABLE("Resultado" integer, "Mensaje" character varying)
 LANGUAGE plpgsql
AS $function$
BEGIN
    IF NOT EXISTS (SELECT 1 FROM public."Empresa") THEN
        RETURN QUERY SELECT -1, 'Empresa no encontrada'::VARCHAR(500);
        RETURN;
    END IF;

    UPDATE public."Empresa" SET
        "Empresa"   = COALESCE(NULLIF(p_row_json->>'Empresa', ''::character varying), "Empresa")::character varying,
        "RIF"       = COALESCE(NULLIF(p_row_json->>'RIF', ''::character varying), "RIF")::character varying,
        "Nit"       = COALESCE(NULLIF(p_row_json->>'Nit', ''::character varying), "Nit")::character varying,
        "Telefono"  = COALESCE(NULLIF(p_row_json->>'Telefono', ''::character varying), "Telefono")::character varying,
        "Direccion" = COALESCE(NULLIF(p_row_json->>'Direccion', ''::character varying), "Direccion")::character varying,
        "Rifs"      = COALESCE(NULLIF(p_row_json->>'Rifs', ''::character varying), "Rifs")::character varying;

    RETURN QUERY SELECT 1, 'OK'::VARCHAR(500);

EXCEPTION WHEN OTHERS THEN
    RETURN QUERY SELECT -99, SQLERRM::VARCHAR(500);
END;
$function$
;

-- ============================================================
-- usp_facturas_getbynumfact
-- ============================================================
CREATE OR REPLACE FUNCTION public.usp_facturas_getbynumfact(p_num_fact character varying)
 RETURNS TABLE("Id" integer, "DocumentNumber" character varying, "OperationType" character varying, "DocumentDate" timestamp without time zone, "UserCode" character varying, "ClientCode" character varying, "ClientName" character varying, "SubTotal" numeric, "TaxAmount" numeric, "TotalAmount" numeric, "Currency" character varying, "ExchangeRate" numeric, "Notes" character varying, "IsDeleted" boolean, "CreatedAt" timestamp without time zone, "UpdatedAt" timestamp without time zone)
 LANGUAGE plpgsql
AS $function$
BEGIN
    RETURN QUERY
    SELECT
        sd."Id",
        sd."DocumentNumber",
        sd."OperationType",
        sd."DocumentDate",
        sd."UserCode",
        sd."ClientCode",
        sd."ClientName",
        sd."SubTotal",
        sd."TaxAmount",
        sd."TotalAmount",
        sd."Currency",
        sd."ExchangeRate",
        sd."Notes",
        sd."IsDeleted",
        sd."CreatedAt",
        sd."UpdatedAt"
    FROM ar."SalesDocument" sd
    WHERE sd."DocumentNumber" = p_num_fact
      AND sd."OperationType" = 'FACT'
      AND sd."IsDeleted" = FALSE;
END;
$function$
;

-- ============================================================
-- usp_facturas_list
-- ============================================================
CREATE OR REPLACE FUNCTION public.usp_facturas_list(p_num_fact character varying DEFAULT NULL::character varying, p_cod_usuario character varying DEFAULT NULL::character varying, p_from date DEFAULT NULL::date, p_to date DEFAULT NULL::date, p_page integer DEFAULT 1, p_limit integer DEFAULT 50)
 RETURNS TABLE("TotalCount" integer, "Id" integer, "DocumentNumber" character varying, "OperationType" character varying, "DocumentDate" timestamp without time zone, "UserCode" character varying, "ClientCode" character varying, "ClientName" character varying, "SubTotal" numeric, "TaxAmount" numeric, "TotalAmount" numeric, "Currency" character varying, "ExchangeRate" numeric, "Notes" character varying, "IsDeleted" boolean, "CreatedAt" timestamp without time zone, "UpdatedAt" timestamp without time zone)
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_offset INT;
    v_limit  INT;
    v_total  INT;
BEGIN
    v_limit  := COALESCE(NULLIF(p_limit, 0), 50)::character varying;
    IF v_limit < 1 THEN v_limit := 50; END IF;
    IF v_limit > 500 THEN v_limit := 500; END IF;
    v_offset := (COALESCE(NULLIF(p_page, 0), 1)::character varying - 1) * v_limit;
    IF v_offset < 0 THEN v_offset := 0; END IF;

    -- Contar total
    SELECT COUNT(1) INTO v_total
    FROM ar."SalesDocument" sd
    WHERE sd."OperationType" = 'FACT'
      AND sd."IsDeleted" = FALSE
      AND (p_num_fact IS NULL OR TRIM(p_num_fact) = '' OR sd."DocumentNumber" = p_num_fact)
      AND (p_cod_usuario IS NULL OR TRIM(p_cod_usuario) = '' OR sd."UserCode" = p_cod_usuario)
      AND (p_from IS NULL OR sd."DocumentDate" >= p_from)
      AND (p_to IS NULL OR sd."DocumentDate" <= p_to);

    -- Devolver filas
    RETURN QUERY
    SELECT
        v_total,
        sd."Id",
        sd."DocumentNumber",
        sd."OperationType",
        sd."DocumentDate",
        sd."UserCode",
        sd."ClientCode",
        sd."ClientName",
        sd."SubTotal",
        sd."TaxAmount",
        sd."TotalAmount",
        sd."Currency",
        sd."ExchangeRate",
        sd."Notes",
        sd."IsDeleted",
        sd."CreatedAt",
        sd."UpdatedAt"
    FROM ar."SalesDocument" sd
    WHERE sd."OperationType" = 'FACT'
      AND sd."IsDeleted" = FALSE
      AND (p_num_fact IS NULL OR TRIM(p_num_fact) = '' OR sd."DocumentNumber" = p_num_fact)
      AND (p_cod_usuario IS NULL OR TRIM(p_cod_usuario) = '' OR sd."UserCode" = p_cod_usuario)
      AND (p_from IS NULL OR sd."DocumentDate" >= p_from)
      AND (p_to IS NULL OR sd."DocumentDate" <= p_to)
    ORDER BY sd."DocumentDate" DESC
    LIMIT v_limit OFFSET v_offset;
END;
$function$
;

-- ============================================================
-- usp_feriados_delete
-- ============================================================
CREATE OR REPLACE FUNCTION public.usp_feriados_delete(p_fecha date)
 RETURNS TABLE("Resultado" integer, "Mensaje" character varying)
 LANGUAGE plpgsql
AS $function$
BEGIN
    IF NOT EXISTS (SELECT 1 FROM public."Feriados" WHERE "Fecha"::DATE = p_fecha) THEN
        RETURN QUERY SELECT -1, 'Feriado no encontrado'::VARCHAR(500);
        RETURN;
    END IF;

    DELETE FROM public."Feriados" WHERE "Fecha"::DATE = p_fecha;

    RETURN QUERY SELECT 1, 'OK'::VARCHAR(500);

EXCEPTION WHEN OTHERS THEN
    RETURN QUERY SELECT -99, SQLERRM::VARCHAR(500);
END;
$function$
;

-- ============================================================
-- usp_feriados_getbyfecha
-- ============================================================
CREATE OR REPLACE FUNCTION public.usp_feriados_getbyfecha(p_fecha date)
 RETURNS TABLE("Fecha" date, "Descripcion" character varying)
 LANGUAGE plpgsql
AS $function$
BEGIN
    RETURN QUERY
    SELECT
        f."Fecha"::DATE,
        f."Descripcion"
    FROM public."Feriados" f
    WHERE f."Fecha"::DATE = p_fecha;
END;
$function$
;

-- ============================================================
-- usp_feriados_insert
-- ============================================================
CREATE OR REPLACE FUNCTION public.usp_feriados_insert(p_row_json jsonb)
 RETURNS TABLE("Resultado" integer, "Mensaje" character varying)
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_fecha DATE;
BEGIN
    v_fecha := (p_row_json->>'Fecha')::DATE;

    IF EXISTS (
        SELECT 1 FROM public."Feriados"
        WHERE "Fecha"::DATE = v_fecha
    ) THEN
        RETURN QUERY SELECT -1, 'Feriado ya existe para esta fecha'::VARCHAR(500);
        RETURN;
    END IF;

    INSERT INTO public."Feriados" ("Fecha", "Descripcion")
    VALUES (
        v_fecha,
        NULLIF(p_row_json->>'Descripcion', ''::character varying)
    );

    RETURN QUERY SELECT 1, 'OK'::VARCHAR(500);

EXCEPTION WHEN OTHERS THEN
    RETURN QUERY SELECT -99, SQLERRM::VARCHAR(500);
END;
$function$
;

-- ============================================================
-- usp_feriados_list
-- ============================================================
CREATE OR REPLACE FUNCTION public.usp_feriados_list(p_search character varying DEFAULT NULL::character varying, p_anio integer DEFAULT NULL::integer, p_page integer DEFAULT 1, p_limit integer DEFAULT 50)
 RETURNS TABLE("TotalCount" integer, "Fecha" date, "Descripcion" character varying)
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_offset  INT;
    v_limit   INT;
    v_search  VARCHAR(100);
    v_total   INT;
BEGIN
    v_limit  := COALESCE(NULLIF(p_limit, 0), 50)::character varying;
    IF v_limit < 1 THEN v_limit := 50; END IF;
    IF v_limit > 500 THEN v_limit := 500; END IF;
    v_offset := (COALESCE(NULLIF(p_page, 0), 1)::character varying - 1) * v_limit;
    IF v_offset < 0 THEN v_offset := 0; END IF;

    v_search := NULL;
    IF p_search IS NOT NULL AND TRIM(p_search) <> '' THEN
        v_search := '%' || p_search || '%';
    END IF;

    -- Contar total
    SELECT COUNT(1) INTO v_total
    FROM public."Feriados" f
    WHERE (v_search IS NULL OR f."Descripcion" LIKE v_search)
      AND (p_anio IS NULL OR EXTRACT(YEAR FROM f."Fecha") = p_anio);

    -- Devolver filas
    RETURN QUERY
    SELECT
        v_total,
        f."Fecha"::DATE,
        f."Descripcion"
    FROM public."Feriados" f
    WHERE (v_search IS NULL OR f."Descripcion" LIKE v_search)
      AND (p_anio IS NULL OR EXTRACT(YEAR FROM f."Fecha") = p_anio)
    ORDER BY f."Fecha"
    LIMIT v_limit OFFSET v_offset;
END;
$function$
;

-- ============================================================
-- usp_feriados_update
-- ============================================================
CREATE OR REPLACE FUNCTION public.usp_feriados_update(p_fecha date, p_row_json jsonb)
 RETURNS TABLE("Resultado" integer, "Mensaje" character varying)
 LANGUAGE plpgsql
AS $function$
BEGIN
    IF NOT EXISTS (SELECT 1 FROM public."Feriados" WHERE "Fecha"::DATE = p_fecha) THEN
        RETURN QUERY SELECT -1, 'Feriado no encontrado'::VARCHAR(500);
        RETURN;
    END IF;

    UPDATE public."Feriados" SET
        "Descripcion" = COALESCE(NULLIF(p_row_json->>'Descripcion', ''::character varying), "Descripcion")::character varying
    WHERE "Fecha"::DATE = p_fecha;

    RETURN QUERY SELECT 1, 'OK'::VARCHAR(500);

EXCEPTION WHEN OTHERS THEN
    RETURN QUERY SELECT -99, SQLERRM::VARCHAR(500);
END;
$function$
;

-- ============================================================
-- usp_fin_bank_delete
-- ============================================================
CREATE OR REPLACE FUNCTION public.usp_fin_bank_delete(p_company_id integer, p_bank_name character varying, p_user_id integer DEFAULT NULL::integer)
 RETURNS TABLE("Success" boolean, "Message" character varying)
 LANGUAGE plpgsql
AS $function$
DECLARE v_affected INT;
BEGIN
    UPDATE fin."Bank"
    SET "IsActive" = FALSE, "UpdatedAt" = NOW() AT TIME ZONE 'UTC', "UpdatedByUserId" = p_user_id
    WHERE "CompanyId" = p_company_id AND "BankName" = p_bank_name AND "IsActive" = TRUE;

    GET DIAGNOSTICS v_affected = ROW_COUNT;
    IF v_affected <= 0 THEN
        RETURN QUERY SELECT FALSE, 'Banco no encontrado'::TEXT;
    ELSE
        RETURN QUERY SELECT TRUE, 'Banco eliminado'::TEXT;
    END IF;
END;
$function$
;

-- ============================================================
-- usp_fin_bank_getbyname
-- ============================================================
CREATE OR REPLACE FUNCTION public.usp_fin_bank_getbyname(p_company_id integer, p_bank_name character varying)
 RETURNS TABLE("Nombre" character varying, "Contacto" character varying, "Direccion" character varying, "Telefonos" character varying)
 LANGUAGE plpgsql
AS $function$
BEGIN
    RETURN QUERY
    SELECT b."BankName", b."ContactName", b."AddressLine", b."Phones"
    FROM fin."Bank" b
    WHERE b."CompanyId" = p_company_id AND b."IsActive" = TRUE AND b."BankName" = p_bank_name
    ORDER BY b."BankId" DESC LIMIT 1;
END;
$function$
;

-- ============================================================
-- usp_fin_bank_insert
-- ============================================================
CREATE OR REPLACE FUNCTION public.usp_fin_bank_insert(p_company_id integer, p_bank_code character varying, p_bank_name character varying, p_contact_name character varying DEFAULT NULL::character varying, p_address_line character varying DEFAULT NULL::character varying, p_phones character varying DEFAULT NULL::character varying, p_user_id integer DEFAULT NULL::integer)
 RETURNS TABLE("Success" boolean, "Message" character varying)
 LANGUAGE plpgsql
AS $function$
BEGIN
    IF EXISTS (SELECT 1 FROM fin."Bank" WHERE "CompanyId" = p_company_id AND "BankName" = p_bank_name) THEN
        RETURN QUERY SELECT FALSE, 'Banco ya existe'::TEXT;
        RETURN;
    END IF;

    INSERT INTO fin."Bank" ("CompanyId", "BankCode", "BankName", "ContactName", "AddressLine", "Phones", "IsActive", "CreatedByUserId", "UpdatedByUserId")
    VALUES (p_company_id, p_bank_code, p_bank_name, p_contact_name, p_address_line, p_phones, TRUE, p_user_id, p_user_id);

    RETURN QUERY SELECT TRUE, 'Banco creado'::TEXT;
END;
$function$
;

-- ============================================================
-- usp_fin_bank_list
-- ============================================================
CREATE OR REPLACE FUNCTION public.usp_fin_bank_list(p_company_id integer, p_search character varying DEFAULT NULL::character varying, p_offset integer DEFAULT 0, p_limit integer DEFAULT 50)
 RETURNS TABLE("TotalCount" bigint, "Nombre" character varying, "Contacto" character varying, "Direccion" character varying, "Telefonos" character varying)
 LANGUAGE plpgsql
AS $function$
DECLARE v_total BIGINT;
BEGIN
    SELECT COUNT(1) INTO v_total FROM fin."Bank"
    WHERE "CompanyId" = p_company_id AND "IsActive" = TRUE
      AND (p_search IS NULL OR "BankName" ILIKE p_search OR "ContactName" ILIKE p_search);

    RETURN QUERY
    SELECT v_total, b."BankName", b."ContactName", b."AddressLine", b."Phones"
    FROM fin."Bank" b
    WHERE b."CompanyId" = p_company_id AND b."IsActive" = TRUE
      AND (p_search IS NULL OR b."BankName" ILIKE p_search OR b."ContactName" ILIKE p_search)
    ORDER BY b."BankName"
    LIMIT p_limit OFFSET p_offset;
END;
$function$
;

-- ============================================================
-- usp_fin_bank_update
-- ============================================================
CREATE OR REPLACE FUNCTION public.usp_fin_bank_update(p_company_id integer, p_bank_name character varying, p_contact_name character varying DEFAULT NULL::character varying, p_address_line character varying DEFAULT NULL::character varying, p_phones character varying DEFAULT NULL::character varying, p_user_id integer DEFAULT NULL::integer)
 RETURNS TABLE("Success" boolean, "Message" character varying)
 LANGUAGE plpgsql
AS $function$
DECLARE v_affected INT;
BEGIN
    UPDATE fin."Bank"
    SET "ContactName" = COALESCE(p_contact_name, "ContactName"),
        "AddressLine" = COALESCE(p_address_line, "AddressLine"),
        "Phones"      = COALESCE(p_phones, "Phones"),
        "UpdatedAt"   = NOW() AT TIME ZONE 'UTC',
        "UpdatedByUserId" = p_user_id
    WHERE "CompanyId" = p_company_id AND "BankName" = p_bank_name AND "IsActive" = TRUE;

    GET DIAGNOSTICS v_affected = ROW_COUNT;
    IF v_affected <= 0 THEN
        RETURN QUERY SELECT FALSE, 'Banco no encontrado'::TEXT;
    ELSE
        RETURN QUERY SELECT TRUE, 'Banco actualizado'::TEXT;
    END IF;
END;
$function$
;

-- ============================================================
-- usp_fin_pettycash_box_create
-- ============================================================
CREATE OR REPLACE FUNCTION public.usp_fin_pettycash_box_create(p_company_id integer, p_branch_id integer, p_name character varying, p_account_code character varying DEFAULT NULL::character varying, p_max_amount numeric DEFAULT 0, p_responsible character varying DEFAULT NULL::character varying, p_created_by_user_id integer DEFAULT NULL::integer)
 RETURNS TABLE("Resultado" integer, "Mensaje" character varying)
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_new_id INT;
BEGIN
    IF EXISTS (
        SELECT 1 FROM fin."PettyCashBox"
        WHERE "CompanyId" = p_company_id
          AND "BranchId" = p_branch_id
          AND "Name" = p_name
          AND "Status" = 'ACTIVE'
    ) THEN
        RETURN QUERY SELECT -1, 'Ya existe una caja chica activa con ese nombre en esta sucursal.'::VARCHAR(500);
        RETURN;
    END IF;

    BEGIN
        INSERT INTO fin."PettyCashBox" (
            "CompanyId", "BranchId", "Name", "AccountCode", "MaxAmount",
            "CurrentBalance", "Responsible", "Status", "CreatedAt", "CreatedByUserId"
        )
        VALUES (
            p_company_id, p_branch_id, p_name, p_account_code, p_max_amount,
            0, p_responsible, 'ACTIVE', NOW() AT TIME ZONE 'UTC', p_created_by_user_id
        )
        RETURNING "Id" INTO v_new_id;

        RETURN QUERY SELECT v_new_id, 'Caja chica creada exitosamente.'::VARCHAR(500);
    EXCEPTION WHEN OTHERS THEN
        RETURN QUERY SELECT -1, SQLERRM::VARCHAR(500);
    END;
END;
$function$
;

-- ============================================================
-- usp_fin_pettycash_box_list
-- ============================================================
CREATE OR REPLACE FUNCTION public.usp_fin_pettycash_box_list(p_company_id integer)
 RETURNS TABLE("Id" integer, "CompanyId" integer, "BranchId" integer, "Name" character varying, "AccountCode" character varying, "MaxAmount" numeric, "CurrentBalance" numeric, "Responsible" character varying, "Status" character varying, "CreatedAt" timestamp with time zone, "CreatedByUserId" integer)
 LANGUAGE plpgsql
AS $function$
BEGIN
    RETURN QUERY
    SELECT
        b."Id", b."CompanyId", b."BranchId", b."Name",
        b."AccountCode", b."MaxAmount", b."CurrentBalance",
        b."Responsible", b."Status", b."CreatedAt", b."CreatedByUserId"
    FROM fin."PettyCashBox" b
    WHERE b."CompanyId" = p_company_id
    ORDER BY b."Name";
END;
$function$
;

-- ============================================================
-- usp_fin_pettycash_expense_add
-- ============================================================
CREATE OR REPLACE FUNCTION public.usp_fin_pettycash_expense_add(p_session_id integer, p_box_id integer, p_category character varying, p_description character varying, p_amount numeric, p_beneficiary character varying DEFAULT NULL::character varying, p_receipt_number character varying DEFAULT NULL::character varying, p_account_code character varying DEFAULT NULL::character varying, p_created_by_user_id integer DEFAULT NULL::integer)
 RETURNS TABLE("Resultado" integer, "Mensaje" character varying)
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_opening_amount NUMERIC(18,2);
    v_total_expenses NUMERIC(18,2);
    v_new_id         INT;
BEGIN
    -- Validar que la sesion existe y esta abierta
    IF NOT EXISTS (
        SELECT 1 FROM fin."PettyCashSession"
        WHERE "Id" = p_session_id AND "BoxId" = p_box_id AND "Status" = 'OPEN'
    ) THEN
        RETURN QUERY SELECT -1, 'La sesion no existe, no pertenece a esta caja o ya esta cerrada.'::VARCHAR(500);
        RETURN;
    END IF;

    -- Validar monto positivo
    IF p_amount <= 0 THEN
        RETURN QUERY SELECT -2, 'El monto del gasto debe ser mayor a cero.'::VARCHAR(500);
        RETURN;
    END IF;

    -- Validar que haya saldo suficiente
    SELECT "OpeningAmount", "TotalExpenses"
    INTO v_opening_amount, v_total_expenses
    FROM fin."PettyCashSession"
    WHERE "Id" = p_session_id;

    IF (v_total_expenses + p_amount) > v_opening_amount THEN
        RETURN QUERY SELECT -3, ('El monto del gasto excede el saldo disponible en la sesion. Disponible: ' || (v_opening_amount - v_total_expenses)::TEXT)::VARCHAR(500);
        RETURN;
    END IF;

    BEGIN
        -- Insertar el gasto
        INSERT INTO fin."PettyCashExpense" (
            "SessionId", "BoxId", "Category", "Description", "Amount",
            "Beneficiary", "ReceiptNumber", "AccountCode", "CreatedAt", "CreatedByUserId"
        )
        VALUES (
            p_session_id, p_box_id, p_category, p_description, p_amount,
            p_beneficiary, p_receipt_number, p_account_code,
            NOW() AT TIME ZONE 'UTC', p_created_by_user_id
        )
        RETURNING "Id" INTO v_new_id;

        -- Actualizar total de gastos en la sesion
        UPDATE fin."PettyCashSession"
        SET "TotalExpenses" = "TotalExpenses" + p_amount
        WHERE "Id" = p_session_id;

        -- Actualizar saldo actual en la caja (restar gasto)
        UPDATE fin."PettyCashBox"
        SET "CurrentBalance" = "CurrentBalance" - p_amount
        WHERE "Id" = p_box_id;

        RETURN QUERY SELECT v_new_id, 'Gasto registrado exitosamente.'::VARCHAR(500);
    EXCEPTION WHEN OTHERS THEN
        RETURN QUERY SELECT -1, SQLERRM::VARCHAR(500);
    END;
END;
$function$
;

-- ============================================================
-- usp_fin_pettycash_expense_list
-- ============================================================
CREATE OR REPLACE FUNCTION public.usp_fin_pettycash_expense_list(p_box_id integer, p_session_id integer DEFAULT NULL::integer)
 RETURNS TABLE("Id" integer, "SessionId" integer, "BoxId" integer, "Category" character varying, "Description" character varying, "Amount" numeric, "Beneficiary" character varying, "ReceiptNumber" character varying, "AccountCode" character varying, "CreatedAt" timestamp with time zone, "CreatedByUserId" integer)
 LANGUAGE plpgsql
AS $function$
BEGIN
    RETURN QUERY
    SELECT
        e."Id", e."SessionId", e."BoxId", e."Category", e."Description",
        e."Amount", e."Beneficiary", e."ReceiptNumber", e."AccountCode",
        e."CreatedAt", e."CreatedByUserId"
    FROM fin."PettyCashExpense" e
    WHERE e."BoxId" = p_box_id
      AND (p_session_id IS NULL OR e."SessionId" = p_session_id)
    ORDER BY e."CreatedAt" DESC;
END;
$function$
;

-- ============================================================
-- usp_fin_pettycash_session_close
-- ============================================================
CREATE OR REPLACE FUNCTION public.usp_fin_pettycash_session_close(p_box_id integer, p_closed_by_user_id integer DEFAULT NULL::integer, p_notes character varying DEFAULT NULL::character varying)
 RETURNS TABLE("Resultado" integer, "Mensaje" character varying)
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_session_id     INT;
    v_opening_amount NUMERIC(18,2);
    v_total_expenses NUMERIC(18,2);
    v_closing_amount NUMERIC(18,2);
BEGIN
    -- Buscar la sesion abierta para esta caja
    SELECT "Id", "OpeningAmount", "TotalExpenses"
    INTO v_session_id, v_opening_amount, v_total_expenses
    FROM fin."PettyCashSession"
    WHERE "BoxId" = p_box_id AND "Status" = 'OPEN';

    IF v_session_id IS NULL THEN
        RETURN QUERY SELECT -1, 'No existe una sesion abierta para esta caja chica.'::VARCHAR(500);
        RETURN;
    END IF;

    -- Calcular monto de cierre
    v_closing_amount := v_opening_amount - v_total_expenses;

    BEGIN
        -- Cerrar la sesion
        UPDATE fin."PettyCashSession"
        SET "Status" = 'CLOSED',
            "ClosingAmount" = v_closing_amount,
            "ClosedAt" = NOW() AT TIME ZONE 'UTC',
            "ClosedByUserId" = p_closed_by_user_id,
            "Notes" = p_notes
        WHERE "Id" = v_session_id;

        -- Actualizar saldo en la caja
        UPDATE fin."PettyCashBox"
        SET "CurrentBalance" = v_closing_amount
        WHERE "Id" = p_box_id;

        RETURN QUERY SELECT v_session_id, ('Sesion cerrada exitosamente. Monto de cierre: ' || v_closing_amount::TEXT)::VARCHAR(500);
    EXCEPTION WHEN OTHERS THEN
        RETURN QUERY SELECT -1, SQLERRM::VARCHAR(500);
    END;
END;
$function$
;

-- ============================================================
-- usp_fin_pettycash_session_getactive
-- ============================================================
CREATE OR REPLACE FUNCTION public.usp_fin_pettycash_session_getactive(p_box_id integer)
 RETURNS TABLE("Id" integer, "BoxId" integer, "OpeningAmount" numeric, "ClosingAmount" numeric, "TotalExpenses" numeric, "Status" character varying, "OpenedAt" timestamp with time zone, "ClosedAt" timestamp with time zone, "OpenedByUserId" integer, "ClosedByUserId" integer, "Notes" character varying, "AvailableBalance" numeric, "ExpenseCount" bigint)
 LANGUAGE plpgsql
AS $function$
BEGIN
    RETURN QUERY
    SELECT
        s."Id", s."BoxId", s."OpeningAmount", s."ClosingAmount",
        s."TotalExpenses", s."Status", s."OpenedAt", s."ClosedAt",
        s."OpenedByUserId", s."ClosedByUserId", s."Notes",
        (s."OpeningAmount" - s."TotalExpenses"),
        (SELECT COUNT(1) FROM fin."PettyCashExpense" e WHERE e."SessionId" = s."Id")
    FROM fin."PettyCashSession" s
    WHERE s."BoxId" = p_box_id
      AND s."Status" = 'OPEN';
END;
$function$
;

-- ============================================================
-- usp_fin_pettycash_session_open
-- ============================================================
CREATE OR REPLACE FUNCTION public.usp_fin_pettycash_session_open(p_box_id integer, p_opening_amount numeric, p_opened_by_user_id integer DEFAULT NULL::integer)
 RETURNS TABLE("Resultado" integer, "Mensaje" character varying)
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_max_amount NUMERIC(18,2);
    v_new_id     INT;
BEGIN
    -- Validar que la caja existe y esta activa
    IF NOT EXISTS (SELECT 1 FROM fin."PettyCashBox" WHERE "Id" = p_box_id AND "Status" = 'ACTIVE') THEN
        RETURN QUERY SELECT -1, 'La caja chica no existe o no esta activa.'::VARCHAR(500);
        RETURN;
    END IF;

    -- Validar que no haya otra sesion abierta para esta caja
    IF EXISTS (SELECT 1 FROM fin."PettyCashSession" WHERE "BoxId" = p_box_id AND "Status" = 'OPEN') THEN
        RETURN QUERY SELECT -2, 'Ya existe una sesion abierta para esta caja chica. Debe cerrarla primero.'::VARCHAR(500);
        RETURN;
    END IF;

    -- Validar que el monto de apertura no exceda el maximo permitido
    SELECT "MaxAmount" INTO v_max_amount FROM fin."PettyCashBox" WHERE "Id" = p_box_id;

    IF v_max_amount > 0 AND p_opening_amount > v_max_amount THEN
        RETURN QUERY SELECT -3, ('El monto de apertura excede el monto maximo permitido para esta caja chica (' || v_max_amount::TEXT || ').')::VARCHAR(500);
        RETURN;
    END IF;

    BEGIN
        -- Crear la sesion
        INSERT INTO fin."PettyCashSession" (
            "BoxId", "OpeningAmount", "ClosingAmount", "TotalExpenses",
            "Status", "OpenedAt", "OpenedByUserId"
        )
        VALUES (
            p_box_id, p_opening_amount, NULL, 0,
            'OPEN', NOW() AT TIME ZONE 'UTC', p_opened_by_user_id
        )
        RETURNING "Id" INTO v_new_id;

        -- Actualizar el saldo actual de la caja
        UPDATE fin."PettyCashBox"
        SET "CurrentBalance" = p_opening_amount
        WHERE "Id" = p_box_id;

        RETURN QUERY SELECT v_new_id, 'Sesion de caja chica abierta exitosamente.'::VARCHAR(500);
    EXCEPTION WHEN OTHERS THEN
        RETURN QUERY SELECT -1, SQLERRM::VARCHAR(500);
    END;
END;
$function$
;

-- ============================================================
-- usp_fin_pettycash_summary_box
