-- ============================================================
-- usp_fiscal_taxbook_populate
-- ============================================================
CREATE OR REPLACE FUNCTION public.usp_fiscal_taxbook_populate(p_company_id integer, p_book_type character varying, p_period_code character varying, p_country_code character varying, p_cod_usuario character varying, OUT p_resultado integer, OUT p_mensaje text)
 RETURNS record
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_period_start  DATE;
    v_period_end    DATE;
    v_rows_inserted INTEGER := 0;
BEGIN
    p_resultado := 0;
    p_mensaje   := '';

    v_period_start := CAST(p_period_code || '-01' AS DATE);
    v_period_end   := (DATE_TRUNC('month', v_period_start) + INTERVAL '1 month - 1 day')::DATE;

    IF p_book_type NOT IN ('SALES', 'PURCHASE') THEN
        p_resultado := 0;
        p_mensaje   := 'BookType debe ser SALES o PURCHASE';
        RETURN;
    END IF;

    BEGIN
        -- Eliminar entradas existentes para regenerar
        DELETE FROM fiscal."TaxBookEntry"
        WHERE "CompanyId"   = p_company_id
          AND "BookType"    = p_book_type
          AND "PeriodCode"  = p_period_code
          AND "CountryCode" = p_country_code;

        IF p_book_type = 'SALES' THEN
            -- Fuente: dbo.DocumentosVenta
            INSERT INTO fiscal."TaxBookEntry" (
                "CompanyId", "BookType", "PeriodCode", "EntryDate",
                "DocumentNumber", "DocumentType", "ControlNumber",
                "ThirdPartyId", "ThirdPartyName",
                "TaxableBase", "ExemptAmount", "TaxRate", "TaxAmount",
                "WithholdingRate", "WithholdingAmount", "TotalAmount",
                "SourceDocumentId", "SourceModule", "CountryCode", "CreatedAt"
            )
            SELECT
                p_company_id,
                'SALES',
                p_period_code,
                v."FECHA",
                v."NUM_DOC",
                CASE v."SERIALTIPO"
                    WHEN 'FAC' THEN 'FACTURA'
                    WHEN 'NC'  THEN 'NOTA_CREDITO'
                    WHEN 'ND'  THEN 'NOTA_DEBITO'
                    ELSE v."SERIALTIPO"
                END,
                v."NUM_CONTROL",
                v."RIF",
                v."NOMBRE",
                COALESCE(v."MONTO_GRA", 0),
                COALESCE(v."MONTO_EXE", 0),
                COALESCE(v."ALICUOTA", 0),
                COALESCE(v."IVA", 0),
                0,
                0,
                COALESCE(v."TOTAL", 0),
                v."ID",
                'AR',
                p_country_code,
                (NOW() AT TIME ZONE 'UTC')
            FROM dbo."DocumentosVenta" v
            WHERE v."FECHA" BETWEEN v_period_start AND v_period_end
              AND v."ANULADA" = 0;

            GET DIAGNOSTICS v_rows_inserted = ROW_COUNT;

        ELSIF p_book_type = 'PURCHASE' THEN
            -- Fuente: dbo.DocumentosCompra
            INSERT INTO fiscal."TaxBookEntry" (
                "CompanyId", "BookType", "PeriodCode", "EntryDate",
                "DocumentNumber", "DocumentType", "ControlNumber",
                "ThirdPartyId", "ThirdPartyName",
                "TaxableBase", "ExemptAmount", "TaxRate", "TaxAmount",
                "WithholdingRate", "WithholdingAmount", "TotalAmount",
                "SourceDocumentId", "SourceModule", "CountryCode", "CreatedAt"
            )
            SELECT
                p_company_id,
                'PURCHASE',
                p_period_code,
                c."FECHA",
                c."NUM_DOC",
                CASE c."SERIALTIPO"
                    WHEN 'FAC' THEN 'FACTURA'
                    WHEN 'NC'  THEN 'NOTA_CREDITO'
                    WHEN 'ND'  THEN 'NOTA_DEBITO'
                    ELSE c."SERIALTIPO"
                END,
                c."NUM_CONTROL",
                c."RIF",
                c."NOMBRE",
                COALESCE(c."MONTO_GRA", 0),
                COALESCE(c."MONTO_EXE", 0),
                COALESCE(c."ALICUOTA", 0),
                COALESCE(c."IVA", 0),
                0,
                0,
                COALESCE(c."TOTAL", 0),
                c."ID",
                'AP',
                p_country_code,
                (NOW() AT TIME ZONE 'UTC')
            FROM dbo."DocumentosCompra" c
            WHERE c."FECHA" BETWEEN v_period_start AND v_period_end
              AND c."ANULADA" = 0;

            GET DIAGNOSTICS v_rows_inserted = ROW_COUNT;
        END IF;

        p_resultado := 1;
        p_mensaje   := 'Libro fiscal generado: ' || v_rows_inserted::TEXT || ' registros';
    EXCEPTION WHEN OTHERS THEN
        p_resultado := 0;
        p_mensaje   := 'Error: ' || SQLERRM;
    END;
END;
$function$
;

-- ============================================================
-- usp_fiscal_taxbook_summary
-- ============================================================
CREATE OR REPLACE FUNCTION public.usp_fiscal_taxbook_summary(p_company_id integer, p_book_type character varying, p_period_code character varying, p_country_code character varying)
 RETURNS TABLE("TaxRate" numeric, "TaxableBase" numeric, "ExemptAmount" numeric, "TaxAmount" numeric, "WithholdingAmount" numeric, "TotalAmount" numeric, "EntryCount" bigint)
 LANGUAGE plpgsql
AS $function$
BEGIN
    RETURN QUERY
    SELECT "TaxRate",
           SUM("TaxableBase")        AS "TaxableBase",
           SUM("ExemptAmount")       AS "ExemptAmount",
           SUM("TaxAmount")          AS "TaxAmount",
           SUM("WithholdingAmount")  AS "WithholdingAmount",
           SUM("TotalAmount")        AS "TotalAmount",
           COUNT(*)                  AS "EntryCount"
    FROM fiscal."TaxBookEntry"
    WHERE "CompanyId"   = p_company_id
      AND "BookType"    = p_book_type
      AND "PeriodCode"  = p_period_code
      AND "CountryCode" = p_country_code
    GROUP BY "TaxRate"
    ORDER BY "TaxRate";
END;
$function$
;

-- ============================================================
-- usp_fiscal_withholding_generate
-- ============================================================
CREATE OR REPLACE FUNCTION public.usp_fiscal_withholding_generate(p_company_id integer, p_document_id bigint, p_withholding_type character varying, p_country_code character varying, p_cod_usuario character varying, OUT p_voucher_id bigint, OUT p_resultado integer, OUT p_mensaje text)
 RETURNS record
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_taxable_base       NUMERIC(18,2);
    v_rate               NUMERIC(8,4);
    v_withholding_amount NUMERIC(18,2);
    v_period_code        VARCHAR(7);
    v_voucher_number     VARCHAR(50);
    v_next_seq           INTEGER;
    v_doc_fecha          DATE;
    v_doc_num_doc        VARCHAR(50);
    v_third_party_id     VARCHAR(50);
    v_third_party_name   VARCHAR(200);
BEGIN
    p_voucher_id := 0;
    p_resultado  := 0;
    p_mensaje    := '';

    SELECT COALESCE(c."MONTO_GRA", 0), c."FECHA", c."NUM_DOC", c."RIF", c."NOMBRE"
    INTO v_taxable_base, v_doc_fecha, v_doc_num_doc, v_third_party_id, v_third_party_name
    FROM dbo."DocumentosCompra" c
    WHERE c."ID" = p_document_id;

    IF v_taxable_base IS NULL THEN
        p_voucher_id := 0;
        p_mensaje    := 'Documento de compra no encontrado';
        RETURN;
    END IF;

    SELECT "RetentionRate" INTO v_rate
    FROM master."TaxRetention"
    WHERE "RetentionType" = p_withholding_type
      AND "CountryCode"   = p_country_code
    LIMIT 1;

    IF v_rate IS NULL THEN
        p_voucher_id := 0;
        p_mensaje    := 'Tasa de retencion no configurada para tipo: ' || p_withholding_type || ', pais: ' || p_country_code;
        RETURN;
    END IF;

    v_withholding_amount := ROUND(v_taxable_base * v_rate / 100.0, 2);
    v_period_code        := TO_CHAR(v_doc_fecha, 'YYYY-MM');

    BEGIN
        SELECT COALESCE(MAX(
            CAST(RIGHT("VoucherNumber", 4) AS INTEGER)
        ), 0) + 1
        INTO v_next_seq
        FROM fiscal."WithholdingVoucher"
        WHERE "CompanyId"      = p_company_id
          AND "WithholdingType" = p_withholding_type
          AND "PeriodCode"     = v_period_code
          AND "CountryCode"    = p_country_code;

        v_voucher_number := p_withholding_type || '-'
                          || REPLACE(v_period_code, '-', '') || '-'
                          || LPAD(v_next_seq::TEXT, 4, '0');

        INSERT INTO fiscal."WithholdingVoucher" (
            "CompanyId", "VoucherNumber", "VoucherDate",
            "WithholdingType", "ThirdPartyId", "ThirdPartyName",
            "DocumentNumber", "DocumentDate", "TaxableBase",
            "WithholdingRate", "WithholdingAmount", "PeriodCode",
            "Status", "CountryCode", "CreatedBy", "CreatedAt"
        )
        VALUES (
            p_company_id, v_voucher_number, (NOW() AT TIME ZONE 'UTC'),
            p_withholding_type, v_third_party_id, v_third_party_name,
            v_doc_num_doc, v_doc_fecha, v_taxable_base,
            v_rate, v_withholding_amount, v_period_code,
            'GENERATED', p_country_code, p_cod_usuario, (NOW() AT TIME ZONE 'UTC')
        )
        RETURNING "VoucherId" INTO p_voucher_id;

        p_resultado := 1;
        p_mensaje   := 'Comprobante generado: ' || v_voucher_number
                     || ', Monto retenido: ' || v_withholding_amount::TEXT;
    EXCEPTION WHEN OTHERS THEN
        p_voucher_id := 0;
        p_resultado  := 0;
        p_mensaje    := 'Error: ' || SQLERRM;
    END;
END;
$function$
;

-- ============================================================
-- usp_fiscal_withholding_get
-- ============================================================
CREATE OR REPLACE FUNCTION public.usp_fiscal_withholding_get(p_company_id integer, p_voucher_id bigint)
 RETURNS TABLE("VoucherId" bigint, "CompanyId" integer, "VoucherNumber" character varying, "VoucherDate" timestamp without time zone, "WithholdingType" character varying, "ThirdPartyId" character varying, "ThirdPartyName" character varying, "DocumentNumber" character varying, "DocumentDate" date, "TaxableBase" numeric, "WithholdingRate" numeric, "WithholdingAmount" numeric, "PeriodCode" character varying, "Status" character varying, "CountryCode" character varying, "JournalEntryId" bigint, "CreatedBy" character varying, "CreatedAt" timestamp without time zone)
 LANGUAGE plpgsql
AS $function$
BEGIN
    RETURN QUERY
    SELECT "VoucherId", "CompanyId", "VoucherNumber", "VoucherDate",
           "WithholdingType", "ThirdPartyId", "ThirdPartyName",
           "DocumentNumber", "DocumentDate", "TaxableBase",
           "WithholdingRate", "WithholdingAmount", "PeriodCode",
           "Status", "CountryCode", "JournalEntryId",
           "CreatedBy", "CreatedAt"
    FROM fiscal."WithholdingVoucher"
    WHERE "CompanyId" = p_company_id
      AND "VoucherId" = p_voucher_id
    LIMIT 1;
END;
$function$
;

-- ============================================================
-- usp_fiscal_withholding_list
-- ============================================================
CREATE OR REPLACE FUNCTION public.usp_fiscal_withholding_list(p_company_id integer, p_withholding_type character varying DEFAULT NULL::character varying, p_period_code character varying DEFAULT NULL::character varying, p_country_code character varying DEFAULT NULL::character varying, p_page integer DEFAULT 1, p_limit integer DEFAULT 50)
 RETURNS TABLE(p_total_count bigint, "VoucherId" bigint, "CompanyId" integer, "VoucherNumber" character varying, "VoucherDate" timestamp without time zone, "WithholdingType" character varying, "ThirdPartyId" character varying, "ThirdPartyName" character varying, "DocumentNumber" character varying, "DocumentDate" date, "TaxableBase" numeric, "WithholdingRate" numeric, "WithholdingAmount" numeric, "PeriodCode" character varying, "Status" character varying, "CountryCode" character varying, "JournalEntryId" bigint, "CreatedBy" character varying, "CreatedAt" timestamp without time zone)
 LANGUAGE plpgsql
AS $function$
BEGIN
    IF p_page  < 1   THEN p_page  := 1;  END IF;
    IF p_limit < 1   THEN p_limit := 50; END IF;
    IF p_limit > 500 THEN p_limit := 500; END IF;

    RETURN QUERY
    SELECT COUNT(*) OVER()  AS p_total_count,
           "VoucherId", "CompanyId", "VoucherNumber", "VoucherDate",
           "WithholdingType", "ThirdPartyId", "ThirdPartyName",
           "DocumentNumber", "DocumentDate", "TaxableBase",
           "WithholdingRate", "WithholdingAmount", "PeriodCode",
           "Status", "CountryCode", "JournalEntryId",
           "CreatedBy", "CreatedAt"
    FROM fiscal."WithholdingVoucher"
    WHERE "CompanyId" = p_company_id
      AND (p_withholding_type IS NULL OR "WithholdingType" = p_withholding_type)
      AND (p_period_code      IS NULL OR "PeriodCode"      = p_period_code)
      AND (p_country_code     IS NULL OR "CountryCode"     = p_country_code)
    ORDER BY "VoucherDate" DESC
    LIMIT p_limit OFFSET (p_page - 1) * p_limit;
END;
$function$
;

-- ============================================================
-- usp_governance_capturesnapshot
-- ============================================================
CREATE OR REPLACE FUNCTION public.usp_governance_capturesnapshot(p_notes character varying DEFAULT NULL::character varying)
 RETURNS TABLE("Id" bigint, "SnapshotAt" timestamp without time zone, "TotalTables" integer, "TablesWithoutPK" integer, "TablesWithoutCreatedAt" integer, "TablesWithoutUpdatedAt" integer, "TablesWithoutCreatedBy" integer, "TablesWithoutDateColumns" integer, "DuplicateNameCandidatePairs" integer, "SimilarityCandidatePairs" integer, "Notes" character varying)
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_total INT := 0;
    v_no_pk INT := 0;
    v_no_cat INT := 0;
    v_no_uat INT := 0;
    v_no_cby INT := 0;
    v_no_dt INT := 0;
    v_dup INT := 0;
    v_sim INT := 0;
BEGIN
    SELECT
        COUNT(1),
        SUM(CASE WHEN NOT has_pk THEN 1 ELSE 0 END),
        SUM(CASE WHEN NOT has_created_at THEN 1 ELSE 0 END),
        SUM(CASE WHEN NOT has_updated_at THEN 1 ELSE 0 END),
        SUM(CASE WHEN NOT has_created_by THEN 1 ELSE 0 END),
        SUM(CASE WHEN date_column_count = 0 THEN 1 ELSE 0 END)
    INTO v_total, v_no_pk, v_no_cat, v_no_uat, v_no_cby, v_no_dt
    FROM public."vw_Governance_AuditCoverage";

    SELECT COUNT(1) INTO v_dup FROM public."vw_Governance_DuplicateNameCandidates";
    SELECT COUNT(1) INTO v_sim FROM public."vw_Governance_TableSimilarityCandidates" WHERE similarity_ratio >= 0.7000;

    INSERT INTO public."SchemaGovernanceSnapshot" (
        "TotalTables", "TablesWithoutPK", "TablesWithoutCreatedAt", "TablesWithoutUpdatedAt",
        "TablesWithoutCreatedBy", "TablesWithoutDateColumns", "DuplicateNameCandidatePairs",
        "SimilarityCandidatePairs", "Notes"
    ) VALUES (v_total, v_no_pk, v_no_cat, v_no_uat, v_no_cby, v_no_dt, v_dup, v_sim, p_notes);

    RETURN QUERY
    SELECT s.* FROM public."SchemaGovernanceSnapshot" s ORDER BY s."Id" DESC LIMIT 1;
END;
$function$
;

-- ============================================================
-- usp_grupos_delete
-- ============================================================
CREATE OR REPLACE FUNCTION public.usp_grupos_delete(p_codigo integer)
 RETURNS TABLE("Resultado" integer, "Mensaje" character varying)
 LANGUAGE plpgsql
AS $function$
BEGIN
    IF NOT EXISTS (SELECT 1 FROM public."Grupos" WHERE "Codigo" = p_codigo) THEN
        RETURN QUERY SELECT 0, 'Grupo no encontrado'::VARCHAR(500);
        RETURN;
    END IF;

    DELETE FROM public."Grupos" WHERE "Codigo" = p_codigo;

    RETURN QUERY SELECT 1, 'Grupo eliminado exitosamente'::VARCHAR(500);

EXCEPTION WHEN OTHERS THEN
    RETURN QUERY SELECT 0, SQLERRM::VARCHAR(500);
END;
$function$
;

-- ============================================================
-- usp_grupos_getbycodigo
-- ============================================================
CREATE OR REPLACE FUNCTION public.usp_grupos_getbycodigo(p_codigo integer)
 RETURNS TABLE("Codigo" integer, "Descripcion" character varying, "Co_Usuario" character varying, "Porcentaje" double precision)
 LANGUAGE plpgsql
AS $function$
BEGIN
    RETURN QUERY
    SELECT
        g."Codigo",
        g."Descripcion",
        g."Co_Usuario",
        g."Porcentaje"
    FROM public."Grupos" g
    WHERE g."Codigo" = p_codigo;
END;
$function$
;

-- ============================================================
-- usp_grupos_insert
-- ============================================================
CREATE OR REPLACE FUNCTION public.usp_grupos_insert(p_row_json jsonb)
 RETURNS TABLE("Resultado" integer, "Mensaje" character varying, "NuevoCodigo" integer)
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_descripcion  VARCHAR(50);
    v_co_usuario   VARCHAR(10);
    v_porcentaje_str VARCHAR(50);
    v_porcentaje   DOUBLE PRECISION;
    v_nuevo_codigo INT;
BEGIN
    v_descripcion    := NULLIF(p_row_json->>'Descripcion', ''::character varying);
    v_co_usuario     := NULLIF(p_row_json->>'Co_Usuario', ''::character varying);
    v_porcentaje_str := NULLIF(p_row_json->>'Porcentaje', ''::character varying);
    v_porcentaje     := CASE
                            WHEN v_porcentaje_str IS NOT NULL AND v_porcentaje_str ~ '^\d+(\.\d+)?$'
                            THEN v_porcentaje_str::DOUBLE PRECISION
                            ELSE 0
                        END;

    INSERT INTO public."Grupos" ("Descripcion", "Co_Usuario", "Porcentaje")
    VALUES (v_descripcion, v_co_usuario, v_porcentaje)
    RETURNING "Codigo" INTO v_nuevo_codigo;

    RETURN QUERY SELECT 1, 'Grupo creado exitosamente'::VARCHAR(500), v_nuevo_codigo;

EXCEPTION WHEN OTHERS THEN
    RETURN QUERY SELECT 0, SQLERRM::VARCHAR(500), NULL::INT;
END;
$function$
;

-- ============================================================
-- usp_grupos_list
-- ============================================================
CREATE OR REPLACE FUNCTION public.usp_grupos_list(p_search character varying DEFAULT NULL::character varying, p_page integer DEFAULT 1, p_limit integer DEFAULT 50)
 RETURNS TABLE("TotalCount" integer, "Codigo" integer, "Descripcion" character varying, "Co_Usuario" character varying, "Porcentaje" double precision)
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_offset  INT;
    v_total   INT;
BEGIN
    v_offset := (p_page - 1) * p_limit;

    -- Contar total
    SELECT COUNT(1) INTO v_total
    FROM public."Grupos" g
    WHERE (p_search IS NULL
           OR g."Codigo"::VARCHAR(20) LIKE '%' || p_search || '%'
           OR g."Descripcion" LIKE '%' || p_search || '%');

    -- Devolver filas
    RETURN QUERY
    SELECT
        v_total,
        g."Codigo",
        g."Descripcion",
        g."Co_Usuario",
        g."Porcentaje"
    FROM public."Grupos" g
    WHERE (p_search IS NULL
           OR g."Codigo"::VARCHAR(20) LIKE '%' || p_search || '%'
           OR g."Descripcion" LIKE '%' || p_search || '%')
    ORDER BY g."Codigo"
    LIMIT p_limit OFFSET v_offset;
END;
$function$
;

-- ============================================================
-- usp_grupos_update
-- ============================================================
CREATE OR REPLACE FUNCTION public.usp_grupos_update(p_codigo integer, p_row_json jsonb)
 RETURNS TABLE("Resultado" integer, "Mensaje" character varying)
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_descripcion  VARCHAR(50);
    v_co_usuario   VARCHAR(10);
    v_porcentaje_str VARCHAR(50);
    v_porcentaje   DOUBLE PRECISION;
BEGIN
    IF NOT EXISTS (SELECT 1 FROM public."Grupos" WHERE "Codigo" = p_codigo) THEN
        RETURN QUERY SELECT 0, 'Grupo no encontrado'::VARCHAR(500);
        RETURN;
    END IF;

    v_descripcion    := NULLIF(p_row_json->>'Descripcion', ''::character varying);
    v_co_usuario     := NULLIF(p_row_json->>'Co_Usuario', ''::character varying);
    v_porcentaje_str := NULLIF(p_row_json->>'Porcentaje', ''::character varying);
    v_porcentaje     := CASE
                            WHEN v_porcentaje_str IS NOT NULL AND v_porcentaje_str ~ '^\d+(\.\d+)?$'
                            THEN v_porcentaje_str::DOUBLE PRECISION
                            ELSE 0
                        END;

    UPDATE public."Grupos" SET
        "Descripcion" = v_descripcion,
        "Co_Usuario"  = v_co_usuario,
        "Porcentaje"  = v_porcentaje
    WHERE "Codigo" = p_codigo;

    RETURN QUERY SELECT 1, 'Grupo actualizado exitosamente'::VARCHAR(500);

EXCEPTION WHEN OTHERS THEN
    RETURN QUERY SELECT 0, SQLERRM::VARCHAR(500);
END;
$function$
;

-- ============================================================
-- usp_hr_committee_addmember
-- ============================================================
CREATE OR REPLACE FUNCTION public.usp_hr_committee_addmember(p_safety_committee_id integer, p_company_id integer, p_employee_id bigint DEFAULT NULL::bigint, p_employee_code character varying DEFAULT NULL::character varying, p_employee_name character varying DEFAULT NULL::character varying, p_role character varying DEFAULT NULL::character varying, p_start_date date DEFAULT NULL::date, p_end_date date DEFAULT NULL::date, OUT p_resultado integer, OUT p_mensaje character varying)
 RETURNS record
 LANGUAGE plpgsql
AS $function$
BEGIN
    p_resultado := 0;
    p_mensaje   := '';

    IF p_role NOT IN ('PRESIDENT','SECRETARY','DELEGATE','EMPLOYER_REP') THEN
        p_resultado := -1;
        p_mensaje   := 'Rol no vÃƒÂ¡lido.';
        RETURN;
    END IF;

    IF NOT EXISTS (
        SELECT 1 FROM hr."SafetyCommittee"
        WHERE "SafetyCommitteeId" = p_safety_committee_id AND "CompanyId" = p_company_id
    ) THEN
        p_resultado := -1;
        p_mensaje   := 'ComitÃƒÂ© no encontrado.';
        RETURN;
    END IF;

    IF EXISTS (
        SELECT 1 FROM hr."SafetyCommitteeMember"
        WHERE "SafetyCommitteeId" = p_safety_committee_id
          AND "EmployeeCode" = p_employee_code
          AND ("EndDate" IS NULL OR "EndDate" >= p_start_date)
    ) THEN
        p_resultado := -1;
        p_mensaje   := 'El empleado ya es miembro activo de este comitÃƒÂ©.';
        RETURN;
    END IF;

    BEGIN
        INSERT INTO hr."SafetyCommitteeMember" (
            "SafetyCommitteeId", "EmployeeId", "EmployeeCode", "EmployeeName",
            "Role", "StartDate", "EndDate"
        )
        VALUES (
            p_safety_committee_id, p_employee_id, p_employee_code, p_employee_name,
            p_role, p_start_date, p_end_date
        )
        RETURNING "MemberId" INTO p_resultado;

        p_mensaje := 'Miembro agregado exitosamente al comitÃƒÂ©.';

    EXCEPTION WHEN OTHERS THEN
        p_resultado := -1;
        p_mensaje   := SQLERRM;
    END;
END;
$function$
;

-- ============================================================
-- usp_hr_committee_getmeetings
-- ============================================================
CREATE OR REPLACE FUNCTION public.usp_hr_committee_getmeetings(p_safety_committee_id integer, p_company_id integer, p_from_date date DEFAULT NULL::date, p_to_date date DEFAULT NULL::date, p_page integer DEFAULT 1, p_limit integer DEFAULT 50)
 RETURNS TABLE(p_total_count bigint, "MeetingId" integer, "SafetyCommitteeId" integer, "MeetingDate" date, "MinutesUrl" character varying, "TopicsSummary" character varying, "ActionItems" character varying, "CreatedAt" timestamp without time zone, "CommitteeName" character varying)
 LANGUAGE plpgsql
AS $function$
BEGIN
    IF p_page  < 1   THEN p_page  := 1;   END IF;
    IF p_limit < 1   THEN p_limit := 50;  END IF;
    IF p_limit > 500 THEN p_limit := 500; END IF;

    -- Verificar que el comitÃƒÂ© pertenece a la empresa
    IF NOT EXISTS (
        SELECT 1 FROM hr."SafetyCommittee"
        WHERE "SafetyCommitteeId" = p_safety_committee_id AND "CompanyId" = p_company_id
    ) THEN
        RETURN;
    END IF;

    RETURN QUERY
    SELECT
        COUNT(*) OVER()         AS p_total_count,
        m."MeetingId",
        m."SafetyCommitteeId",
        m."MeetingDate",
        m."MinutesUrl",
        m."TopicsSummary",
        m."ActionItems",
        m."CreatedAt",
        sc."CommitteeName"
    FROM hr."SafetyCommitteeMeeting" m
    INNER JOIN hr."SafetyCommittee" sc ON sc."SafetyCommitteeId" = m."SafetyCommitteeId"
    WHERE m."SafetyCommitteeId" = p_safety_committee_id
      AND (p_from_date IS NULL OR m."MeetingDate" >= p_from_date)
      AND (p_to_date   IS NULL OR m."MeetingDate" <= p_to_date)
    ORDER BY m."MeetingDate" DESC
    LIMIT p_limit OFFSET (p_page - 1) * p_limit;
END;
$function$
;

-- ============================================================
-- usp_hr_committee_list
-- ============================================================
CREATE OR REPLACE FUNCTION public.usp_hr_committee_list(p_company_id integer, p_country_code character DEFAULT NULL::bpchar, p_is_active boolean DEFAULT NULL::boolean, p_page integer DEFAULT 1, p_limit integer DEFAULT 50)
 RETURNS TABLE(p_total_count bigint, "SafetyCommitteeId" integer, "CompanyId" integer, "CountryCode" character, "CommitteeName" character varying, "FormationDate" date, "MeetingFrequency" character varying, "IsActive" boolean, "CreatedAt" timestamp without time zone, "ActiveMemberCount" bigint, "TotalMeetings" bigint)
 LANGUAGE plpgsql
AS $function$
BEGIN
    IF p_page  < 1   THEN p_page  := 1;   END IF;
    IF p_limit < 1   THEN p_limit := 50;  END IF;
    IF p_limit > 500 THEN p_limit := 500; END IF;

    RETURN QUERY
    SELECT
        COUNT(*) OVER()         AS p_total_count,
        sc."SafetyCommitteeId",
        sc."CompanyId",
        sc."CountryCode",
        sc."CommitteeName",
        sc."FormationDate",
        sc."MeetingFrequency",
        sc."IsActive",
        sc."CreatedAt",
        (
            SELECT COUNT(*) FROM hr."SafetyCommitteeMember" m
            WHERE m."SafetyCommitteeId" = sc."SafetyCommitteeId"
              AND (m."EndDate" IS NULL OR m."EndDate" >= CAST((NOW() AT TIME ZONE 'UTC') AS DATE))
        )::BIGINT AS "ActiveMemberCount",
        (
            SELECT COUNT(*) FROM hr."SafetyCommitteeMeeting" mt
            WHERE mt."SafetyCommitteeId" = sc."SafetyCommitteeId"
        )::BIGINT AS "TotalMeetings"
    FROM hr."SafetyCommittee" sc
    WHERE sc."CompanyId" = p_company_id
      AND (p_country_code IS NULL OR sc."CountryCode" = p_country_code)
      AND (p_is_active    IS NULL OR sc."IsActive"    = p_is_active)
    ORDER BY sc."IsActive" DESC, sc."FormationDate" DESC
    LIMIT p_limit OFFSET (p_page - 1) * p_limit;
END;
$function$
;

-- ============================================================
-- usp_hr_committee_recordmeeting
-- ============================================================
CREATE OR REPLACE FUNCTION public.usp_hr_committee_recordmeeting(p_safety_committee_id integer, p_company_id integer, p_meeting_date timestamp without time zone, p_minutes_url character varying DEFAULT NULL::character varying, p_topics_summary text DEFAULT NULL::text, p_action_items text DEFAULT NULL::text, OUT p_resultado integer, OUT p_mensaje character varying)
 RETURNS record
 LANGUAGE plpgsql
AS $function$
BEGIN
