-- ============================================================
-- usp_hr_employee_getdefaultcompany
-- ============================================================
CREATE OR REPLACE FUNCTION public.usp_hr_employee_getdefaultcompany()
 RETURNS TABLE("CompanyId" integer)
 LANGUAGE plpgsql
AS $function$
BEGIN
    RETURN QUERY
    SELECT c."CompanyId"
    FROM cfg."Company" c
    WHERE c."IsDeleted" = FALSE
