    SELECT cr."Id", cr."EmpresaId", cr."SucursalId", cr."StationId",
           cr."DeviceName", cr."DeviceType", cr."ConnectionType",
           cr."ConnectionConfig", cr."ProviderId", cr."IsActive",
           cr."LastSeenAt", cr."CreatedAt"
