AS $function$
BEGIN
    UPDATE pay."CompanyPaymentConfig"
    SET "IsActive"  = FALSE,
        "UpdatedAt" = NOW() AT TIME ZONE 'UTC'
    WHERE "Id" = p_id;
END;
$function$
;

