    SELECT
        r."Id", r."InventarioId",
        i."ProductName",
        r."Cantidad", r."Unidad", r."Comentario"
    FROM "RestauranteRecetas" r
    LEFT JOIN master."Product" i ON i."ProductCode" = r."InventarioId"
    WHERE r."ProductoId" = p_id;
