    SELECT
        b."BrandCode"::VARCHAR(20),
        b."BrandName"::VARCHAR(200),
        0::INT
    FROM master."Brand" b
    WHERE b."CompanyId" = p_company_id
      AND b."IsDeleted" = FALSE
      AND b."IsActive"  = TRUE
    ORDER BY b."BrandName";
