AS $function$
BEGIN
    IF NOT EXISTS (SELECT 1 FROM master."Seller" WHERE "SellerCode" = p_codigo AND COALESCE("IsDeleted", FALSE) = FALSE) THEN
        RETURN QUERY SELECT -1, 'Vendedor no encontrado'::VARCHAR(500);
